const app = express();

// Per-request CSP nonce. Generated before helmet so the script-src directive
// (a function below) can read it, and reused when we render index.html so the
// inline bootstrap <script> carries the matching nonce. Lets us drop
// 'unsafe-inline' from script-src without breaking the pre-mount theme script.
app.use((req, res, next) => {
    res.locals.cspNonce = crypto.randomBytes(16).toString('base64');
    next();
});

// Security: HTTP headers via helmet
app.use(helmet({
    contentSecurityPolicy: {
        directives: {
            defaultSrc: ["'self'"],
            // No 'unsafe-inline' for scripts — the only inline script (the
            // pre-mount theme bootstrap in index.html) is allowed via a
            // per-request nonce stamped at render time. External bundles are
            // covered by 'self'.
            scriptSrc: ["'self'", (req, res) => `'nonce-${res.locals.cspNonce}'`],
            // style-src keeps 'unsafe-inline': MUI/emotion injects <style>
            // elements at runtime without a nonce, so removing it would break
            // styling. (Tracked as accepted risk.)
            styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],  // Required for MUI and Google Fonts
            imgSrc: ["'self'", "data:", "https:"],
            connectSrc: ["'self'", "wss:", "ws:"],  // WebSocket connections
            fontSrc: ["'self'", "https://fonts.gstatic.com"],
            // find_video renders clips inline as click-to-play <iframe> embeds
            // (YouTube, Vimeo, Dailymotion's geo player, Internet Archive, and
            // PeerTube federation) plus CC-licensed direct .webm/.ogv via
            // <video>. The multi-source search pulls embeds from PeerTube's
            // federated instances — arbitrary, unbounded https hosts that can't
            // be allow-listed — so frame-src is relaxed to https: (script-src
            // stays locked: no unsafe-inline/eval, nonce-gated). media/img
            // already allow https: for direct files + posters.
            frameSrc: ["'self'", "https:"],
            mediaSrc: ["'self'", "data:", "blob:", "https:"],
            objectSrc: ["'none'"],
            upgradeInsecureRequests: [],
        },
    },
    crossOriginEmbedderPolicy: false,  // Required for some external resources
    crossOriginResourcePolicy: { policy: "same-origin" },
    // Don't emit the deprecated X-XSS-Protection header at all. Helmet's
    // default sets it to "0" (the modern, OWASP-aligned value that disables
    // the buggy legacy XSS auditor), but the cleanest posture is to omit the
    // dead header entirely rather than ship a 0 that scanners still flag.
    xXssProtection: false,
    // HSTS off: the dev cert is self-signed, so once Chrome caches an HSTS
    // policy for this origin it refuses to honor the user's "proceed past
    // cert warning" exception for background requests — artifact downloads
    // then surface as "Network issue" / NET::ERR_CERT_AUTHORITY_INVALID
    // mid-stream. HSTS adds no real security value without a trusted CA
    // chain; leave it disabled until we ship trusted certs.
    strictTransportSecurity: false,
}));

// Security: Rate limiting for authentication endpoints
const authRateLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 10, // 10 attempts per window
    message: { error: 'Too many login attempts, please try again later' },
    standardHeaders: true,
    legacyHeaders: false,
    skipSuccessfulRequests: false, // Count all requests
});

// Security: General API rate limiting. Mounted on /api/* (see the global gate
// after the CSRF middleware). Real-time endpoints are exempted so the limit
// never breaks live updates: the chat background-streaming status poll fires
// every ~100ms (≈600 req/min for a single stream) and the automation SSE event
// stream is one long-lived connection — throttling either would regress
// streaming UX (the foreground/background streaming behavior CLAUDE.md flags).
const apiRateLimiter = rateLimit({
    windowMs: 60 * 1000, // 1 minute
    max: 100, // 100 requests per minute
    message: { error: 'Too many requests, please slow down' },
    standardHeaders: true,
    legacyHeaders: false,
    skip: (req) => {
        const p = req.path; // full path — the limiter runs from a global gate
        if (/^\/api\/conversations\/[^/]+\/streaming$/.test(p)) return true; // ~100ms poll
        if (p === '/api/automations/events') return true; // long-lived SSE
        return false;
    },
});

// Security: dedicated limiter for the unauthenticated bootstrap probe
// (/api/auth/has-users). Decoupled from authRateLimiter so polling this
// endpoint can't drain the login/register budget and so it can't be used as a
// recon prelude to brute force. It returns only a single boolean, so the
// window stays generous enough for ordinary page reloads.
const hasUsersRateLimiter = rateLimit({
    windowMs: 5 * 60 * 1000, // 5 minutes
    max: 30,
    message: { error: 'Too many requests, please slow down' },
    standardHeaders: true,
    legacyHeaders: false,
});

// Security: stricter limiter for the unauthenticated public webhook. A webhook
// hit runs an ENTIRE workflow (model completions, scraping, tool calls) as the
// owner, so even with a 192-bit token the endpoint must not be usable to
// amplify load if a token leaks. Per-IP; sits on top of the general /api limit.
const webhookRateLimiter = rateLimit({
    windowMs: 60 * 1000, // 1 minute
    max: 20, // 20 webhook triggers per minute per IP
    message: { error: 'Too many webhook requests, please slow down' },
    standardHeaders: true,
    legacyHeaders: false,
});

