// SSL configuration - use HTTPS if certificates exist
const CERTS_DIR = '/certs';
const SSL_KEY_PATH = path.join(CERTS_DIR, 'server.key');
const SSL_CERT_PATH = path.join(CERTS_DIR, 'server.crt');

let server;
let httpRedirectServer;
let useHttps = false;

if (fsSync.existsSync(SSL_KEY_PATH) && fsSync.existsSync(SSL_CERT_PATH)) {
    try {
        const sslOptions = {
            key: fsSync.readFileSync(SSL_KEY_PATH),
            cert: fsSync.readFileSync(SSL_CERT_PATH),
            // Refuse TLS 1.0 / 1.1 — both deprecated (PCI-DSS, RFC 8996).
            // Node 22+ defaults to TLSv1.2 but this makes the floor explicit
            // and survives a Node downgrade.
            minVersion: 'TLSv1.2',
        };
        server = https.createServer(sslOptions, app);
        useHttps = true;
        console.log('HTTPS enabled with SSL certificates');

        // Create HTTP server on port 3080 for internal container-to-container communication
        // This allows internal services to connect without SSL verification issues
        console.log('HTTP server enabled on port 3080 for internal API access');
        httpRedirectServer = http.createServer(app);
    } catch (error) {
        console.error('Failed to load SSL certificates, falling back to HTTP:', error.message);
        server = http.createServer(app);
    }
} else {
    console.log('SSL certificates not found, using HTTP');
    server = http.createServer(app);
}

// WebSocket Origin check (CSWSH defense-in-depth, 2026-05-27). The
// broadcast() guard already drops frames for sessionless clients, but the
// upgrade itself was previously accepted from any Origin — so a
// cross-origin attacker page could complete the handshake (and could try
// to ride a victim's cookie if SameSite policy ever loosened). Reject the
// upgrade unless: no Origin header (native CLIs / curl don't send one),
// OR the Origin host matches the request Host. Allowlist additional
// origins via WS_ALLOWED_ORIGINS=foo.example.com,bar.example.com if you
// front the app with a different hostname.
const WS_EXTRA_ORIGINS = new Set(
    (process.env.WS_ALLOWED_ORIGINS || '')
        .split(',').map(s => s.trim().toLowerCase()).filter(Boolean)
);
function verifyWsOrigin(info) {
    const origin = info.req.headers.origin;
    if (!origin) return true; // CLI / native app — no browser context
    let originHost;
    try { originHost = new URL(origin).host.toLowerCase(); }
    catch { return false; }
    const reqHost = String(info.req.headers.host || '').toLowerCase();
    if (originHost === reqHost) return true;
    if (WS_EXTRA_ORIGINS.has(originHost)) return true;
    console.warn(`[WS] rejecting cross-origin upgrade: origin=${origin} host=${reqHost}`);
    return false;
}
const wss = new WebSocket.Server({ server, verifyClient: verifyWsOrigin });
const docker = new Docker({ socketPath: '/var/run/docker.sock' });

// Timing-safe string comparison to prevent timing attacks on API keys
function timingSafeCompare(a, b) {
    if (typeof a !== 'string' || typeof b !== 'string') return false;
    if (a.length !== b.length) return false;
    return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
}

// Admin-controlled (Apps tab) switch: when true, the SSRF private-network block
// below is relaxed so web tools / fetch / http_request may reach internal hosts.
// Default false (secure). Persisted in system-settings.json; loaded at boot and
// updated by PUT /api/system-settings. The cloud-metadata range (169.254.0.0/16)
// stays blocked even when this is on (credential-theft floor).
let allowInternalNetworkFlag = false;
function allowInternalNetwork() { return allowInternalNetworkFlag; }

// SSRF protection: validate URLs against private IP ranges and dangerous protocols.
// Returns null if the URL is allowed, or a descriptive error string if it's blocked.
const PRIVATE_URL_MSG = 'URL points to a private/internal address — blocked for safety.';
function urlBlockReason(urlString) {
    let parsed;
    try { parsed = new URL(urlString); } catch { return 'Invalid URL.'; }
    if (!['http:', 'https:'].includes(parsed.protocol)) {
        const proto = parsed.protocol.replace(/:$/, '');
        return `Only http(s) URLs are accepted; got "${proto}://" — file://, javascript:, data:, etc. are not supported. To work with local files, use read_file / read_pdf instead of a fetch tool.`;
    }
    const hostname = parsed.hostname.toLowerCase();
    const parts = hostname.split('.').map(Number);
    // Metadata floor — ALWAYS blocked (169.254.0.0/16), even when internal access
    // is enabled, to prevent cloud credential theft via the metadata endpoint.
    if (parts.length === 4 && parts.every(p => !isNaN(p)) && parts[0] === 169 && parts[1] === 254) {
        return PRIVATE_URL_MSG;
    }
    // Admin opted into internal access → only the metadata floor + protocol check
    // apply; private LAN / loopback / docker-host are permitted.
    if (allowInternalNetwork()) return null;
    if (['localhost', '127.0.0.1', '::1', '0.0.0.0', 'host.docker.internal'].includes(hostname)) return PRIVATE_URL_MSG;
    if (parts.length === 4 && parts.every(p => !isNaN(p))) {
        if (parts[0] === 10) return PRIVATE_URL_MSG; // 10.0.0.0/8
        if (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) return PRIVATE_URL_MSG; // 172.16.0.0/12
        if (parts[0] === 192 && parts[1] === 168) return PRIVATE_URL_MSG; // 192.168.0.0/16
        if (parts[0] === 0) return PRIVATE_URL_MSG; // 0.0.0.0/8
    }
    return null;
}

function isPrivateUrl(urlString) {
    return urlBlockReason(urlString) !== null;
}

// Validate model name to prevent path traversal (e.g. ../../etc/passwd)
function isValidModelName(modelName) {
    if (!modelName || typeof modelName !== 'string') return false;
    // Reject path traversal sequences and absolute paths
    if (modelName.includes('..') || modelName.startsWith('/') || modelName.startsWith('\\')) return false;
    // Ensure resolved path stays within /models
    const resolved = path.resolve('/models', modelName);
    return resolved.startsWith('/models/');
}

