// Get all users (admin only)
app.get('/api/users', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const users = await getAllUsers();
        res.json(users);
    } catch (error) {
        console.error('Get users error:', error);
        res.status(500).json({ error: 'Failed to get users' });
    }
});

// Update user (admin only)
app.put('/api/users/:id', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const { id } = req.params;

        // Whitelist allowed fields to prevent mass assignment
        const { email, disabled, role, allowedSkills } = req.body;
        const updates = {};
        if (email !== undefined) updates.email = email;
        if (disabled !== undefined) updates.disabled = disabled;
        if (role !== undefined && req.user.role === 'admin') updates.role = role;
        if (allowedSkills !== undefined) {
            if (allowedSkills !== null && (!Array.isArray(allowedSkills) || !allowedSkills.every(s => typeof s === 'string'))) {
                return res.status(400).json({ error: 'allowedSkills must be an array of strings or null' });
            }
            updates.allowedSkills = Array.isArray(allowedSkills) ? allowedSkills : null;
        }

        const updatedUser = await updateUser(id, updates);
        res.json(updatedUser);
    } catch (error) {
        console.error('Update user error:', error);
        res.status(400).json({ error: error.message || 'Failed to update user' });
    }
});

// Delete user (admin only)
app.delete('/api/users/:id', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const { id } = req.params;

        // Prevent deleting self
        if (id === req.user.id) {
            return res.status(400).json({ error: 'Cannot delete your own account' });
        }

        await deleteUser(id);
        res.json({ success: true, message: 'User deleted successfully' });
    } catch (error) {
        console.error('Delete user error:', error);
        res.status(400).json({ error: error.message || 'Failed to delete user' });
    }
});

// Reset user password (admin only)
app.post('/api/users/:username/reset-password', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const { username } = req.params;
        const { newPassword } = req.body;

        if (!newPassword || newPassword.length < 8) {
            return res.status(400).json({ error: 'New password must be at least 8 characters long' });
        }

        await adminResetPassword(username, newPassword);
        res.json({ success: true, message: 'Password reset successfully' });
    } catch (error) {
        console.error('Reset password error:', error);
        res.status(400).json({ error: error.message || 'Failed to reset password' });
    }
});

// Create user (admin only)
app.post('/api/users', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const { username, email, password, role } = req.body;

        if (!username || !email || !password) {
            return res.status(400).json({ error: 'Username, email, and password are required' });
        }

        if (password.length < 8) {
            return res.status(400).json({ error: 'Password must be at least 8 characters long' });
        }

        const user = await createUser({ username, email, password, role: role || 'user' });
        res.status(201).json(user);
    } catch (error) {
        console.error('Create user error:', error);
        res.status(400).json({ error: error.message || 'Failed to create user' });
    }
});

// Invite user by email (admin only) - creates pending user
app.post('/api/users/invite', requireAuth, async (req, res) => {
    try {
        // Check if user is admin
        if (!req.user || req.user.role !== 'admin') {
            return res.status(403).json({ error: 'Admin access required' });
        }

        const { email } = req.body;

        if (!email) {
            return res.status(400).json({ error: 'Email is required' });
        }

        // Validate email format
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email)) {
            return res.status(400).json({ error: 'Invalid email format' });
        }

        const user = await createPendingUser(email);
        res.status(201).json({
            success: true,
            user,
            message: `Invitation created for ${email}. User can now register with this email.`
        });
    } catch (error) {
        console.error('Invite user error:', error);
        res.status(400).json({ error: error.message || 'Failed to invite user' });
    }
});

// Disable user (admin only)
