// ============================================================================
// AUTOMATION ENGINE ENDPOINTS
// Workflow definitions + user-authored node-types + run/control. Mirrors the
// /api/skills CRUD pattern: requireAuth + checkPermission('automation') +
// filterByUserId + checkOwnership + crypto-random ids. Session/UI callers
// (no apiKeyData) bypass the permission check; API-key/bearer callers need
// the 'automation' permission. Telegram nodes are intentionally not wired yet.
// ============================================================================

// Tracks in-flight automation runs so they can be cancelled. runId -> { abort, userId, workflowId }
const activeAutomationRuns = new Map();

const AUTOMATION_PERM = 'automation';

// --- Workflow (automation) CRUD ---

// Attach a resolved _ownerName to each item (for the admin-wide view).
// global/no-userId items get null; unknown ids fall back to the raw id.
async function attachOwnerNames(items) {
    try {
        const users = await getAllUsers();
        const byId = new Map((users || []).map(u => [String(u.id), u.username]));
        return items.map(it => ({ ...it, _ownerName: it.userId ? (byId.get(String(it.userId)) || it.userId) : null }));
    } catch (_) {
        return items.map(it => ({ ...it, _ownerName: it.userId || null }));
    }
}

app.get('/api/automations', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    try {
        const workflows = await loadWorkflows();
        // Admins (session or admin-keyed) get an org-wide view with owner names;
        // everyone else sees their own + global items.
        if (callerIsAdmin(req)) return res.json(await attachOwnerNames(workflows));
        res.json(filterByUserId(workflows, req.userId));
    } catch (error) {
        console.error('Error loading automations:', error);
        res.status(500).json({ error: 'Failed to load automations' });
    }
});

// Live run-event stream (SSE) — the chat editor subscribes while open so
// server-triggered runs (schedule / telegram / webhook / event) animate too.
// Registered before the `:id` route so "events" isn't treated as an id.
app.get('/api/automations/events', requireAuth, (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.setHeader('X-Accel-Buffering', 'no');
    if (typeof res.flushHeaders === 'function') res.flushHeaders();
    const userId = req.userId;
    if (!automationEventListeners.has(userId)) automationEventListeners.set(userId, new Set());
    const set = automationEventListeners.get(userId);
    set.add(res);
    try { res.write(`data: ${JSON.stringify({ type: 'connected' })}\n\n`); } catch (_) {}
    const keepalive = setInterval(() => { try { res.write(': keepalive\n\n'); } catch (_) {} }, 25000);
    req.on('close', () => {
        clearInterval(keepalive);
        const s = automationEventListeners.get(userId);
        if (s) { s.delete(res); if (!s.size) automationEventListeners.delete(userId); }
    });
});

app.get('/api/automations/:id', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    try {
        const workflows = await loadWorkflows();
        const wf = workflows.find(w => w.id === req.params.id);
        if (!wf) return res.status(404).json({ error: 'Automation not found' });
        if (!checkOwnership(wf, req.userId) && !callerIsAdmin(req)) {
            return res.status(403).json({ error: 'Access denied: automation belongs to another user' });
        }
        res.json(wf);
    } catch (error) {
        console.error('Error loading automation:', error);
        res.status(500).json({ error: 'Failed to load automation' });
    }
});

app.post('/api/automations', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    const { name, description, nodes, edges, enabled, archived } = req.body || {};
    if (!name) return res.status(400).json({ error: 'Automation name is required' });
    try {
        const workflows = await loadWorkflows();
        const now = new Date().toISOString();
        const wf = {
            id: crypto.randomBytes(16).toString('hex'),
            name,
            description: description || '',
            nodes: Array.isArray(nodes) ? nodes : [],
            edges: Array.isArray(edges) ? edges : [],
            enabled: enabled !== false,
            archived: archived === true,
            userId: req.userId || null,
            createdAt: now,
            updatedAt: now
        };
        workflows.push(wf);
        await saveWorkflows(workflows);
        res.status(201).json(wf);
    } catch (error) {
        console.error('Error creating automation:', error);
        res.status(500).json({ error: 'Failed to create automation' });
    }
});

// Max model-driven repair passes per Test-&-improve invocation. A run that
// "completes" with zero real data still counts as needing repair (see
// automationEngine.assessRunHealth), so this loops run→assess→repair, not once.
// Raised to 5 so the model gets several reasoning attempts at a genuinely broken
// workflow (each pass re-runs against fresh per-node outputs, so it can chase a
// fix across the whole chain rather than giving up after one try).
const MAX_REPAIR_PASSES = 5;

// Ask the model whether a finished run actually achieved the user's stated goal
// (semantic check beyond structural health) — e.g. a PDF was really produced
// with real content, charts are present if asked, the report is substantive.
// Returns { achieved:boolean, problems:string, fix:string }. Defaults to
// achieved=true on any parse/transport failure so a flaky judge never blocks a
// structurally-clean build. Credentials/unreachable-site gaps are out of scope
// (the user supplies those).
async function judgeGoalAchieved(goalPrompt, runSummary, model, dedupVerified = false) {
    const dedupNote = dedupVerified
        ? '\n\nALREADY VERIFIED (do not re-judge): the "only new / only changed" requirement was CONFIRMED working by re-running the workflow — duplicates were suppressed on the second run. Do NOT raise anything about only-new / dedup / filtering / "skipped: 0" / newness; treat that requirement as MET. Judge ONLY content quality and whether the requested artifact was produced.'
        : '';
    const messages = [
        { role: 'system', content: 'You verify whether an automation run achieved the user\'s goal. Reply with ONLY a JSON object: {"achieved": true|false, "problems": "<what is missing or wrong; empty if achieved>", "fix": "<one concrete change to the workflow; empty if achieved>"}. Judge the END RESULT, not intentions.' + dedupNote },
        { role: 'user', content: `User's goal for the automation:\n${String(goalPrompt).slice(0, 1200)}\n\nWhat the run produced (per node, in order):\n${runSummary}\n\nDid the run ACHIEVE the goal? Require: real data flowed end-to-end (not placeholders, empties, or "no content" apologies); the FINAL artifact matches the request (if a PDF/report/file was asked for, an artifact was actually generated with real content; if charts/graphs were asked for, a chart/render step ran; if a summary/notification was asked for, it is substantive); and any "only new items / only when changed" requirement is implemented with a db_store key or track_changes node.\n\nIMPORTANT — judge the WIRING, not the luck of this run: a run that correctly produces NOTHING because there is no new/changed/matching data yet is SUCCESSFUL, not a failure. Specifically:\n- The FIRST run of a change monitor (track_changes returns changed=false / firstSeen — it stores a baseline) and a dedup re-run where nothing is new (db_store .new is empty, so a downstream gate correctly skips the notification) are CORRECT behavior.\n- For a workflow started by an EXTERNAL message/webhook trigger (telegram / slack / webhook), this TEST run uses PLACEHOLDER/empty input — so input-dependent gates (e.g. checking the message text for a keyword) will naturally NOT match and the run may take a default/no-op branch. That is EXPECTED, not a defect. Judge whether the gates REFERENCE the trigger input correctly (e.g. {{input.text}}) and each branch leads to a sensible action — NOT whether a particular branch fired this run.\nDo NOT judge whether cross-run dedup / "only new" / "only changed" actually works — that is verified SEPARATELY by re-running the workflow. In particular, a FRESH run that stores ALL items with 0 skipped/duplicates is CORRECT (nothing has been seen yet) — never call that a dedup failure. Treat the "only new" requirement as satisfied as long as the graph HAS the right structure for it: a db_store with a key (or a track_changes node) feeding a gate that routes the new/changed data onward. Judge only what THIS run shows: did real content flow (not placeholders/errors), and was the requested final output (PDF/report/file/chart/message) actually produced this run.\nMark achieved=true whenever real content flowed and the requested artifact was produced (or correctly skipped on a no-new/no-match run). Only mark achieved=false for a real wiring/logic defect (missing PDF/chart step, broken field paths, NO db_store-key/track_changes at all for an "only new" requirement, a gate that can NEVER be true, empty/error data where there should be content). Ignore missing credentials/tokens and unreachable external sites. Respond with ONLY the JSON object.` },
    ];
    const text = await runModelCompletion({ messages, model, temperature: 0, maxTokens: 500, disableThinking: true });
    let raw = String(text || '').trim();
    const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i); if (fence) raw = fence[1].trim();
    const lo = raw.indexOf('{'), hi = raw.lastIndexOf('}'); if (lo !== -1 && hi > lo) raw = raw.slice(lo, hi + 1);
    const v = JSON.parse(raw);
    return { achieved: v.achieved !== false, problems: v.problems || '', fix: v.fix || '' };
}

// Before each build-test pass, clear any cross-run state (db_store tables /
// track_changes snapshots) so the run starts FRESH — items appear as new and
// the full happy path (gate true → notify / PDF) executes, which is what the
// goal-judge needs to see. Without this, state persisted from an earlier pass
// makes every later run a no-op (nothing new), and the judge wrongly concludes
// the final step is broken. The dedup double-run later in the pass still proves
// suppression because it runs AFTER this fresh run has populated the store.
async function resetStatefulStorage(wfObj, req) {
    const stateful = automationEngine.findStatefulNodes(wfObj);
    if (!stateful.any) return;
    const chatTools = require('./services/chatTools');
    const ctx = { userId: req.userId, apiKeyData: req.apiKeyData || null, conversationId: null, workspaceBucket: `automation-${wfObj.id}` };
    const dispatch = async (name, args) => {
        try { await chatTools.executeToolCall({ id: `reset-${name}`, function: { name, arguments: JSON.stringify(args) } }, ctx); }
        catch (_) { /* best-effort: a clear failure just means the dedup re-run still proves suppression */ }
    };
    for (const id of stateful.storeKeyIds) {
        const d = (wfObj.nodes.find(x => x.id === id) || {}).data || {};
        await dispatch('workspace_db', { action: 'clear', table: d.table || 'records', db: d.db || 'automation.db' });
    }
    for (const id of stateful.trackIds) {
        const d = (wfObj.nodes.find(x => x.id === id) || {}).data || {};
        await dispatch('track_changes', { action: 'clear', table: d.table || 'snapshots', db: d.db || 'automation.db' });
    }
}

// Run `wfObj`, assess whether it actually produced data, and — while it didn't and
// the failure isn't pure missing-config — ask the model to repair it, looping up
// to MAX_REPAIR_PASSES. Mutates wfObj.nodes/edges in place and appends a rich
// per-pass log to buildLog. Does NOT persist (caller decides). `base` is the
// workflow the model edits against (id/position preservation); for Build it's
// wfObj itself, for the Edit preview it's the original (so the proposed revision
// is what's run/fixed). Keeps the BEST (fewest-issues) version seen.
async function runAndRepairWorkflow(wfObj, base, model, req, buildLog, goalPrompt = '') {
    // Compact per-node summary fed back to the model so it fixes against the
    // ACTUAL outputs (wrong paths, error payloads, empty results).
    // Per-node summary fed back to the model. Healthy nodes get a short preview;
    // FLAGGED nodes (the ones assessRunHealth marked bad) get a longer slice so
    // the model can see the actual traceback / error payload / wrong shape and
    // reason about the root cause — not just the symptom at the final node.
    const summarize = (outcome, rec, badIds) => {
        const bad = badIds instanceof Set ? badIds : new Set();
        const L = [`run status=${outcome.status}`];
        if (outcome.error) L.push(`run error: ${outcome.error}`);
        if (rec && Array.isArray(rec.nodes)) for (const n of rec.nodes) {
            const o = n.output;
            const os = o == null ? '' : (typeof o === 'string' ? o : JSON.stringify(o));
            const cap = bad.has(n.nodeId) ? 600 : 180;
            const flag = bad.has(n.nodeId) ? ' ⚠ PROBLEM' : '';
            L.push(`- ${n.nodeId} (${n.type}): ${n.status}${flag}${n.error ? ' ERROR: ' + n.error : ''}${os ? ' → ' + String(os).slice(0, cap) : ''}`);
        }
        return L.join('\n');
    };
    // A webhook/message-triggered workflow whose steps read {{input...}} has NO real
    // user input during a TEST run. Feed it a representative sample so input-dependent
    // nodes (fetch_url {{input.url}}, a keyword gate on {{input.text}}, …) actually
    // execute end-to-end and can be judged fairly, instead of failing on empty input.
    const triggerType = ((wfObj.nodes || []).find(n => typeof n.type === 'string' && n.type.startsWith('trigger.')) || {}).type || '';
    const inputDriven = /^trigger\.(webhook|telegram|slack|manual)$/.test(triggerType)
        && /\{\{\s*input\b/.test(JSON.stringify(wfObj.nodes || []));
    const testInput = inputDriven
        ? { url: 'https://example.com', text: 'test message', message: 'test message', body: 'test', query: 'test', content: 'test', chat: { id: '0' }, user: 'tester', from: { id: '0' } }
        : {};
    // Missing-input errors that slip through anyway are "needs live input", not a defect.
    const isInputMissingError = (s) => /\b(is required|are required|missing)\b/i.test(String(s || ''))
        && /\b(url|input|content|value|text|query|message|body)\b/i.test(String(s || ''));

    const runOnce = async () => {
        try {
            // Mirror test-run events to the user's SSE stream so the editor
            // animates each pass on the board when the workflow is open (Edit case).
            const { runId, outcome } = await executeWorkflowRun(wfObj, { userId: req.userId, apiKeyData: req.apiKeyData || null, trigger: 'test', input: testInput, onEvent: (evt) => { try { mirrorAutomationEvent(req.userId, evt); } catch (_) {} } });
            let rec = null; try { rec = await workflowRunStore.getRun(req.userId, runId); } catch (_) {}
            return { outcome, rec };
        } catch (e) { return { outcome: { status: 'failed', error: e.message }, rec: null }; }
    };
    // Pure-config errors the user must resolve (don't burn passes trying to fix
    // a missing token or an unreachable site — that's not a wiring bug).
    const isConfigError = (s) => /token|credential|chat id|webhook url|bot token|api key|not in the channel|channels:history|requires a /i.test(String(s || ''));

    // Targeted, data-driven guidance appended to every repair request — these are
    // the exact traps the cybersecurity-newspaper workflow fell into.
    const REPAIR_GUIDANCE = [
        'GUIDANCE — diagnose the WHOLE chain, then fix the EARLIEST broken node (a failure upstream poisons everything after it). Apply only what the run results above show is broken:',
        '- If a run_python / run_node node shows a non-zero returncode or a stderr traceback like "NameError: name \'nodes\' is not defined": the script tried to read workflow data as a variable. run_python/run_node have NO `nodes`/`last`/`input` variables — those names do not exist in the sandbox. The CORRECT fix is almost always to REMOVE the run_python node and replace that step with the right native node: for a JSON API/feed use http_request → parse_json; for an HTML page use fetch_url → a model node to extract. Only keep run_python for a pure local transform, and then pass upstream data by INTERPOLATING it as a literal string (e.g. code begins `data = json.loads(r\'\'\'{{nodes.n2.content}}\'\'\')`), never by naming a node.',
        '- If the source is a website you are scraping for structured records: check whether it has a JSON API or feed (paths like /api/recent, /api/<thing>, .json, /feed, /rss). If so, http_request that endpoint and parse_json its .data — that is far more reliable than parsing HTML. http_request output is { success, status, data }; parse_json "source" must be "{{nodes.<httpId>.data}}".',
        '- If an http_request node shows status >= 400: the URL/method is wrong — correct it (or switch to the site\'s real JSON endpoint).',
        '- If a db_store node\'s `.new` contains error objects (e.g. a stored {returncode:1,...}): the node feeding its "value" is broken — fix THAT upstream node; also make sure "key" is a real unique field of the records (e.g. "link" or an id), not a field that doesn\'t exist on the actual data shape shown above.',
        '- If web_search nodes returned an {error} about rate-limiting / DuckDuckGo / Brave / Scrapling: site-specific web_search queries are unreliable. Replace them with fetch_url or crawl_pages directly on the source site\'s homepage or RSS/Atom feed (e.g. https://thehackernews.com/, https://www.darkreading.com/, https://cybersecuritynews.com/, or that site\'s feed URL).',
        '- If a parse_json node returned [] or extracted nothing: its "path" does not match the real upstream shape shown above. A merge outputs {items:[...],count}; web_search outputs {results:[...]}. To get all urls from MERGED searches use path "items.*.results.*.url" (NOT "*.url").',
        '- If a map node returned results full of {error:"…needs a tool/skill name"}: a map\'s "action" must be "tool" or "model". For a tool action set "action":"tool", set "tool" to a valid name (e.g. "fetch_url" or "crawl_pages"), and put per-item args in "args" using {{item}} for the current item. Do NOT put the tool name in "action".',
        '- If a map node failed EVERY item with "Invalid URL" (or ran once treating a whole string as a single item): its "items" resolved to a STRING, not a list. A model node\'s output is a STRING, so you CANNOT feed a model node straight into a map. Fix it one of two ways: (a) replace that model node with a "set" node whose "value" is a real JSON array of the actual URLs (e.g. {"name":"urls","value":["https://a.com/feed/","https://b.com/rss.xml"]}); OR (b) add a "parse_json" node after the model to parse its JSON-array string into a real array. Then point the map\'s "items" at that node with an EXACT template (items:"{{nodes.<id>}}" or "{{nodes.<id>.<field>}}", no surrounding text) so the raw array is passed.',
        '- For "latest news from a site", fetch_url works on the site HOMEPAGE and on its RSS/Atom FEED and returns real recent content. Prefer feed URLs, e.g. https://www.bleepingcomputer.com/feed/ , https://www.darkreading.com/rss.xml , https://krebsonsecurity.com/feed/ , https://thehackernews.com/ (homepage). Avoid feedburner.com mirrors (often refused).',
        '- If the final model node wrote an "error retrieving / no content" style message: that means it had no real source data — fix the upstream fetch/extract nodes so real content reaches it.',
        '- If a telegram/slack node failed with HTTP 400 / "message is too long": the text exceeds the platform limit. Keep the model node\'s output concise (ask it to summarize, not dump every record), and/or only forward the new items, so the message stays well under a few thousand characters.',
        '- DEDUP THAT SILENTLY SUPPRESSES EVERYTHING: if a db_store reports records on the FIRST run then ZERO "new" on later runs while real content keeps appearing — OR its input is a fetch_url of a HOMEPAGE/section page (or a merge of such) — it is keying on the SOURCE PAGE, not the articles. fetch_url on a homepage returns ONE record per site whose url never changes, so every later run sees "already seen" and the gate blocks forever. This is the #1 dedup bug. FIX: replace each homepage fetch_url with a parse_rss node on that site\'s RSS/Atom feed (one record PER ARTICLE with a stable link), fan them into a merge, and set db_store value="{{nodes.<merge>.items.*.items}}" (the ".*.items" flattens every feed\'s items into one article list) with key="link". Then gate.if on .new. For full article text (not just the feed summary), add a map node after the gate: { "items":"{{nodes.<store>.new}}", "action":"tool", "tool":"fetch_url", "args":{"url":"{{item.link}}"} } and feed the model "{{nodes.<map>.results}}".',
    ].join('\n');

    // Snapshot the best version seen so a worse final pass doesn't win.
    let best = { score: Infinity, nodes: null, edges: null };
    const remember = (assess) => {
        if (assess && assess.score < best.score) {
            best = { score: assess.score, nodes: JSON.parse(JSON.stringify(wfObj.nodes)), edges: JSON.parse(JSON.stringify(wfObj.edges)) };
        }
    };

    let lastAssess = null;
    let lastOutcome = null;
    let lastRec = null;     // the most recent run record (per-node detail for the test report)
    let passesRun = 0;      // how many run/repair passes actually executed
    let configStop = false;
    let goalFix = '';

    for (let pass = 1; pass <= MAX_REPAIR_PASSES; pass++) {
        passesRun = pass;
        // Start each pass from clean cross-run state so this run exercises the
        // full happy path (new items → notify/PDF) for the goal-judge to see.
        await resetStatefulStorage(wfObj, req);
        const { outcome, rec } = await runOnce();
        lastOutcome = outcome;
        lastRec = rec;
        goalFix = '';
        const configError = outcome.status === 'failed' && isConfigError(outcome.error);
        // assessRunHealth reads rec.nodes; if the run threw before producing a
        // record, treat the thrown error itself as a high-severity issue.
        let assess;
        if (rec) {
            assess = automationEngine.assessRunHealth(rec);
        } else {
            assess = { ok: outcome.status === 'completed', issues: outcome.error ? [{ nodeId: '(run)', type: '', severity: 'high', detail: outcome.error }] : [], score: outcome.error ? 3 : 0 };
        }

        // Deeper verification on a structurally-healthy run — this is what makes
        // the loop iterate toward the user's ACTUAL goal, not just "no errors":
        //   (a) re-run once and prove dedup / change-tracking suppresses repeats
        //       (the only way to verify "only notify on NEW content" works);
        //   (b) ask the model whether the END RESULT matches the user's request
        //       (real data flowed, the PDF/report/chart actually got produced).
        // Both run only when the structure is sound, so a broken graph isn't
        // charged extra runs/model calls. Failures here become repairable issues.
        if (assess.ok && !configError) {
            const stateful = automationEngine.findStatefulNodes(wfObj);
            let dedupVerified = false; // the re-run proved "only new/changed" works
            if (stateful.any && rec && Array.isArray(rec.nodes)) {
                const second = await runOnce();
                const r2 = second.rec;
                const outOf = (record, id) => {
                    const n = record && Array.isArray(record.nodes) ? record.nodes.find(x => x.nodeId === id) : null;
                    return n ? n.output : null;
                };
                // Read the scalar `stored` count, not new.length — on a fresh
                // run the large `.new` array makes db_store's output exceed the
                // record size cap and it's stored as { _truncated, preview }, so
                // new.length (and even o.stored) read null. The preview keeps the
                // head of the JSON, where "stored":N sits before the big array.
                const newCount = (o) => {
                    if (!o || typeof o !== 'object') return null;
                    if (typeof o.stored === 'number') return o.stored;
                    if (Array.isArray(o.new)) return o.new.length;
                    if (o._truncated && typeof o.preview === 'string') {
                        const m = o.preview.match(/"stored"\s*:\s*(\d+)/);
                        if (m) return parseInt(m[1], 10);
                    }
                    return null;
                };
                for (const id of stateful.storeKeyIds) {
                    const o1 = outOf(rec, id), o2 = outOf(r2, id);
                    const n1 = newCount(o1);
                    const n2 = newCount(o2);
                    if (n1 != null && n2 != null && n1 > 0 && n2 >= n1) {
                        assess.issues.push({ nodeId: id, type: 'db_store', severity: 'high', detail: `dedup is NOT working: re-running immediately produced ${n2} "new" record(s) again (same as the first run's ${n1}). The "key" is not a STABLE unique field of the actual records — set it to the real id/url field shown in the data above (add keyNormalize:true / a comma-fallback like "link,title") so already-seen items are suppressed on later runs.` });
                        buildLog.push(`Pass ${pass}: dedup check — db_store ${id} re-reported ${n2} items (key not stable) ✗`);
                    } else if (n1 != null && n2 != null) {
                        if (n1 > 0 && n2 < n1) dedupVerified = true;
                        buildLog.push(`Pass ${pass}: dedup check — db_store ${id} suppressed repeats on re-run (${n1}→${n2} new) ✓`);
                    }
                }
                for (const id of stateful.trackIds) {
                    const o2 = outOf(r2, id);
                    if (o2 && typeof o2 === 'object' && o2.changed === true) {
                        assess.issues.push({ nodeId: id, type: 'track_changes', severity: 'medium', detail: `change-tracker reported a change on an immediate re-run of the same source — the "key" should be a CONSTANT id (e.g. the page URL) so the previous snapshot is found next run.` });
                        buildLog.push(`Pass ${pass}: change check — track_changes ${id} flagged a change on identical re-run (key may be unstable) ✗`);
                    } else if (o2 && typeof o2 === 'object') {
                        dedupVerified = true;
                        buildLog.push(`Pass ${pass}: change check — track_changes ${id} reported no change on re-run ✓`);
                    }
                }
            }
            // Did the fresh run actually produce a downloadable artifact (PDF /
            // file / chart)? Used to override the judge's known dedup blind spot.
            const artifactProduced = Array.isArray(rec.nodes) && rec.nodes.some(n => {
                const o = n && n.output;
                return o && typeof o === 'object' && Array.isArray(o._artifacts) && o._artifacts.length > 0;
            });
            if (goalPrompt) {
                try {
                    const verdict = await judgeGoalAchieved(goalPrompt, summarize(outcome, rec, new Set()), model, dedupVerified);
                    if (verdict && verdict.achieved === false) {
                        // Deterministic guard against the judge's known blind spot:
                        // it can't see edges in the run summary, so it often claims
                        // "no only-new filtering / no notification" even though the
                        // stateful node → gate is correctly wired. When the re-run
                        // already PROVED the only-new/only-changed mechanism works
                        // (and structural health ruled out empty/apology content),
                        // the goal is objectively met for two cases:
                        //  • dedup feed: the fresh run produced its artifact;
                        //  • change monitor: its notify path can't fire in a rapid
                        //    double-run (same content → no change), so "nothing this
                        //    run" is the only testable — and correct — outcome.
                        const isChangeMonitor = stateful.trackIds.length > 0;
                        if (dedupVerified && (artifactProduced || isChangeMonitor)) {
                            buildLog.push(`Pass ${pass}: goal check — overridden ✓ (${isChangeMonitor ? 'change-detection verified; no change this run is correct, it will notify on a real change' : 're-run proved dedup AND the fresh run produced its artifact'})`);
                        } else {
                            goalFix = verdict.fix ? String(verdict.fix) : '';
                            assess.issues.push({ nodeId: '(goal)', type: 'goal', severity: 'high', detail: `the run did not achieve the user's goal — ${String(verdict.problems || '').slice(0, 300)}${goalFix ? ' — FIX: ' + goalFix.slice(0, 300) : ''}` });
                            buildLog.push(`Pass ${pass}: goal check — not met: ${String(verdict.problems || '').slice(0, 160)}`);
                        }
                    } else if (verdict && verdict.achieved === true) {
                        buildLog.push(`Pass ${pass}: goal check — achieved ✓`);
                    }
                } catch (e) { buildLog.push(`Pass ${pass}: goal check skipped — ${e.message}`); }
            }
            // Recompute health after enrichment: any newly-added high issue makes
            // the run unhealthy so the loop keeps iterating toward the goal.
            assess.score = assess.issues.reduce((s, i) => s + (i.severity === 'high' ? 3 : 1), 0);
            if (assess.issues.some(i => i.severity === 'high')) assess.ok = false;
        }

        lastAssess = assess;
        remember(assess);

        const issuesLine = automationEngine.summarizeIssues(assess.issues);
        // Node ids the assessment flagged — these get expanded output in the
        // repair prompt so the model sees the actual error, not just a preview.
        const badIds = new Set((assess.issues || []).map(i => i.nodeId).filter(Boolean));
        buildLog.push(`Pass ${pass}: ${assess.ok ? 'data is flowing' : 'issues — ' + issuesLine}`);

        // "Needs live input" — an input-driven workflow whose only high-severity
        // issues are missing-input errors during the no-input test run. Treat like
        // config: it builds correctly and runs when triggered with real data.
        const highIssues = (assess.issues || []).filter(i => i.severity === 'high');
        const inputNeeded = inputDriven && !assess.ok && highIssues.length > 0
            && highIssues.every(i => isInputMissingError(i.detail));

        // Stop early when healthy, or when the only thing wrong is missing config.
        if (configError || inputNeeded) {
            buildLog.push(inputNeeded
                ? 'This workflow needs live input from its trigger (e.g. the webhook request body or the incoming message). It builds correctly and will run when triggered with real data.'
                : 'That failure is just missing configuration (e.g. a token / unreachable site) — fill it in and it will run.');
            configStop = true;
            break;
        }
        if (!automationEngine.shouldRepair(assess, pass, MAX_REPAIR_PASSES, configError)) break;

        // Ask the model to repair against the ACTUAL failing outputs + guidance.
        // Compact oversized field values to __KEEP_FIELD_N__ tokens first (same as
        // the edit endpoint) so a big systemPrompt/template doesn't truncate the
        // echoed workflow and silently abort the repair loop.
        const currentForLLM = { name: wfObj.name, nodes: wfObj.nodes.map(n => ({ id: n.id, type: n.type, data: n.data })), edges: wfObj.edges.map(e => ({ source: e.source, target: e.target, ...(e.sourceHandle ? { sourceHandle: e.sourceHandle } : {}) })) };
        const { compacted: compactedWf, placeholders: repairPlaceholders, byIndex: repairByIndex, count: keepCount, prefix: repairPrefix } = automationEngine.compactWorkflowForLLM(currentForLLM);
        const repairKeepNote = keepCount > 0
            ? `\n\nNOTE: ${keepCount} long field value(s) were replaced with placeholder tokens like ${repairPrefix}0__. Keep each token EXACTLY as-is to leave that field unchanged; only replace a token if the fix requires editing that specific field.`
            : '';
        const messages = [
            { role: 'system', content: automationEngine.buildBuilderSystemPrompt() },
            { role: 'user', content: `This workflow was just run and did not yet succeed. Fix the cause (wrong field paths, bad wiring, rate-limited searches, misconfigured map actions, missing required args, or a missing step needed to meet the goal). IGNORE failures from missing credentials/tokens or unreachable external sites — the user configures those.${goalPrompt ? `\n\nThe user's ORIGINAL goal (the run must actually achieve this):\n${String(goalPrompt).slice(0, 800)}` : ''}${goalFix ? `\n\nGoal not met — required change: ${goalFix}` : ''}\n\nDetected problems:\n${issuesLine}\n\nRun results (per node, ⚠ marks the flagged ones):\n${summarize(outcome, rec, badIds)}\n\n${REPAIR_GUIDANCE}\n\nCurrent workflow:\n${JSON.stringify(compactedWf)}${repairKeepNote}\n\nReturn the FULL revised workflow as one JSON object, keeping existing node ids. Respond with ONLY the JSON.` },
        ];
        try {
            const text = await runModelCompletion({ messages, model, temperature: 0.2, maxTokens: 8000, disableThinking: true });
            let raw = String(text || '').trim();
            const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i); if (fence) raw = fence[1].trim();
            const lo = raw.indexOf('{'), hi = raw.lastIndexOf('}'); if (lo !== -1 && hi > lo) raw = raw.slice(lo, hi + 1);
            // Use the jsonrepair-backed parser (same as build/edit) — repair
            // replies routinely contain run_python code / long strings with raw
            // newlines or trailing commas that plain JSON.parse rejects, which
            // silently aborted the whole repair loop.
            const spec = parseBuilderSpec(raw);
            if (!spec || typeof spec !== 'object') throw new Error('repair reply was not valid JSON');
            // Restore placeholder tokens BEFORE materializing so node-signature
            // id-recovery operates on the real field values: exact → tolerant index →
            // recover a still-residual field from the matching original node. A token
            // that survives all three would otherwise be saved as a bare placeholder,
            // so treat that as an unusable repair and skip the pass.
            const repairOrigById = new Map((base.nodes || []).map(n => [n.id, n]));
            if (Array.isArray(spec.nodes)) for (const node of spec.nodes) {
                if (!node || !node.data) continue;
                node.data = automationEngine.expandPlaceholders(node.data, repairPlaceholders, repairByIndex);
                if (automationEngine.hasResidualKeepToken(node.data) && repairOrigById.has(node.id)) {
                    automationEngine.recoverResidualFromOriginal(node, repairOrigById.get(node.id));
                }
            }
            if (keepCount > 0 && Array.isArray(spec.nodes) && spec.nodes.some(n => n && automationEngine.hasResidualKeepToken(n.data))) {
                throw new Error('repair reply left an unrecoverable placeholder token');
            }
            const revised = automationEngine.materializeWorkflowEdit(spec, base);
            wfObj.nodes = revised.nodes; wfObj.edges = revised.edges;
            buildLog.push(`Pass ${pass}: applied a repair, re-running…`);
        } catch (e) {
            buildLog.push(`Pass ${pass}: auto-fix skipped — ${e.message}`);
            break; // can't repair without a usable model edit; stop
        }
    }

    // Restore the best version if the final pass regressed (more issues than an
    // earlier attempt). best.nodes is null only if every pass scored Infinity,
    // which can't happen (a clean run scores 0), so this is safe.
    if (best.nodes && lastAssess && lastAssess.score > best.score) {
        wfObj.nodes = best.nodes; wfObj.edges = best.edges;
        buildLog.push(`Kept the best attempt (${best.score} issue-points) over a worse final pass.`);
    }

    // Clear verdict.
    let verdictText;
    let outcomeKind; // 'ok' | 'config' | 'failed'
    if (configStop) {
        outcomeKind = 'config';
        verdictText = 'Runs — only needs configuration you must supply (a token / credential / reachable source).';
        // (the specific config message was already pushed to buildLog above)
    } else if (lastAssess && lastAssess.ok) {
        outcomeKind = 'ok';
        verdictText = 'Data is flowing end to end ✓';
        buildLog.push('Result: data is flowing ✓');
    } else {
        outcomeKind = 'failed';
        verdictText = 'Still no data after repair passes — best attempt kept; likely needs the sites\' RSS feeds or a configured search/API key.';
        buildLog.push('Result: ' + verdictText);
    }

    // Structured report for the UI — the same information the buildLog conveys in
    // prose, but per-node and machine-readable so the Assistant panel can render a
    // clear pass/fail table instead of a wall of bullet text.
    const labelById = new Map((wfObj.nodes || []).map(n => [String(n.id), (n.data && n.data.label) || n.type]));
    const shortPreview = (o) => {
        if (o == null) return '';
        let s = typeof o === 'string' ? o : (() => { try { return JSON.stringify(o); } catch (_) { return String(o); } })();
        s = s.replace(/\s+/g, ' ').trim();
        return s.length > 160 ? s.slice(0, 160) + '…' : s;
    };
    const flaggedIds = new Set((lastAssess && lastAssess.issues || []).map(i => i.nodeId).filter(Boolean));
    const reportNodes = (lastRec && Array.isArray(lastRec.nodes) ? lastRec.nodes : []).map(n => ({
        id: n.nodeId,
        label: labelById.get(String(n.nodeId)) || n.type,
        type: n.type,
        status: n.status,
        error: n.error || null,
        preview: shortPreview(n.output),
        flagged: flaggedIds.has(n.nodeId),
    }));
    const testReport = {
        outcome: outcomeKind,                 // ok | config | failed
        ok: outcomeKind === 'ok',
        configNeeded: outcomeKind === 'config',
        status: lastOutcome ? lastOutcome.status : 'unknown',
        passes: passesRun,
        verdict: verdictText,
        issues: (lastAssess && lastAssess.issues || []).map(i => ({ nodeId: i.nodeId, type: i.type, severity: i.severity, detail: i.detail })),
        nodes: reportNodes,
    };
    return testReport;
}

// Build an automation from a natural-language prompt: the model emits a workflow
// spec, which is validated + auto-laid-out + saved. Returns the created workflow.
// With { test: true } it also runs it once and auto-fixes a fixable failure.
// Parse a builder/edit model response into a workflow spec. Plain JSON.parse
// fails whenever the model emits a Script Block (run_python) node, because the
// `code` string almost always contains literal newlines/quotes that aren't
// escaped as valid JSON — that's what made "Build with LLM" reject every
// python step. Fall back to jsonrepair (already used for tool-call args), which
// fixes unescaped newlines/quotes, trailing commas, and unquoted keys.
function parseBuilderSpec(raw) {
    if (!raw || typeof raw !== 'string') return null;
    try { return JSON.parse(raw); } catch (_) { /* fall through to repair */ }
    try {
        const { jsonrepair } = require('jsonrepair');
        const repaired = jsonrepair(raw);
        const obj = JSON.parse(repaired);
        return obj && typeof obj === 'object' ? obj : null;
    } catch (_) { return null; }
}

// Extract a builder JSON object from a model's raw text the same way the build /
// edit endpoints do (strip a ``` fence, then take the outermost { … }).
function extractBuilderJson(text) {
    let raw = String(text || '').trim();
    if (!raw) return '';
    const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (fence) raw = fence[1].trim();
    const lo = raw.indexOf('{'), hi = raw.lastIndexOf('}');
    if (lo !== -1 && hi !== -1 && hi > lo) raw = raw.slice(lo, hi + 1);
    return raw;
}

// Generate a workflow spec from builder messages, robustly. Thinking is suppressed
// (see requestModelCompletion) so a reasoning model can't spend the token budget on
// chain-of-thought and truncate the JSON — the root cause of intermittent "no
// recognizable nodes". We parse the CONTENT ONLY (never the reasoning trace, which
// is not JSON) and retry a couple of times because generation is stochastic. With
// thinking off a build emits ~150-400 tokens, so the budget is never the limit.
async function generateBuilderSpec(messages, model, maxTokens = 8000) {
    let lastReason = 'no output';
    for (let attempt = 1; attempt <= 3; attempt++) {
        let res;
        try { res = await requestModelCompletion({ messages, model, temperature: 0.2, maxTokens, disableThinking: true }); }
        catch (e) { lastReason = e.message; continue; }
        const raw = extractBuilderJson(res.content);
        if (!raw) { lastReason = `empty content (finish_reason=${res.finishReason})`; continue; }
        const spec = parseBuilderSpec(raw);
        if (spec && typeof spec === 'object' && Array.isArray(spec.nodes) && spec.nodes.length) {
            if (attempt > 1) console.log(`[builder] spec generated on attempt ${attempt}`);
            return spec;
        }
        lastReason = res.finishReason === 'length' ? 'output truncated' : 'no parseable workflow nodes';
    }
    console.warn(`[builder] spec generation failed after 3 attempts: ${lastReason}`);
    return null;
}

// Turn a structured workflow diff into plain-English change-log lines. Used both
// as the deterministic fallback summary and as context for the model summarizer.
function diffToChangeLines(diff) {
    if (!diff || typeof diff !== 'object') return [];
    const lines = [];
    for (const n of (diff.addedNodes || [])) lines.push(`Added a “${n.label}” step.`);
    for (const n of (diff.changedNodes || [])) {
        const fields = (n.changes || []).map(c => c.field).filter(Boolean);
        lines.push(`Updated “${n.label}”${fields.length ? ` (${fields.join(', ')})` : ''}.`);
    }
    for (const n of (diff.removedNodes || [])) lines.push(`Removed the “${n.label}” step.`);
    const ae = diff.addedEdges || 0, re = diff.removedEdges || 0;
    if (ae || re) lines.push(`Rewired ${ae ? `${ae} new connection${ae > 1 ? 's' : ''}` : ''}${ae && re ? ' and ' : ''}${re ? `removed ${re} connection${re > 1 ? 's' : ''}` : ''}.`);
    return lines;
}

// Deterministic, model-free summary — always available so the Assistant panel
// has a headline even when the summarizer model call fails/times out.
function deterministicSummary({ isBuild, wf, diff }) {
    if (isBuild) {
        const chain = (wf.nodes || []).map(n => (n.data && n.data.label) || n.type);
        if (!chain.length) return 'An empty automation.';
        return `A ${chain.length}-step automation: ${chain.join(' → ')}.`;
    }
    const lines = diffToChangeLines(diff);
    return lines.length ? lines.join(' ') : 'No structural changes were needed.';
}

// Best-effort, time-boxed plain-English summary of what an automation does (build)
// or what a change did (edit) for the Assistant panel headline. Falls back to the
// deterministic summary on any failure/timeout so the response is never blocked.
async function summarizeAutomation({ isBuild, prompt, wf, diff, model }) {
    try {
        const stepList = (wf.nodes || []).map(n => (n.data && n.data.label) || n.type).join(' → ');
        const ask = isBuild
            ? `Summarize, in 1-2 friendly plain-English sentences addressed to the user, what this automation does. Do NOT list node types, ids, or JSON.\n\nThe user asked for: "${String(prompt || '').slice(0, 300)}"\nSteps: ${stepList}`
            : `Summarize, in 1-2 friendly plain-English sentences addressed to the user, what this change does to their automation. Do NOT mention node ids or JSON.\n\nThe user asked: "${String(prompt || '').slice(0, 300)}"\nWhat changed:\n${diffToChangeLines(diff).join('\n') || '(no structural change — only field tweaks)'}`;
        const messages = [
            { role: 'system', content: 'You write one short, friendly summary sentence (max ~50 words) of an automation workflow. Output ONLY the sentence(s) — no preamble, no markdown, no bullet points.' },
            { role: 'user', content: ask },
        ];
        // Time-box the summary so a stuck model can't stall the build/edit response;
        // clear the timer on the common (model-wins) path so it doesn't dangle.
        let summaryTimer;
        const text = await Promise.race([
            runModelCompletion({ messages, model, temperature: 0.3, maxTokens: 160, disableThinking: true }),
            new Promise((_, reject) => { summaryTimer = setTimeout(() => reject(new Error('summary timeout')), 10000); }),
        ]).finally(() => clearTimeout(summaryTimer));
        let s = String(text || '').replace(/<think>[\s\S]*?<\/think>/gi, '').replace(/^```[\s\S]*?\n?|```\s*$/g, '').trim();
        s = s.replace(/^[-*•\s"]+/, '').replace(/["\s]+$/, '').trim();
        return s || deterministicSummary({ isBuild, wf, diff });
    } catch (_) {
        return deterministicSummary({ isBuild, wf, diff });
    }
}

app.post('/api/automations/build', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    const { prompt, model } = req.body || {};
    if (!prompt || !String(prompt).trim()) {
        return res.status(400).json({ error: 'A prompt describing the automation is required' });
    }
    try {
        const messages = [
            { role: 'system', content: automationEngine.buildBuilderSystemPrompt() },
            { role: 'user', content: `Build an automation for this request:\n\n${String(prompt).trim()}\n\nRespond with ONLY the JSON object.` },
        ];
        // No compaction here (unlike edit/repair): build generates a workflow from
        // scratch and never echoes an existing one back, so there's nothing large
        // to round-trip. generateBuilderSpec suppresses thinking + retries so the
        // reasoning trace can't truncate the JSON (the old "no recognizable nodes").
        const spec = await generateBuilderSpec(messages, model, 8000);
        if (!spec || typeof spec !== 'object') {
            return res.status(422).json({ error: 'The model did not return a valid workflow. Try rephrasing your request.' });
        }
        let built;
        try { built = automationEngine.materializeWorkflow(spec); }
        catch (e) { return res.status(422).json({ error: `Could not assemble the workflow: ${e.message}` }); }
        const workflows = await loadWorkflows();
        const now = new Date().toISOString();
        const wf = {
            id: crypto.randomBytes(16).toString('hex'),
            name: built.name,
            description: `Built with LLM — ${String(prompt).trim().slice(0, 160)}`,
            nodes: built.nodes,
            edges: built.edges,
            enabled: true,
            archived: false,
            userId: req.userId || null,
            createdAt: now,
            updatedAt: now,
        };
        workflows.push(wf);
        await saveWorkflows(workflows);
        const buildLog = [`Built ${wf.nodes.length} node(s): ${wf.nodes.map(n => (n.data && n.data.label) || n.type).join(' → ')}`];
        let testReport = null;
        if (req.body && req.body.test) {
            try {
                testReport = await runAndRepairWorkflow(wf, wf, model, req, buildLog, String(prompt).trim());
                wf.updatedAt = new Date().toISOString();
                await saveWorkflows(workflows); // persist any auto-fix
            } catch (e) { buildLog.push(`Test & improve skipped: ${e.message}`); }
        }
        const summary = await summarizeAutomation({ isBuild: true, prompt: String(prompt).trim(), wf, model });
        res.status(201).json({ ...wf, buildLog, summary, ...(testReport ? { testReport } : {}) });
    } catch (error) {
        console.error('Error building automation:', error);
        res.status(500).json({ error: `Failed to build automation: ${error.message}` });
    }
});

// Propose an LLM edit to an existing automation. Returns { proposed, diff } —
// does NOT save; the client shows the diff and applies via PUT on confirm.
app.post('/api/automations/:id/edit', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    const { prompt, model } = req.body || {};
    if (!prompt || !String(prompt).trim()) {
        return res.status(400).json({ error: 'A prompt describing the change is required' });
    }
    try {
        const workflows = await loadWorkflows();
        const wf = workflows.find(w => w.id === req.params.id);
        if (!wf) return res.status(404).json({ error: 'Automation not found' });
        if (!checkOwnership(wf, req.userId) && !callerIsAdmin(req)) {
            return res.status(403).json({ error: 'Access denied: automation belongs to another user' });
        }
        const current = {
            name: wf.name,
            nodes: (wf.nodes || []).map(n => ({ id: n.id, type: n.type, data: n.data || {} })),
            edges: (wf.edges || []).map(e => ({ source: e.source, target: e.target, ...(e.sourceHandle ? { sourceHandle: e.sourceHandle } : {}) })),
        };
        // Swap multi-KB field values (e.g. a model node's embedded HTML template)
        // for short __KEEP_FIELD_N__ tokens so the whole workflow fits the model's
        // output budget when it echoes it back; restored verbatim after parsing.
        // Without this, a big systemPrompt truncates the JSON → "did not return a
        // valid workflow" (the original Cybersecurity-Newspaper edit failure).
        const { compacted, placeholders, byIndex, count, prefix } = automationEngine.compactWorkflowForLLM(current);
        const keepNote = count > 0
            ? `\n\nNOTE: ${count} long field value(s) were replaced with placeholder tokens like ${prefix}0__. Keep each token EXACTLY as-is to leave that field unchanged; only replace a token with new text if THIS change requires editing that specific field.`
            : '';
        const messages = [
            { role: 'system', content: automationEngine.buildBuilderSystemPrompt() },
            { role: 'user', content: `Here is the current automation as JSON:\n${JSON.stringify(compacted)}\n\nApply this change: "${String(prompt).trim()}"\n\nReturn the FULL revised automation as one JSON object (same shape).\n\nCRITICAL — node id discipline (this keeps the change log readable and the wiring correct):\n- KEEP every retained node's "id" BYTE-FOR-BYTE. Do NOT renumber: if you insert a node between n2 and n3, the existing n3, n4 … keep their ids — do NOT shift them up.\n- Give each genuinely NEW node a brand-new unused id (e.g. n7, n8). Never reuse or reassign an existing id to a different node.\n- Update every edge to reference these stable ids. Renumbering corrupts the diff (it reads as a cascade of phantom "type changed" entries) and can mis-wire the graph.\n- Preserve nodes the change does not touch exactly as they are.${keepNote}\n\nRespond with ONLY the JSON.` },
        ];
        // Thinking off + content-only + retry: a reasoning model would otherwise
        // spend the budget on chain-of-thought and truncate the echoed-back
        // workflow JSON (the bigger the workflow, the likelier). Parse content only.
        let spec = null;
        for (let attempt = 1; attempt <= 3 && !spec; attempt++) {
            let res2;
            try { res2 = await requestModelCompletion({ messages, model, temperature: 0.2, maxTokens: 8000, disableThinking: true }); }
            catch (_) { continue; }
            const raw = extractBuilderJson(res2.content);
            if (!raw) continue;
            const parsed = parseBuilderSpec(raw);
            if (parsed && typeof parsed === 'object' && Array.isArray(parsed.nodes) && parsed.nodes.length) spec = parsed;
        }
        if (!spec || typeof spec !== 'object') {
            return res.status(422).json({ error: 'The model did not return a valid workflow. Try rephrasing your change.' });
        }
        // Restore the placeholder tokens to their original (large) field values
        // BEFORE materializing, so id-recovery's node-signature matching sees real
        // values — and the diff, the test-run, and the saved workflow all carry the
        // real text.
        // Three-layer restore so a mangled token can never reach the saved workflow
        // (the "__KEEP_FIELD_1__ leaked into a model prompt → model explains
        // {result:false}" bug): exact match → tolerant index match → recover the
        // still-residual field from the matching ORIGINAL node (a token always stood
        // for an UNCHANGED field). Anything that survives all three means the model
        // corrupted a long field beyond recovery — reject the edit rather than hand
        // back (and let the user save) a workflow carrying a bare placeholder token.
        const origById = new Map((wf.nodes || []).map(n => [n.id, n]));
        if (Array.isArray(spec.nodes)) for (const node of spec.nodes) {
            if (!node || !node.data) continue;
            node.data = automationEngine.expandPlaceholders(node.data, placeholders, byIndex);
            if (automationEngine.hasResidualKeepToken(node.data) && origById.has(node.id)) {
                automationEngine.recoverResidualFromOriginal(node, origById.get(node.id));
            }
        }
        if (count > 0 && Array.isArray(spec.nodes) && spec.nodes.some(n => n && automationEngine.hasResidualKeepToken(n.data))) {
            console.warn(`[automations/edit] ${wf.id}: unrecoverable placeholder token after restore — rejecting to avoid saving a corrupted field.`);
            return res.status(422).json({ error: 'The edit could not be applied cleanly (the model garbled a long field). Please try again or rephrase the change.' });
        }
        let proposed;
        try { proposed = automationEngine.materializeWorkflowEdit(spec, wf); }
        catch (e) { return res.status(422).json({ error: `Could not apply the change: ${e.message}` }); }
        let buildLog;
        let testReport = null;
        if (req.body && req.body.test) {
            buildLog = [`Proposed ${proposed.nodes.length} node(s)`];
            try {
                // Run the PROPOSED revision (not saved) and auto-fix a fixable failure,
                // so the diff the user confirms is the tested-and-improved version.
                const probe = { ...wf, nodes: proposed.nodes, edges: proposed.edges };
                testReport = await runAndRepairWorkflow(probe, wf, model, req, buildLog, String(prompt).trim());
                proposed.nodes = probe.nodes;
                proposed.edges = probe.edges;
            } catch (e) { buildLog.push(`Test & improve skipped: ${e.message}`); }
        }
        const diff = automationEngine.diffWorkflows(wf, proposed);
        const changelog = diffToChangeLines(diff);
        const summary = await summarizeAutomation({ isBuild: false, prompt: String(prompt).trim(), wf: proposed, diff, model });
        res.json({ proposed, diff, summary, changelog, ...(buildLog ? { buildLog } : {}), ...(testReport ? { testReport } : {}) });
    } catch (error) {
        console.error('Error editing automation:', error);
        res.status(500).json({ error: `Failed to edit automation: ${error.message}` });
    }
});

// Test a SAVED automation: run it once, auto-repair fixable failures, and return
// a structured test report. The same engine the build/edit "Test & improve"
// toggle uses, but invokable on an existing automation on its own — the clean
// "test it for me" path. Persists the repair only if it changed the graph
// (skip with { apply: false }); never touches enabled/schedule state.
app.post('/api/automations/:id/test', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    try {
        const workflows = await loadWorkflows();
        const idx = workflows.findIndex(w => w.id === req.params.id);
        if (idx === -1) return res.status(404).json({ error: 'Automation not found' });
        const wf = workflows[idx];
        if (!checkOwnership(wf, req.userId) && !callerIsAdmin(req)) {
            return res.status(403).json({ error: 'Access denied: automation belongs to another user' });
        }
        const model = (req.body && req.body.model) || undefined;
        const goalPrompt = (req.body && req.body.goal) || wf.description || '';
        const buildLog = [`Testing ${(wf.nodes || []).length} node(s)…`];
        const before = JSON.stringify({ nodes: wf.nodes || [], edges: wf.edges || [] });
        // Repair operates on a deep copy; only commit if it actually improved the graph.
        const probe = { ...wf, nodes: JSON.parse(JSON.stringify(wf.nodes || [])), edges: JSON.parse(JSON.stringify(wf.edges || [])) };
        const testReport = await runAndRepairWorkflow(probe, wf, model, req, buildLog, String(goalPrompt).trim());
        let applied = false;
        if (!(req.body && req.body.apply === false) && JSON.stringify({ nodes: probe.nodes, edges: probe.edges }) !== before) {
            wf.nodes = probe.nodes; wf.edges = probe.edges; wf.updatedAt = new Date().toISOString();
            await saveWorkflows(workflows);
            applied = true;
        }
        res.json({ id: wf.id, testReport, buildLog, applied, ...(applied ? { name: wf.name, nodes: wf.nodes, edges: wf.edges } : {}) });
    } catch (error) {
        console.error('Error testing automation:', error);
        res.status(500).json({ error: `Failed to test automation: ${error.message}` });
    }
});

