// Shared workflow runner used by the SSE route, the scheduler, the webhook
// route, and system events. Creates a run record, runs the engine, persists
// the final record, and emits status via onEvent (the SSE route adds SSE
// writes + WS mirror; background triggers pass a broadcast-only onEvent).
// Emits a 'run_created' event first so callers can capture the runId (e.g. to
// wire client-disconnect cancellation). Returns { runId, outcome }.
// Per-user SSE listeners for live automation run events. The chat editor has no
// WebSocket, so server-triggered runs (schedule / telegram / webhook / event)
// would never animate there. This streams each engine event to any open editor.
const automationEventListeners = new Map(); // userId -> Set<res>
function pushAutomationSSE(userId, evt) {
    const set = automationEventListeners.get(userId);
    if (!set || !set.size) return;
    const line = `data: ${JSON.stringify(evt)}\n\n`;
    for (const res of set) { try { res.write(line); } catch (_) {} }
}
// Mirror an engine run event to both WebSocket clients (webapp) and the live SSE
// listeners (chat editor). Use everywhere a run's onEvent fires.
function mirrorAutomationEvent(userId, evt) {
    try { broadcast({ type: 'automation_event', ...evt }, userId); } catch (_) {}
    try { pushAutomationSSE(userId, evt); } catch (_) {}
}

async function executeWorkflowRun(wf, { userId = null, apiKeyData = null, trigger = 'manual', input = {}, onEvent = () => {} } = {}) {
    const chatTools = require('./services/chatTools');
    const abort = new AbortController();
    let runId;
    try {
        runId = await workflowRunStore.createRun(userId, { workflowId: wf.id, workflowName: wf.name, trigger });
    } catch (_) {
        runId = crypto.randomBytes(16).toString('hex'); // still run even if history write failed
    }
    activeAutomationRuns.set(runId, { abort, userId, workflowId: wf.id });

    const emit = (evt) => { try { onEvent({ ...evt, runId, workflowId: wf.id }); } catch (_) {} };
    emit({ type: 'run_created' });

    const deps = { runModelCompletion, executeToolCall: chatTools.executeToolCall };
    const ctx = { userId, apiKeyData, workspaceBucket: `automation-${wf.id}` };

    let outcome;
    try {
        outcome = await automationEngine.runWorkflow(wf, { input, deps, onEvent: emit, ctx, signal: abort.signal });
    } catch (e) {
        outcome = { status: 'failed', result: null, error: e.message || String(e), timeline: [] };
        emit({ type: 'run_finish', status: 'failed', error: outcome.error });
    } finally {
        activeAutomationRuns.delete(runId);
    }

    // Copy any `_artifacts` produced during this run to a persistent location
    // so they remain downloadable from the run history after the 1-hour sandbox
    // sweep deletes the per-tool-run scratch dir. URLs in the stored node
    // outputs are rewritten to point at the workflow-run download endpoint.
    try { await persistRunArtifacts(userId, runId, outcome); } catch (e) { console.warn('[automation] persistRunArtifacts failed:', e.message); }

    try {
        await workflowRunStore.updateRun(userId, runId, {
            status: outcome.status,
            finishedAt: new Date().toISOString(),
            error: outcome.error,
            nodes: outcome.timeline,
            result: outcome.result,
        });
    } catch (_) {}

    return { runId, outcome };
}

// Copy sandboxed-tool artifacts (the bytes behind `_artifacts[].url`) into a
// per-run directory under workflow-runs/<userIdSafe>/artifacts/<runId>/ and
// rewrite the URLs to a stable endpoint so run-history downloads keep working
// after the sandbox TTL sweep deletes the originals.
async function persistRunArtifacts(userId, runId, outcome) {
    if (!outcome || !runId) return;
    const fsSync = require('fs');
    const path = require('path');
    const destDir = path.join('/models/.modelserver/workflow-runs', workflowRunStore.userIdSafe(userId), 'artifacts', runId);
    let made = false;
    const ensureDir = async () => { if (!made) { await fs.mkdir(destDir, { recursive: true }); made = true; } };
    const copyOne = async (art) => {
        if (!art || !art.runId || !art.name) return;
        const safeName = path.basename(art.name);
        if (!safeName || safeName.startsWith('.') || safeName.includes('..')) return;
        const src = path.join('/models/.modelserver/sandbox', String(art.runId), 'artifacts', safeName);
        if (!fsSync.existsSync(src)) return;
        await ensureDir();
        const dst = path.join(destDir, safeName);
        try { await fs.copyFile(src, dst); } catch (_) { return; }
        art.url = `/api/automations/runs/${runId}/artifacts/${encodeURIComponent(safeName)}`;
        delete art.runId;
    };
    const visit = async (val) => {
        if (!val || typeof val !== 'object') return;
        if (Array.isArray(val._artifacts)) for (const a of val._artifacts) await copyOne(a);
    };
    for (const node of (outcome.timeline || [])) await visit(node.output);
    await visit(outcome.result);
}

// Run a workflow now (manual trigger), streaming live status over SSE and
// mirroring each event to the owner's WebSocket clients for the editor animation.
app.post('/api/automations/:id/run', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    let wf;
    try {
        const workflows = await loadWorkflows();
        wf = workflows.find(w => w.id === req.params.id);
        if (!wf) return res.status(404).json({ error: 'Automation not found' });
        if (!checkOwnership(wf, req.userId) && !callerIsAdmin(req)) {
            return res.status(403).json({ error: 'Access denied: automation belongs to another user' });
        }
    } catch (error) {
        return res.status(500).json({ error: 'Failed to load automation' });
    }

    // SSE setup
    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.setHeader('X-Accel-Buffering', 'no');
    if (typeof res.flushHeaders === 'function') res.flushHeaders();

    const userId = req.userId;
    const input = (req.body && typeof req.body.input === 'object' && req.body.input) || {};

    let capturedRunId = null;
    const onEvent = (evt) => {
        if (evt.type === 'run_created') capturedRunId = evt.runId;
        try { res.write(`data: ${JSON.stringify(evt)}\n\n`); } catch (_) {}
        mirrorAutomationEvent(userId, evt);
    };

    // Cancel if the client disconnects mid-run.
    req.on('close', () => {
        if (!res.writableEnded && capturedRunId) {
            const e = activeAutomationRuns.get(capturedRunId);
            if (e) { try { e.abort.abort(); } catch (_) {} }
        }
    });

    const { runId, outcome } = await executeWorkflowRun(wf, {
        userId, apiKeyData: req.apiKeyData || null, trigger: 'manual', input, onEvent
    });

    try { res.write(`data: ${JSON.stringify({ type: 'done', runId, status: outcome.status, result: outcome.result, error: outcome.error })}\n\n`); } catch (_) {}
    try { res.end(); } catch (_) {}
});

// Synchronous run for API / Pi / programmatic callers — runs the workflow and
