// LLM-built chip: describe a chip in plain language → a valid chip definition.
app.post('/api/chips/build', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) return res.status(403).json({ error: 'Automation permission required' });
    const { prompt, model } = req.body || {};
    if (!prompt || !String(prompt).trim()) return res.status(400).json({ error: 'Describe the chip you want' });
    try {
        const sys = [
            'You design "chips" for an automation node settings panel. A chip controls one setting on a node. Output a SINGLE JSON object and NOTHING else.',
            'Shape: {"label":"<short>","appliesTo":["<nodeKind>",…] or ["*"],"field":"<node.data path it controls>","type":"value|multiline|choice|toggle|number","options":[{"value","label"}]? ,"acceptsData":true|false,"placeholder":"…"?,"default":<any>?,"when":{"field","op":"truthy|eq|neq|in|notIn","value"}?}',
            'Rules:',
            '- "field" is the node.data key the chip writes (dotted for nested, e.g. "args.url", "condition.left"). Pick the real field for the target node.',
            '- type "value"/"multiline" hold text and can accept data references (acceptsData true) — use for messages, URLs, prompts, content. "choice" replaces a dropdown (needs options). "toggle" is on/off. "number" is numeric.',
            '- appliesTo lists the node kinds this chip is for, or ["*"] for any. Valid kinds: ' + CHIP_NODE_KINDS.join(', ') + '.',
            '- Keep label short (1-3 words). Do not invent fields that conflict with required ones unless that is the intent.',
            'Example — "a Bcc field for the email node": {"label":"Bcc","appliesTo":["email"],"field":"bcc","type":"value","acceptsData":true,"placeholder":"name@example.com"}',
            'Example — "priority high/normal/low for tasks": {"label":"Priority","appliesTo":["*"],"field":"priority","type":"choice","options":[{"value":"high","label":"High"},{"value":"normal","label":"Normal"},{"value":"low","label":"Low"}],"default":"normal"}',
        ].join('\n');
        const messages = [
            { role: 'system', content: sys },
            { role: 'user', content: `Build a chip for this request:\n\n${String(prompt).trim()}\n\nRespond with ONLY the JSON object.` },
        ];
        const text = await runModelCompletion({ messages, model, temperature: 0.2, maxTokens: 800, disableThinking: true });
        let raw = String(text || '').trim();
        const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i); if (fence) raw = fence[1].trim();
        const lo = raw.indexOf('{'), hi = raw.lastIndexOf('}'); if (lo !== -1 && hi > lo) raw = raw.slice(lo, hi + 1);
        let spec; try { spec = JSON.parse(raw); } catch (_) { spec = null; }
        if (!spec) return res.status(422).json({ error: 'The model did not return a valid chip. Try rephrasing.' });
        let def;
        try { def = materializeChip(spec); }
        catch (e) { return res.status(422).json({ error: `Could not build the chip: ${e.message}` }); }
        res.json(def); // preview only — the client reviews then POSTs to save
    } catch (error) {
        console.error('Error building chip:', error);
        res.status(500).json({ error: `Failed to build chip: ${error.message}` });
    }
});

// --- Webhook triggers ---

// Generate (or rotate) the webhook token for a workflow that has a
// trigger.webhook node. Stored at the workflow level so it survives node edits.
app.post('/api/automations/:id/webhook-token', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, AUTOMATION_PERM)) {
        return res.status(403).json({ error: 'Automation permission required' });
    }
    try {
        const workflows = await loadWorkflows();
        const idx = workflows.findIndex(w => w.id === req.params.id);
        if (idx === -1) return res.status(404).json({ error: 'Automation not found' });
        if (!checkOwnership(workflows[idx], req.userId) && !callerIsAdmin(req)) {
            return res.status(403).json({ error: 'Access denied: automation belongs to another user' });
        }
        const token = crypto.randomBytes(24).toString('hex');
        workflows[idx] = { ...workflows[idx], webhookToken: token, updatedAt: new Date().toISOString() };
        await saveWorkflows(workflows);
        res.json({ token, url: `/api/automations/webhook/${token}` });
    } catch (error) {
        console.error('Error generating webhook token:', error);
        res.status(500).json({ error: 'Failed to generate webhook token' });
    }
});

// Public webhook entry point — gated only by the unguessable token, runs as
// the workflow owner. No requireAuth (external services call this); the global
// CSRF check is cookie-auth-only so token callers are exempt. Fires in the
// background and returns 202 so the caller isn't blocked on the run.
app.post('/api/automations/webhook/:token', webhookRateLimiter, async (req, res) => {
    const token = req.params.token;
    if (!token || token.length < 24) return res.status(404).json({ error: 'Not found' });
    try {
        const workflows = await loadWorkflows();
        const wf = workflows.find(w =>
            w.webhookToken === token && w.enabled && !w.archived &&
            (w.nodes || []).some(n => n.type === 'trigger.webhook')
        );
        if (!wf) return res.status(404).json({ error: 'No active automation for this webhook' });

        const input = {
            body: req.body,
            query: req.query,
            receivedAt: new Date().toISOString()
        };
        executeWorkflowRun(wf, {
            userId: wf.userId || null,
            trigger: 'webhook',
            input,
            onEvent: (evt) => { mirrorAutomationEvent(wf.userId, evt); }
        }).catch(e => console.error('[automation] webhook run failed:', e.message));

        res.status(202).json({ message: 'Automation triggered', workflowId: wf.id });
    } catch (error) {
        console.error('Error handling webhook:', error);
        res.status(500).json({ error: 'Failed to trigger automation' });
    }
});

// --- Event triggers + scheduler (fired internally, not over HTTP) ---

// Run every enabled workflow that has a trigger.event node matching eventName.
// Called from existing event points (e.g. a model finishing load). Best-effort.
async function fireAutomationEvent(eventName, payload = {}) {
    try {
        const workflows = await loadWorkflows();
        for (const wf of workflows) {
            if (!wf.enabled || wf.archived) continue;
            const matches = (wf.nodes || []).some(n => n.type === 'trigger.event' && n.data && n.data.event === eventName && !n.data.disabled);
            if (!matches) continue;
            executeWorkflowRun(wf, {
                userId: wf.userId || null,
                trigger: `event:${eventName}`,
                input: { event: eventName, ...payload },
                onEvent: (evt) => { mirrorAutomationEvent(wf.userId, evt); }
            }).catch(e => console.error(`[automation] event "${eventName}" run failed:`, e.message));
        }
    } catch (e) {
        console.error('[automation] fireAutomationEvent failed:', e.message);
    }
}

// Per-trigger scheduler state (in-memory; recomputed from "now" on restart).
const automationScheduleState = new Map(); // `${wfId}:${nodeId}` -> { lastFiredPeriod?, lastFiredMinute? }
const AUTOMATION_MIN_INTERVAL_MS = 5000; // floor for interval schedules (matches the tick)

// Coarse scheduler tick (called every 60s). Fires due trigger.schedule nodes.
// cron → fire once per matching minute; intervalMs → fire every N ms (min 60s).
async function automationSchedulerTick() {
    try {
        const workflows = await loadWorkflows();
        const now = new Date();
        const nowMs = now.getTime();
        const minuteKey = `${now.getFullYear()}-${now.getMonth()}-${now.getDate()}-${now.getHours()}-${now.getMinutes()}`;
        const liveKeys = new Set();
        for (const wf of workflows) {
            if (!wf.enabled || wf.archived) continue;
            for (const node of (wf.nodes || [])) {
                if (node.type !== 'trigger.schedule') continue;
                // Per-node power toggle: a disabled trigger does not fire. Skip
                // before liveKeys.add so its schedule state is dropped (re-enabling
                // re-seeds fresh, firing one interval later).
                if (node.data && node.data.disabled) continue;
                const key = `${wf.id}:${node.id}`;
                liveKeys.add(key);
                const d = node.data || {};
                let due = false;
                // Calendar mode (multi-rule): d.crons[] is a list of 5-field cron
                // expressions (each one weekday-group@time). Fire if ANY matches,
                // once per minute. Coexists with the legacy single d.cron.
                const cronList = [];
                if (Array.isArray(d.crons)) for (const c of d.crons) if (typeof c === 'string' && c.trim()) cronList.push(c.trim());
                // Tolerate the LLM emitting `cron` as an array — treat it the same as crons[].
                if (Array.isArray(d.cron)) {
                    for (const c of d.cron) if (typeof c === 'string' && c.trim()) cronList.push(c.trim());
                } else if (typeof d.cron === 'string' && d.cron.trim()) {
                    cronList.push(d.cron.trim());
                }
                if (cronList.length) {
                    const anyMatch = cronList.some(c => { try { return automationEngine.cronMatches(c, now); } catch (_) { return false; } });
                    if (anyMatch) {
                        const st = automationScheduleState.get(key) || {};
                        if (st.lastFiredMinute !== minuteKey) {
                            due = true;
                            automationScheduleState.set(key, { ...st, lastFiredMinute: minuteKey });
                        }
                    }
                }
                // Calendar mode (specific dates): d.runAt[] is a list of ISO
                // timestamps that should fire ONCE when wallclock passes them.
                // In-memory `firedRunAt` Set per node tracks what already fired;
                // a freshly-loaded server only fires entries whose ts is within
                // the current minute (no replay of long-past timestamps).
                if (Array.isArray(d.runAt) && d.runAt.length) {
                    const st = automationScheduleState.get(key) || {};
                    const fired = st.firedRunAt instanceof Set ? st.firedRunAt : new Set();
                    for (const iso of d.runAt) {
                        const ts = Date.parse(iso);
                        if (!Number.isFinite(ts)) continue;
                        if (fired.has(iso)) continue;
                        // Fire if ts is in the current minute (now-60s..now+60s)
                        // OR within ±AUTOMATION_TICK_MS of now and not already fired.
                        // Fire on the FIRST tick whose wallclock has reached ts
                        // (and within the last 60s, so we don't replay long-past
                        // entries if state was lost). Never fire EARLY.
                        if (nowMs >= ts && nowMs - ts <= 60000) {
                            due = true;
                            fired.add(iso);
                        } else if (ts < nowMs - 60000) {
                            // Past entry; mark fired so it doesn't replay if it
                            // suddenly falls into range due to a clock jump.
                            fired.add(iso);
                        }
                    }
                    automationScheduleState.set(key, { ...st, firedRunAt: fired });
                }
                const hasCalendar = cronList.length || (Array.isArray(d.runAt) && d.runAt.length);
                if (!hasCalendar && d.intervalMs) {
                    // Anchor-relative interval so "every N <unit>" fires N units after
                    // it was configured (anchorMs), and the editor countdown (same
                    // formula, client-side: scheduleNextFire) shows the FULL interval.
                    // Pure epoch-alignment made "every 1 day" fire at UTC midnight, so
                    // the countdown showed time-until-midnight (≤24h) — near 23:00 a
                    // 1-day schedule read as "~1hr left", looking like the unit never
                    // applied. Schedules saved before anchorMs existed fall back to the
                    // legacy epoch-aligned base (0) so they keep firing unchanged. Fires
                    // when the period index advances; first sight seeds the current
                    // period so it doesn't fire immediately on enable.
                    const interval = Math.max(AUTOMATION_MIN_INTERVAL_MS, Number(d.intervalMs) || 0);
                    const anchor = Number(d.anchorMs);
                    const base = Number.isFinite(anchor) ? anchor : 0;
                    const period = Math.floor((nowMs - base) / interval);
                    // Re-seed whenever the schedule definition changes (interval or
                    // anchor edited). The period numbering is relative to interval+base,
                    // so a lastFiredPeriod carried over from the previous definition is
                    // meaningless against the new one — and because editing the unit
                    // resets anchorMs to now (period restarts at 0) while the stale
                    // value is usually far larger, `period > lastFiredPeriod` would
                    // never hold and the schedule would silently STOP firing. Treat an
                    // edited schedule like a fresh one: seed to the current period so it
                    // next fires one full interval later, matching the editor countdown.
                    let st = automationScheduleState.get(key);
                    if (!st || st.interval !== interval || st.base !== base) {
                        st = { interval, base, lastFiredPeriod: period };
                    }
                    if (period > st.lastFiredPeriod) { due = true; st.lastFiredPeriod = period; }
                    automationScheduleState.set(key, st);
                }
                if (due) {
                    executeWorkflowRun(wf, {
                        userId: wf.userId || null,
                        trigger: 'schedule',
                        input: { firedAt: now.toISOString(), node: node.id },
                        onEvent: (evt) => { mirrorAutomationEvent(wf.userId, evt); }
                    }).catch(e => console.error('[automation] scheduled run failed:', e.message));
                }
            }
        }
        // Drop state for triggers that no longer exist so the map can't grow unbounded.
        for (const k of automationScheduleState.keys()) if (!liveKeys.has(k)) automationScheduleState.delete(k);
    } catch (e) {
        console.error('[automation] scheduler tick failed:', e.message);
    }
}

// ---- Telegram trigger polling -------------------------------------------------
// `trigger.telegram` nodes fire when their bot receives a message. Since this
// server is typically localhost/self-signed (no public webhook), we poll
// getUpdates per bot token. Per-token offset is in-memory; on first sight of a
// token we fast-forward past the backlog so old messages don't replay on boot.
const automationTelegramState = new Map(); // botToken -> { offset, initialized }
let automationTelegramTickRunning = false;

function telegramTextMatches(text, keyword, mode) {
    if (!keyword) return true;
    const t = String(text || '');
    const k = String(keyword);
    switch (mode || 'contains') {
        case 'equals':     return t.trim().toLowerCase() === k.trim().toLowerCase();
        case 'startsWith': return t.trim().toLowerCase().startsWith(k.trim().toLowerCase());
        case 'regex':      { try { return new RegExp(k, 'i').test(t); } catch { return false; } }
        case 'contains':
        default:           return t.toLowerCase().includes(k.toLowerCase());
    }
}

function telegramChatMatches(chat, filter) {
    if (!filter) return true;
    const f = String(filter).trim().toLowerCase();
    if (!chat) return false;
    if (String(chat.id) === f) return true;
    if (chat.username && `@${String(chat.username).toLowerCase()}` === f) return true;
    return false;
}

async function automationTelegramTick() {
    if (automationTelegramTickRunning) return; // never overlap (getUpdates is serial per bot)
    automationTelegramTickRunning = true;
    try {
        const workflows = await loadWorkflows();
        // Group live trigger.telegram nodes by bot token.
        const byToken = new Map(); // token -> [{ wf, node }]
        for (const wf of workflows) {
            if (!wf.enabled || wf.archived) continue;
            for (const node of (wf.nodes || [])) {
                if (node.type !== 'trigger.telegram') continue;
                if (node.data && node.data.disabled) continue; // per-node power toggle
                const token = String((node.data && node.data.botToken) || '').trim();
                if (!token) continue;
                if (!byToken.has(token)) byToken.set(token, []);
                byToken.get(token).push({ wf, node });
            }
        }
        // Drop offset state for tokens no longer in use.
        for (const t of automationTelegramState.keys()) if (!byToken.has(t)) automationTelegramState.delete(t);

        for (const [token, subs] of byToken.entries()) {
            const st = automationTelegramState.get(token) || { offset: 0, initialized: false };
            try {
                const params = { timeout: 0, allowed_updates: ['message'] };
                if (st.offset) params.offset = st.offset;
                const resp = await axios.get(`https://api.telegram.org/bot${token}/getUpdates`, { params, timeout: 10000 });
                const updates = (resp.data && resp.data.ok && Array.isArray(resp.data.result)) ? resp.data.result : [];
                if (updates.length) st.offset = updates[updates.length - 1].update_id + 1;

                if (!st.initialized) {
                    // First poll for this token: skip backlog, only act on future messages.
                    st.initialized = true;
                    automationTelegramState.set(token, st);
                    continue;
                }
                automationTelegramState.set(token, st);

                for (const upd of updates) {
                    const message = upd.message;
                    if (!message) continue;
                    const text = message.text || message.caption || '';
                    for (const { wf, node } of subs) {
                        const d = node.data || {};
                        if (!telegramChatMatches(message.chat, d.chatId)) continue;
                        if (!telegramTextMatches(text, d.keyword, d.match)) continue;
                        executeWorkflowRun(wf, {
                            userId: wf.userId || null,
                            trigger: 'telegram',
                            input: message,
                            onEvent: (evt) => { mirrorAutomationEvent(wf.userId, evt); },
                        }).catch(e => console.error('[automation] telegram run failed:', e.message));
                    }
                }
            } catch (e) {
                const code = e.response && e.response.status;
                // 409 = another getUpdates consumer for this bot; 401/404 = bad token.
                console.error(`[automation] telegram poll failed for a bot${code ? ` (HTTP ${code})` : ''}:`, e.message);
                automationTelegramState.set(token, st);
            }
        }
    } catch (e) {
        console.error('[automation] telegram tick failed:', e.message);
    } finally {
        automationTelegramTickRunning = false;
    }
}

// ---- Slack trigger polling ----------------------------------------------------
// `trigger.slack` nodes fire when a new message appears in a Slack channel.
// Like Telegram, there's no public webhook on a localhost/self-signed host, so
// we poll conversations.history per (bot token, channel). Per-key cursor is the
// newest seen `ts`; on first sight we fast-forward past the backlog so old
// messages don't replay on boot. Bot must be in the channel with channels:history.
const automationSlackState = new Map(); // `${token}::${channel}` -> { oldest, initialized }
let automationSlackTickRunning = false;

async function automationSlackTick() {
    if (automationSlackTickRunning) return; // never overlap (conversations.history is serial per channel)
    automationSlackTickRunning = true;
    try {
        const workflows = await loadWorkflows();
        // Group live trigger.slack nodes by `${token}::${channel}`.
        const byKey = new Map(); // key -> { token, channel, subs: [{ wf, node }] }
        for (const wf of workflows) {
            if (!wf.enabled || wf.archived) continue;
            for (const node of (wf.nodes || [])) {
                if (node.type !== 'trigger.slack') continue;
                if (node.data && node.data.disabled) continue; // per-node power toggle
                const token = String((node.data && node.data.botToken) || '').trim();
                const channel = String((node.data && node.data.channel) || '').trim();
                if (!token || !channel) continue;
                const key = `${token}::${channel}`;
                if (!byKey.has(key)) byKey.set(key, { token, channel, subs: [] });
                byKey.get(key).subs.push({ wf, node });
            }
        }
        // Drop cursor state for (token, channel) pairs no longer in use.
        for (const k of automationSlackState.keys()) if (!byKey.has(k)) automationSlackState.delete(k);

        for (const [key, { token, channel, subs }] of byKey.entries()) {
            const st = automationSlackState.get(key) || { oldest: '0', initialized: false };
            try {
                const resp = await axios.get('https://slack.com/api/conversations.history', {
                    headers: { Authorization: `Bearer ${token}` },
                    params: { channel, limit: 50, ...(st.oldest && st.oldest !== '0' ? { oldest: st.oldest } : {}) },
                    timeout: 10000,
                });
                if (!resp.data || !resp.data.ok) {
                    // invalid_auth, not_in_channel, missing_scope, channel_not_found, etc.
                    console.error(`[automation] slack poll failed for a channel: ${(resp.data && resp.data.error) || 'unknown_error'}`);
                    automationSlackState.set(key, st);
                    continue;
                }
                const messages = Array.isArray(resp.data.messages) ? resp.data.messages : [];
                const newestTs = messages.length ? messages[0].ts : null; // Slack returns newest-first

                if (!st.initialized) {
                    // First poll for this key: skip backlog, only act on future messages.
                    st.initialized = true;
                    st.oldest = newestTs || (Date.now() / 1000).toFixed(6);
                    automationSlackState.set(key, st);
                    continue;
                }

                // Process oldest-first so runs fire in chronological order.
                for (const message of messages.slice().reverse()) {
                    // Skip bot/system messages to avoid echo loops.
                    if (message.bot_id || message.subtype === 'bot_message') continue;
                    for (const { wf, node } of subs) {
                        const d = node.data || {};
                        if (!telegramTextMatches(message.text || '', d.keyword, d.match)) continue;
                        executeWorkflowRun(wf, {
                            userId: wf.userId || null,
                            trigger: 'slack',
                            input: message,
                            onEvent: (evt) => { mirrorAutomationEvent(wf.userId, evt); },
                        }).catch(e => console.error('[automation] slack run failed:', e.message));
                    }
                }

                st.oldest = newestTs || st.oldest;
                automationSlackState.set(key, st);
            } catch (e) {
                const code = e.response && e.response.status;
                console.error(`[automation] slack poll failed${code ? ` (HTTP ${code})` : ''}: ${e.message}`);
                automationSlackState.set(key, st);
            }
        }
    } catch (e) {
        console.error('[automation] slack tick failed:', e.message);
    } finally {
        automationSlackTickRunning = false;
    }
}

// ============================================================================
// AGENT-SKILL INTEGRATION ENDPOINTS
// ============================================================================

// List available (enabled) skills for agents
app.get('/api/agents/skills/available', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    try {
        const skills = await loadSkills();
        // Only return enabled skills, excluding the code for security
        const availableSkills = skills
            .filter(s => s.enabled)
            .map(s => ({
                id: s.id,
                name: s.name,
                description: s.description,
                type: s.type,
                parameters: s.parameters,
                enabled: s.enabled
            }));

        res.json(availableSkills);
    } catch (error) {
        console.error('Error loading available skills:', error);
        res.status(500).json({ error: 'Failed to load available skills' });
    }
});

// Discover skills by type or search query
app.get('/api/agents/skills/discover', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { type, query } = req.query;

    try {
        const skills = await loadSkills();
        let filteredSkills = skills.filter(s => s.enabled);

        // Filter by type if provided
        if (type) {
            filteredSkills = filteredSkills.filter(s => s.type === type);
        }

        // Search by query if provided (searches name and description)
        if (query) {
            const searchTerm = query.toLowerCase();
            filteredSkills = filteredSkills.filter(s =>
                s.name.toLowerCase().includes(searchTerm) ||
                s.description.toLowerCase().includes(searchTerm)
            );
        }

        // Return without code
        const discoveredSkills = filteredSkills.map(s => ({
            id: s.id,
            name: s.name,
            description: s.description,
            type: s.type,
            parameters: s.parameters
        }));

        res.json(discoveredSkills);
    } catch (error) {
        console.error('Error discovering skills:', error);
        res.status(500).json({ error: 'Failed to discover skills' });
    }
});

// Get skill recommendations for a task description
app.post('/api/agents/skills/recommend', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { taskDescription } = req.body;

    if (!taskDescription) {
        return res.status(400).json({ error: 'taskDescription is required' });
    }

    try {
        const skills = await loadSkills();
        const enabledSkills = skills.filter(s => s.enabled);

        // Simple keyword-based matching
        const keywords = taskDescription.toLowerCase().split(/\s+/);
        const recommendations = [];

        for (const skill of enabledSkills) {
            const skillText = (skill.name + ' ' + skill.description).toLowerCase();
            let score = 0;

            // Count matching keywords
            for (const keyword of keywords) {
                if (skillText.includes(keyword)) {
                    score++;
                }
            }

            if (score > 0) {
                recommendations.push({
                    id: skill.id,
                    name: skill.name,
                    description: skill.description,
                    type: skill.type,
                    parameters: skill.parameters,
                    relevanceScore: score
                });
            }
        }

        // Sort by relevance score (highest first)
        recommendations.sort((a, b) => b.relevanceScore - a.relevanceScore);

        // Return top 5 recommendations
        res.json(recommendations.slice(0, 5));
    } catch (error) {
        console.error('Error recommending skills:', error);
        res.status(500).json({ error: 'Failed to recommend skills' });
    }
});

// ============================================================================
// SKILL EXECUTION
// ============================================================================

// Execute a skill
app.post('/api/skills/:skillName/execute', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { skillName } = req.params;
    const { agentId, ...params } = req.body; // Extract agentId if provided

    try {
        const skills = await loadSkills();
        const skill = skills.find(s => s.name === skillName);

        if (!skill) {
            return res.status(404).json({ error: 'Skill not found' });
        }

        // Skill access policy: agent-scoped whitelist + API-key denylist
        // (disabledSkills) + legacy allowedSkills whitelist on key/user.
        const policy = await resolveSkillPolicy({
            userId: req.userId,
            apiKeyData: req.apiKeyData,
            agentId
        });
        if (isSkillBlocked(policy, skill.name)) {
            const inDeny = policy.deny && policy.deny.has(safeToolName(skill.name));
            return res.status(403).json({
                error: inDeny
                    ? `Skill "${skill.name}" is disabled for this API key.`
                    : 'Skill is not in the allowed-skills list for this scope.'
            });
        }

        if (!skill.enabled) {
            return res.status(403).json({
                error: 'Skill is not available',
                message: `The skill '${skillName}' is currently disabled and cannot be executed. Please enable it in the Skills tab to use it.`,
                skillName: skillName,
                enabled: false
            });
        }

        // Log skill execution if agentId is provided
        if (agentId) {
            console.log(`[Agent ${agentId}] Executing skill: ${skillName}`);
        }

        // Broadcast to Process Logs so API-key callers (Pi, scripts) are
        // visible in the webapp Logs tab — previously these only hit stdout
        // and never surfaced in the UI, so users couldn't tell whether Pi
        // was actually invoking tools against the server.
        if (req.apiKeyData) {
            try {
                broadcast({
                    type: 'log',
                    message: `[Pi/API] ${req.apiKeyData.name || 'key'} → skill ${skillName}`,
                    level: 'info',
                    targetUserId: req.userId
                });
            } catch (_) { /* never break execution on log failure */ }
        }

        let result;

        // Bearer-key (Pi) and other API-key callers get one persistent,
        // user-manageable workspace per key: 'agent-<apiKeyId>'. This is what
        // lets a Pi agent build a file across turns (create_file → append_to_file
        // → create_pdf contentFile=...) and have it survive, instead of landing
        // in the shared 'global' bucket. Session (UI) callers have no apiKeyData,
        // so they fall through to conversation/global scoping unchanged.
        const skillCtx = {
            userId: req.userId,
            workspaceBucket: req.apiKeyData && req.apiKeyData.id
                ? `agent-${req.apiKeyData.id}`
                : null,
        };

        // Execute Python skill code
        if (skill.code && skill.code.trim() && !skill.code.startsWith('Uses ') && !skill.code.startsWith('Runs ')) {
            try {
                // Execute Python code
                result = await executePythonSkill(skill, params, skillCtx);
            } catch (error) {
                console.error(`Error executing skill ${skillName}:`, error);
                if (agentId) {
                    console.error(`[Agent ${agentId}] Skill execution failed: ${error.message}`);
                }
                return res.status(500).json({ error: 'Skill execution failed' });
            }
        } else {
            // Fallback to hardcoded implementations for legacy skills
            result = await executeLegacySkill(skillName, params);
        }

        // Add metadata to result if agent executed it
        if (agentId) {
            result.executedBy = agentId;
            result.executedAt = new Date().toISOString();
        }

        if (req.apiKeyData) {
            try {
                const ok = !(result && result.success === false);
                broadcast({
                    type: 'log',
                    message: `[Pi/API] skill ${skillName} ${ok ? 'completed' : 'failed'}`,
                    level: ok ? 'success' : 'warning',
                    targetUserId: req.userId
                });
            } catch (_) { /* ignore */ }
        }

        res.json(result);
    } catch (error) {
        console.error('Error executing skill:', error);
        res.status(500).json({ error: 'Failed to execute skill' });
    }
});

// ============================================================================
// SANDBOX WORKSPACES — persistent sandbox workspaces, surfaced in the webapp
// "Sandbox Workspace" tab. Two flavours, both listed/deletable here:
//   • agent-<apiKeyId>  — one per API key (bearer or key+secret). Survives
//     across turns so a Pi/API agent can build files incrementally
//     (create_file → append_to_file → create_pdf contentFile).
//   • conv-<id> / global — webchat session + shared workspaces.
// Admins get an org-wide view (every owner); non-admins see only their own.
// ============================================================================
function callerIsAdmin(req) {
    return !!(req.user && req.user.role === 'admin')
        || !!(req.apiKeyData && Array.isArray(req.apiKeyData.permissions) && req.apiKeyData.permissions.includes('admin'));
}

app.get('/api/agent-workspaces', requireAuth, async (req, res) => {
    try {
        const sbRunner = require('./services/sandboxRunner');
        const isAdmin = callerIsAdmin(req);
        const list = isAdmin
            ? await sbRunner.listAllWorkspaces()
            : await sbRunner.listWorkspaces(req.userId);

        // owner dir name (== userId for UUID ids) → user record
        const usersById = new Map();
        try {
            const users = await getAllUsers();
            for (const u of users) usersById.set(String(u.id), u);
        } catch { /* ignore — fall back to raw owner id */ }

        // keyId → api key (label + active). Covers ALL keys, not just bearer.
        const keysById = new Map();
        try {
            const keys = await loadApiKeys();
            for (const k of keys) keysById.set(k.id, k);
        } catch { /* ignore — fall back to raw bucket name */ }

        // Lazily resolve conversation titles per owner for conv-* buckets so the
        // webchat section shows real titles instead of bare UUIDs.
        const convTitlesByOwner = new Map();
        async function convTitle(owner, convId) {
            if (!usersById.has(owner)) return null; // only real users have convs
            if (!convTitlesByOwner.has(owner)) {
                const m = new Map();
                try {
                    const idx = await loadConversationsIndex(owner);
                    for (const c of (idx || [])) if (c && c.id) m.set(String(c.id), c.title || null);
                } catch { /* ignore */ }
                convTitlesByOwner.set(owner, m);
            }
            return convTitlesByOwner.get(owner).get(convId) || null;
        }

        const out = [];
        for (const w of list) {
            const owner = w.owner;
            const ownerUser = usersById.get(owner);
            const ownerName = owner === 'global' ? null : (ownerUser ? ownerUser.username : owner);
            let label = w.bucket;
            let keyId = null;
            let keyActive = null;
            if (w.type === 'agent') {
                keyId = w.bucket.slice('agent-'.length);
                const k = keysById.get(keyId);
                if (k) { label = k.name || keyId; keyActive = k.active !== false; }
                else { label = `(deleted key ${keyId.slice(0, 8)}…)`; keyActive = false; }
            } else if (w.type === 'conversation') {
                const convId = w.bucket.slice('conv-'.length);
                label = (await convTitle(owner, convId)) || ('Chat ' + convId.slice(0, 12));
            } else if (w.type === 'global') {
                label = 'Shared (global)';
            }
            out.push({ ...w, ownerName, label, keyId, keyActive });
        }
        out.sort((a, b) => (b.mtimeMs || 0) - (a.mtimeMs || 0));
        res.json({ workspaces: out, isAdmin });
    } catch (e) {
        console.error('Error listing sandbox workspaces:', e);
        res.status(500).json({ error: 'Failed to list workspaces' });
    }
});

app.delete('/api/agent-workspaces/:owner/:bucket', requireAuth, async (req, res) => {
    const { owner, bucket } = req.params;
    // Strict allowlist — owner/bucket dir names are only ever [A-Za-z0-9_-].
    // Anything else is a traversal attempt; reject before touching the fs.
    if (!/^[A-Za-z0-9_-]{1,128}$/.test(owner || '') || !/^[A-Za-z0-9_-]{1,128}$/.test(bucket || '')) {
        return res.status(400).json({ error: 'Invalid owner or bucket' });
    }
    // Non-admins may only delete their own buckets.
    const ownOwner = req.userId == null ? 'global' : String(req.userId).replace(/[^A-Za-z0-9_-]/g, '_');
    if (!callerIsAdmin(req) && owner !== ownOwner) {
        return res.status(403).json({ error: 'You can only delete your own workspaces' });
    }
    try {
        const sbRunner = require('./services/sandboxRunner');
        const result = await sbRunner.deleteWorkspaceBucketByOwner(owner, bucket);
        if (!result.deleted) {
            return res.status(404).json({ error: result.error || 'Workspace not found' });
        }
        broadcast({ type: 'log', message: `Sandbox workspace deleted: ${owner}/${bucket} (${result.fileCount} files)` });
        res.json(result);
    } catch (e) {
        console.error('Error deleting sandbox workspace:', e);
        res.status(500).json({ error: 'Failed to delete workspace' });
    }
});

// --- host <-> server-workspace file bridge (powers Pi's auto-bridge) --------
// These let a Pi/API agent move a file BETWEEN the two filesystems it lives in:
// its host (Pi's own read/write/bash) and the server sandbox workspace (where
// read_pdf/create_pdf/transform_image/... run). Scoped to the caller's own
// agent-<apiKeyId> bucket, so the uploaded file is exactly what the next skill
// call (same key -> same bucket) sees mounted at /workspace.
//
// resolveAgentWorkspaceTarget validates the relative path against traversal and
// returns the absolute on-disk path inside the caller's bucket.
async function resolveAgentWorkspaceTarget(req, rel) {
    if (!req.apiKeyData || !req.apiKeyData.id) {
        const e = new Error('Agent workspace requires API-key auth'); e.httpStatus = 400; throw e;
    }
    if (!rel || rel.startsWith('/') || rel.includes('..') || rel.includes('\0') || rel.length > 256) {
        const e = new Error('Invalid path'); e.httpStatus = 400; throw e;
    }
    const sbRunner = require('./services/sandboxRunner');
    const ws = await sbRunner.ensureWorkspace(req.userId, null, 'agent-' + req.apiKeyData.id);
    const path_ = require('path');
    const dir = path_.resolve(ws.localInContainer);
    const target = path_.resolve(path_.join(dir, rel));
    if (target !== dir && !target.startsWith(dir + path_.sep)) {
        const e = new Error('Path escapes workspace'); e.httpStatus = 400; throw e;
    }
    return target;
}

app.post('/api/agent-workspaces/file',
    requireAuth,
    express.raw({ type: 'application/octet-stream', limit: '50mb' }),
    async (req, res) => {
        try {
            if (!Buffer.isBuffer(req.body) || req.body.length === 0) {
                return res.status(400).json({ error: 'Empty body (send raw bytes as application/octet-stream)' });
            }
            const rel = String(req.query.path || '');
            const target = await resolveAgentWorkspaceTarget(req, rel);
            const path_ = require('path');
            await fs.mkdir(path_.dirname(target), { recursive: true });
            await fs.writeFile(target, req.body);
            res.json({ written: true, path: '/workspace/' + rel, bytes: req.body.length });
        } catch (e) {
            if (e.httpStatus) return res.status(e.httpStatus).json({ error: e.message });
            console.error('Agent workspace upload failed:', e);
            res.status(500).json({ error: 'Upload failed' });
        }
    }
);

app.get('/api/agent-workspaces/file', requireAuth, async (req, res) => {
    try {
        const rel = String(req.query.path || '');
        const target = await resolveAgentWorkspaceTarget(req, rel);
        const st = await fs.stat(target).catch(() => null);
        if (!st || !st.isFile()) return res.status(404).json({ error: 'File not found in workspace' });
        const ext = (rel.split('.').pop() || '').toLowerCase();
        const mime = {
            pdf: 'application/pdf', png: 'image/png', jpg: 'image/jpeg', jpeg: 'image/jpeg',
            gif: 'image/gif', webp: 'image/webp', svg: 'image/svg+xml',
            txt: 'text/plain; charset=utf-8', md: 'text/markdown; charset=utf-8',
            csv: 'text/csv; charset=utf-8', json: 'application/json; charset=utf-8',
            html: 'text/html; charset=utf-8', xml: 'application/xml; charset=utf-8',
            docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            zip: 'application/zip',
        }[ext] || 'application/octet-stream';
        res.setHeader('Content-Type', mime);
        res.setHeader('Content-Length', st.size);
        const base = require('path').basename(rel);
        // RFC 5987 filename* so non-ASCII names (e.g. fullwidth ｜) survive.
        res.setHeader('Content-Disposition',
            `attachment; filename*=UTF-8''${encodeURIComponent(base)}`);
        // Stream rather than fs.readFile — a single-buffer read throws
        // ERR_FS_FILE_TOO_LARGE past ~2 GiB, so multi-GB downloads (e.g. a
        // full video pulled by download_video) would otherwise 500.
        const stream = fsSync.createReadStream(target);
        stream.on('error', (err) => {
            console.error('Agent workspace download stream failed:', err);
            if (!res.headersSent) res.status(500).json({ error: 'Download failed' });
            else res.destroy();
        });
        stream.pipe(res);
    } catch (e) {
        if (e.httpStatus) return res.status(e.httpStatus).json({ error: e.message });
        console.error('Agent workspace download failed:', e);
        res.status(500).json({ error: 'Download failed' });
    }
});

// Python skill executor. By default runs in a gVisor-sandboxed container
// (see webapp/services/sandboxRunner.js). Individual skills can opt out with
// `sandbox: false` on the skill definition — useful for trusted built-ins
// that need host FS access (file ops etc.) which won't work under --read-only.
//
// The legacy in-process path is still here for opted-out skills and as an
// automatic fallback if the sandbox runner throws during setup (missing
// image, broken Docker socket, etc.) — we'd rather degrade to the old
// behavior than fail the whole request.
async function executePythonSkill(skill, params, ctx = null) {
    const sandbox = require('./services/sandboxRunner');
    // Sandbox policy:
    //   - explicit skill.sandbox true/false → respect it
    //   - user-created skill (has userId) → sandbox by default (untrusted origin)
    //   - built-in default skill (no userId) → in-process by default because
    //     many of them (create_file, read_file, list_directory, …) need
    //     host FS access that --read-only would break. Containerizing the
    //     full default catalog with workspace-bound mounts is follow-up
    //     work; for now we trust the built-ins that ship with the product.
    const wantSandbox = typeof skill.sandbox === 'boolean'
        ? skill.sandbox
        : !!skill.userId;

    if (wantSandbox) {
        try {
            // Network policy from the skill definition.
            //   - User-created skills (have userId) default to public
            //     internet via `allowlist: ['*']`. The egress proxy still
            //     applies its `resolvesPublicly` check, so private/internal
            //     IPs (10/8, 172.16/12, 192.168/16, 127/8, link-local) stay
            //     blocked. This matches the "open internet, no LAN reach"
            //     policy users expect when they write a tool that talks to
            //     a third-party API.
            //   - Built-in skills (no userId) keep the explicit policy on
            //     their skill record — most are `'none'` for FS work;
            //     web tools (playwright, scrapling, fetch_url) declare
            //     `'allowlist'` with their own narrow host list.
            const isUserSkill = !!skill.userId;
            const network = skill.network || (isUserSkill ? 'allowlist' : 'none');
            const allowlist = skill.allowlist || (isUserSkill && network === 'allowlist' ? ['*'] : []);
            // User skills also default to workspace=true so the sandbox's
            // ReadonlyRootfs doesn't block ad-hoc `pip install` for
            // dependencies. Without this, every user skill that needs a
            // package not in the base image fails before it can run.
            // The persistent /workspace/.deps cache (PIP_TARGET) makes the
            // install cheap on subsequent calls.
            const workspace = typeof skill.workspace === 'boolean'
                ? skill.workspace
                : isUserSkill;
            const run = await sandbox.runPythonSkill({
                code: skill.code,
                params,
                network,
                allowlist,
                workspace,
                // Opt out of sandbox-side path rewriting when the skill
                // declares it. Needed for git_* skills where `path` is a
                // repo-relative filter ('.', 'src/app.py'), not a
                // filesystem path to be rerouted under /workspace.
                pathNormalize: skill.pathNormalize !== false,
                timeoutMs: skill.timeoutMs || 30_000,
                memory: skill.memory || '512m',
                cpus: skill.cpus || '1.0',
                toolName: skill.name,
                // userId scopes the workspace owner; ctx.userId (from the
                // chat stream) wins over skill.userId so anonymous/global
                // built-in skills still bucket under the caller's account.
                userId: (ctx && ctx.userId) || skill.userId || null,
                // conversationId scopes the per-chat sub-bucket so cleanup
                // on DELETE /api/conversations/:id can wipe everything the
                // chat produced. Null for direct /api/skills/:name/execute
                // (falls back to the 'global' bucket).
                conversationId: (ctx && ctx.conversationId) || null,
                // workspaceBucket pins a persistent per-agent workspace for
                // bearer-key (Pi) callers — 'agent-<apiKeyId>'. Set by the
                // /api/skills/:name/execute route from req.apiKeyData.id so
                // every turn of a Pi agent shares one manageable workspace.
                workspaceBucket: (ctx && ctx.workspaceBucket) || null,
            });
            if (run.timedOut) {
                // Runs with no artifacts are cleaned up immediately; nothing
                // downstream will need them.
                sandbox.cleanupRun(run.runId).catch(() => {});
                return { success: false, error: 'Skill timed out', timedOut: true };
            }
            // Runs that produced artifacts are kept on disk so the
            // `/api/tool-artifacts/:runId/:filename` endpoint can stream
            // them to the client. Periodic sweep (set up at boot) removes
            // runs older than ARTIFACT_TTL_MS. Runs without artifacts are
            // cleaned up immediately.
            if (!run.artifacts.length) {
                sandbox.cleanupRun(run.runId).catch(() => {});
            }
            if (run.result && typeof run.result === 'object') {
                if (run.artifacts.length) {
                    run.result._artifacts = run.artifacts.map(a => ({
                        name: a.name,
                        size: a.size,
                        runId: run.runId,
                        url: `/api/tool-artifacts/${run.runId}/${encodeURIComponent(a.name)}`,
                    }));
                }
                return run.result;
            }
            // Fallback when skill didn't return JSON — expose raw output.
            return {
                success: run.exitCode === 0,
                error: run.parseError || (run.stderr ? `sandbox stderr: ${run.stderr.slice(0, 2000)}` : 'no JSON output'),
                stdout: run.stdout.slice(0, 2000),
            };
        } catch (sandboxErr) {
            console.warn(`[executePythonSkill] sandbox run failed for "${skill.name}", falling back to in-process:`, sandboxErr.message);
            // Fall through to the legacy path below.
        }
    }

    // ------------------------------------------------------------------
    // Legacy in-process path — runs on the webapp container directly.
    // Only reached when skill.sandbox === false or when the sandbox path
    // errored out of band.
    // ------------------------------------------------------------------
    const tempFile = `/tmp/skill_${Date.now()}_${crypto.randomBytes(12).toString('hex')}.py`;
    try {
        const paramsFile = `/tmp/skill_params_${Date.now()}_${crypto.randomBytes(12).toString('hex')}.json`;
        await fs.writeFile(paramsFile, JSON.stringify(params));

        const pythonScript = `#!/usr/bin/env python3
import json
import sys
import os

with open("${paramsFile}", "r") as f:
    params = json.load(f)

${skill.code}

try:
    result = execute(params)
    if not isinstance(result, dict):
        result = {"success": False, "error": "Skill must return a dictionary"}
    print(json.dumps(result))
except Exception as e:
    print(json.dumps({"success": False, "error": str(e)}))
    sys.exit(1)
`;

        await fs.writeFile(tempFile, pythonScript, { mode: 0o755 });
        const { stdout, stderr } = await execPromise(
            `python3 "${tempFile}"`,
            { timeout: 30000, maxBuffer: 10 * 1024 * 1024 }
        );
        await fs.unlink(paramsFile).catch(() => {});
        await fs.unlink(tempFile).catch(() => {});
        try {
            return JSON.parse(stdout.trim());
        } catch (parseError) {
            console.error('Failed to parse Python output:', stdout, stderr);
            throw new Error(`Invalid JSON output from Python skill: ${parseError.message}`);
        }
    } catch (error) {
        await fs.unlink(tempFile).catch(() => {});
        throw error;
    }
}

// Legacy skill executor (for backward compatibility)
async function executeLegacySkill(skillName, params) {
    let result;

        switch (skillName) {
            // File Operations
            case 'create_file':
            case 'update_file':
                const content = params.content || '';
                const filePath = params.filePath;
                if (!filePath) {
                    throw new Error('filePath required' );
                }
                await fs.writeFile(filePath, content);
                result = { success: true, message: `File ${skillName === 'create_file' ? 'created' : 'updated'}: ${filePath}` };
                break;

            case 'read_file': {
                if (!params.filePath) {
                    throw new Error('filePath required');
                }
                const fileContent = await fs.readFile(params.filePath, 'utf8');
                const lines = fileContent.split('\n');
                const totalLines = lines.length;
                const chunkSize = params.chunkSize ? parseInt(params.chunkSize) : 500;
                const maxContentChars = params.maxContentChars ? parseInt(params.maxContentChars) : 100000;
                const totalChunks = Math.ceil(totalLines / chunkSize);
                const estimatedTokens = Math.ceil(fileContent.length / 4);

                // Handle specific line ranges
                if (params.startLine || params.endLine) {
                    const start = params.startLine ? parseInt(params.startLine) - 1 : 0;
                    const end = params.endLine ? parseInt(params.endLine) : totalLines;
                    const selectedLines = lines.slice(start, end);
                    result = {
                        success: true,
                        content: selectedLines.join('\n'),
                        lineRange: { start: start + 1, end: Math.min(end, totalLines) },
                        totalLines
                    };
                    break;
                }

                // Handle chunk-based reading
                if (params.chunkIndex !== undefined) {
                    const chunkIndex = parseInt(params.chunkIndex);
                    if (chunkIndex < 0 || chunkIndex >= totalChunks) {
                        result = { success: false, error: `Invalid chunkIndex. Valid range: 0-${totalChunks - 1}` };
                        break;
                    }
                    const start = chunkIndex * chunkSize;
                    const end = Math.min(start + chunkSize, totalLines);
                    const chunkContent = lines.slice(start, end).join('\n');
                    result = {
                        success: true,
                        content: chunkContent,
                        currentChunk: chunkIndex,
                        totalChunks,
                        linesInChunk: end - start,
                        lineRange: { start: start + 1, end },
                        totalLines
                    };
                    break;
                }

                // Check if file is too large
                if (fileContent.length > maxContentChars || estimatedTokens > 20000) {
                    result = {
                        success: true,
                        warning: 'FILE_TOO_LARGE',
                        message: `File has ${totalLines} lines (~${estimatedTokens} tokens). Use chunkIndex parameter to read in parts.`,
                        totalLines,
                        totalChunks,
                        chunkSize,
                        estimatedTokens,
                        filePath: params.filePath,
                        suggestedApproach: `Read with chunkIndex=0 through chunkIndex=${totalChunks - 1} to process entire file`
                    };
                    break;
                }

                result = { success: true, content: fileContent, totalLines };
                break;
            }

            case 'delete_file':
                if (!params.filePath) {
                    throw new Error('filePath required' );
                }
                await fs.unlink(params.filePath);
                result = { success: true, message: `File deleted: ${params.filePath}` };
                break;

            case 'list_directory':
                if (!params.dirPath) {
                    throw new Error('dirPath required' );
                }
                const files = await fs.readdir(params.dirPath);
                result = { success: true, files };
                break;

            case 'move_file':
                if (!params.sourcePath || !params.destPath) {
                    throw new Error('sourcePath and destPath required' );
                }
                await fs.rename(params.sourcePath, params.destPath);
                result = { success: true, message: `File moved: ${params.sourcePath} -> ${params.destPath}` };
                break;

            case 'copy_file':
                if (!params.sourcePath || !params.destPath) {
                    throw new Error('sourcePath and destPath required' );
                }
                await fs.copyFile(params.sourcePath, params.destPath);
                result = { success: true, message: `File copied: ${params.sourcePath} -> ${params.destPath}` };
                break;

            // Data Processing
            case 'parse_json':
                if (!params.jsonString) {
                    throw new Error('jsonString required' );
                }
                try {
                    const parsed = JSON.parse(params.jsonString);
                    result = { success: true, data: parsed };
                } catch (e) {
                    throw new Error('Invalid JSON: ' + e.message );
                }
                break;

            case 'parse_csv':
                if (!params.csvString) {
                    throw new Error('csvString required' );
                }
                const delimiter = params.delimiter || ',';
                const lines = params.csvString.split('\n').filter(l => l.trim());
                const headers = lines[0].split(delimiter);
                const data = lines.slice(1).map(line => {
                    const values = line.split(delimiter);
                    const obj = {};
                    headers.forEach((h, i) => obj[h.trim()] = values[i]?.trim());
                    return obj;
                });
                result = { success: true, data };
                break;

            case 'format_markdown':
                if (!params.text) {
                    throw new Error('text required' );
                }
                // Basic markdown formatting
                let markdown = params.text;
                result = { success: true, markdown };
                break;

            case 'base64_encode':
                if (!params.data) {
                    throw new Error('data required' );
                }
                const encoded = Buffer.from(params.data).toString('base64');
                result = { success: true, encoded };
                break;

            case 'base64_decode':
                if (!params.encodedData) {
                    throw new Error('encodedData required' );
                }
                try {
                    const decoded = Buffer.from(params.encodedData, 'base64').toString('utf8');
                    result = { success: true, decoded };
                } catch (e) {
                    throw new Error('Invalid base64: ' + e.message );
                }
                break;

            case 'extract_archive': {
                const archiveExtractor = require('./services/archiveExtractor');
                const fname = params.filename || params.archiveName;
                const b64 = params.base64Data || params.archiveData;
                if (!b64) throw new Error('base64Data required');
                if (!fname) throw new Error('filename required (extension picks the extractor)');
                let buf;
                try {
                    buf = Buffer.from(String(b64).replace(/^data:[^;]+;base64,/, ''), 'base64');
                } catch (e) {
                    throw new Error('Invalid base64Data: ' + e.message);
                }
                if (!buf.length) throw new Error('Decoded buffer is empty');
                if (buf.length > 50 * 1024 * 1024) {
                    throw new Error(`Archive is ${buf.length} bytes; 50MB max.`);
                }
                result = await archiveExtractor.extractArchive(buf, fname);
                break;
            }

            // Web & Network
            case 'fetch_url':
                if (!params.url) {
                    throw new Error('url required' );
                }
                if (isPrivateUrl(params.url)) {
                    throw new Error('URLs targeting private/internal networks are not allowed');
                }
                try {
                    const axios = require('axios');
                    const response = await axios.get(params.url, { timeout: 10000 });
                    result = { success: true, data: response.data, status: response.status };
                } catch (e) {
                    throw new Error('Fetch failed: ' + e.message );
                }
                break;

            case 'http_request':
                if (!params.url || !params.method) {
                    throw new Error('url and method required' );
                }
                if (isPrivateUrl(params.url)) {
                    throw new Error('URLs targeting private/internal networks are not allowed');
                }
                try {
                    const axios = require('axios');
                    const config = {
                        method: params.method,
                        url: params.url,
                        timeout: 10000
                    };
                    if (params.headers) config.headers = params.headers;
                    if (params.body) config.data = params.body;
                    const response = await axios(config);
                    result = { success: true, data: response.data, status: response.status };
                } catch (e) {
                    throw new Error('Request failed: ' + e.message );
                }
                break;

            case 'dns_lookup':
                if (!params.domain) {
                    throw new Error('domain required' );
                }
                const dns = require('dns').promises;
                try {
                    const addresses = await dns.resolve4(params.domain);
                    result = { success: true, addresses };
                } catch (e) {
                    throw new Error('DNS lookup failed: ' + e.message );
                }
                break;

            case 'check_port':
                if (!params.host || !params.port) {
                    throw new Error('host and port required' );
                }
                const net = require('net');
                result = await new Promise((resolve) => {
                    const socket = new net.Socket();
                    const timeout = setTimeout(() => {
                        socket.destroy();
                        resolve({ success: true, open: false, message: 'Connection timeout' });
                    }, 3000);

                    socket.connect(params.port, params.host, () => {
                        clearTimeout(timeout);
                        socket.destroy();
                        resolve({ success: true, open: true, message: 'Port is open' });
                    });

                    socket.on('error', () => {
                        clearTimeout(timeout);
                        socket.destroy();
                        resolve({ success: true, open: false, message: 'Port is closed' });
                    });
                });
                break;

            // System Commands
            case 'netstat':
                const netstatCmd = process.platform === 'win32' ? 'netstat' : 'netstat';
                const netstatArgs = (params.flags || '-tuln').replace(/[;&|`$(){}]/g, '');
                try {
                    const { stdout } = await execPromise(`${netstatCmd} ${netstatArgs}`);
                    result = { success: true, output: stdout };
                } catch (e) {
                    throw new Error('Command failed: ' + e.message );
                }
                break;

            case 'process_list':
                const psCmd = process.platform === 'win32' ? 'tasklist' : 'ps aux';
                try {
                    const { stdout } = await execPromise(psCmd);
                    let output = stdout;
                    if (params.filter) {
                        output = stdout.split('\n').filter(line =>
                            line.toLowerCase().includes(params.filter.toLowerCase())
                        ).join('\n');
                    }
                    result = { success: true, output };
                } catch (e) {
                    throw new Error('Command failed: ' + e.message );
                }
                break;

            case 'system_info':
                const os = require('os');
                result = {
                    success: true,
                    platform: os.platform(),
                    arch: os.arch(),
                    cpus: os.cpus().length,
                    totalMemory: os.totalmem(),
                    freeMemory: os.freemem(),
                    uptime: os.uptime()
                };
                break;

            case 'run_bash':
            case 'run_powershell':
            case 'execute_command':
                if (!params.command) {
                    throw new Error('command required' );
                }
                try {
                    const shell = skillName === 'run_powershell' ? 'powershell' : '/bin/bash';
                    const { stdout, stderr } = await execPromise(params.command, {
                        shell,
                        timeout: params.timeout || 30000
                    });
                    result = { success: true, stdout, stderr };
                } catch (e) {
                    throw new Error('Command failed: ' + e.message );
                }
                break;

            // Code Analysis
            case 'find_patterns':
                if (!params.text || !params.pattern) {
                    throw new Error('text and pattern required' );
                }
                // Reject obviously dangerous regex patterns (catastrophic backtracking)
                if (params.pattern.length > 200) throw new Error('Pattern too long (max 200 chars)');
                if (/(\+\+|\*\*|\{\d+,\}\+|\(\?[^)]*\)\+\+)/.test(params.pattern)) {
                    throw new Error('Pattern contains potentially dangerous constructs');
                }
                try {
                    const regex = new RegExp(params.pattern, params.flags || 'g');
                    const matches = [...params.text.matchAll(regex)];
                    result = { success: true, matches: matches.map(m => ({ match: m[0], index: m.index })) };
                } catch (e) {
                    throw new Error('Invalid regex: ' + e.message );
                }
                break;

            case 'count_lines':
                if (!params.filePath) {
                    throw new Error('filePath required' );
                }
                const fileData = await fs.readFile(params.filePath, 'utf8');
                const fileLines = fileData.split('\n');
                const totalLines = fileLines.length;
                const blankLines = fileLines.filter(l => l.trim() === '').length;
                const codeLines = totalLines - blankLines;
                result = { success: true, totalLines, codeLines, blankLines };
                break;

            case 'git_status':
                const repoPath = params.repoPath || '.';
                // Validate repoPath to prevent path traversal
                const resolvedRepoPath = path.resolve(repoPath);
                if (!resolvedRepoPath.startsWith('/models') && resolvedRepoPath !== path.resolve('.')) {
                    throw new Error('repoPath must be within /models directory');
                }
                try {
                    const { stdout } = await execPromise('git status', { cwd: resolvedRepoPath });
                    result = { success: true, output: stdout };
                } catch (e) {
                    throw new Error('Git command failed: ' + e.message );
                }
                break;

            case 'git_diff':
                const gitRepoPath = params.repoPath || '.';
                // Validate repoPath to prevent path traversal
                const resolvedGitRepoPath = path.resolve(gitRepoPath);
                if (!resolvedGitRepoPath.startsWith('/models') && resolvedGitRepoPath !== path.resolve('.')) {
                    throw new Error('repoPath must be within /models directory');
                }
                const gitArgs = ['diff'];
                if (params.files && Array.isArray(params.files)) {
                    // Sanitize: only allow filenames without shell metacharacters
                    const safeFiles = params.files.filter(f => typeof f === 'string' && !/[;&|`$(){}]/.test(f));
                    gitArgs.push('--', ...safeFiles);
                }
                try {
                    const { stdout } = await execPromise(`git ${gitArgs.map(a => `'${a.replace(/'/g, "'\\''")}'`).join(' ')}`, { cwd: resolvedGitRepoPath });
                    result = { success: true, output: stdout };
                } catch (e) {
                    throw new Error('Git command failed: ' + e.message );
                }
                break;

            default:
                throw new Error(`Skill ${skillName} execution not implemented yet`);
        }

    return result;
}

// ============================================================================
// TASKS API ENDPOINTS
// ============================================================================

// List all tasks (optionally filter by agent)
app.get('/api/tasks', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { agentId } = req.query;

    try {
        let tasks = await loadTasks();

        // Filter by userId first
        tasks = filterByUserId(tasks, req.userId);

        // Then filter by agentId if provided
        if (agentId) {
            tasks = tasks.filter(t => t.agentId === agentId);
        }

        res.json(tasks);
    } catch (error) {
        console.error('Error loading tasks:', error);
        res.status(500).json({ error: 'Failed to load tasks' });
    }
});

// Get a single task
app.get('/api/tasks/:id', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { id } = req.params;
    try {
        const tasks = await loadTasks();
        const task = tasks.find(t => t.id === id);
        if (!task) {
            return res.status(404).json({ error: 'Task not found' });
        }
        if (!checkOwnership(task, req.userId)) {
            return res.status(403).json({ error: 'Access denied: task belongs to another user' });
        }
        res.json(task);
    } catch (error) {
        console.error('Error loading task:', error);
        res.status(500).json({ error: 'Failed to load task' });
    }
});

// Create a new task
app.post('/api/tasks', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { agentId, description, priority, collaborators } = req.body;

    if (!agentId || !description) {
        return res.status(400).json({ error: 'Agent ID and description are required' });
    }

    try {
        // Verify agent exists
        const agents = await loadAgents();
        if (!agents.find(a => a.id === agentId)) {
            return res.status(404).json({ error: 'Agent not found' });
        }

        const tasks = await loadTasks();
        const newTask = {
            id: crypto.randomBytes(16).toString('hex'),
            agentId,
            description,
            status: 'pending', // pending, in_progress, completed, failed
            priority: priority || 'medium', // low, medium, high
            result: null,
            error: null,
            collaborators: collaborators || [], // Array of agent IDs
            userId: req.userId || null,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            completedAt: null
        };

        tasks.push(newTask);
        await saveTasks(tasks);

        res.status(201).json(newTask);
    } catch (error) {
        console.error('Error creating task:', error);
        res.status(500).json({ error: 'Failed to create task' });
    }
});

// Update a task
app.put('/api/tasks/:id', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { id } = req.params;
    const { status, result, error, priority } = req.body;

    try {
        const tasks = await loadTasks();
        const taskIndex = tasks.findIndex(t => t.id === id);

        if (taskIndex === -1) {
            return res.status(404).json({ error: 'Task not found' });
        }

        if (!checkOwnership(tasks[taskIndex], req.userId)) {
            return res.status(403).json({ error: 'Access denied: task belongs to another user' });
        }

        // Update task
        tasks[taskIndex] = {
            ...tasks[taskIndex],
            status: status || tasks[taskIndex].status,
            result: result !== undefined ? result : tasks[taskIndex].result,
            error: error !== undefined ? error : tasks[taskIndex].error,
            priority: priority || tasks[taskIndex].priority,
            updatedAt: new Date().toISOString(),
            completedAt: (status === 'completed' || status === 'failed') ? new Date().toISOString() : tasks[taskIndex].completedAt
        };

        await saveTasks(tasks);
        res.json(tasks[taskIndex]);
    } catch (error) {
        console.error('Error updating task:', error);
        res.status(500).json({ error: 'Failed to update task' });
    }
});

// Delete a task
app.delete('/api/tasks/:id', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'agents')) {
        return res.status(403).json({ error: 'Agents permission required' });
    }

    const { id } = req.params;

    try {
        const tasks = await loadTasks();
        const taskIndex = tasks.findIndex(t => t.id === id);

        if (taskIndex === -1) {
            return res.status(404).json({ error: 'Task not found' });
        }

        if (!checkOwnership(tasks[taskIndex], req.userId)) {
            return res.status(403).json({ error: 'Access denied: task belongs to another user' });
        }

        tasks.splice(taskIndex, 1);
        await saveTasks(tasks);

        res.json({ message: 'Task deleted successfully' });
    } catch (error) {
        console.error('Error deleting task:', error);
        res.status(500).json({ error: 'Failed to delete task' });
    }
});

