// Documentation endpoint - fetch from DevDocs.io
app.get('/api/docs', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'query permission required' });
    }

    const { library, query } = req.query;

    if (!library) {
        return res.status(400).json({ error: 'Library parameter is required' });
    }

    // Check cache first
    const cacheKey = `docs:${library}:${query || 'index'}`;
    cleanExpiredCache();

    if (searchCache.has(cacheKey)) {
        const cached = searchCache.get(cacheKey);
        return res.json({ ...cached.data, cached: true });
    }

    try {
        // Map common library names to DevDocs slugs
        const libraryMap = {
            'javascript': 'javascript',
            'js': 'javascript',
            'node': 'node',
            'nodejs': 'node',
            'python': 'python~3.12',
            'py': 'python~3.12',
            'react': 'react',
            'vue': 'vue~3',
            'angular': 'angular',
            'express': 'express',
            'django': 'django~5.0',
            'flask': 'flask~3.0',
            'typescript': 'typescript',
            'ts': 'typescript',
            'docker': 'docker',
            'git': 'git',
            'bash': 'bash',
            'css': 'css',
            'html': 'html',
            'mdn': 'mdn'
        };

        const slug = libraryMap[library.toLowerCase()] || library.toLowerCase();

        // If no specific query, fetch the index
        if (!query) {
            const indexUrl = `https://docs.devdocs.io/${slug}/index.json`;
            const response = await axios.get(indexUrl, { timeout: 10000 });

            const entries = response.data.entries || [];
            const topEntries = entries.slice(0, 10).map(entry => ({
                name: entry.name,
                path: entry.path,
                type: entry.type || 'reference'
            }));

            const resultData = {
                library: slug,
                type: 'index',
                entries: topEntries,
                count: topEntries.length,
                total: entries.length
            };

            // Cache the results
            searchCache.set(cacheKey, {
                data: resultData,
                timestamp: Date.now()
            });

            return res.json(resultData);
        }

        // Search for specific documentation
        const indexUrl = `https://docs.devdocs.io/${slug}/index.json`;
        const response = await axios.get(indexUrl, { timeout: 10000 });

        const entries = response.data.entries || [];
        const searchTerm = query.toLowerCase();
        const matches = entries
            .filter(entry => entry.name.toLowerCase().includes(searchTerm))
            .slice(0, 10)
            .map(entry => ({
                name: entry.name,
                path: entry.path,
                type: entry.type || 'reference',
                url: `https://devdocs.io/${slug}/${entry.path}`
            }));

        const resultData = {
            library: slug,
            query: query,
            type: 'search',
            results: matches,
            count: matches.length
        };

        // Cache the results
        searchCache.set(cacheKey, {
            data: resultData,
            timestamp: Date.now()
        });

        res.json(resultData);
    } catch (error) {
        console.error('Documentation fetch error:', error);
        res.status(500).json({
            error: 'Failed to fetch documentation',
            details: error.message
        });
    }
});

// ============================================================================
// CONVERSATION MANAGEMENT API
// ============================================================================

const CONVERSATIONS_DIR = path.join(DATA_DIR, 'conversations');

// Base64 wrapper for conversation and memory files. This is obfuscation,
// not encryption — it just keeps casual disk inspection from showing
// plaintext chat history. Every write goes through encodeConversationData
// so new files are always base64; reads sniff the format so legacy JSON
// files keep loading and convert on next save. Format detection is cheap
// (one character check) and the conversion is transparent to callers.
function encodeConversationData(value) {
    const json = JSON.stringify(value, null, 2);
    return Buffer.from(json, 'utf8').toString('base64');
}
function decodeConversationData(raw, fallback = null) {
    if (!raw || !raw.trim()) return fallback;
    const trimmed = raw.trim();
    // Legacy plaintext JSON starts with { or [
    if (trimmed[0] === '{' || trimmed[0] === '[') {
        try { return JSON.parse(trimmed); }
        catch { return fallback; }
    }
    // Everything else is treated as base64-encoded JSON
    try {
        const decoded = Buffer.from(trimmed, 'base64').toString('utf8');
        return JSON.parse(decoded);
    } catch {
        return fallback;
    }
}

// Ensure conversations directory exists for a user
async function ensureUserConversationsDir(userId) {
    const userDir = path.join(CONVERSATIONS_DIR, userId);
    await fs.mkdir(userDir, { recursive: true });
    return userDir;
}

// Per-path write lock + atomic rename. Conversation indexes and message
// files are read-modify-write hotspots — chat-stream save, memory
// extraction, and explicit POST/PUT/DELETE routes can hit the same file
// within milliseconds. Plain fs.writeFile is neither atomic nor serialized,
// so two writes of different lengths can interleave at the byte level and
// leave a valid prefix from the shorter write followed by stray tail bytes
// from the longer one. The decoder then fails and the user's whole
// conversation list "disappears." safeWriteFile gives every write its own
// turn (per path) and only swaps the final file in via rename.
const _fileLocks = new Map();
function withFileLock(key, fn) {
    const prev = _fileLocks.get(key) || Promise.resolve();
    const next = prev.then(fn, fn);
    _fileLocks.set(key, next.catch(() => {}));
    return next;
}
async function atomicWriteFile(filePath, data) {
    const tmp = `${filePath}.${process.pid}.${Date.now().toString(36)}.${crypto.randomBytes(4).toString('hex')}.tmp`;
    try {
        await fs.writeFile(tmp, data);
        await fs.rename(tmp, filePath);
    } catch (err) {
        try { await fs.unlink(tmp); } catch {}
        throw err;
    }
}
async function safeWriteFile(filePath, data) {
    return withFileLock(filePath, () => atomicWriteFile(filePath, data));
}

// Load conversations index for a user. If the file is missing, empty,
// or corrupt, scan the user's directory for {uuid}.json conversation
// files and rebuild the index from them in place rather than returning
// an empty list (which would make every conversation appear "deleted").
async function loadConversationsIndex(userId) {
    const userDir = await ensureUserConversationsDir(userId);
    const indexPath = path.join(userDir, 'index.json');
    let parsed = null;
    try {
        const data = await fs.readFile(indexPath, 'utf8');
        parsed = decodeConversationData(data, null);
    } catch (error) {
        if (error.code !== 'ENOENT') throw error;
    }
    if (Array.isArray(parsed)) return parsed;
    return await withFileLock(indexPath, async () => {
        // Re-check inside the lock — a concurrent caller may have rebuilt.
        try {
            const fresh = await fs.readFile(indexPath, 'utf8');
            const reparsed = decodeConversationData(fresh, null);
            if (Array.isArray(reparsed) && reparsed.length > 0) return reparsed;
        } catch (err) {
            if (err.code !== 'ENOENT') throw err;
        }
        const rebuilt = await rebuildConversationsIndexFromDisk(userId, userDir);
        if (rebuilt.length > 0) {
            console.warn(`Rebuilt conversations index for user ${userId} from ${rebuilt.length} on-disk files`);
            await atomicWriteFile(indexPath, encodeConversationData(rebuilt));
        }
        return rebuilt;
    });
}

// Walk a user's conversations dir and reconstruct an index from the
// {uuid}.json files actually on disk. Title comes from the first user
// message; timestamps from file stat; memoryCount from the per-conversation
// memory index when present. Sorted newest-first to match how new
// conversations are unshifted onto the live index.
async function rebuildConversationsIndexFromDisk(userId, userDir) {
    let names;
    try { names = await fs.readdir(userDir); }
    catch { return []; }
    const idRegex = /^([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.json$/i;
    const entries = [];
    for (const name of names) {
        const m = name.match(idRegex);
        if (!m) continue;
        const id = m[1];
        const filePath = path.join(userDir, name);
        let stat;
        try { stat = await fs.stat(filePath); }
        catch { continue; }
        let messages = [];
        try { messages = await loadConversationMessages(userId, id); } catch {}
        let title = 'New Conversation';
        const firstUser = messages.find(msg => msg && msg.role === 'user');
        if (firstUser) {
            let txt = '';
            if (typeof firstUser.content === 'string') {
                txt = firstUser.content;
            } else if (Array.isArray(firstUser.content)) {
                const part = firstUser.content.find(p => p && p.type === 'text' && typeof p.text === 'string');
                txt = part ? part.text : '';
            }
            const cleaned = txt.replace(/\s+/g, ' ').trim();
            if (cleaned) title = cleaned.length > 60 ? cleaned.slice(0, 57) + '...' : cleaned;
        }
        // Memory is account-scoped now (managed in the webapp Memory tab), so
        // per-conversation memory counts are retired.
        const memoryCount = 0;
        const created = (stat.birthtime && stat.birthtime.getTime() > 0 ? stat.birthtime : stat.ctime).toISOString();
        entries.push({
            id,
            title,
            createdAt: created,
            updatedAt: stat.mtime.toISOString(),
            messageCount: messages.length,
            memoryCount
        });
    }
    entries.sort((a, b) => (b.updatedAt || '').localeCompare(a.updatedAt || ''));
    return entries;
}

// Save conversations index for a user
async function saveConversationsIndex(userId, conversations) {
    const userDir = await ensureUserConversationsDir(userId);
    const indexPath = path.join(userDir, 'index.json');
    await safeWriteFile(indexPath, encodeConversationData(conversations));
}

// Load messages for a conversation
async function loadConversationMessages(userId, conversationId) {
    // Validate conversationId format to prevent path traversal
    if (!/^[a-zA-Z0-9_-]+$/.test(conversationId)) {
        throw new Error('Invalid conversation ID format');
    }
    const userDir = await ensureUserConversationsDir(userId);
    const messagesPath = path.join(userDir, `${conversationId}.json`);
    try {
        const data = await fs.readFile(messagesPath, 'utf8');
        const parsed = decodeConversationData(data, null);
        if (parsed === null) {
            console.error(`Corrupted conversation ${conversationId} for user ${userId}`);
            return [];
        }
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        if (error.code === 'ENOENT') return [];
        throw error;
    }
}

// Save messages for a conversation
async function saveConversationMessages(userId, conversationId, messages, { memoryUserId = userId } = {}) {
    // Validate conversationId format to prevent path traversal
    if (!/^[a-zA-Z0-9_-]+$/.test(conversationId)) {
        throw new Error('Invalid conversation ID format');
    }
    const userDir = await ensureUserConversationsDir(userId);
    const messagesPath = path.join(userDir, `${conversationId}.json`);
    await safeWriteFile(messagesPath, encodeConversationData(messages));

    // Update messageCount in conversations index — and CREATE the entry when
    // it's missing. A brand-new conversation that completes in the BACKGROUND
    // (user navigated away before the client created the index row) would
    // otherwise write its message file with no index entry; loadConversationsIndex
    // only rescans disk when index.json is absent, and GET /api/conversations/:id
    // returns an empty stub for any id not in the index — so the on-disk
    // response would be invisible / show as an empty "New Conversation".
    try {
        const conversations = await loadConversationsIndex(userId);
        const conv = conversations.find(c => c.id === conversationId);
        if (conv) {
            conv.messageCount = messages.length;
            conv.updatedAt = new Date().toISOString();
            await saveConversationsIndex(userId, conversations);
        } else {
            // Derive a title from the first user message (same convention as
            // rebuildConversationsIndexFromDisk); fall back to 'New Conversation'.
            let title = 'New Conversation';
            const firstUser = messages.find(msg => msg && msg.role === 'user');
            if (firstUser) {
                let txt = '';
                if (typeof firstUser.content === 'string') txt = firstUser.content;
                else if (Array.isArray(firstUser.content)) {
                    const part = firstUser.content.find(p => p && p.type === 'text' && typeof p.text === 'string');
                    txt = part ? part.text : '';
                }
                const cleaned = txt.replace(/\s+/g, ' ').trim();
                if (cleaned) title = cleaned.length > 60 ? cleaned.slice(0, 57) + '...' : cleaned;
            }
            const now = new Date().toISOString();
            conversations.unshift({ id: conversationId, title, createdAt: now, updatedAt: now, messageCount: messages.length });
            await saveConversationsIndex(userId, conversations);
        }
    } catch (e) {
        // Non-critical - don't fail message save if index update fails
    }

    // Fire-and-forget memory extraction from any new user→assistant pairs
    // since the last save. Memory work must never block the save or leak
    // errors back to the caller — user turns always succeed to disk.
    // `memoryUserId` (defaults to the conversation owner) lets the chat stream
    // route extraction to the ACCOUNT memory bucket even when the conversation
    // itself is owned by an API key — so an API-key chat's memories land where
    // retrieval (memAccountId) later reads them.
    extractNewMemoriesFromSave(memoryUserId, conversationId, messages).catch(err => {
        console.warn(`[Memory] Extraction failed for ${conversationId}: ${err.message}`);
    });
}

// ============================================================================
// ACCOUNT MEMORY — extraction heuristics
// ============================================================================
// Memory is ACCOUNT-scoped (see services/memoryService.js for storage). The
// chat stream extracts short, heuristically-compressed facts from user↔assistant
// turns and hands them to the memory service, which dedups account-wide and
// keeps them bounded. On follow-up messages the stream scores the user's whole
// memory against the new query and injects the top matches as a system message.
// The functions below (scoring / shorthand / sentence splitting) PRODUCE the
// candidate facts; persistence lives in the service.

// Target token budget for injected memories on a single turn (fallback when
// the model's context size is unknown — see memoryBudgetForCtx).
const MEMORY_RETRIEVAL_TOKEN_BUDGET = 1500;
// Minimum factuality score to keep a sentence as a memory.
const MEMORY_MIN_SCORE = 2;
// Cosine threshold for the SEMANTIC relevance gate (memoryIndex embeddings).
// potion-retrieval cosines, measured against real chat queries: a relevant
// intent phrased as a full chat sentence lands ~0.26-0.43 (instruction
// boilerplate dilutes the embedding; the same intent phrased tersely scores
// ~0.4-0.66), unrelated content tops out ~0.2. 0.28 sits between the bands —
// 0.35 looked safe on terse probes but rejected most sentence-length queries.
// Tunable without a rebuild via env.
const MEMORY_SEM_THRESHOLD = parseFloat(process.env.MEMORY_SEM_THRESHOLD || '') || 0.28;
// Max memories pulled in by 1-hop LINK EXPANSION at retrieval. A memory the user
// or the model CONNECTED to a relevant one rides along even if it wouldn't pass
// the relevance gate on its own — that's the whole point of a link. Bounded +
// token-budgeted so a dense link graph can't flood the context; 1-hop only (we
// never expand an expansion). Set to 0 to disable. Tunable without a rebuild.
const LINK_EXPANSION_MAX = parseInt(process.env.MEMORY_LINK_EXPANSION_MAX) || 4;

// Semantic scores for a chat query: search with the full text AND a
// keyword-condensed form, keeping the best cosine per memory. Real chat
// queries carry instruction boilerplate ("one sentence", "don't search the
// web") that dilutes the embedding — on the same intent the full sentence
// measured 0.257 vs 0.289 condensed vs 0.395 terse against the matching
// memory, so the condensed pass recovers part of the lost signal for one
// extra local CPU search. Same null-on-engine-down contract as
// memoryIndex.search; the condensed pass is best-effort on top.
async function semanticMemoryScores(userId, query, k = 32) {
    const sem = await memoryIndex.search(userId, query, k);
    if (!sem) return null;
    const condensed = extractQueryKeywords(query).join(' ');
    if (condensed && condensed.length < String(query).trim().length) {
        try {
            const semCond = await memoryIndex.search(userId, condensed, k);
            if (semCond) {
                for (const [id, s] of semCond.scores) {
                    const prev = sem.scores.get(id);
                    if (prev == null || s > prev) sem.scores.set(id, s);
                }
            }
        } catch (_) { /* best-effort — full-query scores already in hand */ }
    }
    return sem;
}

// Scale the memory/persona injection budget with the model's context window —
// a 4k-ctx model can't afford the same block a 131k one shrugs off. ~4% of
// ctx, clamped: 4-8k → min, 32k → ~1.3k, 64k+ → capped.
function memoryBudgetForCtx(ctx, { base = MEMORY_RETRIEVAL_TOKEN_BUDGET, min = 400, max = 2500 } = {}) {
    if (!Number.isFinite(ctx) || ctx <= 0) return base;
    return Math.max(min, Math.min(max, Math.floor(ctx * 0.04)));
}


// Score a sentence for how "fact-like" it is. Facts are what we want to
// remember; filler phrases and meta-commentary are what we want to drop.
// This is a heuristic, not a classifier — tuned so the top-scored sentences
// from a typical Q&A turn are the ones a human would also pick.
function scoreFactuality(sentence) {
    const s = sentence.trim();
    if (s.length < 15 || s.length > 500) return 0;
    let score = 0;
    // URLs and identifiers are high-value
    if (/https?:\/\//.test(s)) score += 4;
    if (/\b[a-z][a-zA-Z0-9]+[A-Z][a-zA-Z0-9]+\b/.test(s)) score += 2; // camelCase
    if (/\b[a-z0-9]+_[a-z0-9_]+\b/.test(s)) score += 2;               // snake_case
    if (/\b[A-Z][A-Z0-9_]{3,}\b/.test(s)) score += 2;                  // ALL_CAPS constants
    // Filesystem paths: absolute (/etc/foo), home (~/foo), or relative
    // (./foo, ../foo) — the dot-prefixed forms appear constantly in build
    // instructions ("./build.sh") and must score as high-value.
    if (/(^|\s)(\.{1,2}\/|[/~])[\w./-]+/.test(s)) score += 2;
    // Bare filenames with a common extension ("build.sh", "config.yaml",
    // "model.gguf") are also path-like facts worth keeping.
    if (/\b[\w-]+\.(sh|py|js|jsx|ts|tsx|json|ya?ml|toml|conf|cfg|ini|md|txt|log|sql|go|rs|rb|java|cpp|c|h|hpp|html|css|xml|env|lock|gguf|bin|onnx)\b/i.test(s)) score += 2;
    if (/`[^`]+`/.test(s)) score += 2;                                 // backtick code
    if (/"[^"]{3,}"|'[^']{3,}'/.test(s)) score += 1;                   // quoted strings
    // Numbers, dates, versions, amounts
    if (/\b\d+(\.\d+)?\b/.test(s)) score += 1;
    if (/\b\d{4}-\d{2}-\d{2}\b/.test(s)) score += 2;                   // ISO date
    if (/\bv?\d+\.\d+(\.\d+)?\b/.test(s)) score += 1;                  // version
    // Declarative predicates — expanded beyond the basic copula to cover
    // the verbs that most often introduce concrete facts in technical
    // prose. Missing these produces lots of false-negatives on simple
    // statements like "the webapp listens on port 3001" or "the build
    // runs ./build.sh".
    if (/\b(is|was|are|were|has|have|had|named|called|equals?|returns?|contains?|requires?|means?|uses|runs|listens?|provides?|accepts?|includes?|mounts?|exports?|handles?|matches?|starts?|stops?|binds?|loads?|writes?|reads?|stores?|points?|lives?|located|depends?\s+on)\b/i.test(s)) score += 1;
    // Capitalized words that are not sentence-initial — proper nouns
    const caps = (s.match(/(?<=[a-z]\s)[A-Z][a-zA-Z]+/g) || []).length;
    if (caps >= 1) score += Math.min(2, caps);
    // Filler/meta-commentary penalties
    if (/^(sure|okay|ok|yes|no|thanks|thank you|got it|great|alright|certainly)\b/i.test(s)) score -= 5;
    if (/\b(let me|I'll|I will|I can|here's|here is|as requested|as an ai)\b/i.test(s)) score -= 3;
    if (/\b(in summary|to summarize|in conclusion|overall|basically|essentially)\b/i.test(s)) score -= 2;
    return score;
}

// Lightweight JS-side shorthand compression — a subset of AIMem's shorthand
// stage ported over to avoid spawning a Python subprocess on every turn.
// These replacements are lossless for meaning but shave ~15-25% off length
// on typical prose. Longer replacements come first to avoid partial overlap.
const SHORTHAND_REPLACEMENTS = [
    [/\bin order to\b/gi, 'to'],
    [/\bdue to the fact that\b/gi, 'because'],
    [/\bwith respect to\b/gi, 're:'],
    [/\bfor the purpose of\b/gi, 'to'],
    [/\bin the event that\b/gi, 'if'],
    [/\bat this point in time\b/gi, 'now'],
    [/\bfor example\b/gi, 'e.g.'],
    [/\bthat is\b/gi, 'i.e.'],
    [/\bas well as\b/gi, 'and'],
    [/\bin addition to\b/gi, 'and'],
    [/\bas a result\b/gi, 'so'],
    [/\bit is important to note that\b/gi, 'note:'],
    [/\bit should be noted that\b/gi, 'note:'],
    [/\bplease note that\b/gi, 'note:'],
    [/\bkeep in mind that\b/gi, 'note:'],
    [/\bthe user (?:is )?asking\b/gi, 'user asks'],
    [/\bthe user wants\b/gi, 'user wants'],
    [/\bthe user said\b/gi, 'user:'],
    [/\bI would like to\b/gi, "I'd"],
    [/\byou would like to\b/gi, "you'd"],
    [/\bdo not\b/gi, "don't"],
    [/\bdoes not\b/gi, "doesn't"],
    [/\bis not\b/gi, "isn't"],
    [/\bare not\b/gi, "aren't"],
    [/\bwill not\b/gi, "won't"],
    [/\bcannot\b/gi, "can't"],
    [/\s{2,}/g, ' '],
];
function shorthandCompress(text) {
    let out = text;
    for (const [pattern, repl] of SHORTHAND_REPLACEMENTS) {
        out = out.replace(pattern, repl);
    }
    return out.trim();
}

// Split text into sentences without breaking on dots inside filesystem
// paths, URLs, version numbers, decimals, or mid-word abbreviations. A
// sentence boundary is either a newline OR a .!? terminator followed by
// whitespace and a capital-letter sentence start (optionally preceded by
// an opening quote or paren). This preserves /etc/foo.conf, v1.2.3,
// https://example.com/a.html, and 3.14 as single tokens inside whatever
// sentence they belong to.
function splitIntoSentences(text) {
    if (!text) return [];
    const out = [];
    const lines = text.split(/\r?\n/);
    for (const line of lines) {
        const trimmedLine = line.trim();
        if (!trimmedLine) continue;
        const parts = trimmedLine.split(/(?<=[.!?]["')\]]?)\s+(?=["'(\[]?[A-Z])/);
        for (const p of parts) {
            const t = p.trim();
            if (t) out.push(t);
        }
    }
    return out;
}

// Extract up to `maxKeep` memory-worthy sentences from a user→assistant pair.
// Returns an array of { text, keywords, tokens, sourceRole }. Runs entirely
// in-process, no subprocess spawn, safe to call on every save.
// Heuristic type/impact classifier for AUTO-extracted memories. Extraction is
// model-free (runs on every save), so this is cue-based and deliberately
// CONSERVATIVE — it only assigns a non-'fact' type on a clear signal. Without
// it every auto memory is a typeless, importance-less 'fact', so the Memory tab
// shows a wall of untyped rows and it looks like nothing classifies them. A
// user-stated preference/correction becomes a directive (always injected); a
// plain fact's importance scales with its factuality score but never outranks
// an explicit directive.
function classifyMemoryHeuristic(sentence, role, factScore) {
    const s = String(sentence).toLowerCase();
    const isUser = role === 'user';
    // Order matters: correction/limitation cues take precedence over a generic
    // preference cue when a sentence trips more than one.
    if (/\b(actually|that'?s (wrong|incorrect|not right)|not correct|i meant|i didn'?t mean|instead of|should (be|have been)|don'?t say|stop (doing|saying)|you (misunderstood|got .* wrong))\b/.test(s)) {
        return { type: 'correction', impact: isUser ? 'important' : 'medium' };
    }
    if (/\b(doesn'?t work|not work(ing)?|cannot|can'?t|fail(s|ed)?|not supported|unsupported|no longer|deprecated|broke(n)?|not available|throws? (an )?error|errors? out)\b/.test(s)) {
        return { type: 'limitation', impact: 'medium' };
    }
    if (/\b(i (prefer|like|love|want|use|always|never|usually|typically)|i'?d (prefer|rather)|please (always|use|don'?t|make sure|ensure)|from now on|going forward|by default|my (preferred|favou?rite|go-to))\b/.test(s)) {
        return { type: 'preference', impact: isUser ? 'important' : 'medium' };
    }
    if (isUser && /\b(thanks?,? that (worked|helped)|that'?s (better|great|exactly|perfect)|good (job|call)|nailed it|works? (great|now|perfectly))\b/.test(s)) {
        return { type: 'feedback', impact: 'low' };
    }
    // Plain fact — importance scales with factuality so the strongest facts
    // still surface, but they never outrank explicit directives.
    return { type: 'fact', impact: factScore >= 6 ? 'medium' : 'low' };
}

// Reject lines that are structural markdown noise, not durable facts. The
// auto-extractor used to capture email-field dumps and report fragments verbatim
// ("| Subject | Add Love to Your Story |", "| Body Links | https://… |") which
// then became their own memory AND their own (garbage) title. These are never
// worth remembering: they're transient analysis artifacts, not facts about the
// user or their work. Conservative — only fires on clear table/separator/heading
// structure so ordinary prose containing a single pipe or asterisk is kept.
function isJunkMemoryLine(sentence) {
    const t = String(sentence || '').trim();
    if (!t) return true;
    // Markdown table row or multi-cell line (≥2 pipes) — the biggest offender.
    if ((t.match(/\|/g) || []).length >= 2) return true;
    // Table separator / alignment row ( |---|:--:| ).
    if (/^\|?\s*:?-{2,}:?\s*(\|\s*:?-{0,}:?\s*)*\|?$/.test(t)) return true;
    // Any markdown heading ("## Findings", "## What We Know So Far") — a section
    // label from the assistant's formatted answer, not a durable fact.
    if (/^#{1,6}\s+/.test(t)) return true;
    // Markdown list item / numbered or analysis step ("- Watch …", "2. **Recipient**: …").
    // These are pieces of a formatted answer, not standalone facts about the user.
    if (/^[\s>]*([-*+]|\d+[.)])\s+/.test(t)) return true;
    // A line that LEADS with a bolded span ("**Subject**: …", "**The irony:**
    // …", "**Links**: …") — a row/label out of an assistant's structured
    // breakdown, never a durable user fact (which reads as prose).
    if (/^\s*\*\*[^*]+\*\*/.test(t)) return true;
    // Code-ish line: shell/PowerShell pipelines, variable assignments, calls, or
    // statement punctuation. Real facts mentioning code survive (the cue must be
    // structural), code FRAGMENTS stored verbatim do not.
    if (/^\s*\$\w+\s*=/.test(t)) return true;                         // $x = …
    if (/^\s*(echo|curl|wget|sudo|apt|apk|npm|pip|git|chmod|mkdir|export)\s+["'-]/i.test(t)) return true;  // a line that IS a shell command (echo "…", curl -…), not prose about one
    if (/^\s*["'][^"'\n]{1,60}["']\s*[:=]\s*["']/.test(t)) return true;                                     // "key" = "value" / "Header": "value" literal — a code/config fragment, not a fact
    if (/\b(Where-Object|Write-Host|ForEach-Object|Select-Object|Invoke-RestMethod)\b/.test(t)) return true;
    if (/=>|;\s*$|\{\s*$|^\s*(function|const|let|var|def|class|import|return|public|private)\b/.test(t)) return true;
    // Link-dominated line ("📖 Read more: [Vogue HK](https://…)", "https://… for updates"):
    // strip markdown links + bare URLs; if barely any prose remains, it's a
    // pointer/citation, not a fact worth keeping.
    const noLinks = t.replace(/\[[^\]]*\]\([^)]*\)/g, ' ').replace(/https?:\/\/\S+/g, ' ');
    if ((t.match(/https?:\/\/|\]\(/g) || []).length >= 1 && (noLinks.match(/[a-zA-Z]/g) || []).length < 20) return true;
    // Almost no letters (separator rules "---"/"===", pure number/symbol lines)
    // — not a real fact. Kept low (<4) so genuine short facts ("Pi is 3.14",
    // "IP 1.2.3.4") survive; the scoreFactuality length gate backstops the rest.
    const letters = (t.match(/[a-zA-Z]/g) || []).length;
    if (letters < 4) return true;
    return false;
}

// A line that is a REQUEST/COMMAND to the assistant ("Give me all the info for
// the Diablo 4 patch", "show me a picture of X", "can you check Y?") rather than
// a durable FACT about the user. Such lines describe what the user wanted in one
// turn, not a stable truth — re-injected later under "WHAT YOU KNOW ABOUT THIS
// USER" they're noise (the largest junk class in the live store).
// IMPORTANT: this is type-AWARE at every call site (only ever applied to
// fact-typed / !isDirectiveType candidates). It must NOT be wired into
// isJunkMemoryLine, which runs PRE-classification and would silently kill a
// leading-imperative DIRECTIVE ("please always use tabs", "from now on output
// JSON") — exactly the behavioral memory worth keeping.
// `^`-anchored + multi-word, assistant-addressed openers only, so a mid-sentence
// "the API lets users find records" never matches. Weak verbs (check/verify/…)
// require an explicit "please" softener so a bare imperative isn't over-caught.
function looksLikeRequest(text) {
    const t = String(text || '').trim();
    if (/\?\s*$/.test(t)) return true;                                  // trailing-? = a question
    // Strong, unambiguous request openers (with or without a leading "please").
    if (/^(please\s+)?(give me|show me|tell me|find me|get me|send me|look ?up|search for|help me|can you|could you|would you|will you)\b/i.test(t)) return true;
    // Weaker verbs count as a request ONLY when softened by an explicit "please".
    if (/^please\s+(give|show|tell|find|get|search|look ?up|check|verify|confirm|make sure|pull up)\b/i.test(t)) return true;
    return false;
}

// ----------------------------------------------------------------------------
// LLM-assisted extraction — the quality upgrade over the regex heuristics.
// Every save runs right after a LOCAL model finished generating on the user's
// own GPU, so a small post-save completion is free; it understands "my
// daughter is 7" and "that approach failed, X worked" where scoreFactuality
// (biased toward URLs/paths/code) scores them near zero. Fire-and-forget from
// the save path, bounded in-flight, hard-timeout, and ALWAYS falls back to the
// heuristic extractor on any failure — extraction can never regress below the
// regex baseline. Returns:
//   null  → LLM unavailable/failed (caller runs the heuristics)
//   []    → LLM ran and judged nothing durable (VALID — do not fall back,
//           that would re-add exactly the noise the model filtered out)
//   [...] → candidates shaped like extractMemoriesFromTurn's output
// ----------------------------------------------------------------------------
let llmExtractInFlight = 0;
const LLM_EXTRACT_MAX_INFLIGHT = 2;
const LLM_EXTRACT_TIMEOUT_MS = 30000;

const LLM_EXTRACT_SYSTEM_PROMPT =
    'You extract long-term memories from one chat exchange so an assistant can serve this user better in FUTURE, unrelated conversations. ' +
    'Return ONLY a JSON array, no prose. Each item: {"text": string, "type": string, "impact": "important"|"medium"|"low"}.\n' +
    'Types:\n' +
    '- "fact": a durable fact about the user, their life, work, projects, or environment.\n' +
    '- "preference": how the user wants things done (style, tools, format).\n' +
    '- "correction": the user corrected the assistant — what to do instead.\n' +
    '- "limitation": something that does not work / is unavailable.\n' +
    '- "workaround": a working alternative that was found.\n' +
    '- "learning": what approach worked or failed when DOING a task (coding, research, analysis) — phrase as an ADAPTIVE heuristic the assistant should reuse ("ran into X, doing Y first avoids it"; "approach Z worked best for this kind of task"), never a rigid absolute. THIS IS THE MOST VALUABLE TYPE — prefer it.\n' +
    'Rules:\n' +
    '- Only items worth remembering WEEKS from now, in unrelated conversations.\n' +
    '- The GOAL is to make the assistant work better next time: capture what went wrong and the fix, the best approach found for a task, durable facts about the user, and how they like work done. Favor experiential learnings (what worked / what to do better).\n' +
    '- DO NOT store the user\'s passive INTERESTS, hobbies, or topics they were merely curious about this turn ("the user is interested in <show/game/topic>", "is a fan of X", "likes the series Y", "enjoys watching Z"). These are not actionable. (A working-style preference like "prefers concise answers" or a durable WORK/identity fact like "is a backend engineer" IS fine — the test is whether it changes how you should WORK or who they ARE, not what they happen to enjoy.)\n' +
    '- NO content whose VALUE is time-bound (current date/time, today\'s news, live prices).\n' +
    '- A durable change phrased with time words ("we are migrating to X this year", "I use Y now") IS worth keeping — rephrase it atemporally as the new steady state (e.g. "The user\'s hospital is migrating its network from Cisco to Juniper"), do not drop it.\n' +
    '- DO NOT extract the assistant\'s OWN output as facts: article/search-result summaries, quoted passages, headings/bullets/tables, code snippets, commands, links/citations, or "what we found" write-ups are NOT memories. A memory is about the USER (their life/work/projects/environment), their stable preferences/corrections, or a reusable lesson from the task — never the content the assistant produced this turn.\n' +
    '- NO one-off task details, pleasantries, restatements of the question, or generic knowledge the assistant already has.\n' +
    '- Each text must stand alone without this conversation as context (resolve "it"/"that").\n' +
    '- 0 to 5 items. If nothing qualifies, return [].';

async function llmExtractMemoriesFromTurn(userText, assistantText) {
    if (process.env.MEMORY_LLM_EXTRACTION === '0') return null;
    // Only when a local model is ALREADY serving — never queue behind a cold
    // load, and never stack more than a couple of extraction completions.
    let hasRunning = false;
    for (const inst of modelInstances.values()) {
        if (inst.status === 'running') { hasRunning = true; break; }
    }
    if (!hasRunning || llmExtractInFlight >= LLM_EXTRACT_MAX_INFLIGHT) return null;

    const clean = (t, cap) => String(t || '')
        .replace(/<(think|thinking|reasoning|reasoning_engine)>[\s\S]*?<\/\1>/gi, '')
        .trim().slice(0, cap);
    const u = clean(userText, 4000);
    const a = clean(assistantText, 6000);
    if (!u && !a) return null;

    llmExtractInFlight++;
    try {
        const raw = await Promise.race([
            runModelCompletion({
                messages: [
                    { role: 'system', content: LLM_EXTRACT_SYSTEM_PROMPT },
                    { role: 'user', content: `USER MESSAGE:\n${u || '(none)'}\n\nASSISTANT REPLY:\n${a || '(none)'}` },
                ],
                temperature: 0,
                maxTokens: 700,
                disableThinking: true, // memory extraction needs clean JSON, not a reasoning trace that truncates it
            }),
            new Promise((_, rej) => {
                const t = setTimeout(() => rej(new Error('llm extraction timed out')), LLM_EXTRACT_TIMEOUT_MS);
                if (t.unref) t.unref();
            }),
        ]);
        // Parse: strip reasoning, isolate the array, jsonrepair as fallback.
        const stripped = String(raw || '')
            .replace(/<(think|thinking|reasoning|reasoning_engine)>[\s\S]*?<\/\1>/gi, '').trim();
        const start = stripped.indexOf('[');
        const end = stripped.lastIndexOf(']');
        if (start < 0 || end <= start) return null;
        const slice = stripped.slice(start, end + 1);
        let arr;
        try { arr = JSON.parse(slice); }
        catch (_) {
            try { arr = JSON.parse(require('jsonrepair').jsonrepair(slice)); }
            catch (_) { return null; }
        }
        if (!Array.isArray(arr)) return null;

        // Validate + apply the SAME safety filters the heuristic path uses —
        // the model is better, not trusted: junk/ephemeral lines still drop.
        const out = [];
        for (const it of arr) {
            if (out.length >= 5) break;
            const text = shorthandCompress(String(it?.text || '').trim());
            if (text.length < 12 || text.length > 600) continue;
            if (isJunkMemoryLine(text)) continue;
            const type = (typeof it?.type === 'string' && memoryService.VALID_TYPES.has(it.type) && it.type !== 'procedure')
                ? it.type : 'fact';
            const isDirectiveType = type !== 'fact';
            if (!isDirectiveType && isEphemeralFact(text)) continue;
            const impact = memoryService.VALID_IMPACTS.has(it?.impact)
                ? it.impact : (isDirectiveType ? 'medium' : 'low');
            const keywords = extractQueryKeywords(text);
            if (!keywords.length) continue;
            out.push({
                text,
                keywords,
                tokens: Math.ceil(text.length / 3),
                score: impact === 'important' ? 7 : (impact === 'medium' ? 5 : 3),
                type,
                impact,
                sourceRole: null,
            });
        }
        return out;
    } catch (_) {
        return null; // unavailable/slow/garbled → heuristic fallback
    } finally {
        llmExtractInFlight--;
    }
}

function extractMemoriesFromTurn(userText, assistantText, maxKeep = 5) {
    const memories = [];

    const processSide = (text, role) => {
        if (!text || typeof text !== 'string') return;
        // Strip reasoning blocks — they're introspection, not facts worth
        // remembering across turns. Covers <think>, <thinking>, <reasoning>,
        // and <reasoning_engine> variants emitted by different models.
        const clean = text.replace(/<(think|thinking|reasoning|reasoning_engine)>[\s\S]*?<\/\1>/gi, '').trim();
        if (!clean) return;
        // Skip pure-code payloads entirely — splitting code into "sentences"
        // produces garbage and the useful facts about code live in the prose
        // around it, not the code itself.
        if (looksLikeCode(clean)) return;
        const sentences = splitIntoSentences(clean);
        for (const sentence of sentences) {
            // Drop structural markdown noise (table rows / separators / bare
            // headings) before any scoring — these are transient artifacts, not
            // memories, and used to pollute both the store and the titles.
            if (isJunkMemoryLine(sentence)) continue;
            const score = scoreFactuality(sentence);
            const { type, impact } = classifyMemoryHeuristic(sentence, role, score);
            // Keep fact-like sentences (factuality gate) OR any sentence with a
            // clear preference/correction/limitation/feedback cue. The latter
            // are the durable BEHAVIORAL memories — and they routinely score ~0
            // on factuality (a bare "I prefer dark mode" / "actually, use tabs"
            // has no URLs/paths/numbers/code), so the score gate would drop them
            // before they could ever be classified. Those are exactly what the
            // user wants remembered, so a directive cue overrides the gate.
            const isDirectiveType = type !== 'fact';
            // Plain FACTS from the ASSISTANT side are almost always the model's
            // own generated content (article summaries, search results, code,
            // citations) — not durable facts ABOUT THE USER. scoreFactuality
            // rewards URLs/paths/code/numbers, so that content scored high and
            // flooded the store. Keep assistant-side ONLY for behavioral memories
            // (corrections / workarounds / learnings the exchange established);
            // real user facts come from the USER side (or the LLM extractor).
            if (role === 'assistant' && !isDirectiveType) continue;
            // A question OR a bare command to the assistant is the user ASKING,
            // not a durable fact — "my script keeps crashing — any idea why?",
            // "Give me all the info for the Diablo 4 patch" are not memories. Drop
            // request-shaped sentences from the fact path. The `!isDirectiveType`
            // guard is load-bearing: an imperative PREFERENCE ("please always use
            // tabs", "from now on output JSON") is typed preference/correction by
            // classifyMemoryHeuristic → isDirectiveType, and must stay exempt.
            if (!isDirectiveType && looksLikeRequest(sentence)) continue;
            if (score < MEMORY_MIN_SCORE && !isDirectiveType) continue;
            // Passive consumption-interest ("user is into the show X") is not a
            // memory the user wants — drop it here too (the candidate choke point
            // is the backstop, this keeps it out of the per-turn top-N as well).
            if (!isDirectiveType && isLowValueInterest(sentence)) continue;
            // Drop time-bound / live-news facts: their truth is anchored to this
            // moment, so persisting them poisons future turns (a cached "today
            // is …" date, yesterday's headlines). Directive-typed sentences
            // (preferences/corrections) are kept even if they mention a day —
            // their behavioral intent is durable.
            if (!isDirectiveType && isEphemeralFact(sentence)) continue;
            const compressed = shorthandCompress(sentence);
            const keywords = extractQueryKeywords(compressed);
            if (keywords.length === 0) continue;
            // Floor a directive's score so it survives the per-turn top-N keep
            // and outranks incidental facts.
            const effScore = isDirectiveType
                ? Math.max(score, impact === 'important' ? 6 : 4)
                : score;
            memories.push({
                text: compressed,
                keywords,
                tokens: Math.ceil(compressed.length / 3),
                sourceRole: role,
                score: effScore,
                type,
                impact,
            });
        }
    };

    processSide(userText, 'user');
    processSide(assistantText, 'assistant');

    // Sort by score and keep the top N; also dedup within the same turn by
    // keyword-set overlap so we don't save two paraphrases of the same fact.
    memories.sort((a, b) => b.score - a.score);
    const kept = [];
    for (const m of memories) {
        const dup = kept.some(k => jaccardSimilarity(k.keywords, m.keywords) >= 0.7);
        if (!dup) kept.push(m);
        if (kept.length >= maxKeep) break;
    }
    return kept;
}

function jaccardSimilarity(aKeywords, bKeywords) {
    if (!aKeywords.length || !bKeywords.length) return 0;
    const a = new Set(aKeywords);
    const b = new Set(bKeywords);
    let inter = 0;
    for (const k of a) if (b.has(k)) inter++;
    const union = a.size + b.size - inter;
    return union === 0 ? 0 : inter / union;
}

// A sentence whose truth is anchored to the MOMENT it was captured — a current
// date/time ("Today is Thursday, June 4, 2026"), a relative timestamp ("21 hours
// ago"), or live news ("breaking headlines right now"). These must never become
// durable memories: stored once and re-injected on a later turn, they actively
// corrupt accuracy (the model parrots a stale date / yesterday's news as if it
// were current). Deliberately CONSERVATIVE — only strong temporal-deixis /
// relative-time / live-news cues fire, so durable facts that merely contain a
// number, a date-like id (CVE-2026-…), or the bare word "now" are kept.
const EPHEMERAL_PATTERNS = [
    /\b(today|yesterday|tomorrow|tonight)\b/i,
    /\bthis (morning|afternoon|evening|week|month|year|quarter)\b/i,
    /\b(last|next|past|coming) (night|week|month|year|quarter|few days|couple (of )?days)\b/i,
    /\bright now\b/i,
    /\bas of (now|today|writing|this)\b/i,
    /\bat (the moment|present|this time)\b/i,
    /\b(these days|nowadays|currently|at present)\b/i,
    /\b(\d+|a|an|few|several|couple|many)\s+(second|minute|hour|day|week|month|year|sec|min|hr|yr)s?\s+ago\b/i,
    /\b(just|moments?|recently)\s+(now|ago|announced|released|published|reported|launched|happened)\b/i,
    /\b(breaking|latest|top|recent)\s+(news|stories|headlines?)\b/i,
    /\bheadlines?\b/i,
    /\bnews (right now|today|this (week|morning))\b/i,
    /\bin the news\b/i,
    // Transient SESSION-scoped state — a file that was/wasn't on disk THIS
    // session, what's available "in this conversation". True only for the moment
    // it was captured; re-injected on a later turn it's actively misleading
    // ("the SVG isn't available on disk in this session" when it later is).
    /\b(in|for|during) this (session|conversation|chat|turn)\b/i,
    /\b(isn'?t|is not|not|no longer)\s+(available|present|found|on disk)\b[^.]{0,40}\b(on disk|this session|this conversation)\b/i,
];
function isEphemeralFact(sentence) {
    const s = String(sentence || '');
    return EPHEMERAL_PATTERNS.some((re) => re.test(s));
}

// A PASSIVE consumption/curiosity statement about the user — "the user is
// interested in X", "has an interest in the series Y", "is a fan of Z",
// "enjoys watching/reading/playing W", "likes the show/anime/game …". The user
// explicitly does NOT want these stored: they are not actionable for serving
// them better. Memory should hold (a) durable WORK/identity facts, (b)
// behavioral preferences (HOW they want work done), and (c) experiential
// learnings (what approach worked / failed). Deliberately targets the
// consumption/curiosity FRAMING, so professional-identity facts ("works in
// cybersecurity", "is a backend engineer") and real working-style preferences
// ("prefers concise answers", "wants code first") are NOT matched.
const INTEREST_PATTERNS = [
    /\binterest(ed)?\s+in\b/i,
    /\bhas (an?|some) (interest|fascination|fondness|liking|passion|curiosity|affinity|obsession)\b/i,
    /\bis (interested|curious|enthusiastic|passionate|keen|excited)\b/i,
    /\b(is|are|being)\s+(a |an )?(big |huge |avid |major |massive )?fan(s)? of\b/i,
    /\benjoys?\s+(watching|reading|playing|listening|following|the\b|this\b)/i,
    /\b(likes?|loves?|enjoys?|follows?|watches?|reads?|plays?|into)\b[^.]*\b(series|show|movie|film|anime|manga|cartoon|game|video game|book|novel|comic|song|album|artist|band|musician|character|franchise|genre|sport|team|celebrity|youtuber|streamer)\b/i,
];
function isLowValueInterest(text) {
    const s = String(text || '');
    if (!s) return false;
    return INTEREST_PATTERNS.some((re) => re.test(s));
}

// A keyword distinctive enough that a SINGLE shared one is a confident match:
// an identifier (digit / underscore / camelCase), a path/URL token, or a
// hyphen-compound (cve-2026-…, kv-cache). Common domain words ("security",
// "running", "download") are NOT specific — they're long but collide constantly,
// and keywords are lowercased at extraction so a raw-length rule can't tell an
// identifier from an ordinary word. A plain word therefore needs a SECOND shared
// keyword to match (see factKeywordMatch).
function isSpecificKeyword(k) {
    if (!k) return false;
    if (/\d/.test(k)) return true;                        // versions, CVE ids, ports, dates
    if (/_/.test(k)) return true;                         // snake_case
    if (/[a-z][A-Z]/.test(k)) return true;                // camelCase (pre-lowercase safety)
    if (/[/.~]/.test(k)) return true;                     // path / url-ish
    if (k.includes('-') && k.length >= 6) return true;    // hyphen-compound
    return false;
}

// Decide whether an auto-extracted FACT is relevant enough to the query to
// inject. Replaces the old bare `jaccard >= 0.2` gate, which let a single
// common shared word ("today", "news", "security") trigger a false-positive —
// the root of memories corrupting accuracy. Rule: >=2 shared keywords (real
// topical overlap), OR exactly one shared keyword that is highly specific
// (an identifier). No jaccard floor — it rejected legitimate 2-keyword matches
// between a long fact and a short query (2/12 = 0.16 < 0.2).
function factKeywordMatch(factKeywords, queryKeywords) {
    const fk = factKeywords || [];
    if (!fk.length || !queryKeywords.length) return false;
    const qs = new Set(queryKeywords);
    let inter = 0, lastShared = null;
    for (const k of fk) if (qs.has(k)) { inter++; lastShared = k; }
    if (inter >= 2) return true;
    if (inter === 1 && isSpecificKeyword(lastShared)) return true;
    return false;
}

// Get text content from a chat message, handling both string and vision-array
// formats. Strips image_url parts since memories are text-only.
function messageText(msg) {
    if (!msg || !msg.content) return '';
    if (typeof msg.content === 'string') return msg.content;
    if (Array.isArray(msg.content)) {
        return msg.content.filter(p => p.type === 'text').map(p => p.text || '').join('\n');
    }
    return '';
}

// Account-scoped memory disable check (chat-app preference). Best-effort: a
// failed lookup defaults to ENABLED so memory never silently turns off on a
// transient read error. Honored at extraction, retrieval, and record_learning.
async function isMemoryDisabledForUser(userId) {
    try {
        if (!userId) return false;
        const user = await getUserById(userId);
        const prefs = user?.preferences;
        if (!prefs) return false;
        const scoped = (prefs.byApp && prefs.byApp.chat) ? prefs.byApp.chat : prefs;
        return scoped?.memoryDisabled === true;
    } catch { return false; }
}

// After a saveConversationMessages call, walk any user→assistant pairs newer
// than the per-conversation extraction cursor and extract ACCOUNT-scoped
// memories from each. Memories now belong to the user (not the conversation),
// so they're deduped account-wide and follow the user everywhere. The cursor
// (which assistant msg we last processed for THIS conversation) lives in the
// memory service so re-saves don't re-extract. Fire-and-forget; errors swallow.
async function extractNewMemoriesFromSave(userId, conversationId, messages) {
    if (!Array.isArray(messages) || messages.length < 2) return;
    if (await isMemoryDisabledForUser(userId)) return;
    // Import any legacy per-conversation memories first (idempotent) so we
    // don't re-extract turns that already produced memories before the move.
    try { await memoryService.migrateLegacyForUser(userId); } catch (_) { /* best-effort */ }

    const cursor = await memoryService.getCursor(userId, conversationId);
    let startIdx = 0;
    if (cursor) {
        const cursorIdx = messages.findIndex(m => m.id === cursor);
        if (cursorIdx >= 0) startIdx = cursorIdx + 1;
    }

    // Collect the new user→assistant pairs first, then extract per pair.
    let newestCursor = cursor;
    const pairs = [];
    for (let i = startIdx; i < messages.length; i++) {
        const msg = messages[i];
        if (msg.role !== 'assistant') continue;
        // Walk backwards to find the most recent user message before this one.
        let userMsg = null;
        for (let j = i - 1; j >= 0; j--) {
            if (messages[j].role === 'user') { userMsg = messages[j]; break; }
            if (messages[j].role === 'assistant') break; // not paired
        }
        if (msg.id) newestCursor = msg.id;
        if (!userMsg) continue;
        pairs.push({ userText: messageText(userMsg), assistantText: messageText(msg), msgId: msg.id || null });
    }

    const candidates = [];
    let usedLlm = false;
    for (const pair of pairs) {
        // LLM extraction first (free — rides the loaded local model), but only
        // on a normal-sized batch; a long legacy backlog goes straight to the
        // heuristics rather than queueing N completions. `null` = unavailable
        // → heuristic fallback. `[]` = the model judged nothing durable — a
        // VALID verdict we keep (falling back would re-add the filtered noise).
        let extracted = null;
        if (pairs.length <= 2) {
            extracted = await llmExtractMemoriesFromTurn(pair.userText, pair.assistantText);
            if (extracted) usedLlm = true;
        }
        if (extracted == null) {
            extracted = extractMemoriesFromTurn(pair.userText, pair.assistantText);
        }
        for (const mem of extracted) {
            // Drop passive consumption/curiosity statements ("user is interested
            // in X", "is a fan of Y") regardless of how either extractor typed
            // them — the user wants memory focused on durable facts, behavioral
            // preferences, and experiential learnings, not topic interests.
            if (isLowValueInterest(mem.text)) continue;
            // Bare request/command stored as a fact — covers BOTH the heuristic
            // and the LLM extractor uniformly (the LLM path occasionally emits a
            // raw user request as type:'fact'). Scoped to fact-typed only, so an
            // imperative-phrased directive is untouched.
            if (mem.type === 'fact' && looksLikeRequest(mem.text)) continue;
            candidates.push({
                text: mem.text,
                keywords: mem.keywords,
                tokens: mem.tokens,
                score: mem.score,
                type: mem.type,
                impact: mem.impact,
                sourceRole: mem.sourceRole,
                sourceTurnId: pair.msgId,
                sourceConvId: conversationId,
            });
        }
    }

    let added = 0, superseded = 0;
    let addedItems = [];
    if (candidates.length) {
        // Dedup + supersedence are account-wide and prune-to-cap happens
        // inside the service.
        const res = await memoryService.addAutoMemories(userId, candidates, { sourceConvId: conversationId });
        added = res.added;
        superseded = res.superseded || 0;
        addedItems = res.items || [];
    }
    if (newestCursor && newestCursor !== cursor) {
        await memoryService.setCursor(userId, conversationId, newestCursor);
    }
    // Background self-consolidation: once the store grows past the soft cap, merge
    // any near-duplicate clusters that have accumulated. Fire-and-forget, no LLM
    // (keep-strongest text), so it stays cheap. Only does work when over the cap.
    if (added > 0) {
        memoryService.consolidateUser(userId, { auto: true }).then((r) => {
            if (r && r.merged > 0) logUserActivity(userId, `Memory: consolidated ${r.merged} near-duplicate memories (${r.before} → ${r.after})`);
        }).catch(() => {});
    }
    if (added > 0 || superseded > 0) {
        const total = await memoryService.countForUser(userId).catch(() => -1);
        console.log(`[Memory] Extracted ${added} new + ${superseded} refreshed account memories from conversation ${conversationId} (${usedLlm ? 'llm' : 'heuristic'}; account total: ${total})`);
        // Surface it in the user's process log too (not just server console),
        // with a brief preview of what was learned this turn.
        const preview = addedItems.slice(0, 3)
            .map(it => `${it.superseded ? '↻ ' : ''}${it.type}/${it.impact || 'low'}: “${(it.text || '').slice(0, 60)}”`).join('; ');
        // Lead with "created new" vs "updated existing" so the user can tell at
        // a glance whether this turn added a fresh memory or enhanced one already
        // on file (supersedence refines an existing row in place).
        const verbParts = [];
        if (added > 0) verbParts.push(`created ${added} new`);
        if (superseded > 0) verbParts.push(`updated ${superseded} existing`);
        logUserActivity(userId,
            `Memory: ${verbParts.join(', ')} memor${(added + superseded) === 1 ? 'y' : 'ies'} from this turn${preview ? ` — ${preview}` : ''}`);
    }
}

// ============================================================================
// EXPERIENCE / PROCEDURE memories — the model's persona ("who you are")
// ============================================================================
// A turn is mapped to ONE high-level activity ("reading emails", "web
// research") from the tools it used + the files it handled + the user's ask.
// After the turn we record/refine an experience memory for that activity that
// captures the SUCCESSFUL tool path (the lean recipe — failed/exploratory calls
// are dropped). Injected back on the next similar task so the model front-loads
// the approach that worked and skips the fumbling → fewer tool calls, faster.

// Priority-ordered: the FIRST matching rule wins (most specific → most generic).
// test(toolSet, attachmentKinds, userTextLower) → boolean.
//
// Each rule matches on the tools the turn USED and/or the attachment kinds —
// AND, crucially, on TEXT cues from the user's ask. The text cues exist because
// the activity hint is computed PRE-turn (before any tool runs), so a tool-only
// rule (coding, data-viz, …) could never fire pre-turn and the matching
// experience memory would never lead. That's what made memory injection drop
// the relevant experience and look irrelevant: a coding question got no
// activity hint, so its coding experience was indistinguishable from the
// (irrelevant) email/web experiences. The text cues let the right experience
// be identified from the question alone.
const ACTIVITY_RULES = [
    { activity: 'reading-emails', label: 'Reading emails',
      test: (t, a, q) => a.has('email') || /\bemails?\b|\.eml\b|\.msg\b|\binbox\b|\bsender\b/.test(q) },
    { activity: 'spreadsheet-analysis', label: 'Spreadsheet & data analysis',
      test: (t, a, q) => a.has('spreadsheet') || t.has('read_xlsx') || t.has('create_xlsx') || t.has('query_sqlite')
          || /\b(spreadsheet|excel|csv|tsv|xlsx?|pivot table|google sheets?)\b/.test(q) },
    { activity: 'binary-ctf-analysis', label: 'Binary / CTF analysis',
      test: (t, a, q) => t.has('hex_dump') || t.has('extract_strings') || t.has('xor_bytes') || t.has('hex_convert')
          || /\b(ctf|reverse[- ]?engineer\w*|disassembl\w+|shellcode|hex dump|\bxor\b|crackme|buffer overflow|capture the flag)\b/.test(q) },
    { activity: 'audio-transcription', label: 'Audio transcription',
      test: (t, a, q) => a.has('audio') || t.has('transcribe_audio') || /\b(transcribe|transcription|audio file|voice memo)\b/.test(q) },
    { activity: 'image-analysis', label: 'Image analysis',
      test: (t, a, q) => a.has('image') || t.has('transform_image') || /\b(this image|the image|screenshot|photo|picture|resize|crop|rotate)\b/.test(q) },
    { activity: 'code-analysis', label: 'Reading & analyzing code',
      test: (t, a, q) => a.has('archive') || a.has('code') || t.has('extract_archive') || t.has('tar_extract')
          || t.has('grep_code') || t.has('outline_file') || t.has('read_file') || t.has('list_directory') || t.has('search_files')
          || /\b(analy[sz]e|review|explain|understand|trace|debug|audit|walk through)\b[^.]{0,40}\b(code|codebase|repo(sitory)?|stack ?trace|traceback|this (file|function|script|error|bug))\b/.test(q) },
    { activity: 'document-analysis', label: 'Reading documents',
      test: (t, a, q) => a.has('pdf') || a.has('document') || t.has('read_pdf') || /\bpdf\b|\bdocx?\b/.test(q) },
    { activity: 'web-research', label: 'Web research',
      test: (t, a, q) => t.has('web') || t.has('web_search') || t.has('fetch_url') || t.has('crawl_pages') || t.has('scrapling_fetch') || t.has('playwright_fetch') || t.has('playwright_interact')
          || /\b(search the web|look ?up online|latest|current|news|who is|what is the (price|stock)|google)\b/.test(q) },
    { activity: 'knowledge-base-lookup', label: 'Knowledge base lookup',
      test: (t, a, q) => t.has('search_knowledge_base') || /\b(knowledge ?base|my (docs|documents|files|notes|library|pdfs?|books?)|in my (kb|knowledge))\b/.test(q) },
    { activity: 'data-visualization', label: 'Data visualization',
      test: (t, a, q) => t.has('render_chart') || t.has('fetch_timeseries')
          || /\b(chart|graph|plot|visuali[sz]e|bar chart|line chart|pie chart|dashboard|histogram|scatter ?plot)\b/.test(q) },
    { activity: 'coding', label: 'Writing & running code',
      test: (t, a, q) => t.has('run_python') || t.has('run_node') || t.has('replace_lines') || t.has('create_file')
          // Technical nouns only — 'app'/'website' were dropped because they
          // false-matched non-coding asks like "write a story about a website".
          || /\b(write|implement|create|generate|build|fix|refactor|optimi[sz]e|debug)\b[^.]{0,40}\b(function|code|script|class|method|program|algorithm|api|endpoint|component|query|regex|for ?loop)\b/.test(q)
          || /\b(python|javascript|typescript|c\+\+|golang|\brust\b|\bsql\b|bash script|react|node\.?js)\b/.test(q) },
];

function deriveAttachmentKinds(attachments) {
    const kinds = new Set();
    for (const a of (Array.isArray(attachments) ? attachments : [])) {
        const name = String(a?.filename || a?.name || '').toLowerCase();
        const mime = String(a?.mimeType || a?.type || '').toLowerCase();
        if (/\.(eml|msg)$/.test(name) || mime.includes('message/')) kinds.add('email');
        else if (/\.(xlsx|xls|csv|tsv)$/.test(name) || mime.includes('spreadsheet') || mime.includes('csv')) kinds.add('spreadsheet');
        else if (/\.pdf$/.test(name) || mime.includes('pdf')) kinds.add('pdf');
        else if (/\.(docx?|odt|rtf)$/.test(name) || mime.includes('word') || mime.includes('officedocument.wordprocessing')) kinds.add('document');
        else if (/\.(png|jpe?g|gif|bmp|tiff?|webp)$/.test(name) || mime.startsWith('image/')) kinds.add('image');
        else if (/\.(mp3|wav|m4a|flac|ogg|aac|mp4|mov|webm)$/.test(name) || mime.startsWith('audio/') || mime.startsWith('video/')) kinds.add('audio');
        else if (/\.(zip|7z|rar|tar|tgz|gz|bz2|xz)$/.test(name)) kinds.add('archive');
        else if (/\.(jsx?|tsx?|py|go|rs|java|c|cpp|h|hpp|rb|php|sh|json|ya?ml|toml)$/.test(name)) kinds.add('code');
    }
    return kinds;
}

function classifyTurnActivity({ toolLabels = [], userText = '', attachmentKinds = new Set() }) {
    const t = new Set(toolLabels);
    const q = String(userText || '').toLowerCase();
    for (const rule of ACTIVITY_RULES) {
        try { if (rule.test(t, attachmentKinds, q)) return { activity: rule.activity, label: rule.label }; }
        catch (_) { /* a bad rule must not break the turn */ }
    }
    return null;
}

// Fire-and-forget after a turn: record/refine the experience memory for the
// turn's activity from the SUCCESSFUL tool path. Failed/exploratory calls are
// excluded, so even a fumbling cold run produces a CLEAN recipe the warm run
// follows directly. Atomic + activity-keyed in the service.
async function recordTurnActivity({ userId, conversationId, toolChips, userText, attachments, steps }) {
    try {
        if (!userId || userId === 'default') return;
        if (await isMemoryDisabledForUser(userId)) return;
        const chips = Array.isArray(toolChips) ? toolChips : [];
        const okChips = chips.filter(c => c && c.status === 'success' && c.label);
        const attachmentKinds = deriveAttachmentKinds(attachments);
        const toolLabels = okChips.map(c => c.label);
        const act = classifyTurnActivity({ toolLabels, userText, attachmentKinds });
        if (!act) return;
        // Only record when the turn actually DID something procedural.
        if (!okChips.length && !attachmentKinds.size) return;

        // Lean successful path: unique tool labels in first-seen order. We do
        // NOT enshrine repeat counts as "the approach" — a tool called many
        // times is usually inefficient flailing (e.g. list_directory loops),
        // which is exactly what the next run should AVOID. A heavily-repeated
        // tool is flagged as a smell so the warm run goes direct instead.
        const seq = [];
        const counts = {};
        for (const l of toolLabels) { counts[l] = (counts[l] || 0) + 1; if (!seq.includes(l)) seq.push(l); }
        const pathStr = seq.join(' → ');
        // A tool repeated several times in one turn is usually avoidable
        // repetition (per-subtopic KB searches, list_directory loops, narrow
        // re-reads). Record an ACTIONABLE consolidation directive — name the
        // over-called tool, its count, and the fix (do it in as few calls as
        // possible, ideally one broad/comprehensive call). The old note ("avoid
        // over-calling X — go straight to the file you need") wasn't actionable
        // and read oddly for search tools, so the warm run didn't actually use
        // fewer calls; this phrasing measurably reduces repeat calls. Threshold
        // 3 (was 4) to catch moderate repetition too.
        const flail = seq.filter(l => counts[l] >= 3);
        const flailNote = flail.length
            ? ` EFFICIENCY: last time ${flail.map(l => `${l} was called ${counts[l]}×`).join('; ')} — that repetition was avoidable. Do this in as FEW ${flail.length === 1 ? 'calls' : 'calls per tool'} as possible: prefer ONE broad/comprehensive call that covers everything you need over many narrow repeats, then only make an extra call if something specific is genuinely missing.`
            : '';
        const fileNote = attachmentKinds.size ? ` Input: ${[...attachmentKinds].join('/')}.` : '';
        const text = pathStr
            ? `${act.label}: the tools that got it done — ${pathStr}.${fileNote}${flailNote} Reuse this path and go direct; only deviate if a step fails.`
            : `${act.label}:${fileNote} answered directly from the message content without extra tool calls.`;
        const keywords = extractQueryKeywords(
            `${act.label} ${act.activity.replace(/-/g, ' ')} ${seq.join(' ')} ${[...attachmentKinds].join(' ')}`);

        const res = await memoryService.upsertActivityMemory(userId, {
            activity: act.activity, text, keywords,
            impact: 'medium', source: 'auto', sourceConvId: conversationId,
            // efficiency of this run — keeps the leanest recipe. Callers may pass
            // steps:null (e.g. /v1 in-progress recording) to reinforce + refresh
            // the recipe without the bestSteps comparison.
            steps: (steps === undefined ? okChips.length : steps),
        });
        logUserActivity(userId,
            `Memory: ${res.updated ? `updated existing experience (${res.keptRecipe ? 'reinforced' : 'refined'})` : 'created new experience'} [${act.activity}] (×${res.count}, ${res.impact}, ${okChips.length} steps) — ${pathStr || 'inline'}`);
    } catch (e) {
        console.warn('[Memory] activity record failed:', e.message);
    }
}

// Pre-turn retrieval: score the user's ENTIRE account memory against the
// incoming query and pack the top matches into a token budget. Memory is now
// account-scoped, so this surfaces relevant facts/learnings from ANY past
// conversation ("I worked on a similar thing before — here's what works"),
// while a recency boost and a same-conversation boost keep the current thread's
// context on top. Model-recorded learnings are floored so the evolving persona
// persists even when keyword overlap is weak. Returns an injectable block or
// null. `currentConvId` is optional (used only for the continuity boost).
async function retrieveRelevantMemories(userId, currentConvId, query, tokenBudget = MEMORY_RETRIEVAL_TOKEN_BUDGET, { activityHint = null } = {}) {
    if (!query || typeof query !== 'string') return null;
    // Defense-in-depth: callers should pass clean user text, but strip any
    // thinking-control prefix that slipped through (see the chat stream's
    // latestUserText handling) so it never reaches the embedding or keywords.
    query = query.replace(/^\/(no_)?think\b\s*/i, '');
    if (!query.trim()) return null;
    let all;
    try { all = await memoryService.listMemories(userId); } catch { return null; }
    if (!all || !all.length) return null;
    // Muted memories are kept in the store but never injected (user flag).
    const storedCount = all.length;
    all = all.filter(m => !m.muted);
    if (!all.length) return null;

    const queryKeywords = extractQueryKeywords(query);

    // ---- Semantic relevance (PRIMARY signal) ----------------------------
    // Embedding cosine from the memory index. Catches paraphrase that keyword
    // overlap can't ("can you graph this" ↔ a render_chart memory). When the
    // engine is down `semScores` stays null and everything below degrades to
    // the keyword gates — memory never silently stops working.
    let semScores = null;
    try {
        const sem = await semanticMemoryScores(userId, query, 32);
        if (sem) {
            semScores = sem.scores;
            // Self-heal: an EMPTY index while memories exist (store migrated
            // before the engine was warm, wiped dir, …) → rebuild in the
            // background; this turn falls back to keywords.
            if (sem.total === 0 && storedCount > 0) {
                memoryService.reindexUser(userId).catch(() => {});
                semScores = null;
            } else if (sem.total > 0) {
                // Engine confirmed HEALTHY (real vectors back): if this account
                // extracted memories while it was down, merge the duplicates that
                // accreted keyword-only. Fire-and-forget, no-ops unless flagged.
                memoryService.reconcileIfPending(userId);
            }
        }
    } catch (_) { semScores = null; }
    // Cosine for a memory, or null when semantic mode is unavailable. A memory
    // outside the top-k scores 0 (sem mode still active → keyword gate still
    // backstops it in isRelevant).
    const semOf = (m) => (semScores ? (semScores.get(m.id) ?? 0) : null);
    const now = Date.now();
    // DIRECTIVES are curated, persona-shaping memories — anything you authored
    // (manual), the model recorded (model learnings), or that's flagged
    // important, or carries a non-'fact' type (preference/correction/…). These
    // shape behavior and must inject regardless of keyword overlap. FACTS are
    // plain auto-extracted statements; they're numerous and noisy, so they only
    // inject on a strong keyword match. Without this split, at scale a flood of
    // auto-facts sharing common words crowds out the handful of memories that
    // actually matter.
    // PROCEDURES are EXPERIENCE memories (how the model did an activity + the
    // approach that worked) — the persona. DIRECTIVES are user-authored/model
    // learnings/preferences. FACTS are noisy auto-extractions (keyword-gated).
    const isProcedure = (m) => m.type === 'procedure';
    // CURATED = the user (manual) or the model (record_learning) deliberately
    // saved it. Curated memories are the persona's backbone and inject
    // regardless of keyword overlap. AUTO-extracted memories are heuristic
    // guesses, so they must EARN injection by being topically relevant (see the
    // candidate filters below). Without this, an unrelated auto "preference" or
    // "limitation" — a one-off task request, or a stray sentence misclassified
    // as a limitation — injected on EVERY turn. That's the "coding question, but
    // it surfaces a memory about buses" failure the relevance gate fixes.
    const isCurated = (m) => m.source === 'manual' || m.source === 'model';
    const isDirective = (m) => !isProcedure(m) && (isCurated(m)
        || m.impact === 'important' || (m.type && m.type !== 'fact'));

    // Relevance for RANKING: best of semantic cosine and keyword Jaccard.
    const relOf = (m) => {
        const j = jaccardSimilarity(m.keywords || [], queryKeywords);
        const s = semOf(m);
        return s != null ? Math.max(s, j) : j;
    };
    // Topical-relevance GATE for AUTO memories: semantic cosine ≥ threshold,
    // OR the keyword rule (≥2 shared keywords / one specific identifier) as a
    // hybrid backstop — embeddings can miss exact identifiers (a CVE id, a
    // port number) that keywords nail. Curated memories bypass it.
    const isRelevant = (m) => {
        const s = semOf(m);
        if (s != null && s >= MEMORY_SEM_THRESHOLD) return true;
        return factKeywordMatch(m.keywords || [], queryKeywords);
    };
    // A GLOBAL behavioral directive — a durable, cross-topic rule about HOW to
    // respond ("from now on, be concise", "always use type hints"). These apply
    // to every turn, so an AUTO-extracted one still injects unconditionally even
    // though other auto memories are relevance-gated. Excludes one-off TASK
    // requests that merely start with "I like/prefer" ("I like Sonify, can you
    // check …") — those name a thing to act on now, not a standing rule, and are
    // what the relevance gate is meant to suppress.
    const isGlobalBehavioralDirective = (m) => {
        if (m.type !== 'preference' && m.type !== 'correction') return false;
        const t = String(m.text || '').toLowerCase();
        if (/\?|\bcan you\b|\bcould you\b|\bplease (check|find|make sure|look|verify|confirm|see)\b/.test(t)) return false;
        // Require an explicit STANDING-RULE marker, NOT a bare "I prefer X" /
        // "I like X" — those are usually topical or one-off ("I prefer Python",
        // "I like Sonify") and would otherwise inject on every unrelated turn.
        // A genuine global style pref that lacks such a marker still surfaces
        // once the model records it (record_learning → curated) or the user adds
        // it by hand (manual → curated); both bypass relevance unconditionally.
        // The strong markers are unambiguously about a standing user rule.
        if (/\b(from now on|going forward|always|never|whenever|every time)\b/.test(t)) return true;
        // "by default" is the ambiguous one: it far more often describes a
        // THIRD-PARTY software default ("the server runs on port 3000 by
        // default", "it installs by default") than a user standing rule. Treat
        // it as a global directive ONLY when the sentence is explicitly about how
        // the USER wants things done (a 1st/2nd-person directive cue) AND is NOT
        // a 3rd-person description of how some tool behaves. Without this, an
        // auto/assistant-side software-trivia line injected on 100% of turns —
        // the measured "by default" precision leak (id 096fa323).
        if (/\bby default\b/.test(t)) {
            return /\b(i|i'd|i'm|we|you|your|use|prefer|default to|stick to|give me|send me|reply|respond|answer|format|output)\b/.test(t)
                && !/\b(runs?|installs?|listens?|serves?|exposes?|binds?|starts?|comes?|ships?|defaults? to port|on port)\b/.test(t);
        }
        return false;
    };
    const scoreOf = (m) => {
        const ts = Date.parse(m.updatedAt || m.createdAt || '') || now;
        const ageDays = Math.max(0, (now - ts) / 86400000);
        const recencyBoost = 0.15 * (1 - Math.min(ageDays, 90) / 90);        // up to +0.15 when fresh
        const convBoost = (currentConvId && m.sourceConvId === currentConvId) ? 0.2 : 0;
        const impactBoost = m.impact === 'important' ? 0.5 : (m.impact === 'low' ? -0.05 : 0);
        return relOf(m) + recencyBoost + convBoost + impactBoost;
    };
    // Procedure score: keyword relevance + a strong boost when the procedure's
    // activity matches THIS turn's likely activity (so the right experience
    // leads), + experience depth (count) so well-practiced skills surface.
    const procScoreOf = (m) => {
        const activityMatch = (activityHint && m.activity === activityHint) ? 1.5 : 0;
        const depthBoost = Math.min(0.4, 0.1 * ((m.count || 1) - 1));
        // scoreOf already includes relOf(m) once — adding relOf again here
        // double-counted relevance, letting a coincidentally keyword-heavy
        // WRONG-activity procedure outrank the activity-matched one. Count
        // relevance once (via scoreOf) so activityMatch (1.5) strictly dominates
        // it (max 1.0), restoring "the activity match leads".
        return activityMatch + depthBoost + scoreOf(m);
    };

    const PROC_MAX = 8, DIRECTIVE_MAX = 18, FACT_MAX = 8;
    const procBudget = Math.floor(tokenBudget * 0.4);
    const directiveBudget = Math.floor(tokenBudget * 0.85);
    const tokOf = (m) => m.tokens || Math.ceil((m.text || '').length / 3);

    // Procedures (experience) inject when they're the RIGHT experience for THIS
    // turn: the predicted activity matches OR there's genuine keyword overlap.
    // Procedures are inherently ACTIVITY-specific (a coding recipe, an email
    // recipe), so they are ALWAYS activity/topic-gated — even a model-curated
    // one — so a procedure for an unrelated activity (the "reading-emails"
    // experience during a coding task) never leads. That irrelevant-persona
    // leakage was the worst offender of the "buses" problem.
    const procCands = all.filter(isProcedure)
        .filter(m => (activityHint && m.activity === activityHint) || isRelevant(m))
        .map(m => ({ m, s: procScoreOf(m) })).sort((a, b) => b.s - a.s);
    // Directives: only GLOBAL ones apply across topics — a pinned memory or a
    // genuine standing rule ("from now on, be concise", "I use tabs"). A directive
    // that is merely curated/important/non-fact but TOPICAL (a coding tip, a tool
    // preference) must be topically relevant AND non-ephemeral, exactly like
    // facts — otherwise it surfaces everywhere (the "coding tip on a cyber-news
    // query" leak). This holds for manual AND model-recorded directives: being
    // user- or model-authored no longer buys an unconditional inject; only being
    // global (marker/pinned) does.
    const directives = all.filter(isDirective)
        .filter(m => m.pinned || isGlobalBehavioralDirective(m) || (!isEphemeralFact(m.text) && isRelevant(m)))
        .map(m => ({ m, s: scoreOf(m) })).sort((a, b) => b.s - a.s);
    // Facts inject only on a substantive query match (semantic cosine ≥
    // threshold, or the keyword rule) AND only if not ephemeral — the
    // ephemeral skip is defense-in-depth for any time-bound fact stored
    // before extraction-time filtering existed. Ordered by relevance so the
    // strongest matches fill the remaining budget first.
    const factCands = all
        .filter(m => !isDirective(m) && !isProcedure(m))
        // Retrieval defense for already-stored rows: a passive interest or a
        // request-shaped fact never injects even if it clears the relevance gate
        // (extraction-time filters only stop NEW writes; these clean the legacy
        // store). Directives/procedures are excluded above, so an imperative-
        // phrased preference is unaffected.
        .filter(m => !isEphemeralFact(m.text) && !isLowValueInterest(m.text) && !looksLikeRequest(m.text) && isRelevant(m))
        .map(m => ({ m, r: relOf(m) })).sort((a, b) => b.r - a.r);

    const picked = [];
    let usedTokens = 0;
    let linkExpanded = 0;
    // Pass 0 — experience/procedures: the persona always applies, capped by a
    // 40% sub-budget. The activity-matched one (if any) leads.
    let procCount = 0;
    for (const p of procCands) {
        if (procCount >= PROC_MAX) break;
        const tk = tokOf(p.m);
        if (usedTokens + tk > procBudget && picked.length) continue;
        if (usedTokens + tk > tokenBudget) continue;
        picked.push(p.m); usedTokens += tk; procCount++;
    }
    // Pass 1 — directives: persona always applies.
    for (const d of directives) {
        if (picked.filter(isDirective).length >= DIRECTIVE_MAX) break;
        const tk = tokOf(d.m);
        if (usedTokens + tk > directiveBudget && picked.length) continue;
        if (usedTokens + tk > tokenBudget) continue;
        picked.push(d.m); usedTokens += tk;
    }
    // Pass 2 — facts: already filtered to substantive, non-ephemeral matches;
    // fill the remainder by overlap strength.
    let factCount = 0;
    for (const f of factCands) {
        if (factCount >= FACT_MAX) break;
        const tk = tokOf(f.m);
        if (usedTokens + tk > tokenBudget) continue;
        picked.push(f.m); usedTokens += tk; factCount++;
    }
    if (picked.length === 0) return null;

    // ---- Link-aware expansion (1-hop) -----------------------------------
    // A memory the user (Memory tab) or the model (record_learning relatesTo /
    // auto-link on extraction) CONNECTED to one that's already relevant rides
    // along — even if it wouldn't clear the relevance gate by itself. That's the
    // point of a link: "when this surfaces, surface what it's tied to." Bounded
    // by LINK_EXPANSION_MAX + the token budget, 1-hop only (we snapshot `picked`
    // so an expansion never seeds further expansion), and muted/dangling/
    // ephemeral targets are skipped. `all` is the non-muted set, so byId can't
    // resurface a muted memory.
    if (LINK_EXPANSION_MAX > 0) {
        const pickedIds = new Set(picked.map(m => m.id));
        const byId = new Map(all.map(m => [m.id, m]));
        for (const seed of [...picked]) {
            if (linkExpanded >= LINK_EXPANSION_MAX) break;
            const links = Array.isArray(seed.links) ? seed.links : [];
            for (const lid of links) {
                if (linkExpanded >= LINK_EXPANSION_MAX) break;
                if (pickedIds.has(lid)) continue;
                const lm = byId.get(lid);
                if (!lm) continue;                              // dangling / muted
                if (isEphemeralFact(lm.text)) continue;         // never resurface time-bound content
                if (isLowValueInterest(lm.text)) continue;      // never resurface a passive interest via a link
                // A linked memory rides along only if it's genuinely on-topic for
                // THIS turn: it clears the normal relevance gate, OR is a semantic
                // near-miss in the top-k (relaxed floor), OR always-surfaces anyway
                // (pinned / global directive / procedure). Without this, link
                // expansion injected arbitrary similarity-graph neighbors that never
                // matched the query — the leak this gate closes. Keyword-only mode
                // (semScores null) → semOf null → the relaxed-floor clause is inert
                // and gating falls to isRelevant's keyword arm, so memory never
                // silently breaks.
                const alwaysSurface = lm.pinned || isProcedure(lm) || isGlobalBehavioralDirective(lm);
                const linkRelevant = isRelevant(lm) || ((semOf(lm) ?? 0) >= MEMORY_SEM_THRESHOLD * 0.7);
                if (!alwaysSurface && !linkRelevant) continue;
                const tk = tokOf(lm);
                if (usedTokens + tk > tokenBudget) continue;
                picked.push(lm); pickedIds.add(lid); usedTokens += tk; linkExpanded++;
            }
        }
    }

    // Render: experience (persona) FIRST, then directives, then facts.
    const impactRank = { important: 0, medium: 1, low: 2 };
    const procedures = picked.filter(isProcedure)
        .sort((a, b) => (b.count || 1) - (a.count || 1));
    const learnings = picked.filter(isDirective)
        .sort((a, b) => (impactRank[a.impact] ?? 1) - (impactRank[b.impact] ?? 1));
    const facts = picked.filter(m => !isDirective(m) && !isProcedure(m))
        .sort((a, b) => (a.createdAt || '').localeCompare(b.createdAt || ''));

    const handleOf = (m) => `#${String(m.id).replace(/-/g, '').slice(0, 6)}`;
    const parts = [];
    if (procedures.length) {
        // Persona lead-in: the model's accumulated experience. Each line is an
        // activity + the approach that worked; reuse it to skip re-exploration.
        const lines = procedures.map(m =>
            `- [${handleOf(m)}] (${m.activity}, done ${m.count || 1}×) ${m.text}`).join('\n');
        parts.push(
            'WHO YOU ARE — YOUR EXPERIENCE (skills built from past work for this user). ' +
            'When the current task matches one of these activities, REUSE the approach that worked — go straight to it instead of re-exploring, and only deviate if a step fails. ' +
            'As you find a better way, refine the matching one via record_learning with replaces:"<#handle>". Handles are internal — never show them:\n' +
            lines
        );
    }
    if (learnings.length) {
        // Each line carries a short [#handle] (first 6 hex of the id) so the
        // model can REFINE a specific learning via record_learning(replaces).
        // This is what turns memory from append-only into continual learning:
        // as it discovers what works best, it updates the lesson in place
        // instead of stacking near-duplicates.
        const lines = learnings.map(m => `- [#${String(m.id).replace(/-/g, '').slice(0, 6)}] ${m.text}`).join('\n');
        // Framed as binding instructions — weak "things you've learned" phrasing
        // was injected but ignored by smaller models. This wording makes the
        // model treat preferences/corrections as rules without overriding an
        // explicit in-turn user request.
        parts.push(
            'PERSISTENT USER INSTRUCTIONS & PREFERENCES (learned from past conversations). ' +
            'Follow EVERY one of these in your response unless the user overrides it in their latest message. ' +
            'As you learn what works best, REFINE these rather than repeating them: call record_learning with replaces:"<#handle>" to update one in place. ' +
            'The [#handles] are internal — never show them to the user:\n' +
            lines
        );
    }
    if (facts.length) {
        const lines = facts.map(m => `- ${m.text}`).join('\n');
        parts.push(`WHAT YOU KNOW ABOUT THIS USER (from past conversations) — use it to avoid asking again and to work faster:\n${lines}`);
    }
    console.log(`[Memory] Injecting ${picked.length} account memories (${usedTokens} tokens; ${procedures.length} experience, ${learnings.length} learnings, ${facts.length} facts${linkExpanded ? `, +${linkExpanded} via links` : ''}; ${semScores ? 'semantic' : 'keyword'} mode) conv=${currentConvId || '-'}`);
    return {
        block: parts.join('\n\n'),
        count: picked.length,
        procedures: procedures.length,
        learnings: learnings.length,
        facts: facts.length,
        linked: linkExpanded,
        tokens: usedTokens,
        previews: picked.slice(0, 5).map(m => (m.text || '').slice(0, 120)),
    };
}

// ============================================================================
// Pi (/v1 passthrough) memory bridge
// ============================================================================
// The /v1/chat/completions passthrough is otherwise transparent. Pi is the
// webapp's OWN agent (authenticated with a bearerOnly key), so we give it the
// SAME persona/experience the web chat gets — that's what lets Pi reuse what
// worked and stop flailing (the climbing 119k-token loop). Memory is keyed on
// `req.userId` (the owning ACCOUNT), which equals the web-session memory id, so
// web + Pi share ONE persona. Gated to bearer callers + memory-enabled + only
// when there's context headroom — raw OpenAI-SDK clients (key+secret) keep the
// fully-transparent contract, and a near-full Pi context is never pushed over
// (which would trip the backend's max_tokens floor → truncated tool calls).

const PI_MEMORY_BUDGET = 800;        // fallback budget — Pi runs near the limit, so smaller than chat
const PI_MEMORY_RESERVE = 2048;      // headroom for the response
const v1RecordInFlight = new Set();  // (userId:convKey) currently being recorded — anti-double-record guard

function v1LatestUserText(messages) {
    for (let i = messages.length - 1; i >= 0; i--) {
        if (messages[i]?.role === 'user') {
            const c = messages[i].content;
            if (typeof c === 'string') return c;
            if (Array.isArray(c)) return c.filter(p => p?.type === 'text').map(p => p.text || '').join('\n');
            return '';
        }
    }
    return '';
}

// Inject the persona/experience block into req.body.messages (mutates in place;
// both passthrough branches read req.body). Returns a short summary or null.
async function injectPersonaForV1(req, instance) {
    // Account id when the key is associated with one (real Pi keys created in a
    // web session are) — unifies with web-chat memory. Falls back to the key id
    // for unassociated keys so memory still works (per-key persona).
    const userId = req.userId || req.apiKeyData?.id;
    const messages = req.body?.messages;
    if (!userId || userId === 'default' || !Array.isArray(messages) || !messages.length) return null;
    if (await isMemoryDisabledForUser(userId)) return null;
    const latestUserText = v1LatestUserText(messages);
    if (!latestUserText) return null;

    // Activity hint = the most recent tool the model has been using this session
    // + the ask. Front-loads the matching experience.
    const toolLabels = [];
    for (const m of messages) {
        if (m?.role === 'assistant' && Array.isArray(m.tool_calls)) {
            for (const tc of m.tool_calls) { const n = tc?.function?.name; if (n) toolLabels.push(n); }
        }
    }
    const activityHint = (classifyTurnActivity({ toolLabels, userText: latestUserText, attachmentKinds: new Set() }) || {}).activity || null;

    // Room-check: never push an already-large Pi context past the model window.
    const ctx = instance?.config?.contextSize || instance?.config?.maxModelLen || 131072;
    // Pi budget scales with the window too, but capped leaner than chat (Pi
    // contexts run hot): clamped 300-1600, falling back to the old fixed 800.
    const piBudget = memoryBudgetForCtx(ctx, { base: PI_MEMORY_BUDGET, min: 300, max: 1600 });
    let inputEst = 0;
    try { inputEst = estimateTokenCount(JSON.stringify(messages)); } catch (_) { inputEst = 0; }
    if (inputEst + piBudget + PI_MEMORY_RESERVE > ctx) return null; // no headroom → skip silently

    const mem = await retrieveRelevantMemories(userId, null, latestUserText, piBudget, { activityHint });
    if (!mem || !mem.block) return null;

    const sys = messages[0];
    if (sys && sys.role === 'system' && typeof sys.content === 'string') {
        messages[0] = { ...sys, content: `${sys.content}\n\n${mem.block}` };
    } else if (sys && sys.role === 'system' && Array.isArray(sys.content)) {
        // Vision-format system message — append a text part rather than a 2nd system msg.
        messages[0] = { ...sys, content: [...sys.content, { type: 'text', text: '\n\n' + mem.block }] };
    } else {
        messages.unshift({ role: 'system', content: mem.block });
    }
    return { count: mem.count, procedures: mem.procedures || 0, learnings: mem.learnings || 0, facts: mem.facts || 0, tokens: mem.tokens, activityHint };
}

// Build the model's persona FROM Pi usage too. /v1 is stateless — Pi resends
// the whole history each turn — and a single agentic task spans many requests
// (tool rounds) without a new user message, so we record the CURRENT in-progress
// task (tools after the latest user message) and re-reinforce it as it accrues
// tools, throttled by a per-key "taskId:toolCount" cursor. Reuses
// recordTurnActivity (synthesized success chips from the tool_calls). Imperfect
// success-mapping is fine: best-recipe protection keeps the leanest version and
// the model can refine via record_learning.
async function recordV1TurnActivity(userId, apiKeyData, messages) {
    if (!userId || userId === 'default' || !Array.isArray(messages)) return;
    const convKey = 'pi-' + (apiKeyData?.id || 'key');
    const lockKey = `${userId}:${convKey}`;
    // In-flight guard: the cursor read→write isn't atomic, so a concurrent
    // retry of the same session could double-record (inflating the experience
    // count). Skip if a record for this (user,session) is already running.
    if (v1RecordInFlight.has(lockKey)) return;
    v1RecordInFlight.add(lockKey);
    try {
        if (await isMemoryDisabledForUser(userId)) return;
        const userIdxs = [];
        messages.forEach((m, i) => { if (m?.role === 'user') userIdxs.push(i); });
        if (!userIdxs.length) return;                    // no task has started yet
        // Record the CURRENT (in-progress) task — everything after the latest
        // user message. /v1 is stateless and a single agentic task spans MANY
        // requests (tool rounds) WITHOUT a new user message, so recording only on
        // task *completion* (the next user message) never fires for a long task —
        // the persona would never grow while the agent works. Instead we capture
        // the in-progress task and re-reinforce it as it accrues tools.
        const taskStart = userIdxs[userIdxs.length - 1];
        const toolLabels = [];
        for (let i = taskStart + 1; i < messages.length; i++) {
            const m = messages[i];
            if (m?.role === 'assistant' && Array.isArray(m.tool_calls)) {
                for (const tc of m.tool_calls) { const n = tc?.function?.name; if (n) toolLabels.push(n); }
            }
        }
        if (!toolLabels.length) return;                  // task hasn't used tools yet
        const taskId = userIdxs.length;                  // bumps with each new user message (≈ each task)
        const toolCount = toolLabels.length;
        // Cursor = "taskId:toolCountAtLastRecord". Record when it's a NEW task, or
        // the current task's tool usage grew enough to re-reinforce — a geometric
        // throttle so a 100-tool-round task records ~7×, not 100× (visible growth
        // without runaway count inflation).
        const cursor = await memoryService.getCursor(userId, convKey);
        let lastTask = 0, lastTools = 0;
        if (cursor) { const p = String(cursor).split(':'); lastTask = parseInt(p[0], 10) || 0; lastTools = parseInt(p[1], 10) || 0; }
        const isNewTask = taskId !== lastTask;
        const grewEnough = toolCount >= lastTools + 4 && toolCount >= Math.ceil(lastTools * 1.5);
        if (!isNewTask && !grewEnough) return;
        const uc = messages[taskStart]?.content;
        const userText = typeof uc === 'string' ? uc
            : (Array.isArray(uc) ? uc.filter(p => p?.type === 'text').map(p => p.text || '').join('\n') : '');
        // Pi resolves tools client-side; we only see results, so treat them as
        // successful. steps:null → reinforce + refresh the recipe to the current
        // (fuller) task path WITHOUT the bestSteps comparison (an in-progress
        // snapshot must not masquerade as a leaner "best" recipe and clobber one).
        const okChips = toolLabels.map(l => ({ status: 'success', label: l }));
        await recordTurnActivity({ userId, conversationId: convKey, toolChips: okChips, userText, attachments: [], steps: null });
        await memoryService.setCursor(userId, convKey, `${taskId}:${toolCount}`);
    } catch (e) {
        console.warn('[Pi/Memory] activity record failed:', e.message);
    } finally {
        v1RecordInFlight.delete(lockKey);
    }
}

// List all conversations for a user
app.get('/api/conversations', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const conversations = await loadConversationsIndex(userId);

        // Backfill messageCount / memoryCount for conversations missing
        // them. Run per-conversation backfills in parallel — each one was
        // a separate disk read previously serialised by `await` in a for
        // loop, blocking the sidebar render for users with many threads.
        let needsSave = false;
        await Promise.all(conversations.map(async (conv) => {
            if (conv.messageCount === undefined) {
                try {
                    const msgs = await loadConversationMessages(userId, conv.id);
                    conv.messageCount = msgs.length;
                    needsSave = true;
                } catch {
                    conv.messageCount = 0;
                }
            }
            // memoryCount is retired (account-scoped memory) — no backfill.
        }));
        if (needsSave) {
            await saveConversationsIndex(userId, conversations).catch(() => {});
        }

        res.json(conversations);
    } catch (error) {
        console.error('Error loading conversations:', error);
        res.status(500).json({ error: 'Failed to load conversations' });
    }
});

// Create a new conversation
app.post('/api/conversations', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const { title } = req.body;

        const conversation = {
            id: crypto.randomUUID(),
            title: title || 'New Conversation',
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString()
        };

        const conversations = await loadConversationsIndex(userId);
        conversations.unshift(conversation);
        await saveConversationsIndex(userId, conversations);

        // Create empty messages file
        await saveConversationMessages(userId, conversation.id, []);

        res.json(conversation);
    } catch (error) {
        console.error('Error creating conversation:', error);
        res.status(500).json({ error: 'Failed to create conversation' });
    }
});

// Get a specific conversation with messages
app.get('/api/conversations/:id', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const { id } = req.params;

        const conversations = await loadConversationsIndex(userId);
        const conversation = conversations.find(c => c.id === id);

        if (!conversation) {
            // Not in the index — but the message file may still exist (e.g. a
            // brand-new chat that completed in the background before its index
            // entry landed). Read it directly so an on-disk response is never
            // invisible; fall back to an empty stub (race / no file / bad id).
            let orphanMessages = [];
            try { orphanMessages = await loadConversationMessages(userId, id); } catch (_) { /* invalid id or no file */ }
            return res.json({
                id,
                title: 'New Conversation',
                createdAt: new Date().toISOString(),
                messages: orphanMessages
            });
        }

        const messages = await loadConversationMessages(userId, id);
        res.json({ ...conversation, messages });
    } catch (error) {
        console.error('Error loading conversation:', error);
        res.status(500).json({ error: 'Failed to load conversation' });
    }
});

// Update a conversation (title, favorite, etc.)
app.put('/api/conversations/:id', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const { id } = req.params;
        const { title, favorite } = req.body;

        const conversations = await loadConversationsIndex(userId);
        const index = conversations.findIndex(c => c.id === id);

        // Auto-create conversation entry if not found (handles race conditions
        // where frontend sends update before index is fully saved)
        if (index === -1) {
            const newConversation = {
                id,
                title: title || 'New Conversation',
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString()
            };
            if (favorite !== undefined) {
                newConversation.favorite = Boolean(favorite);
            }
            conversations.unshift(newConversation);
            await saveConversationsIndex(userId, conversations);
            return res.json(newConversation);
        }

        // Build update object
        const updates = {
            ...conversations[index],
            updatedAt: new Date().toISOString()
        };

        // Only update title if provided
        if (title !== undefined) {
            updates.title = title;
        }

        // Only update favorite if provided (allow toggling on/off)
        if (favorite !== undefined) {
            updates.favorite = Boolean(favorite);
        }

        conversations[index] = updates;

        await saveConversationsIndex(userId, conversations);
        res.json(conversations[index]);
    } catch (error) {
        console.error('Error updating conversation:', error);
        res.status(500).json({ error: 'Failed to update conversation' });
    }
});

// Delete a conversation
app.delete('/api/conversations/:id', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const { id } = req.params;

        // Validate conversation ID format to prevent path traversal
        if (!/^[a-zA-Z0-9_-]+$/.test(id)) {
            return res.status(400).json({ error: 'Invalid conversation ID' });
        }

        const conversations = await loadConversationsIndex(userId);
        const index = conversations.findIndex(c => c.id === id);

        if (index === -1) {
            return res.status(404).json({ error: 'Conversation not found' });
        }

        conversations.splice(index, 1);
        await saveConversationsIndex(userId, conversations);

        // Load the messages BEFORE unlinking so we can walk their
        // attachments and wipe matching entries from the persistent
        // attachment store. Errors here are non-fatal — orphan-sweep at
        // boot will catch anything we miss. Use loadConversationMessages
        // so the base64 wrapper applied by encodeConversationData is
        // transparently undone.
        const userDir = await ensureUserConversationsDir(userId);
        const messagesPath = path.join(userDir, `${id}.json`);
        let convMessages = [];
        try {
            convMessages = await loadConversationMessages(userId, id);
        } catch (_) { /* file may not exist */ }

        try {
            await fs.unlink(messagesPath);
        } catch (e) {
            // Ignore if file doesn't exist
        }

        // Wipe attachment-store entries for every PDF / xlsx / etc. the
        // user uploaded into this conversation. Same broadcast pattern as
        // the sandbox-workspace wipe below.
        try {
            const wipe = await attachmentStore.deleteForConversation(userId, convMessages);
            if (wipe.count > 0) {
                const kb = Math.round((wipe.byteSize || 0) / 1024);
                const logMsg = `[Attachments] Wiped ${wipe.count} attachment(s) for deleted conversation ${id.slice(0, 8)}… — ${kb} KB`;
                console.log(logMsg);
                try {
                    broadcast({ type: 'log', level: 'info', message: logMsg }, userId);
                } catch (_) { /* broadcast best-effort */ }
            }
        } catch (e) {
            console.warn('[Attachments] wipe on conv delete failed:', e.message);
        }

        // Memory is now ACCOUNT-scoped, so it deliberately SURVIVES deleting a
        // single conversation — a learning or fact the model picked up should
        // not vanish because the thread it came from was cleaned up. Users
        // prune memories explicitly from the webapp Memory tab. (Nothing to do
        // here; the stale extraction cursor is harmless — conv ids aren't reused.)

        // Wipe the per-conversation sandbox workspace — git clones, files
        // written by run_python / create_file, chart PNGs, anything else
        // sandboxed skills produced during this chat. Non-blocking log
        // event to the user's Logs tab regardless of whether anything was
        // actually there to delete.
        //
        // Workspace owner must match the userId that the sandbox saw when
        // writing: tool dispatch passes req.userId (null for API-key auth
        // without a bound user; ensureWorkspace buckets those under
        // `global/`). Using the broader `userId` variable declared above
        // (which falls back to apiKeyData.id then 'default') would point at
        // the wrong dir and silently skip the cleanup.
        const workspaceUserId = req.userId ?? null;
        try {
            const sbRunner = require('./services/sandboxRunner');
            const wipe = await sbRunner.deleteConversationWorkspace(workspaceUserId, id);
            if (wipe && wipe.deleted) {
                const kb = Math.round((wipe.byteCount || 0) / 1024);
                const logMsg = `[Sandbox] Wiped workspace for deleted conversation ${id.slice(0, 8)}… — ${wipe.fileCount} file(s), ${kb} KB`;
                console.log(logMsg);
                try {
                    broadcast({ type: 'log', level: 'info', message: logMsg }, userId);
                } catch (_) { /* broadcast is best-effort */ }
            } else if (wipe && wipe.error) {
                const logMsg = `[Sandbox] Workspace cleanup for ${id.slice(0, 8)}… failed: ${wipe.error}`;
                console.warn(logMsg);
                try {
                    broadcast({ type: 'log', level: 'warn', message: logMsg }, userId);
                } catch (_) {}
            }
        } catch (e) {
            console.warn('[Sandbox] workspace wipe on conv delete failed:', e.message);
        }

        res.json({ success: true });
    } catch (error) {
        console.error('Error deleting conversation:', error);
        res.status(500).json({ error: 'Failed to delete conversation' });
    }
});

// Save messages to a conversation
app.post('/api/conversations/:id/messages', requireAuth, async (req, res) => {
    try {
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        const { id } = req.params;
        const { messages } = req.body;

        if (!Array.isArray(messages)) {
            return res.status(400).json({ error: 'Messages must be an array' });
        }

        // Verify conversation exists
        const conversations = await loadConversationsIndex(userId);
        const conversation = conversations.find(c => c.id === id);

        if (!conversation) {
            return res.status(404).json({ error: 'Conversation not found' });
        }

        // saveConversationMessages also updates messageCount and updatedAt in the index.
        // Memory extraction is routed to the ACCOUNT bucket (memAccountId) so a
        // full user→assistant pair persisted by an API-key caller lands where
        // chat retrieval later reads it — same decoupling as the chat stream.
        await saveConversationMessages(userId, id, messages, { memoryUserId: memAccountId(req) });

        res.json({ success: true, messageCount: messages.length });
    } catch (error) {
        console.error('Error saving messages:', error);
        res.status(500).json({ error: 'Failed to save messages' });
    }
});

// ----------------------------------------------------------------------------
// MEMORY MANAGEMENT ROUTES
// ----------------------------------------------------------------------------
// List, edit, and delete per-conversation memories. The store is populated
// automatically on save (via extractNewMemoriesFromSave) and consumed on the
// next turn (via retrieveRelevantMemories). These routes exist so the chat
// UI has a management view — users can correct facts the heuristic got
// wrong, prune noise, or wipe the whole store for a conversation.

// Shared ownership check: the conversation must exist in this user's index
// before we touch its memory directory. Prevents a different user's API key
// from listing / editing / deleting someone else's memories by guessing an
// id. Returns the conversation object on success, null on 404.
async function ownsConversation(userId, conversationId) {
    if (!/^[a-zA-Z0-9_-]+$/.test(conversationId)) return null;
    const list = await loadConversationsIndex(userId);
    return list.find(c => c.id === conversationId) || null;
}

// NOTE: the old per-CONVERSATION memory routes (GET/DELETE/DELETE/PUT
// /api/conversations/:id/memories[/:memId]) were removed when memory became
// ACCOUNT-scoped. Management now lives at /api/memories/* (see below) and the
// webapp Memory tab. Legacy on-disk per-conversation memories are migrated
// into the account store on first use (memoryService.migrateLegacyForUser).

// Check streaming status for a conversation
app.get('/api/conversations/:id/streaming', requireAuth, async (req, res) => {
    try {
        const { id } = req.params;
        const job = activeStreamingJobs.get(id);

        if (!job) {
            return res.json({ streaming: false });
        }

        res.json({
            streaming: true,
            content: job.content,
            reasoning: job.reasoning || '',
            startTime: job.startTime,
            model: job.model,
            clientConnected: job.clientConnected,
            phase: job.phase || null,
            progress: job.progress || null,
            events: Array.isArray(job.events) ? job.events : [],
        });
    } catch (error) {
        console.error('Error checking streaming status:', error);
        res.status(500).json({ error: 'Failed to check streaming status' });
    }
});

// Cancel an active streaming job for a conversation
app.delete('/api/conversations/:id/streaming', requireAuth, async (req, res) => {
    try {
        const { id } = req.params;
        const job = activeStreamingJobs.get(id);

        if (!job) {
            return res.json({ cancelled: false, reason: 'No active stream found' });
        }

        // Abort the underlying model request
        if (job.abortController) {
            job.abortController.abort();
        }

        // Save partial response if there is content
        if (job.content) {
            try {
                const conversationMsgs = await loadConversationMessages(job.userId, id);
                const assistantMessage = {
                    id: crypto.randomUUID(),
                    role: 'assistant',
                    content: job.content,
                    reasoning: job.reasoning || undefined,
                    timestamp: new Date().toISOString(),
                    responseTime: Date.now() - job.startTime,
                    stoppedByUser: true
                };
                conversationMsgs.push(assistantMessage);
                await saveConversationMessages(job.userId, id, conversationMsgs, { memoryUserId: job.memoryUserId || job.userId });
                console.log(`[Chat Stream] Cancelled stream for conversation ${id}, partial response saved (${job.content.length} chars)`);
            } catch (saveErr) {
                console.error(`[Chat Stream] Failed to save partial response on cancel:`, saveErr);
            }
        }

        // Clean up the job
        activeStreamingJobs.delete(id);

        res.json({ cancelled: true, hadContent: !!job.content });
    } catch (error) {
        console.error('Error cancelling stream:', error);
        res.status(500).json({ error: 'Failed to cancel stream' });
    }
});

// Smart content optimizer - removes unnecessary whitespace to save tokens
function optimizeContent(text, options = {}) {
    if (!text || typeof text !== 'string') return text;

    const {
        preserveCodeBlocks = true,
        maxConsecutiveNewlines = 2,
        trimLines = true,
        removeEmptyLines = false,
        compressWhitespace = true
    } = options;

    let result = text;

    // Preserve code blocks by replacing them with placeholders
    const codeBlocks = [];
    if (preserveCodeBlocks) {
        result = result.replace(/```[\s\S]*?```|`[^`\n]+`/g, (match) => {
            codeBlocks.push(match);
            return `__CODE_BLOCK_${codeBlocks.length - 1}__`;
        });
    }

    // Normalize line endings
    result = result.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    // Trim trailing whitespace from each line
    if (trimLines) {
        result = result.split('\n').map(line => line.trimEnd()).join('\n');
    }

    // Compress multiple spaces to single space (within lines)
    if (compressWhitespace) {
        result = result.split('\n').map(line => {
            // Don't compress leading whitespace (indentation)
            const leadingSpaces = line.match(/^(\s*)/)[1];
            const rest = line.slice(leadingSpaces.length);
            return leadingSpaces + rest.replace(/  +/g, ' ');
        }).join('\n');
    }

    // Remove empty lines or limit consecutive newlines
    if (removeEmptyLines) {
        result = result.split('\n').filter(line => line.trim() !== '').join('\n');
    } else if (maxConsecutiveNewlines > 0) {
        const pattern = new RegExp(`\n{${maxConsecutiveNewlines + 1},}`, 'g');
        result = result.replace(pattern, '\n'.repeat(maxConsecutiveNewlines));
    }

    // Restore code blocks
    if (preserveCodeBlocks) {
        codeBlocks.forEach((block, i) => {
            result = result.replace(`__CODE_BLOCK_${i}__`, block);
        });
    }

    return result.trim();
}

// Extract links from text/HTML content - extracts both HTML anchor tags and plain URLs
/**
 * Convert HTML email body to readable plain text, preserving table data and structure
 */
function htmlToPlainText(html) {
    if (!html || typeof html !== 'string') return '';
    return html
        // Table handling - preserve cell data with separators
        .replace(/<\/th>/gi, ' | ')
        .replace(/<\/td>/gi, ' | ')
        .replace(/<\/tr>/gi, '\n')
        .replace(/<\/table>/gi, '\n')
        // List handling
        .replace(/<li[^>]*>/gi, '• ')
        .replace(/<\/li>/gi, '\n')
        // Block elements
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/<\/p>/gi, '\n\n')
        .replace(/<\/div>/gi, '\n')
        .replace(/<\/h[1-6]>/gi, '\n\n')
        .replace(/<hr[^>]*>/gi, '\n---\n')
        // Strip remaining tags
        .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
        .replace(/<[^>]+>/g, '')
        // Decode common HTML entities
        .replace(/&nbsp;/gi, ' ')
        .replace(/&amp;/gi, '&')
        .replace(/&lt;/gi, '<')
        .replace(/&gt;/gi, '>')
        .replace(/&quot;/gi, '"')
        .replace(/&#39;/gi, "'")
        .replace(/&dollar;/gi, '$')
        .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(parseInt(n)))
        .replace(/&[a-zA-Z]+;/g, ' ')
        // Clean up whitespace
        .replace(/[ \t]+/g, ' ')
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

function extractLinksFromText(text) {
    if (!text || typeof text !== 'string') return [];

    const links = [];
    const seenUrls = new Set();

    // Pattern 1: HTML anchor tags with href
    const anchorPattern = /<a\s+[^>]*href=["']?(https?:\/\/[^"'\s>]+)["']?[^>]*>([^<]*)<\/a>/gi;
    let match;
    while ((match = anchorPattern.exec(text)) !== null) {
        const url = match[1];
        const linkText = match[2].trim() || url;
        if (!seenUrls.has(url)) {
            seenUrls.add(url);
            links.push({ url, text: linkText });
        }
    }

    // Pattern 2: Plain URLs (not already inside anchor tags)
    // Remove HTML tags first to avoid duplicate extraction
    const textWithoutAnchors = text.replace(/<a\s+[^>]*href=["']?https?:\/\/[^"'\s>]+["']?[^>]*>[^<]*<\/a>/gi, '');
    const urlPattern = /https?:\/\/[^\s<>"')\]]+/gi;
    while ((match = urlPattern.exec(textWithoutAnchors)) !== null) {
        let url = match[0];
        // Clean trailing punctuation that's likely not part of URL
        url = url.replace(/[.,;:!?)]+$/, '');
        if (!seenUrls.has(url)) {
            seenUrls.add(url);
            links.push({ url, text: url });
        }
    }

    return links;
}

/**
 * Helper function to extract text content from email attachments recursively
 * Handles nested emails (.eml, .msg), PDFs, and text documents
 * @param {Array} attachments - Array of attachment objects from mailparser or msgreader
 * @param {number} depth - Current recursion depth (max 3 levels to prevent infinite loops)
 * @returns {Promise<string>} - Extracted text from all attachments
 */
async function extractEmailAttachmentContent(attachments, depth = 0) {
    if (!attachments || !Array.isArray(attachments) || depth > 3) {
        return '';
    }

    const { simpleParser } = require('mailparser');
    const pdfParse = require('pdf-parse');
    const mammoth = require('mammoth');

    let extractedContent = '';

    for (const att of attachments) {
        try {
            const filename = att.filename || att.fileName || att.name || 'attachment';
            const ext = filename.toLowerCase().split('.').pop();
            const contentType = att.contentType || att.mimeType || '';
            const content = att.content || (att.dataBuffer ? Buffer.from(att.dataBuffer) : null);

            if (!content) continue;

            // Handle nested email attachments (.eml)
            if (ext === 'eml' || contentType === 'message/rfc822') {
                try {
                    const parsed = await simpleParser(content);
                    extractedContent += `\n\n=== Nested Email: ${parsed.subject || 'Untitled'} ===\n`;
                    if (parsed.from?.text) extractedContent += `From: ${parsed.from.text}\n`;
                    if (parsed.to?.text) extractedContent += `To: ${parsed.to.text}\n`;
                    if (parsed.date) extractedContent += `Date: ${parsed.date.toISOString()}\n`;
                    extractedContent += '\n';

                    // Get body text
                    const body = parsed.text || parsed.html?.replace(/<[^>]+>/g, '') || '';
                    extractedContent += body.substring(0, 10000); // Limit nested body

                    // Recursively parse nested email's attachments
                    if (parsed.attachments?.length > 0) {
                        const nestedContent = await extractEmailAttachmentContent(parsed.attachments, depth + 1);
                        if (nestedContent) {
                            extractedContent += nestedContent;
                        }
                    }
                    extractedContent += '\n=== End Nested Email ===\n';
                } catch (emlErr) {
                    console.warn('Failed to parse nested EML:', emlErr.message);
                }
            }
            // Handle nested .msg files
            else if (ext === 'msg' || contentType === 'application/vnd.ms-outlook') {
                try {
                    const MsgReader = require('@kenjiuno/msgreader').default;
                    const msgReader = new MsgReader(content);
                    const fileData = msgReader.getFileData();

                    extractedContent += `\n\n=== Nested Email (MSG): ${fileData.subject || 'Untitled'} ===\n`;
                    if (fileData.senderEmail) extractedContent += `From: ${fileData.senderEmail}\n`;
                    extractedContent += '\n';

                    const body = fileData.body || '';
                    extractedContent += body.substring(0, 10000);

                    // Handle MSG attachments
                    if (fileData.attachments?.length > 0) {
                        for (const msgAtt of fileData.attachments) {
                            const attContent = msgReader.getAttachment(msgAtt);
                            if (attContent?.content) {
                                const nestedContent = await extractEmailAttachmentContent([{
                                    filename: msgAtt.fileName,
                                    content: Buffer.from(attContent.content),
                                    contentType: msgAtt.contentType
                                }], depth + 1);
                                if (nestedContent) {
                                    extractedContent += nestedContent;
                                }
                            }
                        }
                    }
                    extractedContent += '\n=== End Nested Email (MSG) ===\n';
                } catch (msgErr) {
                    console.warn('Failed to parse nested MSG:', msgErr.message);
                }
            }
            // Handle PDF attachments
            else if (ext === 'pdf' || contentType === 'application/pdf') {
                try {
                    const data = await extractPdfText(content);
                    if (data.text?.trim()) {
                        extractedContent += `\n\n=== PDF Attachment: ${filename} ===\n`;
                        extractedContent += repairPdfUrls(data.text).substring(0, 20000); // Limit PDF content
                        extractedContent += '\n=== End PDF ===\n';
                    }
                } catch (pdfErr) {
                    console.warn('Failed to parse PDF attachment:', pdfErr.message);
                }
            }
            // Handle Word documents
            else if (ext === 'docx' || contentType.includes('wordprocessingml')) {
                try {
                    const result = await mammoth.extractRawText({ buffer: content });
                    if (result.value?.trim()) {
                        extractedContent += `\n\n=== Document Attachment: ${filename} ===\n`;
                        extractedContent += result.value.substring(0, 20000);
                        extractedContent += '\n=== End Document ===\n';
                    }
                } catch (docErr) {
                    console.warn('Failed to parse DOCX attachment:', docErr.message);
                }
            }
            // Handle text files
            else if (ext === 'txt' || ext === 'csv' || ext === 'json' || ext === 'xml' ||
                     ext === 'md' || ext === 'log' || contentType.startsWith('text/')) {
                try {
                    const textContent = content.toString('utf-8');
                    if (textContent?.trim()) {
                        extractedContent += `\n\n=== Text Attachment: ${filename} ===\n`;
                        extractedContent += textContent.substring(0, 20000);
                        extractedContent += '\n=== End Text ===\n';
                    }
                } catch (txtErr) {
                    console.warn('Failed to parse text attachment:', txtErr.message);
                }
            }
        } catch (attErr) {
            console.warn('Failed to process attachment:', attErr.message);
        }
    }

    return extractedContent;
}

// File upload endpoint for chat context
app.post('/api/chat/upload', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }

    try {
        // Handle base64-encoded file content
        const { filename, content, mimeType, optimize = true } = req.body;

        // Validate file size (max 50MB)
        const contentLength = content ? content.length : 0;
        if (contentLength > 50 * 1024 * 1024) {
            return res.status(413).json({ error: 'File too large. Maximum size is 50MB.' });
        }

        if (!content) {
            return res.status(400).json({ error: 'File content is required' });
        }

        // True on-disk size of the uploaded file: the client base64-encodes the
        // raw bytes (FileReader.readAsDataURL), so decoding gives back the exact
        // file size the user sees on their machine. Surfaced as `size` on every
        // response below so the UI and model report bytes — never conflating
        // that with the post-extraction character count.
        const uploadedByteSize = Buffer.from(content, 'base64').length;

        // Helper to optionally optimize content
        const maybeOptimize = (text) => optimize ? optimizeContent(text) : text;

        // Helper to sanitize content for model tokenizers
        // Removes/replaces characters that can cause parsing errors
        const sanitizeForModel = (text) => {
            return text
                // Remove NULL bytes and other control characters (except newline, tab, carriage return)
                .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
                // Replace non-breaking spaces and other problematic whitespace
                .replace(/[\u00A0\u2000-\u200B\u2028\u2029\u202F\u205F\u3000]/g, ' ')
                // Remove zero-width characters
                .replace(/[\uFEFF\u200C\u200D]/g, '')
                // Replace problematic Unicode characters that can cause tokenizer issues
                .replace(/[\uFFFD\uFFFF]/g, '')
                // Normalize common problematic sequences
                .replace(/\r\n/g, '\n')
                .replace(/\r/g, '\n');
        };

        // Helper to prepare content with chunking metadata (no truncation at upload time)
        // Truncation happens at chat time based on model's actual context window
        const prepareContent = (text, originalLength) => {
            const estimatedTokens = Math.ceil(text.length / 4);
            const chunkSize = 20000; // chars per chunk (~5000 tokens)
            const totalChunks = Math.ceil(text.length / chunkSize);

            return {
                content: text,
                originalLength,
                estimatedTokens,
                totalChunks,
                chunkSize,
                // Flag if this will likely need chunked processing
                requiresChunking: estimatedTokens > 8000
            };
        };

        // For text-based files, decode and return content
        const textTypes = [
            'text/', 'application/json', 'application/xml',
            'application/javascript', 'application/x-yaml'
        ];

        const isText = textTypes.some(t => mimeType?.startsWith(t) || mimeType?.includes(t));

        if (isText) {
            try {
                const rawBytes = Buffer.from(content, 'base64');
                let decoded = rawBytes.toString('utf8');
                const originalLength = decoded.length;
                decoded = sanitizeForModel(maybeOptimize(decoded));
                const prepared = prepareContent(decoded, originalLength);

                // Persist the original bytes so the file remains previewable
                // after a reload (via attachmentId, the same durable path PDFs
                // use) instead of relying on multi-MB inline content surviving
                // in the conversation JSON. Best-effort: on failure the inline
                // content still works for the current turn.
                let attachmentId = null;
                try {
                    const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
                    attachmentId = await attachmentStore.save(ownerId, {
                        filename,
                        mimeType: mimeType || 'text/plain; charset=utf-8',
                        type: 'text',
                        bytes: rawBytes,
                    });
                } catch (persistErr) {
                    console.error('[Chat Upload] text persist failed:', persistErr);
                }

                return res.json({
                    type: 'text',
                    filename,
                    ...(attachmentId ? { attachmentId } : {}),
                    content: prepared.content,
                    size: rawBytes.length,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks
                });
            } catch (e) {
                return res.status(400).json({ error: 'Failed to decode text content' });
            }
        }

        // Get file extension for fallback detection
        const ext = filename?.toLowerCase()?.split('.').pop();

        // For PDFs, extract text with OCR fallback for scanned documents
        if (mimeType === 'application/pdf' || ext === 'pdf') {
            try {
                const { exec, execSync } = require('child_process');
                const { promisify } = require('util');
                const execAsync = promisify(exec);
                const path = require('path');
                const fs = require('fs');

                const buffer = Buffer.from(content, 'base64');
                const data = await extractPdfText(buffer);
                const pageCount = data.numpages || 1;
                let extractedText = data.text || '';

                // Calculate text density (chars per page)
                const charsPerPage = extractedText.trim().length / pageCount;
                const needsOcr = charsPerPage < 100; // Less than 100 chars/page suggests scanned PDF

                let ocrText = '';
                let ocrPerformed = false;

                if (needsOcr && pageCount <= 50) { // Limit OCR to 50 pages for performance
                    try {
                        // Create temp directory for PDF processing
                        const tempDir = `/tmp/pdf_ocr_${Date.now()}_${Math.random().toString(36).slice(2)}`;
                        fs.mkdirSync(tempDir, { recursive: true });

                        const pdfPath = path.join(tempDir, 'input.pdf');
                        fs.writeFileSync(pdfPath, buffer);

                        // Convert PDF pages to images using pdftoppm (from poppler-utils)
                        // Use PNG format for better OCR quality, 200 DPI for balance of speed/accuracy
                        await execAsync(`pdftoppm -png -r 200 "${pdfPath}" "${tempDir}/page"`, {
                            timeout: 120000 // 2 minute timeout
                        });

                        // Get list of generated images
                        const imageFiles = fs.readdirSync(tempDir)
                            .filter(f => f.startsWith('page') && f.endsWith('.png'))
                            .sort();

                        // Run OCR on each page
                        const ocrResults = [];
                        for (const imageFile of imageFiles) {
                            const imagePath = path.join(tempDir, imageFile);
                            try {
                                // Use tesseract for OCR
                                const { stdout } = await execAsync(`tesseract "${imagePath}" stdout -l eng --psm 1`, {
                                    timeout: 30000 // 30 seconds per page
                                });
                                if (stdout.trim()) {
                                    ocrResults.push(stdout.trim());
                                }
                            } catch (ocrErr) {
                                console.warn(`OCR failed for ${imageFile}:`, ocrErr.message);
                            }
                        }

                        // Cleanup temp directory
                        try {
                            fs.rmSync(tempDir, { recursive: true, force: true });
                        } catch (cleanupErr) {
                            console.warn('Failed to cleanup temp directory:', cleanupErr.message);
                        }

                        if (ocrResults.length > 0) {
                            ocrText = ocrResults.join('\n\n--- Page Break ---\n\n');
                            ocrPerformed = true;
                        }
                    } catch (ocrError) {
                        console.warn('PDF OCR failed, using text extraction only:', ocrError.message);
                    }
                }

                // Combine OCR text with regular extracted text
                let finalText = extractedText;
                if (ocrPerformed && ocrText.trim().length > extractedText.trim().length) {
                    // OCR found more text than regular extraction
                    finalText = ocrText;
                } else if (ocrPerformed && ocrText.trim()) {
                    // Append OCR text if it adds meaningful content
                    const ocrUnique = ocrText.trim().length - extractedText.trim().length;
                    if (ocrUnique > 500) {
                        finalText = extractedText + '\n\n--- OCR Extracted Content ---\n\n' + ocrText;
                    }
                }

                // Repair URLs broken across lines by pdf-parse
                finalText = repairPdfUrls(finalText);

                const originalLength = finalText.length;
                // PDFs often contain problematic characters - sanitize after optimization
                const optimized = sanitizeForModel(maybeOptimize(finalText));
                const prepared = prepareContent(optimized, originalLength);

                // Save the raw PDF to the attachment store so the chat UI
                // can fetch it on demand for inline rendering. Conversations
                // only persist the small attachmentId, not 8 MB of base64.
                let attachmentId = null;
                try {
                    const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
                    attachmentId = await attachmentStore.save(ownerId, {
                        filename,
                        mimeType: 'application/pdf',
                        type: 'pdf',
                        bytes: buffer,
                        meta: { pageCount, charCount: prepared.content.length },
                    });
                } catch (storeErr) {
                    console.warn('[Chat Upload] attachmentStore save failed (PDF):', storeErr.message);
                }

                return res.json({
                    type: 'pdf',
                    filename,
                    content: prepared.content,
                    size: uploadedByteSize,
                    pageCount: pageCount,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks,
                    ocrPerformed: ocrPerformed,
                    ...(attachmentId ? { attachmentId } : {}),
                });
            } catch (e) {
                console.error('PDF parsing error:', e);
                return res.status(400).json({ error: 'Failed to parse PDF: ' + e.message });
            }
        }

        // For .msg (Outlook binary format) files - requires msgreader
        if (ext === 'msg' || mimeType === 'application/vnd.ms-outlook') {
            try {
                const MsgReader = require('@kenjiuno/msgreader').default;
                const buffer = Buffer.from(content, 'base64');
                const msgReader = new MsgReader(buffer);
                const fileData = msgReader.getFileData();

                // Build email content string
                let emailContent = '';
                if (fileData.subject) emailContent += `Subject: ${fileData.subject}\n`;
                if (fileData.senderName || fileData.senderEmail) {
                    emailContent += `From: ${fileData.senderName || ''} <${fileData.senderEmail || ''}>\n`;
                }
                if (fileData.recipients?.length > 0) {
                    const toRecipients = fileData.recipients.filter(r => r.recipType === 'to' || !r.recipType);
                    const ccRecipients = fileData.recipients.filter(r => r.recipType === 'cc');
                    if (toRecipients.length > 0) {
                        emailContent += `To: ${toRecipients.map(r => r.name || r.email).join(', ')}\n`;
                    }
                    if (ccRecipients.length > 0) {
                        emailContent += `CC: ${ccRecipients.map(r => r.name || r.email).join(', ')}\n`;
                    }
                }
                if (fileData.messageDeliveryTime) emailContent += `Date: ${fileData.messageDeliveryTime}\n`;

                // Extract links from body content (both plain text and HTML)
                const bodyText = fileData.body || '';
                // msgreader uses 'bodyHtml' (string) or 'html' (Uint8Array)
                let bodyHtml = fileData.bodyHtml || '';
                if (!bodyHtml && fileData.html) {
                    // Convert Uint8Array to string
                    bodyHtml = Buffer.from(fileData.html).toString('utf-8');
                }
                const links = extractLinksFromText(bodyHtml || bodyText);

                // Add links section if any found
                if (links.length > 0) {
                    emailContent += `\nLinks found: ${links.length}\n`;
                    links.forEach((link, i) => {
                        emailContent += `  ${i + 1}. ${link.text !== link.url ? link.text + ': ' : ''}${link.url}\n`;
                    });
                }

                emailContent += '\n---\n\n';
                // Use HTML body when available (contains tables, dollar amounts, details)
                // Fall back to plain text body if no HTML
                const htmlText = bodyHtml ? htmlToPlainText(bodyHtml) : '';
                const plainText = bodyText.replace(/<[^>]+>/g, '').trim();
                // Use whichever has more content (HTML usually has full details)
                emailContent += (htmlText.length > plainText.length) ? htmlText : plainText;

                // Include attachments info and extract content from attachments
                if (fileData.attachments?.length > 0) {
                    emailContent += '\n\n---\nAttachments:\n';
                    fileData.attachments.forEach(att => {
                        emailContent += `- ${att.fileName || att.name || 'unnamed'} (${att.contentLength || 'unknown size'} bytes)\n`;
                    });

                    // Extract content from attachments (nested emails, PDFs, etc.)
                    try {
                        const attachmentsWithContent = [];
                        for (const att of fileData.attachments) {
                            const attContent = msgReader.getAttachment(att);
                            if (attContent?.content) {
                                attachmentsWithContent.push({
                                    filename: att.fileName,
                                    content: Buffer.from(attContent.content),
                                    contentType: att.contentType || ''
                                });
                            }
                        }
                        const attachmentText = await extractEmailAttachmentContent(attachmentsWithContent);
                        if (attachmentText) {
                            emailContent += '\n\n--- Attachment Contents ---' + attachmentText;
                        }
                    } catch (attErr) {
                        console.warn('Failed to extract MSG attachments:', attErr.message);
                    }
                }

                const originalLength = emailContent.length;
                const optimized = sanitizeForModel(maybeOptimize(emailContent));
                const prepared = prepareContent(optimized, originalLength);

                return res.json({
                    type: 'email',
                    filename,
                    content: prepared.content,
                    size: uploadedByteSize,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    subject: fileData.subject,
                    from: fileData.senderEmail,
                    date: fileData.messageDeliveryTime,
                    links: links,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks,
                    hasAttachments: fileData.attachments?.length > 0
                });
            } catch (e) {
                console.error('MSG parsing error:', e);
                // Fall through to try as raw text
            }
        }

        // For .eml email files - uses mailparser
        if (ext === 'eml' || mimeType === 'message/rfc822') {
            try {
                const { simpleParser } = require('mailparser');
                const buffer = Buffer.from(content, 'base64');
                const parsed = await simpleParser(buffer);

                // Build email content string
                let emailContent = '';
                if (parsed.subject) emailContent += `Subject: ${parsed.subject}\n`;
                if (parsed.from?.text) emailContent += `From: ${parsed.from.text}\n`;
                if (parsed.to?.text) emailContent += `To: ${parsed.to.text}\n`;
                if (parsed.cc?.text) emailContent += `CC: ${parsed.cc.text}\n`;
                if (parsed.date) emailContent += `Date: ${parsed.date.toISOString()}\n`;

                // Extract links from body content (HTML first, then plain text)
                const bodyHtml = parsed.html || parsed.textAsHtml || '';
                const bodyText = parsed.text || '';
                const links = extractLinksFromText(bodyHtml || bodyText);

                // Add links section if any found
                if (links.length > 0) {
                    emailContent += `\nLinks found: ${links.length}\n`;
                    links.forEach((link, i) => {
                        emailContent += `  ${i + 1}. ${link.text !== link.url ? link.text + ': ' : ''}${link.url}\n`;
                    });
                }

                emailContent += '\n---\n\n';
                // Use HTML body when available (contains tables, dollar amounts, details)
                // Fall back to plain text body if no HTML
                const htmlText = bodyHtml ? htmlToPlainText(bodyHtml) : '';
                const plainText = (bodyText || '').trim();
                // Use whichever has more content (HTML usually has full details)
                emailContent += (htmlText.length > plainText.length) ? htmlText : plainText;

                // Include attachments info and extract content from attachments
                if (parsed.attachments?.length > 0) {
                    emailContent += '\n\n---\nAttachments:\n';
                    parsed.attachments.forEach(att => {
                        emailContent += `- ${att.filename || 'unnamed'} (${att.contentType}, ${att.size} bytes)\n`;
                    });

                    // Extract content from attachments (nested emails, PDFs, etc.)
                    try {
                        const attachmentText = await extractEmailAttachmentContent(parsed.attachments);
                        if (attachmentText) {
                            emailContent += '\n\n--- Attachment Contents ---' + attachmentText;
                        }
                    } catch (attErr) {
                        console.warn('Failed to extract EML attachments:', attErr.message);
                    }
                }

                const originalLength = emailContent.length;
                const optimized = sanitizeForModel(maybeOptimize(emailContent));
                const prepared = prepareContent(optimized, originalLength);

                return res.json({
                    type: 'email',
                    filename,
                    content: prepared.content,
                    size: uploadedByteSize,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    subject: parsed.subject,
                    from: parsed.from?.text,
                    date: parsed.date?.toISOString(),
                    links: links,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks,
                    hasAttachments: parsed.attachments?.length > 0
                });
            } catch (e) {
                console.error('EML parsing error:', e);
                // Fall through to try as raw text
            }
        }

        // For Word documents (.docx)
        if (ext === 'docx' || mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
            try {
                const mammoth = require('mammoth');
                const buffer = Buffer.from(content, 'base64');
                const result = await mammoth.extractRawText({ buffer });
                const originalLength = result.value.length;
                const optimized = sanitizeForModel(maybeOptimize(result.value));
                const prepared = prepareContent(optimized, originalLength);

                return res.json({
                    type: 'document',
                    filename,
                    content: prepared.content,
                    size: uploadedByteSize,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks
                });
            } catch (e) {
                console.error('DOCX parsing error:', e);
                // Fall through to try as raw text
            }
        }

        // For Excel files (.xlsx) — parsed via @e965/xlsx
        if (ext === 'xlsx' || ext === 'xls' || mimeType?.includes('spreadsheet')) {
            try {
                const buffer = Buffer.from(content, 'base64');
                const XLSX = require('@e965/xlsx');
                const workbook = XLSX.read(buffer, { type: 'buffer' });
                // Two views of the same data: a CSV blob (what the model sees;
                // matches the legacy xlsxBufferToCsv format byte-for-byte) and
                // a structured `sheets[]` payload that the chat UI's
                // FilePreviewModal renders as a real HTML table. Cap rows
                // per sheet so a 100k-row workbook doesn't bloat the upload
                // response — the model still gets the full CSV in `content`.
                const PREVIEW_ROWS_PER_SHEET = 1000;
                const csvChunks = [];
                const sheetsStructured = [];
                for (const sheetName of workbook.SheetNames) {
                    const ws = workbook.Sheets[sheetName];
                    const csv = XLSX.utils.sheet_to_csv(ws).trim();
                    if (csv) csvChunks.push(`=== Sheet: ${sheetName} ===\n${csv}`);
                    const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false, defval: '' });
                    sheetsStructured.push({
                        name: sheetName,
                        rowCount: aoa.length,
                        truncated: aoa.length > PREVIEW_ROWS_PER_SHEET,
                        rows: aoa.slice(0, PREVIEW_ROWS_PER_SHEET).map(row =>
                            Array.isArray(row) ? row.map(cell => cell == null ? '' : String(cell)) : []
                        ),
                    });
                }
                const textContent = csvChunks.join('\n\n');

                const originalLength = textContent.length;
                const optimized = sanitizeForModel(maybeOptimize(textContent));
                const prepared = prepareContent(optimized, originalLength);

                // Save the structured sheets to the attachment store.
                // FilePreviewModal fetches them on demand via
                // /api/attachments/:id/meta so conversations don't carry
                // hundreds of KB of cell data per upload.
                let attachmentId = null;
                try {
                    const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
                    attachmentId = await attachmentStore.save(ownerId, {
                        filename,
                        mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                        type: 'spreadsheet',
                        // Persist the raw xlsx bytes so /api/chat/stream can
                        // copy the original spreadsheet into the conversation's
                        // sandbox workspace (/workspace/uploads/<name>.xlsx).
                        // Skills like query_sqlite, read_xlsx, run_python can
                        // then operate on the actual file instead of just the
                        // CSV-flattened text content.
                        bytes: buffer,
                        meta: {
                            sheetCount: sheetsStructured.length,
                            sheets: sheetsStructured,
                        },
                    });
                } catch (storeErr) {
                    console.warn('[Chat Upload] attachmentStore save failed (xlsx):', storeErr.message);
                }

                return res.json({
                    type: 'spreadsheet',
                    filename,
                    content: prepared.content,
                    size: uploadedByteSize,
                    charCount: prepared.content.length,
                    originalCharCount: originalLength,
                    saved: originalLength - prepared.content.length,
                    sheetCount: sheetsStructured.length,
                    estimatedTokens: prepared.estimatedTokens,
                    requiresChunking: prepared.requiresChunking,
                    totalChunks: prepared.totalChunks,
                    ...(attachmentId ? { attachmentId } : {}),
                });
            } catch (e) {
                console.error('Excel parsing error:', e);
                // Fall through to try as raw text
            }
        }

        // For images: convert to PNG if needed, run OCR, return both image and text
        if (mimeType?.startsWith('image/')) {
            let imageDataUrl = `data:${mimeType};base64,${content}`;
            let imageMimeType = mimeType;
            let ocrText = '';

            // Convert GIF/BMP/TIFF to PNG for model compatibility (most vision APIs only accept JPEG/PNG/WebP)
            const needsConversion = ['image/gif', 'image/bmp', 'image/tiff'].includes(mimeType);
            if (needsConversion) {
                try {
                    const { Jimp } = require('jimp');
                    const buffer = Buffer.from(content, 'base64');
                    const image = await Jimp.read(buffer);
                    const pngBuffer = await image.getBuffer('image/png');
                    const pngBase64 = pngBuffer.toString('base64');
                    imageDataUrl = `data:image/png;base64,${pngBase64}`;
                    imageMimeType = 'image/png';
                    console.log(`[Chat Upload] Converted ${mimeType} to PNG (${pngBase64.length} base64 chars)`);
                } catch (convErr) {
                    console.error(`[Chat Upload] Image conversion failed for ${mimeType}:`, convErr.message);
                    // Fall back to original format
                }
            }

            // Attempt OCR text extraction via Tesseract CLI
            try {
                const { execFile } = require('child_process');
                const { promisify } = require('util');
                const execFileAsync = promisify(execFile);
                const ocrTmpPath = `/tmp/ocr_${Date.now()}_${crypto.randomBytes(8).toString('hex')}`;

                // Write image to temp file
                const imgBuffer = Buffer.from(content, 'base64');
                // Tesseract needs a file extension it recognizes
                const ocrExt = ext || mimeType.split('/')[1] || 'png';
                const ocrInputPath = `${ocrTmpPath}.${ocrExt}`;
                await fs.writeFile(ocrInputPath, imgBuffer);

                try {
                    const { stdout } = await execFileAsync('tesseract', [ocrInputPath, 'stdout', '--psm', '3'], {
                        timeout: 30000,
                        maxBuffer: 5 * 1024 * 1024
                    });
                    ocrText = (stdout || '').trim();
                    if (ocrText) {
                        console.log(`[Chat Upload] OCR extracted ${ocrText.length} chars from ${filename}`);
                    }
                } finally {
                    // Clean up temp file
                    try { await fs.unlink(ocrInputPath); } catch (e) { /* ignore */ }
                }
            } catch (ocrErr) {
                console.error(`[Chat Upload] OCR failed for ${filename}:`, ocrErr.message);
                // OCR failure is not critical — continue without text
            }

            const result = {
                type: 'image',
                filename,
                dataUrl: imageDataUrl,
                size: uploadedByteSize,
                mimeType: imageMimeType
            };

            // If OCR extracted text, include it so the model can use it
            if (ocrText) {
                const ocrContent = `[OCR extracted text from ${filename}]\n${ocrText}`;
                result.ocrText = ocrText;
                result.content = ocrContent;
                result.charCount = ocrContent.length;
                result.estimatedTokens = Math.ceil(ocrContent.length / 4);
            }

            return res.json(result);
        }

        // Archive uploads: persist to disk and return a short id the
        // model passes to extract_archive. Bytes never transit through
        // tool-call arguments (where base64 routinely gets truncated or
        // mangled by the tokenizer — observed with 15MB 7z files that
        // arrived as 30 bytes of random-looking data on the tool side).
        const ARCHIVE_EXTS = /\.(zip|7z|rar|tar|tar\.gz|tgz|tar\.bz2|tbz2?|tar\.xz|txz|gz|bz2|xz)$/i;
        if (filename && ARCHIVE_EXTS.test(filename)) {
            try {
                const archiveRootDir = '/tmp/modelserver-archives';
                const userDir = String(req.apiKeyData?.userId || req.user?.id || 'anon').replace(/[^a-zA-Z0-9_-]/g, '_');
                const userArchiveDir = `${archiveRootDir}/${userDir}`;
                await require('fs').promises.mkdir(userArchiveDir, { recursive: true, mode: 0o700 });

                // TTL sweep: delete archive dirs older than ARCHIVE_TTL_MS
                // (default 24h). Cheap, keeps /tmp from growing without bound
                // while not expiring an archive in the middle of a task.
                try {
                    const entries = await require('fs').promises.readdir(userArchiveDir);
                    const now = Date.now();
                    for (const e of entries) {
                        const p = `${userArchiveDir}/${e}`;
                        const st = await require('fs').promises.stat(p).catch(() => null);
                        if (st && (now - st.mtimeMs) > ARCHIVE_TTL_MS) {
                            await require('fs').promises.rm(p, { recursive: true, force: true }).catch(() => {});
                        }
                    }
                } catch (_) { /* sweep is best-effort */ }

                const archiveId = crypto.randomBytes(16).toString('hex');
                const dir = `${userArchiveDir}/${archiveId}`;
                await require('fs').promises.mkdir(dir, { mode: 0o700 });
                // Strip any directory component from the filename defensively;
                // the extension is the only thing archiveExtractor cares about.
                const safeName = require('path').basename(filename).replace(/[^a-zA-Z0-9._-]/g, '_');
                const diskPath = `${dir}/${safeName}`;
                const buf = Buffer.from(content, 'base64');
                await require('fs').promises.writeFile(diskPath, buf);

                const marker = `[Archive uploaded: ${safeName} (archiveId=${archiveId}, size=${buf.length} bytes). Call the extract_archive tool with {"archiveId":"${archiveId}"} to list and read its contents — DO NOT extract via run_python/tarfile/zipfile/subprocess; extract_archive lands the files under /workspace/archives/${archiveId}/ where read_file, grep_code, and outline_file can see them, and returns inline text for small entries so you often won't need a follow-up tool call at all.]`;
                return res.json({
                    type: 'archive',
                    filename: safeName,
                    archiveId,
                    archiveSize: buf.length,
                    size: buf.length,
                    content: marker,
                    charCount: marker.length,
                    estimatedTokens: Math.ceil(marker.length / 4),
                });
            } catch (archiveErr) {
                console.error('[Chat Upload] archive persist failed:', archiveErr);
                // Fall through to catch-all so the user still gets *something*.
            }
        }

        // Binary file persist helper — saves bytes to attachmentStore and
        // returns the JSON the chat UI expects. Used by both the explicit
        // audio/video/binary branch and the catch-all U+FFFD fallback.
        // The `content` marker tells the model the file is on disk at
        // /workspace/uploads/<filename> (materializeAttachmentsToWorkspace
        // will load via attachmentId before the model dispatches).
        const persistBinaryFile = async (buffer, finalMime) => {
            const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
            const attachmentId = await attachmentStore.save(ownerId, {
                filename,
                mimeType: finalMime,
                type: 'file',
                bytes: buffer,
            });
            const isAudio = finalMime.startsWith('audio/');
            const isVideo = finalMime.startsWith('video/');
            const hint = isAudio
                ? `Call transcribe_audio with {"file_path":"/workspace/uploads/${filename}"} to transcribe.`
                : isVideo
                    ? `Use ffmpeg via run_python/run_node to extract audio or frames, then process.`
                    : `Read with run_python (open(..., 'rb')) or other sandbox skills.`;
            const marker =
                `[Binary file uploaded: ${filename} (${finalMime}, ${buffer.length} bytes). ` +
                `On disk at /workspace/uploads/${filename}. ${hint}]`;
            return {
                type: 'file',
                filename,
                attachmentId,
                mimeType: finalMime,
                size: buffer.length,
                content: marker,
                charCount: marker.length,
                estimatedTokens: Math.ceil(marker.length / 4),
            };
        };

        // Known-binary mime types: route directly to attachmentStore so the
        // bytes survive intact and land in /workspace/uploads/ for skills
        // like transcribe_audio. Without this branch, audio/video/etc. fell
        // into the catch-all where Buffer.from(b64,'base64').toString('utf8')
        // produced a string of U+FFFD replacement chars that sanitizeForModel
        // then stripped — leaving 4 chars of garbage where the song used to
        // be, and no file on disk for the model to find.
        const isKnownBinaryMime = (mt) => {
            if (!mt) return false;
            return mt.startsWith('audio/') ||
                   mt.startsWith('video/') ||
                   mt.startsWith('font/') ||
                   mt.startsWith('model/') ||
                   mt === 'application/octet-stream' ||
                   mt === 'application/x-executable' ||
                   mt === 'application/x-sharedlib' ||
                   mt === 'application/wasm';
        };
        const BINARY_EXTS = new Set([
            'mp3','wav','flac','ogg','oga','m4a','aac','opus','wma','aiff','ape',
            'mp4','mkv','mov','avi','webm','wmv','flv','m4v','mpg','mpeg','3gp',
            'exe','dll','so','dylib','class','jar','wasm','bin','dat','iso','dmg',
            'img','psd','ai','indd','sqlite','db','sqlite3','mdb','dbf',
            'ttf','otf','woff','woff2','eot',
        ]);
        if (isKnownBinaryMime(mimeType) || (ext && BINARY_EXTS.has(ext))) {
            try {
                const buffer = Buffer.from(content, 'base64');
                const finalMime = mimeType || 'application/octet-stream';
                return res.json(await persistBinaryFile(buffer, finalMime));
            } catch (binErr) {
                console.error('[Chat Upload] binary persist failed:', binErr);
                // Fall through to catch-all so the user still gets *something*.
            }
        }

        // Catch-all: Try to decode as text. If the decode produces many
        // U+FFFD replacement chars, the file is binary with an unknown or
        // wrong mimeType — persist the bytes via attachmentStore instead of
        // returning sanitized garbage.
        try {
            const buffer = Buffer.from(content, 'base64');
            let decoded = buffer.toString('utf8');

            // Binary sniff: legitimate UTF-8 text essentially never produces
            // U+FFFD. A binary file produces them in droves. Threshold: 50
            // absolute + 2% relative, so a stray U+FFFD in a long doc still
            // routes as text but a real binary triggers the persist path.
            const replacementCount = (decoded.match(/\uFFFD/g) || []).length;
            const isBinary = replacementCount > 50 && (replacementCount / decoded.length) > 0.02;

            if (isBinary) {
                const finalMime = mimeType || 'application/octet-stream';
                return res.json(await persistBinaryFile(buffer, finalMime));
            }

            decoded = sanitizeForModel(decoded);
            const originalLength = decoded.length;
            decoded = maybeOptimize(decoded);

            // Persist original bytes for a durable, reload-safe preview (see
            // the text-path note above). Best-effort.
            let attachmentId = null;
            try {
                const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
                attachmentId = await attachmentStore.save(ownerId, {
                    filename,
                    mimeType: mimeType || 'text/plain; charset=utf-8',
                    type: 'text',
                    bytes: buffer,
                });
            } catch (persistErr) {
                console.error('[Chat Upload] text persist (catch-all) failed:', persistErr);
            }

            return res.json({
                type: 'text',
                filename,
                ...(attachmentId ? { attachmentId } : {}),
                content: decoded,
                size: buffer.length,
                charCount: decoded.length,
                originalCharCount: originalLength,
                saved: originalLength - decoded.length
            });
        } catch (decodeError) {
            // Last-resort binary persist if even the UTF-8 decode threw
            // (shouldn't happen — Buffer.toString('utf8') is total — but
            // belt-and-suspenders).
            try {
                const buffer = Buffer.from(content, 'base64');
                const finalMime = mimeType || 'application/octet-stream';
                return res.json(await persistBinaryFile(buffer, finalMime));
            } catch (persistErr) {
                console.error('[Chat Upload] catch-all binary persist failed:', persistErr);
                return res.status(500).json({ error: 'Failed to process file: ' + (persistErr.message || decodeError.message) });
            }
        }
    } catch (error) {
        console.error('File upload error:', error);
        const detail = error.message || 'Unknown processing error';
        res.status(500).json({ error: `Failed to process file: ${detail}` });
    }
});

// ----- Attachment store endpoints --------------------------------------
// PDFs and structured spreadsheet rows live under
// /models/.modelserver/attachments/<userId>/<aid>/ (see attachmentStore.js).
// FilePreviewModal fetches via these routes when the persisted attachment
// has only an attachmentId, no inline dataUrl/sheets. Ownership is path-
// scoped: a user's bucket is /attachments/<userIdSafe>/, derived from
// auth — there's no cross-user lookup.
app.get('/api/attachments/:id', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }
    const { id } = req.params;
    if (!attachmentStore.isValidId(id)) {
        return res.status(400).json({ error: 'invalid attachment id' });
    }
    const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
    const loaded = await attachmentStore.loadBytes(ownerId, id);
    if (!loaded) {
        return res.status(404).json({ error: 'attachment not found' });
    }
    res.setHeader('Content-Type', loaded.meta.mimeType || 'application/octet-stream');
    res.setHeader('Content-Length', String(loaded.bytes.length));
    // Allow inline rendering (the chat UI reads this as a Blob via fetch).
    res.setHeader('Cache-Control', 'private, max-age=300');
    if (loaded.meta.filename) {
        res.setHeader('Content-Disposition', `inline; filename="${loaded.meta.filename.replace(/"/g, '')}"`);
    }
    res.end(loaded.bytes);
});

app.get('/api/attachments/:id/meta', requireAuth, async (req, res) => {
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }
    const { id } = req.params;
    if (!attachmentStore.isValidId(id)) {
        return res.status(400).json({ error: 'invalid attachment id' });
    }
    const ownerId = req.user?.id || req.apiKeyData?.id || 'default';
    const meta = await attachmentStore.loadMeta(ownerId, id);
    if (!meta) {
        return res.status(404).json({ error: 'attachment not found' });
    }
    res.json(meta);
});

// ============================================================================
// SIMPLIFIED WRAPPER API
// ============================================================================

// Simplified chat endpoint - wraps OpenAI API
app.post('/api/chat', requireAuth, async (req, res) => {
    const { message, model, temperature, maxTokens, stream } = req.body;

    // If streaming requested, delegate to stream endpoint
    if (stream) {
        return app._router.handle({ ...req, url: '/api/chat/stream', method: 'POST' }, res);
    }

    if (!message) {
        return res.status(400).json({ error: 'Message is required' });
    }

    // Check permission
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }

    try {
        // Find first running instance or use specified model
        let targetModel = model;
        let targetInstance = null;

        if (!targetModel) {
            // Use first running instance
            targetInstance = Array.from(modelInstances.values())[0];
            if (!targetInstance) {
                return res.status(400).json({ error: 'No running models. Please load a model first.' });
            }
            targetModel = targetInstance.modelName || 'default';
        } else {
            // Find specific model
            targetInstance = modelInstances.get(targetModel);
            if (!targetInstance) {
                return res.status(400).json({ error: `Model ${targetModel} is not running. Please load it first.` });
            }
        }

        // Use container name for Docker network communication
        const targetHost = targetInstance.containerName || `host.docker.internal`;
        const targetPort = targetInstance.internalPort || targetInstance.port;

        // Get context size configuration
        const contextSize = targetInstance.config?.contextSize || targetInstance.config?.maxModelLen || 4096;
        const contextShift = targetInstance.config?.contextShift || false;
        const disableThinking = targetInstance.config?.disableThinking || false;

        // Apply thinking mode control — only models that recognise the
        // /no_think control prefix (Qwen3, DeepSeek-R1) get it. Other
        // families would surface it as literal text in the response.
        let userContent = message;
        if (disableThinking && modelSupportsNoThinkPrefix(targetModel)) {
            userContent = `/no_think\n${message}`;
        }

        // Load system prompt for this model
        const systemPrompts = await loadSystemPrompts();
        const systemPrompt = systemPrompts[targetModel] || '';

        // Estimate token count (rough estimate: 1 token ≈ 4 characters)
        const estimateTokens = (text) => Math.ceil(text.length / 4);

        let systemTokens = systemPrompt ? estimateTokens(systemPrompt) : 0;
        let messageTokens = estimateTokens(userContent);
        let totalInputTokens = systemTokens + messageTokens;

        // Response reserve: input gets priority, response gets what's left (capped by max_tokens)
        const desiredResponseTokens = maxTokens || Math.floor(contextSize * 0.2);
        const minResponseReserve = Math.min(2048, Math.floor(contextSize * 0.2));
        const responseReserve = Math.max(
            minResponseReserve,
            Math.min(desiredResponseTokens, contextSize - totalInputTokens - 200)
        );
        const availableContextForInput = contextSize - responseReserve;

        // Check if input exceeds available context
        if (totalInputTokens > availableContextForInput) {
            // If context shift is enabled, we can truncate the message
            if (contextShift) {
                // Calculate how much we need to truncate
                const excessTokens = totalInputTokens - availableContextForInput;
                const targetMessageLength = userContent.length - (excessTokens * 4);

                if (targetMessageLength > 0) {
                    // Truncate message and add indicator
                    const truncatedMessage = userContent.substring(0, targetMessageLength) +
                        '\n\n[...input truncated due to context limit...]';
                    console.log(`Input truncated: ${userContent.length} -> ${truncatedMessage.length} chars`);

                    // Use truncated message
                    messageTokens = estimateTokens(truncatedMessage);
                    totalInputTokens = systemTokens + messageTokens;

                    // Make request to sglang instance
                    const messages = [];

                    if (systemPrompt) {
                        messages.push({ role: 'system', content: systemPrompt });
                    }
                    messages.push({ role: 'user', content: truncatedMessage });

                    const requestBody = {
                        model: targetModel,
                        messages: messages,
                        temperature: temperature || 0.7,
                        // Always clamped to contextSize - inputTokens to prevent
                        // sglang's "0 input tokens" SglangValidationError.
                        max_tokens: responseReserve,
                        stop: DEFAULT_STOP_STRINGS
                    };

                    const response = await axios.post(`http://${targetHost}:${targetPort}/v1/chat/completions`, requestBody);
                    const choice = response.data.choices[0];
                    const messageData = choice.message;
                    let reply = messageData.content || messageData.reasoning_content || '';

                    return res.json({
                        success: true,
                        response: reply,
                        model: targetModel,
                        tokens: response.data.usage,
                        reasoning: messageData.reasoning_content ? true : false,
                        truncated: true,
                        originalLength: userContent.length,
                        truncatedLength: truncatedMessage.length
                    });
                } else {
                    return res.status(400).json({
                        success: false,
                        error: `Input too large: Your message (${totalInputTokens} tokens) exceeds the model's context window (${contextSize} tokens). Please reduce input size or increase context size in model settings.`
                    });
                }
            } else {
                return res.status(400).json({
                    success: false,
                    error: `Not enough context window: Input requires ~${totalInputTokens} tokens but only ${availableContextForInput} available (context: ${contextSize}, reserved for response: ${responseReserve}). Enable context shifting or reduce input size.`
                });
            }
        }

        // Normal flow - input fits within context
        // Make request to sglang instance
        const messages = [];

        // Add system prompt if one exists
        if (systemPrompt) {
            messages.push({ role: 'system', content: systemPrompt });
        }

        // Add user message (with /no_think prepended if disableThinking is enabled)
        messages.push({ role: 'user', content: userContent });

        const requestBody = {
            model: targetModel,
            messages: messages,
            temperature: temperature || 0.7,
            // Always clamped to contextSize - inputTokens to prevent sglang's
            // "0 input tokens" SglangValidationError when the caller sends a
            // raw max_tokens value equal to contextSize.
            max_tokens: responseReserve,
            stop: DEFAULT_STOP_STRINGS
        };

        const response = await axios.post(`http://${targetHost}:${targetPort}/v1/chat/completions`, requestBody);

        // Extract response - handle reasoning models
        const choice = response.data.choices[0];
        const messageData = choice.message;
        let reply = messageData.content || '';

        // If content is empty but reasoning_content exists, use reasoning_content
        // This happens with reasoning models that only output thinking traces
        if (!reply && messageData.reasoning_content) {
            reply = messageData.reasoning_content;
        }

        // Handle different finish reasons with specific messages
        if (!reply) {
            if (choice.finish_reason === 'length') {
                return res.status(400).json({
                    success: false,
                    error: 'Not enough tokens: The response was truncated because the token limit was reached. Please increase maxTokens in your request.'
                });
            } else if (choice.finish_reason === 'content_filter') {
                return res.status(400).json({
                    success: false,
                    error: 'Content filtered: The response was blocked by content filtering.'
                });
            } else {
                return res.status(500).json({
                    success: false,
                    error: 'Empty response: The model returned no content. This may indicate an issue with the model or prompt.'
                });
            }
        }

        res.json({
            success: true,
            response: reply,
            model: targetModel,
            tokens: response.data.usage,
            reasoning: messageData.reasoning_content ? true : false,  // Indicate if reasoning was used
            contextSize: contextSize  // Include context window size for client tracking
        });
    } catch (error) {
        console.error('Chat error:', error.message);

        // Check for specific error types
        const errorMessage = error.response?.data?.error?.message || error.message || '';

        // Context window exceeded. "too many tokens" / "maximum context" are the
        // backend's phrasings for "the request doesn't fit the window" — that's a
        // CONTEXT overflow, NOT a rate limit. They used to fall through to the 429
        // branch below and surface as a misleading "rate limit exceeded" (e.g.
        // when an agent's tool catalog + history outgrew the model's window).
        if (/context|too long|exceed|too many tokens|maximum context|n_ctx|too large|doesn'?t fit|won'?t fit/i.test(errorMessage)) {
            return res.status(400).json({
                success: false,
                error: 'Context window exceeded: the request (messages + tools) is larger than the model\'s context window. Reduce the input — shorten the conversation, send fewer tools/skills, or load the model with a larger context size.'
            });
        }

        // Genuine rate limit (a per-key limit or an upstream throttle) — distinct
        // from a context overflow, which is handled above.
        if (/rate limit|too many requests/i.test(errorMessage)) {
            return res.status(429).json({
                success: false,
                error: 'Rate limit exceeded: too many requests in a short window. Wait and retry, or raise the key\'s rate limit.'
            });
        }

        res.status(500).json({
            success: false,
            error: 'Failed to get response from model',
            details: error.message
        });
    }
});

// Check continuation queue for a conversation
app.get('/api/chat/continuation/:conversationId', requireAuth, (req, res) => {
    const { conversationId } = req.params;
    const continuation = contentContinuationQueue.get(conversationId);

    if (!continuation) {
        return res.json({ hasMore: false });
    }

    const remainingTokens = Math.ceil(continuation.content.length / 4);
    const remainingChunks = continuation.totalChunks - continuation.processedChunks;

    res.json({
        hasMore: true,
        remainingTokens,
        remainingChunks,
        processedChunks: continuation.processedChunks,
        totalChunks: continuation.totalChunks,
        contextSize: continuation.contextSize,
        modelName: continuation.modelName
    });
});

// Clear continuation queue for a conversation
app.delete('/api/chat/continuation/:conversationId', requireAuth, (req, res) => {
    const { conversationId } = req.params;
    contentContinuationQueue.delete(conversationId);
    res.json({ success: true });
});

// Materialize this turn's attachments to the conversation's sandbox
// workspace at /workspace/uploads/<filename> so disk-read skills
// (read_file, list_directory, grep_code, outline_file, head_file,
// tail_file) can target them. The chat UI still embeds full content
// inline as === FILE N === blocks for immediate access; the disk copy
// is the long-term home that survives context-roll-off (memory
// compression, older-turn truncation) and gets wiped automatically
// when the conversation is deleted (DELETE /api/conversations/:id
// already calls deleteConversationWorkspace).
//
// `workspaceUserId` must follow the same convention as sandbox runs
// and the conv-delete handler — `req.userId ?? null` — so the bucket
// the upload lands in is the same bucket the wipe walks.
// `attachmentOwnerId` follows /api/chat/upload's ownerId
// (req.user?.id || req.apiKeyData?.id || 'default') so loadBytes()
// finds the right attachment row.
async function materializeAttachmentsToWorkspace(workspaceUserId, attachmentOwnerId, conversationId, attachments) {
    if (!conversationId || !Array.isArray(attachments) || attachments.length === 0) {
        return { written: 0 };
    }
    const sbRunner = require('./services/sandboxRunner');
    let ws;
    try {
        ws = await sbRunner.ensureWorkspace(workspaceUserId, conversationId);
    } catch (e) {
        return { written: 0, error: 'ensureWorkspace: ' + e.message };
    }
    const uploadsDir = path.join(ws.localInContainer, 'uploads');
    try {
        await fs.mkdir(uploadsDir, { recursive: true, mode: 0o777 });
        // Explicit chmod — umask may have stripped bits from the mkdir mode.
        // Sandbox container runs as a non-root user; the dir must be world-
        // writable (and the files world-readable below) for the sandbox to
        // open them after webapp (root) wrote them.
        await fs.chmod(uploadsDir, 0o777);
    } catch (e) {
        return { written: 0, error: 'mkdir uploads: ' + e.message };
    }

    const sanitizeName = (raw) => {
        let n = String(raw == null ? 'untitled' : raw);
        n = n.replace(/[\\/]/g, '_');           // no path separators
        n = n.replace(/^\.+/, '_');             // no leading-dot hidden files
        n = n.replace(/[\x00-\x1f\x7f]/g, '');  // no controls
        // Whitelist filename-safe characters; everything else collapses to _.
        n = n.replace(/[^A-Za-z0-9._\-()\[\]+ ]/g, '_');
        if (n.length > 200) n = n.slice(0, 200);
        return n || 'untitled';
    };

    let written = 0;
    const filesWritten = [];
    const errors = [];

    for (const att of attachments) {
        try {
            const safeName = sanitizeName(att && att.filename);
            const targetPath = path.join(uploadsDir, safeName);
            let wrote = false;

            // 1. Image: bytes from dataUrl (base64-encoded data URI).
            if (!wrote && att && att.type === 'image' && typeof att.dataUrl === 'string' && att.dataUrl.startsWith('data:')) {
                const m = att.dataUrl.match(/^data:[^;]+;base64,(.*)$/);
                if (m) {
                    const bytes = Buffer.from(m[1], 'base64');
                    await fs.writeFile(targetPath, bytes);
                    await fs.chmod(targetPath, 0o666);
                    wrote = true;
                }
            }

            // 2. attachmentStore-backed bytes — PDFs and (post-upload-fix) xlsx
            //    carry an attachmentId pointing at the bytes saved by
            //    /api/chat/upload. This preserves the original binary.
            if (!wrote && att && att.attachmentId) {
                try {
                    const loaded = await attachmentStore.loadBytes(attachmentOwnerId, att.attachmentId);
                    if (loaded && loaded.bytes && loaded.bytes.length > 0) {
                        await fs.writeFile(targetPath, loaded.bytes);
                        await fs.chmod(targetPath, 0o666);
                        wrote = true;
                    }
                } catch (_) { /* fall through to text fallback */ }
            }

            // 3. Text content fallback — paste-as-file, csv, json, code,
            //    eml/docx extract, xlsx-without-bytes, etc. The content the
            //    model would have inlined anyway, now on disk so disk-read
            //    skills can slice it without burning context.
            if (!wrote && att && typeof att.content === 'string' && att.content.length > 0) {
                await fs.writeFile(targetPath, att.content, { encoding: 'utf8' });
                await fs.chmod(targetPath, 0o666);
                wrote = true;
            }

            if (wrote) {
                written++;
                filesWritten.push(safeName);
            } else {
                errors.push(`${safeName}: no bytes/content available`);
            }
        } catch (e) {
            errors.push(`${(att && att.filename) || '?'}: ${e.message}`);
        }
    }

    return {
        written,
        filesWritten,
        errors: errors.length ? errors : undefined,
        uploadsDir: '/workspace/uploads',  // path as the sandbox sees it
        hostUploadsDir: uploadsDir,         // for debug logs
    };
}

// Streaming chat endpoint - Server-Sent Events (SSE)
app.post('/api/chat/stream', requireAuth, async (req, res) => {
    // Support both single message (legacy) and messages array (OpenAI compatible)
    const { message, messages: inputMessages, model, temperature, top_p, topP, maxTokens, max_tokens, conversationId, continueProcessing, chunkingStrategy } = req.body;
    const effectiveTopP = top_p !== undefined ? top_p : (topP !== undefined ? topP : 1.0);
    // Chunking strategy: 'auto' (default), 'map-reduce', 'truncate', 'none'
    const effectiveChunkingStrategy = chunkingStrategy || 'auto';

    // Check for continuation request
    if (continueProcessing && conversationId) {
        const continuation = contentContinuationQueue.get(conversationId);
        if (continuation) {
            // Process continuation by injecting remaining content
            console.log(`[Chat Stream] Processing continuation for conversation ${conversationId}`);
            // The remaining content will be added to the message below
        }
    }
    const effectiveMaxTokens = maxTokens || max_tokens;

    // Validate that either message or messages is provided
    if (!message && (!inputMessages || !Array.isArray(inputMessages) || inputMessages.length === 0)) {
        return res.status(400).json({ error: 'Message or messages array is required' });
    }

    // Check permission
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }

    try {
        // Find first running instance or use specified model
        let targetModel = model;
        let targetInstance = null;

        if (!targetModel) {
            // Use first running instance
            targetInstance = Array.from(modelInstances.values())[0];
            if (!targetInstance) {
                return res.status(400).json({ error: 'No running models. Please load a model first.' });
            }
            targetModel = targetInstance.modelName || 'default';
        } else {
            // Find specific model
            targetInstance = modelInstances.get(targetModel);
            if (!targetInstance) {
                return res.status(400).json({ error: `Model ${targetModel} is not running. Please load it first.` });
            }
        }

        // Use container name for Docker network communication
        const targetHost = targetInstance.containerName || `host.docker.internal`;
        const targetPort = targetInstance.internalPort || targetInstance.port;

        // Register the streaming job IMMEDIATELY so refresh / conversation
        // switch-back can see that work is in flight. Prep work (memory
        // compression, chunking prep, file parsing) can take many seconds and
        // the map-reduce path never reaches the old registration site at all,
        // so without this the UI shows an empty bubble during those phases.
        // The job's `phase` field is updated at each transition below.
        const userId = req.user?.id || req.apiKeyData?.id || 'default';
        // Memory identity is the ACCOUNT (memAccountId), decoupled from the
        // conversation owner above. All memory ops this turn — retrieval,
        // record_learning, experience recording, and extraction-on-save — use
        // this so an API-key chat shares the account persona and reads/writes
        // never split across two buckets.
        const chatMemId = memAccountId(req);
        const streamingConversationId = conversationId || req.body.conversationId;
        const streamStartTime = Date.now();
        const streamAbortController = new AbortController();
        if (streamingConversationId) {
            // Seed with a "Processing request" entry so a reconnecting client
            // starts from a rolling-credits feed with at least one line, not
            // a bare spinner — matches what a stay-connected client sees
            // immediately after hitting send.
            const seedEvent = {
                id: `evt-${streamStartTime}-0`,
                at: streamStartTime,
                status: 'active',
                icon: 'edit',
                text: 'Processing request',
                kind: 'setup',
            };
            activeStreamingJobs.set(streamingConversationId, {
                userId,
                memoryUserId: chatMemId,
                content: '',
                reasoning: '',
                startTime: streamStartTime,
                model: targetModel,
                clientConnected: true,
                phase: 'preparing',
                // Server-side mirror of the rolling-credits processing log
                // entries the client would otherwise only see via SSE. On
                // refresh / switch-back the client replays these so the
                // reconnected bubble shows the same rich feed (chunking,
                // map progress, synthesis) instead of a single stub line.
                events: [seedEvent],
                abortController: streamAbortController
            });
        }
        const updateJobPhase = (phase, extra) => {
            if (!streamingConversationId) return;
            const job = activeStreamingJobs.get(streamingConversationId);
            if (!job) return;
            job.phase = phase;
            if (extra) Object.assign(job, extra);
        };
        const pushJobEvent = (entry) => {
            if (!streamingConversationId) return;
            const job = activeStreamingJobs.get(streamingConversationId);
            if (!job) return;
            if (!Array.isArray(job.events)) job.events = [];
            job.events.push({
                id: `evt-${Date.now()}-${job.events.length}`,
                at: Date.now(),
                status: 'active',
                ...entry,
            });
            // Keep the log bounded — the UI only ever displays the last
            // ~5 anyway, but a runaway chunking operation could otherwise
            // let this grow unbounded for the lifetime of the job.
            if (job.events.length > 100) job.events.splice(0, job.events.length - 100);
        };
        const clearStreamingJob = () => {
            if (streamingConversationId) {
                activeStreamingJobs.delete(streamingConversationId);
            }
        };
        // Broadcast to the Process Logs tab so chat activity shows up in
        // real time alongside model / download logs. The completion log
        // already exists below; this covers the start and prep phases.
        // Modern arrow-style logs: `[Chat] <who> → <model> (N msgs)` mirrors
        // the Pi/API format so the Logs tab reads consistently across all
        // chat surfaces.
        const chatWho = req.user?.username || req.apiKeyData?.name || 'user';
        const logChatActivity = (message, level = 'info') => {
            try {
                broadcast({ type: 'log', message: `[Chat] ${message}`, level, targetUserId: req.userId });
            } catch (e) { /* broadcast is best-effort */ }
        };
        const msgCount = Array.isArray(req.body?.messages) ? req.body.messages.length : 0;
        logChatActivity(`${chatWho} → ${targetModel} (${msgCount} msgs)`);

        // Materialize this turn's attachments to /workspace/uploads/ before
        // the model runs, so a tool call in the very first iteration can see
        // the files on disk. Best-effort — failure here logs but does not
        // block the turn (the inline === FILE N === blocks in the user
        // message still carry the content).
        const incomingAttachments = Array.isArray(req.body?.attachments) ? req.body.attachments : [];
        if (incomingAttachments.length > 0 && streamingConversationId) {
            try {
                const workspaceUserId = req.userId ?? null;
                const result = await materializeAttachmentsToWorkspace(
                    workspaceUserId, userId, streamingConversationId, incomingAttachments
                );
                if (result.written > 0) {
                    const fileList = (result.filesWritten || []).join(', ');
                    const msg = `Materialized ${result.written} upload(s) to /workspace/uploads/ (${fileList})`;
                    console.log(`[Uploads→Workspace] conv ${streamingConversationId.slice(0, 8)}… — ${msg}`);
                    logChatActivity(msg);
                }
                if (result.errors && result.errors.length) {
                    console.warn(`[Uploads→Workspace] errors:`, result.errors);
                }
                if (result.error) {
                    console.warn(`[Uploads→Workspace] failed:`, result.error);
                }
            } catch (e) {
                console.warn('[Uploads→Workspace] exception:', e.message);
            }
        }

        // Get context size configuration
        const contextSize = targetInstance.config?.contextSize || targetInstance.config?.maxModelLen || 4096;
        const contextShift = targetInstance.config?.contextShift || false;
        const disableThinking = targetInstance.config?.disableThinking || false;

        // Estimate token count - use conservative ratio for safety.
        // Number-heavy content (prices, dates) tokenizes at ~2-3 chars/token, not 4.
        // Being conservative here ensures chunking triggers before the model API rejects with 400.
        // estimateTokens (the function) was lifted to module scope; the
        // CHARS_PER_TOKEN / SAFETY_MARGIN constants stay locally defined
        // because the chat-stream body recomputes char budgets from them
        // (see e.g. `availableForContent * CHARS_PER_TOKEN` below). They
        // must match CHAT_STREAM_CHARS_PER_TOKEN / CHAT_STREAM_SAFETY_MARGIN.
        const CHARS_PER_TOKEN = 3;
        const SAFETY_MARGIN = 1.1;

        // Build messages array based on input format
        let chatMessages = [];

        if (inputMessages && Array.isArray(inputMessages) && inputMessages.length > 0) {
            // Use provided messages array (OpenAI compatible format)
            // Ensure system prompt is first and only appears once
            const systemMessages = inputMessages.filter(msg => msg.role === 'system');
            const nonSystemMessages = inputMessages.filter(msg => msg.role !== 'system');

            // Add system prompt first (only the first one if multiple exist)
            if (systemMessages.length > 0) {
                chatMessages.push({ ...systemMessages[0] });
            }

            // Add remaining messages in order
            chatMessages.push(...nonSystemMessages.map(msg => ({ ...msg })));

            // Apply thinking mode control to the last user message if
            // disableThinking is enabled AND the model actually recognises
            // /no_think (Qwen3 / DeepSeek-R1). Other models echo it.
            if (disableThinking && modelSupportsNoThinkPrefix(targetModel)) {
                for (let i = chatMessages.length - 1; i >= 0; i--) {
                    if (chatMessages[i].role === 'user') {
                        const content = chatMessages[i].content;
                        if (typeof content === 'string') {
                            chatMessages[i].content = `/no_think\n${content}`;
                        } else if (Array.isArray(content)) {
                            // Vision format: prepend to the first text part
                            const textPartIdx = content.findIndex(p => p.type === 'text');
                            if (textPartIdx !== -1) {
                                content[textPartIdx].text = `/no_think\n${content[textPartIdx].text}`;
                            }
                        }
                        break;
                    }
                }
            }
        } else {
            // Legacy single message format
            let userContent = message;
            if (disableThinking && modelSupportsNoThinkPrefix(targetModel)) {
                userContent = `/no_think\n${message}`;
            }

            // Load system prompt for this model (only for legacy format)
            const systemPrompts = await loadSystemPrompts();
            const systemPrompt = systemPrompts[targetModel] || '';

            if (systemPrompt) {
                chatMessages.push({ role: 'system', content: systemPrompt });
            }
            chatMessages.push({ role: 'user', content: userContent });
        }

        // Inject ACCOUNT memories before counting tokens. We score the user's
        // whole memory (across every conversation) against the latest user
        // message, pack the top matches into a small token budget, and prepend
        // them as a system message. Anything injected here is part of the
        // normal token accounting — it flows through AIMem compression and the
        // chunking gate just like any other system context, so injection can't
        // blow up the context budget. Honors the chat "disable memory" toggle.
        let pendingMemoryNotice = null;
        // Held until SSE headers are flushed below; emits a chunking_progress
        // event so the UI knows the agentic flow took over.
        let pendingAgenticNotice = null;
        // Tool chip events for the agentic auto-prime (synthetic tool_executing
        // + tool_result pair). Flushed after SSE headers below so the UI shows
        // a real read_document_chunk chip instead of the model's first response
        // appearing to materialize from nowhere.
        let pendingPrimedToolEvents = null;
        try {
            const chatUserId = chatMemId;
            const rawConvId = conversationId || req.body.conversationId;
            // Same-conversation continuity boost only — retrieval itself is
            // account-wide and runs even for a brand-new conversation.
            const chatConvId = (rawConvId && /^[a-zA-Z0-9_-]+$/.test(rawConvId)) ? rawConvId : null;
            const memoryOff = await isMemoryDisabledForUser(chatUserId);
            if (!memoryOff) {
                // Find latest user message text for scoring
                let latestUserText = '';
                for (let i = chatMessages.length - 1; i >= 0; i--) {
                    if (chatMessages[i].role === 'user') {
                        const c = chatMessages[i].content;
                        latestUserText = typeof c === 'string'
                            ? c
                            : (Array.isArray(c) ? (c.find(p => p.type === 'text')?.text || '') : '');
                        break;
                    }
                }
                // The /no_think control prefix (prepended above for
                // disableThinking models) is a model control token, not user
                // intent — keep it out of memory retrieval and activity
                // classification (it dilutes the query embedding enough to
                // flip the semantic gate on borderline matches).
                latestUserText = latestUserText.replace(/^\/(no_)?think\b\s*/i, '');
                if (latestUserText) {
                    // Predict THIS turn's activity (from the ask + any attachments,
                    // before any tools run) so the matching experience memory is
                    // surfaced first — that's what front-loads the proven approach.
                    const activityHint = (classifyTurnActivity({
                        toolLabels: [],
                        userText: latestUserText,
                        attachmentKinds: deriveAttachmentKinds(req.body?.attachments),
                    }) || {}).activity || null;
                    const memoryResult = await retrieveRelevantMemories(
                        chatUserId, chatConvId, latestUserText,
                        // Budget scales with the model's window: a small-ctx
                        // model gets a lean persona block, a big one the full.
                        memoryBudgetForCtx(contextSize), { activityHint }
                    );
                    if (memoryResult && memoryResult.count) {
                        // Process-log which memories were pulled into THIS turn so
                        // the user can see what's shaping the response.
                        const preview = (memoryResult.previews || []).slice(0, 3)
                            .map(p => `“${p.slice(0, 70)}”`).join('; ');
                        logUserActivity(chatUserId,
                            `Memory: referenced ${memoryResult.count} memor${memoryResult.count === 1 ? 'y' : 'ies'} ` +
                            `(${memoryResult.procedures} experience, ${memoryResult.learnings} learning${memoryResult.learnings === 1 ? '' : 's'}, ` +
                            `${memoryResult.facts} fact${memoryResult.facts === 1 ? '' : 's'}, ${memoryResult.tokens} tok)` +
                            (memoryResult.linked ? ` +${memoryResult.linked} via links` : '') +
                            (activityHint ? ` [activity: ${activityHint}]` : '') +
                            (preview ? ` — ${preview}` : '')
                        );
                    }
                    if (memoryResult && memoryResult.block) {
                        const memoryBlock = memoryResult.block;
                        // Append to existing system message if one exists,
                        // otherwise insert a new system message at position 0.
                        if (chatMessages.length > 0 && chatMessages[0].role === 'system') {
                            const existing = chatMessages[0].content;
                            if (typeof existing === 'string') {
                                chatMessages[0] = {
                                    ...chatMessages[0],
                                    content: `${existing}\n\n${memoryBlock}`,
                                };
                            } else if (Array.isArray(existing)) {
                                // Vision-format system message — append a text part
                                // rather than dropping the memory block (mirrors
                                // injectPersonaForV1 / the KB nudge).
                                chatMessages[0] = {
                                    ...chatMessages[0],
                                    content: [...existing, { type: 'text', text: `\n\n${memoryBlock}` }],
                                };
                            }
                        } else {
                            chatMessages.unshift({ role: 'system', content: memoryBlock });
                        }
                        // Defer the SSE notice — at this point the response
                        // is still in pre-stream mode (headers not yet set).
                        // Stash the payload and emit it once SSE setup runs
                        // below.
                        pendingMemoryNotice = {
                            type: 'memory_injected',
                            count: memoryResult.count,
                            tokens: memoryResult.tokens,
                            linked: memoryResult.linked,
                            previews: memoryResult.previews,
                        };
                    }
                }
            }
        } catch (memErr) {
            console.warn(`[Memory] Retrieval failed (continuing without): ${memErr.message}`);
        }

        // Inject runtime context (today's date + tool-use guidance) into
        // the leading system message. Local models with older training
        // cutoffs otherwise refuse queries that reference recent dates,
        // and without this nudge they reach for find_patterns / get_timestamp
        // instead of web_search on "current news" style prompts.
        try {
            const prelude = buildChatRuntimePrelude();
            if (chatMessages.length > 0 && chatMessages[0].role === 'system') {
                const existing = chatMessages[0].content;
                if (typeof existing === 'string') {
                    chatMessages[0] = {
                        ...chatMessages[0],
                        content: `${prelude}\n\n${existing}`,
                    };
                } else if (Array.isArray(existing)) {
                    // Vision-format system message — prepend the prelude as a text
                    // part rather than dropping it.
                    chatMessages[0] = {
                        ...chatMessages[0],
                        content: [{ type: 'text', text: `${prelude}\n\n` }, ...existing],
                    };
                }
            } else {
                chatMessages.unshift({ role: 'system', content: prelude });
            }
        } catch (preludeErr) {
            console.warn(`[Chat] Runtime prelude injection failed: ${preludeErr.message}`);
        }

        // KB proactivity nudge — when the user has knowledge base(s), tell the
        // model to consult them for on-topic questions instead of answering only
        // from general knowledge. This is what makes the KB actually get used
        // (and visibly logged). Scoped to req.userId so it matches exactly which
        // KBs the search_knowledge_base tool can see. Best-effort.
        try {
            const kbList = await knowledgeBaseService.listKBs(req.userId || null).catch(() => []);
            const kbNudge = buildKbNudge(kbList);
            if (kbNudge) {
                if (chatMessages.length > 0 && chatMessages[0].role === 'system') {
                    const existing = chatMessages[0].content;
                    if (typeof existing === 'string') {
                        chatMessages[0] = { ...chatMessages[0], content: `${existing}\n\n${kbNudge}` };
                    } else if (Array.isArray(existing)) {
                        // Vision-format system message — append a text part.
                        chatMessages[0] = { ...chatMessages[0], content: [...existing, { type: 'text', text: `\n\n${kbNudge}` }] };
                    }
                } else {
                    chatMessages.unshift({ role: 'system', content: kbNudge });
                }
            }
        } catch (kbNudgeErr) {
            console.warn(`[Chat] KB nudge injection failed: ${kbNudgeErr.message}`);
        }

        // Calculate total tokens from all messages
        let totalInputTokens = 0;
        for (const msg of chatMessages) {
            totalInputTokens += estimateTokens(msg.content);
        }

        // Response reserve: input gets priority, response gets what's left (capped by max_tokens)
        // This matches OpenAI-compatible semantics where max_tokens caps generation length
        // but does NOT pre-emptively starve input of context space
        const desiredResponseTokens = effectiveMaxTokens || Math.max(2048, Math.floor(contextSize * 0.2));
        const minResponseReserve = Math.min(2048, Math.floor(contextSize * 0.2)); // Absolute minimum for a useful response
        // Give input what it needs, response gets the rest (at least minResponseReserve)
        const responseReserve = Math.max(
            minResponseReserve,
            Math.min(desiredResponseTokens, contextSize - totalInputTokens - 200)
        );
        const availableContextForInput = Math.max(512, contextSize - responseReserve);

        // Smart content chunking - use map-reduce for large content
        let contentTruncated = false;
        let remainingContent = null;
        let truncationInfo = null;
        let useMapReduce = false;
        let mapReduceContent = null;
        let mapReduceQuery = null;
        let mapReduceCondensationInfo = null;
        // Agentic chunking — content is stashed in the attachment store
        // with a TF-IDF index, the user message is rewritten with a small
        // documentId handle, and the model walks the doc via the native
        // query_document / read_document_chunk tools. Tracked here so the
        // map-reduce branch below can be skipped when this path runs.
        let useAgentic = false;
        let agenticInfo = null;

        console.log(`[Chat Stream] Context check: totalInputTokens=${totalInputTokens}, contextSize=${contextSize}, responseReserve=${responseReserve}, desiredResponse=${desiredResponseTokens}, availableForInput=${availableContextForInput}, needsChunking=${totalInputTokens > availableContextForInput}`);

        // AIMem compression: compress older conversation messages to save tokens
        // Controlled by compressMemory in model instance config (set at load time in model manager)
        // Normal trigger: 6+ non-system messages and input exceeds 60% of context
        // Early trigger: 3+ messages when input exceeds 80% of context (e.g. bulk file uploads
        // that fill most of the context — without early compression, context shifting would
        // drop the file-heavy messages entirely, leaving follow-ups with no file data)
        const compressMemory = targetInstance.config?.compressMemory || false;
        const aimemThreshold = Math.floor(availableContextForInput * 0.6);
        const aimemCriticalThreshold = Math.floor(availableContextForInput * 0.8);
        const nonSystemCount = chatMessages.filter(m => m.role !== 'system').length;
        const minMessages = totalInputTokens > aimemCriticalThreshold ? 3 : 6;
        let aimemApplied = false;
        let aimemStats = null;

        if (aimemEnabled && memoryCompressorService && compressMemory && nonSystemCount >= minMessages && totalInputTokens > aimemThreshold) {
            try {
                // Extract the current user query for relevance ranking
                let currentQuery = '';
                for (let i = chatMessages.length - 1; i >= 0; i--) {
                    if (chatMessages[i].role === 'user') {
                        const content = chatMessages[i].content;
                        currentQuery = typeof content === 'string' ? content :
                            (Array.isArray(content) ? (content.find(p => p.type === 'text')?.text || '') : '');
                        // Truncate long queries for relevance matching
                        if (currentQuery.length > 500) currentQuery = currentQuery.substring(0, 500);
                        break;
                    }
                }

                console.log(`[AIMem] Attempting compression: ${nonSystemCount} non-system messages (min: ${minMessages}), ${totalInputTokens} tokens (threshold: ${aimemThreshold}${minMessages < 6 ? ', early trigger: >80% context' : ''})`);

                // When few messages but high context usage (bulk file uploads), keep fewer
                // recent messages uncompressed so the file-heavy message gets compressed
                // instead of being skipped entirely then dropped by context shifting
                const keepRecent = nonSystemCount <= 4 ? Math.max(1, nonSystemCount - 2) : 4;
                const compressResult = await memoryCompressorService.compressConversation(
                    chatMessages, currentQuery, availableContextForInput,
                    { keepRecentCount: keepRecent, dedupThreshold: 0.45 }
                );

                if (compressResult.success && compressResult.compressed && compressResult.stats) {
                    chatMessages.length = 0;
                    chatMessages.push(...compressResult.messages);

                    // Recalculate token count after compression
                    totalInputTokens = 0;
                    for (const msg of chatMessages) {
                        totalInputTokens += estimateTokens(msg.content);
                    }

                    aimemApplied = true;
                    aimemStats = compressResult.stats;
                    console.log(`[AIMem] Compression applied: ${compressResult.stats.original_tokens} → ${compressResult.stats.compressed_tokens} tokens (${compressResult.stats.reduction_pct}% reduction). New total input: ${totalInputTokens}`);
                } else if (compressResult.error) {
                    console.log(`[AIMem] Compression skipped: ${compressResult.error}`);
                }
            } catch (aimemErr) {
                console.warn('[AIMem] Compression error (continuing without):', aimemErr.message);
            }
        }

        // Refine totalInputTokens with an exact /tokenize count. The char-based
        // estimator above uses ~3.3 effective chars/token, which works for
        // prose but undercounts dense content (unicode, code, base64) by 2x+
        // and lets messages past the chunking gate that then get rejected by
        // the backend with "request exceeds context size". /tokenize is cheap
        // (one POST) and authoritative for exactly this model's tokenizer.
        // **Snappy path**: skip the precall entirely when the estimate is
        // well below the ceiling. Dense-content undercount is at worst ~2.5×,
        // so anything under (available / 2.8) is unconditionally safe and
        // the precall would just add ~50-150ms of latency for no benefit.
        // For tiny chat turns (≪1k tokens) this avoids the roundtrip
        // entirely; for borderline-sized payloads we still tokenize.
        const tokenizeSafetyCutoff = Math.floor(availableContextForInput / 2.8);
        if (totalInputTokens >= tokenizeSafetyCutoff) try {
            const concatenatedText = chatMessages.map(m => {
                if (typeof m.content === 'string') return m.content;
                if (Array.isArray(m.content)) {
                    return m.content.filter(p => p.type === 'text').map(p => p.text || '').join('\n');
                }
                return '';
            }).join('\n');
            if (concatenatedText.length > 0) {
                const exactCount = await getExactTokenCount(targetHost, targetPort, concatenatedText);
                if (exactCount !== null && exactCount > 0) {
                    // Chat templates add per-message turn markers (role, separators).
                    // Budget ~8 tokens per message as a conservative overhead.
                    const templateOverhead = chatMessages.length * 8;
                    // Array-format messages count ~1000 tokens per image_url part.
                    let imageOverhead = 0;
                    for (const m of chatMessages) {
                        if (Array.isArray(m.content)) {
                            imageOverhead += m.content.filter(p => p.type === 'image_url').length * 1000;
                        }
                    }
                    const refinedTotal = exactCount + templateOverhead + imageOverhead;
                    if (Math.abs(refinedTotal - totalInputTokens) > 50) {
                        console.log(`[Chat Stream] Token count refined via /tokenize: estimate=${totalInputTokens} → exact=${refinedTotal} (raw=${exactCount}, template=${templateOverhead}, images=${imageOverhead})`);
                    }
                    totalInputTokens = refinedTotal;
                }
            }
        } catch (e) {
            console.warn(`[Chat Stream] /tokenize refinement failed: ${e.message} — using estimate ${totalInputTokens}`);
        }

        if (totalInputTokens > availableContextForInput) {
            // Find the last user message (which typically contains the large content)
            for (let i = chatMessages.length - 1; i >= 0; i--) {
                if (chatMessages[i].role === 'user') {
                    const msgContent = chatMessages[i].content;

                    // Handle both string and array content formats (vision models use array)
                    let textContent = '';
                    let isArrayFormat = false;
                    let textPartIdx = -1;

                    if (typeof msgContent === 'string') {
                        textContent = msgContent;
                    } else if (Array.isArray(msgContent)) {
                        // Vision format: find the text part
                        isArrayFormat = true;
                        textPartIdx = msgContent.findIndex(p => p.type === 'text');
                        if (textPartIdx !== -1) {
                            textContent = msgContent[textPartIdx].text || '';
                        }
                    }

                    if (!textContent) break;

                    // Use same estimation as estimateTokens for consistency
                    const contentTokens = Math.ceil((textContent.length / CHARS_PER_TOKEN) * SAFETY_MARGIN);

                    // Calculate how much we need to trim
                    const otherTokens = totalInputTokens - contentTokens;
                    const availableForContent = availableContextForInput - otherTokens - 200;

                    if (availableForContent > 0 && contentTokens > availableForContent) {
                        // Code content still goes through map-reduce — we just
                        // skip the CONDENSATION step inside it, because that's
                        // the part that drops whole sentences by relevance and
                        // mangles the payload. Raw overlapping chunks are fine
                        // for code; sentence-level relevance scoring is not.
                        const contentIsCode = looksLikeCode(textContent);
                        if (contentIsCode) {
                            console.log(`[Chat Stream] Content looks like code (${contentTokens} tokens) — map-reduce will run, condensation will be skipped`);
                            broadcast({
                                type: 'log',
                                level: 'info',
                                message: `Content looks like code (${contentTokens} tokens > ${availableForContent} available). Map-reduce enabled, condensation skipped.`
                            });
                        }

                        // Agentic flow: prefer this over map-reduce when enabled.
                        // We stash the full content in the attachment store with a
                        // TF-IDF index, replace the user-message text with a small
                        // documentId handle + tool-usage hint, and let the native
                        // tool loop run as normal. The model decides which chunks
                        // to read (or queries by relevance) instead of being fed a
                        // single condensed synthesis-of-summaries. Map-reduce
                        // remains the explicit-strategy fallback below.
                        const shouldUseAgentic = CHUNKING_CONFIG.enabled &&
                            CHUNKING_CONFIG.enableAgentic &&
                            (effectiveChunkingStrategy === 'auto' || effectiveChunkingStrategy === 'agentic') &&
                            contentTokens >= CHUNKING_CONFIG.minTokensForChunking;

                        if (shouldUseAgentic) {
                            try {
                                // Pull the user's actual question off the end of
                                // the blob the same way map-reduce does, so the
                                // rewritten message keeps it visible to the model.
                                const { queryPart: qExtracted, contentPart } = extractAgenticQuery(textContent);
                                let queryPart = qExtracted || 'Please analyze and summarize this content using query_document and read_document_chunk.';

                                const documentIndex = require('./services/documentIndex');
                                const indexed = await documentIndex.saveAndIndex(req.userId || userId, {
                                    text: contentPart,
                                    filename: `large-input-${Date.now()}.txt`,
                                    mimeType: 'text/plain; charset=utf-8',
                                    conversationId: streamingConversationId || null,
                                });

                                const sizeNote = describeUploadedSize(contentPart);
                                const handleNotice =
                                    `[SYSTEM: A large document was indexed for retrieval. You CANNOT see the full document body — it is NOT in your context.\n` +
                                    `documentId="${indexed.id}"  •  chunks=${indexed.totalChunks}  •  extracted text=${indexed.totalChars.toLocaleString()} chars${sizeNote}\n` +
                                    `(When asked the FILE's size, report the original file size in bytes/MB above — NOT the "extracted text … chars" count, which is the character length of the indexed text and is a different number.)\n\n` +
                                    `An auto-prime tool call has already been issued for you — a query_document relevance search when your question targets something specific (a section number, a value, a named thing), or read_document_chunk over the opening of the document for a whole-document task. Its result is the assistant→tool message pair immediately following this user turn — read it before you answer.\n\n` +
                                    `Tools available:\n` +
                                    `  • query_document(documentId, query, topK?) — TF-IDF top-K relevance search (use for "find X", "highest/lowest Y", "rows where Z", any targeted lookup)\n` +
                                    `  • read_document_chunk(documentId, chunkIndex, count?) — sequential read; the prior result returned a nextChunkIndex you can pass to continue\n\n` +
                                    `Rules:\n` +
                                    `1. Use the primed result. If it already answers the user's question, answer now and cite line ranges (e.g. "lines 1234–1287").\n` +
                                    `2. If you need more — to scan further chunks, look for specific terms, or cross-check — emit additional tool_calls. Do NOT narrate "let me call X"; just emit the tool_call.\n` +
                                    `3. NEVER fabricate document content. NEVER claim to have read chunks the tools did not return. If a fact isn't in a tool result you've actually received, call another tool to fetch it or say so.\n` +
                                    `4. Cite line ranges from tool results in your final answer.]\n\n`;

                                const rewritten = handleNotice + queryPart;
                                if (isArrayFormat && textPartIdx !== -1) {
                                    chatMessages[i].content[textPartIdx].text = rewritten;
                                } else {
                                    chatMessages[i].content = rewritten;
                                }

                                useAgentic = true;
                                agenticInfo = {
                                    documentId: indexed.id,
                                    totalChunks: indexed.totalChunks,
                                    totalChars: indexed.totalChars,
                                    query: queryPart,
                                };
                                pendingAgenticNotice = {
                                    type: 'chunking_progress',
                                    phase: 'agentic_indexed',
                                    mode: 'agentic',
                                    documentId: indexed.id,
                                    totalChunks: indexed.totalChunks,
                                    totalChars: indexed.totalChars,
                                    message: `Indexed ${indexed.totalChars.toLocaleString()} chars into ${indexed.totalChunks} chunks. Model will query/read via tools.`,
                                };
                                broadcast({
                                    type: 'log',
                                    level: 'info',
                                    message: `Agentic chunking: indexed ${indexed.totalChars.toLocaleString()} chars into ${indexed.totalChunks} chunks (documentId=${indexed.id})`
                                });

                                // Recalculate tokens — the rewritten message is tiny.
                                totalInputTokens = 0;
                                for (const msg of chatMessages) {
                                    totalInputTokens += estimateTokens(msg.content);
                                }
                                console.log(`[Chat Stream] Agentic chunking: indexed ${indexed.totalChars} chars into ${indexed.totalChunks} chunks (documentId=${indexed.id}); user message rewritten to handle. New totalInputTokens=${totalInputTokens}`);
                                break;
                            } catch (agenticErr) {
                                console.warn(`[Chat Stream] Agentic chunking failed (${agenticErr.message}) — falling back to map-reduce`);
                                useAgentic = false;
                                agenticInfo = null;
                                // Fall through to the map-reduce decision below.
                            }
                        }

                        // Determine if we should use map-reduce or simple truncation
                        const shouldUseMapReduce = !useAgentic && CHUNKING_CONFIG.enabled &&
                            (effectiveChunkingStrategy === 'auto' || effectiveChunkingStrategy === 'map-reduce') &&
                            contentTokens >= CHUNKING_CONFIG.minTokensForChunking;

                        if (shouldUseMapReduce) {
                            // Extract query from content (usually the last part or a question)
                            // Try to find a question or instruction at the end
                            const lines = textContent.split('\n');
                            let queryPart = '';
                            let contentPart = textContent;

                            // Look for common query patterns at the end
                            for (let j = lines.length - 1; j >= Math.max(0, lines.length - 10); j--) {
                                const line = lines[j].trim();
                                if (line.endsWith('?') || line.match(/^(please|can you|what|how|why|summarize|analyze|explain|describe|list|find|search)/i)) {
                                    queryPart = lines.slice(j).join('\n');
                                    contentPart = lines.slice(0, j).join('\n');
                                    break;
                                }
                            }

                            // If no clear query found, use a generic one
                            if (!queryPart) {
                                queryPart = 'Please analyze and summarize this content.';
                            }

                            // Apply content condensation if enabled, but NEVER on
                            // code content — condenseContent scores "sentences"
                            // by TF-IDF relevance to the query and drops ~60% of
                            // them. On code that shatters the payload (dropped
                            // declarations, missing function bodies) and the
                            // prepended "[Note: condensed ... N% reduction]"
                            // header leaks into the model's context where it
                            // reads it as evidence the user's input was cut.
                            let finalContent = contentPart;
                            let condensationInfo = null;

                            if (CHUNKING_CONFIG.enableCondensation && !contentIsCode) {
                                const condensationResult = condenseContent(
                                    contentPart,
                                    queryPart,
                                    CHUNKING_CONFIG.condensationRatio
                                );

                                if (condensationResult.reductionPercent > 10) {
                                    // Only use condensation if it provides meaningful reduction
                                    finalContent = condensationResult.condensed;
                                    condensationInfo = condensationResult;

                                    // Check if condensation avoided chunking entirely
                                    // IMPORTANT: Use the same estimateTokens function (3 chars/token, 1.1x margin)
                                    // as the overall context check to avoid divergence where estimateTokenCount
                                    // (4 chars/token) says "fits" but estimateTokens says "doesn't fit"
                                    const condensedTokens = estimateTokens(finalContent);
                                    if (condensedTokens <= availableForContent) {
                                        // Content now fits! No need for map-reduce
                                        console.log(`[Chat Stream] Condensation avoided chunking: ${contentTokens} -> ${condensedTokens} tokens`);

                                        // Update the message with condensed content
                                        const condensedNotice = `[Note: Content was condensed from ${condensationResult.originalLength.toLocaleString()} to ${condensationResult.condensedLength.toLocaleString()} chars (${condensationResult.reductionPercent}% reduction) using query-focused extraction.]\n\n${finalContent}`;

                                        if (isArrayFormat && textPartIdx !== -1) {
                                            chatMessages[i].content[textPartIdx].text = condensedNotice + '\n\n' + queryPart;
                                        } else {
                                            chatMessages[i].content = condensedNotice + '\n\n' + queryPart;
                                        }

                                        // Recalculate tokens - no longer need map-reduce
                                        totalInputTokens = 0;
                                        for (const msg of chatMessages) {
                                            totalInputTokens += estimateTokens(msg.content);
                                        }

                                        // Skip map-reduce since content now fits
                                        break;
                                    }

                                    console.log(`[Chat Stream] Content condensed: ${contentTokens} -> ${estimateTokens(finalContent)} tokens (${condensationResult.reductionPercent}% reduction)`);
                                }
                            }

                            useMapReduce = true;
                            mapReduceContent = finalContent;
                            mapReduceQuery = queryPart;
                            mapReduceCondensationInfo = condensationInfo;

                            console.log(`[Chat Stream] Using map-reduce chunking for ${estimateTokenCount(finalContent)} tokens (query: "${queryPart.substring(0, 50)}...")`);
                        } else {
                            // Fall back to simple truncation
                            const maxChars = Math.floor((availableForContent * CHARS_PER_TOKEN) / SAFETY_MARGIN);
                            const truncatedContent = textContent.substring(0, maxChars);
                            remainingContent = textContent.substring(maxChars);

                            const remainingTokens = estimateTokens(remainingContent);
                            const totalChunks = Math.ceil(contentTokens / availableForContent);

                            const truncatedWithNotice = truncatedContent +
                                `\n\n[CONTENT TRUNCATED - Processing chunk 1 of ${totalChunks}. ~${remainingTokens.toLocaleString()} tokens remaining. The model will be provided with a summary and the next chunk automatically.]`;

                            if (isArrayFormat && textPartIdx !== -1) {
                                chatMessages[i].content[textPartIdx].text = truncatedWithNotice;
                            } else {
                                chatMessages[i].content = truncatedWithNotice;
                            }

                            contentTruncated = true;
                            truncationInfo = {
                                totalTokens: contentTokens,
                                processedTokens: availableForContent,
                                remainingTokens,
                                totalChunks,
                                currentChunk: 1
                            };

                            totalInputTokens = 0;
                            for (const msg of chatMessages) {
                                totalInputTokens += estimateTokens(msg.content);
                            }

                            console.log(`[Chat Stream] Content truncated: Processing ${availableForContent} of ${contentTokens} tokens (chunk 1/${totalChunks})`);
                        }
                    }
                    break;
                }
            }

            // If still over limit after processing and not using map-reduce/agentic
            if (!useMapReduce && !useAgentic && totalInputTokens > availableContextForInput) {
                // Safety fallback: if chunking should have triggered but didn't (e.g. condensation
                // thought it fit but recalculation disagrees, OR availableForContent went negative
                // because the exact tokenizer reports denser tokenization than the char-based
                // estimator predicted — common with dense CSV/numeric content), fall back to
                // agentic indexing or map-reduce for the last user message rather than returning
                // a hard 400 error.
                const lastUserMsgIdx = chatMessages.map(m => m.role).lastIndexOf('user');
                const lastUserMsg = lastUserMsgIdx >= 0 ? chatMessages[lastUserMsgIdx] : null;
                const lastUserIsArray = Array.isArray(lastUserMsg?.content);
                const lastUserTextPartIdx = lastUserIsArray
                    ? lastUserMsg.content.findIndex(p => p.type === 'text')
                    : -1;
                const lastUserContent = typeof lastUserMsg?.content === 'string'
                    ? lastUserMsg.content
                    : (lastUserIsArray
                        ? (lastUserTextPartIdx >= 0 ? (lastUserMsg.content[lastUserTextPartIdx].text || '') : '')
                        : '');
                const lastUserTokens = estimateTokens(lastUserContent);

                // Try agentic first (same priority as the inner gate). Only
                // falls through to map-reduce if agentic is disabled, the
                // strategy is explicitly map-reduce, or saveAndIndex throws.
                const fallbackToAgentic = CHUNKING_CONFIG.enabled &&
                    CHUNKING_CONFIG.enableAgentic &&
                    lastUserTokens >= CHUNKING_CONFIG.minTokensForChunking &&
                    (effectiveChunkingStrategy === 'auto' || effectiveChunkingStrategy === 'agentic') &&
                    lastUserMsg;

                let agenticFallbackOk = false;
                if (fallbackToAgentic) {
                    try {
                        const { queryPart: qExtracted, contentPart } = extractAgenticQuery(lastUserContent);
                        let queryPart = qExtracted || 'Please analyze and summarize this content using query_document and read_document_chunk.';

                        const documentIndex = require('./services/documentIndex');
                        const indexed = await documentIndex.saveAndIndex(req.userId || userId, {
                            text: contentPart,
                            filename: `large-input-${Date.now()}.txt`,
                            mimeType: 'text/plain; charset=utf-8',
                            conversationId: streamingConversationId || null,
                        });

                        const sizeNote = describeUploadedSize(contentPart);
                        const handleNotice =
                            `[A large document (extracted text=${indexed.totalChars.toLocaleString()} chars, ${indexed.totalChunks} chunks${sizeNote}) was indexed for retrieval.\n` +
                            `documentId="${indexed.id}"\n` +
                            `(When asked the FILE's size, report the original file size in bytes/MB above — NOT the "extracted text … chars" count, which is the character length of the indexed text, a different number.)\n\n` +
                            `You CANNOT see the document body in your context. To answer the question below, walk the document with these tools:\n` +
                            `  • query_document(documentId="${indexed.id}", query="...") — top-K relevant chunks (use first for targeted questions)\n` +
                            `  • read_document_chunk(documentId="${indexed.id}", chunkIndex=N, count=1..5) — sequential read\n\n` +
                            `Strategy: for "find/extract/compare X" questions, call query_document with each aspect as a separate query; ` +
                            `for "summarize the whole document", call read_document_chunk linearly from chunkIndex=0 and accumulate facts. ` +
                            `Cite line ranges from the tool results when answering. Do NOT fabricate content the tools didn't return.]\n\n`;

                        const rewritten = handleNotice + queryPart;
                        if (lastUserIsArray && lastUserTextPartIdx >= 0) {
                            chatMessages[lastUserMsgIdx].content[lastUserTextPartIdx].text = rewritten;
                        } else {
                            chatMessages[lastUserMsgIdx].content = rewritten;
                        }

                        useAgentic = true;
                        agenticFallbackOk = true;
                        agenticInfo = {
                            documentId: indexed.id,
                            totalChunks: indexed.totalChunks,
                            totalChars: indexed.totalChars,
                            query: queryPart,
                        };
                        pendingAgenticNotice = {
                            type: 'chunking_progress',
                            phase: 'agentic_indexed',
                            mode: 'agentic',
                            documentId: indexed.id,
                            totalChunks: indexed.totalChunks,
                            totalChars: indexed.totalChars,
                            message: `Indexed ${indexed.totalChars.toLocaleString()} chars into ${indexed.totalChunks} chunks. Model will query/read via tools.`,
                        };
                        broadcast({
                            type: 'log',
                            level: 'info',
                            message: `Agentic chunking (fallback path): indexed ${indexed.totalChars.toLocaleString()} chars into ${indexed.totalChunks} chunks (documentId=${indexed.id})`
                        });

                        totalInputTokens = 0;
                        for (const msg of chatMessages) {
                            totalInputTokens += estimateTokens(msg.content);
                        }
                        console.log(`[Chat Stream] Agentic fallback: indexed ${indexed.totalChars} chars into ${indexed.totalChunks} chunks (documentId=${indexed.id}). New totalInputTokens=${totalInputTokens}`);
                    } catch (agenticErr) {
                        console.warn(`[Chat Stream] Agentic fallback failed (${agenticErr.message}) — trying map-reduce`);
                        useAgentic = false;
                        agenticInfo = null;
                        pendingAgenticNotice = null;
                    }
                }

                if (!agenticFallbackOk && CHUNKING_CONFIG.enabled && lastUserTokens >= CHUNKING_CONFIG.minTokensForChunking &&
                    (effectiveChunkingStrategy === 'auto' || effectiveChunkingStrategy === 'map-reduce')) {
                    console.log(`[Chat Stream] Fallback to map-reduce: condensation did not reduce enough (totalInputTokens=${totalInputTokens}, available=${availableContextForInput})`);
                    useMapReduce = true;
                    mapReduceContent = lastUserContent;
                    mapReduceQuery = mapReduceQuery || 'Please analyze and summarize this content.';
                } else if (!agenticFallbackOk && contextShift && totalInputTokens > availableContextForInput) {
                    // CONTEXT SHIFTING: Remove oldest messages (except system) until input fits
                    // Preserve: system messages, last user message, and as many recent messages as possible
                    console.log(`[Chat Stream] Context shift enabled - trimming ${totalInputTokens} tokens to fit ${availableContextForInput}`);

                    // Separate system messages from conversation messages
                    const systemMessages = chatMessages.filter(m => m.role === 'system');
                    const conversationMessages = chatMessages.filter(m => m.role !== 'system');

                    // Calculate tokens used by system messages (always kept)
                    let systemTokens = 0;
                    for (const msg of systemMessages) {
                        systemTokens += estimateTokens(msg.content);
                    }

                    // Available for conversation after system messages
                    const availableForConversation = availableContextForInput - systemTokens;

                    if (availableForConversation <= 0) {
                        clearStreamingJob();
                        return res.status(400).json({
                            success: false,
                            error: `System prompt alone exceeds context window. Please reduce system prompt size.`
                        });
                    }

                    // Keep messages from the end (most recent) until we run out of space
                    const keptMessages = [];
                    let conversationTokens = 0;

                    // Start from the most recent message and work backwards
                    for (let i = conversationMessages.length - 1; i >= 0; i--) {
                        const msg = conversationMessages[i];
                        const msgTokens = estimateTokens(msg.content);

                        if (conversationTokens + msgTokens <= availableForConversation) {
                            keptMessages.unshift(msg); // Add to front to maintain order
                            conversationTokens += msgTokens;
                        } else if (i === conversationMessages.length - 1) {
                            // Last user message is too large - truncate it
                            const excessTokens = (conversationTokens + msgTokens) - availableForConversation;
                            const targetLength = Math.max(100, msg.content.length - (excessTokens * 4));

                            if (typeof msg.content === 'string') {
                                const truncatedContent = msg.content.substring(0, targetLength) +
                                    '\n\n[...input truncated due to context limit...]';
                                keptMessages.unshift({ ...msg, content: truncatedContent });
                                conversationTokens += estimateTokens(truncatedContent);
                            } else {
                                // Array format (vision) - truncate text part
                                const newContent = msg.content.map(part => {
                                    if (part.type === 'text' && part.text) {
                                        return {
                                            type: 'text',
                                            text: part.text.substring(0, targetLength) + '\n\n[...truncated...]'
                                        };
                                    }
                                    return part;
                                });
                                keptMessages.unshift({ ...msg, content: newContent });
                                conversationTokens += estimateTokens(targetLength);
                            }
                        }
                        // else: skip this older message (context shift removes it)
                    }

                    // If we couldn't keep any messages, error out
                    if (keptMessages.length === 0) {
                        clearStreamingJob();
                        return res.status(400).json({
                            success: false,
                            error: `Input too large even with context shifting. Please reduce message size or clear conversation history.`
                        });
                    }

                    // Rebuild chatMessages with system messages first, then kept conversation
                    const removedCount = conversationMessages.length - keptMessages.length;
                    chatMessages.length = 0;
                    chatMessages.push(...systemMessages, ...keptMessages);

                    // Recalculate total tokens
                    totalInputTokens = systemTokens + conversationTokens;

                    console.log(`[Chat Stream] Context shift removed ${removedCount} old messages. New total: ${totalInputTokens} tokens`);
                } else if (!agenticFallbackOk && !useMapReduce) {
                    clearStreamingJob();
                    return res.status(400).json({
                        success: false,
                        error: `Not enough context window: Input requires ~${totalInputTokens} tokens but only ${availableContextForInput} available (context: ${contextSize}, reserved for response: ${responseReserve}). Enable context shifting or reduce input size.`
                    });
                }
            }
        }

        // Agentic auto-prime: when the agentic flow activated, auto-invoke
        // read_document_chunk(0, 5) and inject the result as a synthetic
        // assistant tool_call + tool message pair. This puts the model in
        // tool-result-aware mode from token zero — instead of opening with
        // prose like "let me call read_document_chunk", it opens by
        // continuing from the tool result we already provided. Concretely
        // fixes the failure mode where smaller / less tool-trained models
        // narrate tool usage without ever emitting a tool_calls delta.
        //
        // Side effects: increases initial input by ~12K chars (the primed
        // chunk content) but the rewritten user message is tiny so total
        // headroom remains comfortable. The injected assistant message
        // does NOT have content (only tool_calls), matching the OpenAI
        // protocol shape the model itself produces on a tool round.
        let agenticPrimeInfo = null;
        if (useAgentic && agenticInfo && agenticInfo.documentId) {
            try {
                const documentIndex = require('./services/documentIndex');
                const docId = agenticInfo.documentId;
                const targeted = isTargetedDocQuery(agenticInfo.query);

                // Build the prime as either a query_document relevance search
                // (targeted questions) or a read_document_chunk over the
                // document opening (whole-document tasks). Priming a targeted
                // question with the opening chunks makes the model summarise
                // the overview instead of answering — query-priming puts the
                // relevant chunk in context from token zero so the answer
                // lands on the FIRST turn instead of only after the user
                // re-asks. Falls back to the opening-chunk prime when not
                // targeted, or when the query surfaces no matches.
                let primeName = null;
                let primeArgs = null;
                let primeToolContent = null;   // JSON string for the tool message
                let primeResult = null;        // trimmed object for the SSE result chip
                let primePreview = null;
                let primeLog = '';
                let primeChunksRead = 0;
                let primeNextChunkIndex = null;

                if (targeted) {
                    const q = String(agenticInfo.query || '').slice(0, 500);
                    const queried = await documentIndex.queryDocument(
                        req.userId || userId,
                        docId,
                        q,
                        { topK: 5, activeDocumentId: docId }
                    );
                    if (queried && Array.isArray(queried.matches) && queried.matches.length > 0) {
                        primeName = 'query_document';
                        primeArgs = JSON.stringify({ documentId: docId, query: q, topK: 5 });
                        primeToolContent = JSON.stringify(queried);
                        primeResult = {
                            documentId: queried.documentId,
                            totalChunks: queried.totalChunks,
                            query: queried.query,
                            matches: (queried.matches || []).map(mt => ({
                                chunkIndex: mt.chunkIndex,
                                score: mt.score,
                                lineRange: mt.lineRange,
                            })),
                        };
                        primePreview = JSON.stringify(primeResult).slice(0, 4000);
                        primeChunksRead = queried.matches.length;
                        primeLog = `query_document(query=${JSON.stringify(q)}, topK=5) → ${queried.matches.length} matches`;
                    }
                }

                if (!primeName) {
                    const primeCount = Math.min(5, agenticInfo.totalChunks || 1);
                    const primed = await documentIndex.readChunk(
                        req.userId || userId,
                        docId,
                        0,
                        { count: primeCount }
                    );
                    if (primed && Array.isArray(primed.chunks) && primed.chunks.length > 0) {
                        primeName = 'read_document_chunk';
                        primeArgs = JSON.stringify({ documentId: docId, chunkIndex: 0, count: primeCount });
                        primeToolContent = JSON.stringify(primed);
                        primeResult = {
                            documentId: primed.documentId,
                            totalChunks: primed.totalChunks,
                            nextChunkIndex: primed.nextChunkIndex,
                            chunks: (primed.chunks || []).map(c => ({
                                chunkIndex: c.chunkIndex,
                                lineRange: c.lineRange,
                            })),
                        };
                        primePreview = JSON.stringify({
                            documentId: primed.documentId,
                            totalChunks: primed.totalChunks,
                            nextChunkIndex: primed.nextChunkIndex,
                            chunks: (primed.chunks || []).map(c => ({
                                chunkIndex: c.chunkIndex,
                                lineRange: c.lineRange,
                                textLength: c.text.length,
                            })),
                        }).slice(0, 4000);
                        primeChunksRead = primed.chunks.length;
                        primeNextChunkIndex = primed.nextChunkIndex;
                        primeLog = `read_document_chunk(0, ${primeCount}) → ${primed.chunks.length} chunks, nextChunkIndex=${primed.nextChunkIndex}`;
                    }
                }

                if (primeName) {
                    const primeCallId = `call_agentic_prime_${Date.now()}`;
                    const primeAssistantMsg = {
                        role: 'assistant',
                        content: '',
                        tool_calls: [{
                            id: primeCallId,
                            type: 'function',
                            function: { name: primeName, arguments: primeArgs },
                        }],
                    };
                    const primeToolMsg = {
                        role: 'tool',
                        tool_call_id: primeCallId,
                        name: primeName,
                        content: primeToolContent,
                    };
                    // Insert after the (rewritten) last user message. Find
                    // it again here — the for-loop above and the safety-net
                    // both leave the rewritten user message at the same
                    // index, but it's cheaper to re-locate than to plumb.
                    const lastUserIdx = chatMessages.map(m => m.role).lastIndexOf('user');
                    if (lastUserIdx >= 0) {
                        chatMessages.splice(lastUserIdx + 1, 0, primeAssistantMsg, primeToolMsg);
                        agenticPrimeInfo = {
                            callId: primeCallId,
                            tool: primeName,
                            chunksRead: primeChunksRead,
                            nextChunkIndex: primeNextChunkIndex,
                        };
                        // Surface the prime as real tool_executing + tool_result
                        // SSE events so the chat UI renders a chip identical to
                        // a model-issued call. Held in pendingPrimedToolEvents
                        // and flushed once SSE headers are written below.
                        pendingPrimedToolEvents = [
                            {
                                type: 'tool_executing',
                                tool_call_id: primeCallId,
                                name: primeName,
                                arguments: primeArgs,
                                source: 'agentic_auto_prime',
                            },
                            {
                                type: 'tool_result',
                                tool_call_id: primeCallId,
                                name: primeName,
                                preview: primePreview,
                                result: primeResult,
                            },
                        ];
                        // Refresh totalInputTokens so any downstream check
                        // (e.g. context-shift safety net) accounts for the
                        // primed payload.
                        totalInputTokens = 0;
                        for (const msg of chatMessages) {
                            totalInputTokens += estimateTokens(msg.content);
                        }
                        console.log(`[Chat Stream] Agentic auto-prime: injected ${primeLog}. New totalInputTokens=${totalInputTokens}`);
                    }
                }
            } catch (primeErr) {
                console.warn(`[Chat Stream] Agentic auto-prime failed (continuing without): ${primeErr.message}`);
            }
        }

        // Set up SSE headers
        res.setHeader('Content-Type', 'text/event-stream');
        res.setHeader('Cache-Control', 'no-cache');
        res.setHeader('Connection', 'keep-alive');
        res.setHeader('X-Accel-Buffering', 'no'); // Disable nginx buffering

        // Disable timeouts for SSE streaming - model responses can take minutes
        // Node.js default is 2 minutes which kills long-running streams
        req.setTimeout(0);
        res.setTimeout(0);

        // Flush any deferred pre-stream notices now that SSE is live.
        // Announce reasoning mode so the client can suppress the Thinking
        // dropdown even if a leaked <think>...</think> survives the per-delta
        // scrub (tags split across SSE chunks re-assemble on the client).
        if (disableThinking) {
            try { res.write(`data: ${JSON.stringify({ type: 'reasoning_mode', disabled: true })}\n\n`); } catch {}
        }
        if (pendingMemoryNotice) {
            try { res.write(`data: ${JSON.stringify(pendingMemoryNotice)}\n\n`); } catch {}
            pendingMemoryNotice = null;
        }
        if (pendingAgenticNotice) {
            try { res.write(`data: ${JSON.stringify(pendingAgenticNotice)}\n\n`); } catch {}
            pendingAgenticNotice = null;
        }
        if (pendingPrimedToolEvents) {
            for (const evt of pendingPrimedToolEvents) {
                try { res.write(`data: ${JSON.stringify(evt)}\n\n`); } catch {}
            }
            pendingPrimedToolEvents = null;
        }
        if (req.socket) req.socket.setTimeout(0);

        // SSE keepalive: emit a comment line every 25s for as long as the
        // response is open. Slow reasoning models can spend several minutes
        // on first-token latency, during which the server sends no data.
        // Clients with their own data-activity timeouts (CLI agents,
        // browsers/proxies/LBs that drop idle SSE
        // connections) would otherwise kill the socket while the server is
        // legitimately working. SSE comment lines start with ':' and are
        // ignored by EventSource parsers, but they still count as bytes on
        // the wire, resetting any inactivity timer.
        const heartbeatInterval = setInterval(() => {
            try {
                if (!res.writableEnded) res.write(': heartbeat\n\n');
            } catch (e) { /* socket closing */ }
        }, 25000);
        const stopHeartbeat = () => {
            if (heartbeatInterval) clearInterval(heartbeatInterval);
        };
        res.on('close', stopHeartbeat);
        res.on('finish', stopHeartbeat);

        // =====================================================================
        // MAP-REDUCE PROCESSING PATH
        // =====================================================================
        // If content exceeds context window and map-reduce is enabled,
        // process chunks in parallel and synthesize the response
        if (useMapReduce && mapReduceContent && mapReduceQuery) {
            console.log(`[Chat Stream] Starting map-reduce processing...`);
            updateJobPhase('chunking');
            logChatActivity(`Map-reduce started: ${estimateTokens(mapReduceContent).toLocaleString()} tokens`);

            // Send initial progress event with token and condensation details
            const mapReduceTokens = estimateTokens(mapReduceContent);
            const progressEvent = {
                type: 'chunking_progress',
                phase: 'starting',
                totalTokens: mapReduceTokens,
                contentLength: mapReduceContent.length,
                condensation: mapReduceCondensationInfo ? {
                    originalLength: mapReduceCondensationInfo.originalLength,
                    condensedLength: mapReduceCondensationInfo.condensedLength,
                    reductionPercent: mapReduceCondensationInfo.reductionPercent,
                } : null,
                message: 'Splitting content into chunks for parallel processing...'
            };
            res.write(`data: ${JSON.stringify(progressEvent)}\n\n`);
            // Mirror the 'starting' entry to the server-side event log so
            // a reconnected client sees the same opening line as a client
            // that stayed connected.
            {
                let startMsg = `Preparing ${mapReduceTokens.toLocaleString()} tokens for parallel processing...`;
                if (mapReduceCondensationInfo) {
                    startMsg += ` (condensed ${mapReduceCondensationInfo.reductionPercent}%)`;
                }
                pushJobEvent({ icon: 'layers', text: startMsg, kind: 'chunk_start' });
            }

            // Build the context messages to forward to map-reduce:
            //   - ALL system messages
            //   - Recent user/assistant turns EXCLUDING the large message
            //     we're chunking (it's in mapReduceContent already)
            //
            // Without this, follow-up questions in a multi-turn
            // conversation lose all prior context the moment chunking
            // triggers — the user sees "the context is lost".
            //
            // Budget prior turns to ~15% of the context window so the
            // chunks still have room to work. Walk the message list
            // newest-first and include turns until we hit the budget.
            const lastUserIdx = chatMessages.map(m => m.role).lastIndexOf('user');
            const priorBudgetTokens = Math.max(0, Math.floor(contextSize * 0.15));
            const systemMsgs = chatMessages.filter(m => m.role === 'system');
            const nonSystemMsgs = chatMessages
                .map((m, idx) => ({ m, idx }))
                .filter(({ m, idx }) => m.role !== 'system' && idx !== lastUserIdx);

            const priorTurns = [];
            let priorTokensUsed = 0;
            for (let i = nonSystemMsgs.length - 1; i >= 0; i--) {
                const { m } = nonSystemMsgs[i];
                const msgTokens = estimateTokens(m.content);
                if (priorTokensUsed + msgTokens > priorBudgetTokens && priorTurns.length > 0) break;
                priorTurns.unshift(m);
                priorTokensUsed += msgTokens;
                if (priorTokensUsed >= priorBudgetTokens) break;
            }

            const priorMsgs = [...systemMsgs, ...priorTurns];
            if (priorTurns.length > 0) {
                console.log(`[Chat Stream] Map-reduce: forwarding ${priorTurns.length} prior turns (${priorTokensUsed} tokens) + ${systemMsgs.length} system message(s)`);
            }

            try {
                const mapReduceResult = await processWithMapReduce({
                    targetHost,
                    targetPort,
                    model: targetModel,
                    largeContent: mapReduceContent,
                    originalQuery: mapReduceQuery,
                    priorMessages: priorMsgs,
                    contextSize,
                    temperature: temperature || 0.7,
                    topP: effectiveTopP,
                    maxTokens: responseReserve,
                    onProgress: (progress) => {
                        // Mirror progress into the persisted job so a reconnected
                        // client (refresh / switch-back) can show the current
                        // map-reduce phase without the SSE stream.
                        const phaseMap = {
                            chunking: 'chunking',
                            map: 'mapping',
                            reduce: 'synthesizing',
                            complete: 'generating',
                        };
                        updateJobPhase(phaseMap[progress.phase] || 'mapping', { progress });

                        // Mirror to the server-side event log so the
                        // reconnected client's ProcessingLogFeed matches
                        // exactly what a continuously-connected client
                        // would have seen. The message text duplicates
                        // the client-side formatting in ChatContainer.jsx.
                        const {
                            phase: pPhase,
                            totalChunks = 0,
                            totalTokens = 0,
                            completedChunks = 0,
                            failedChunks = 0,
                            elapsedMs = 0,
                            retrying,
                            chunkTokens,
                        } = progress;
                        const elapsed = elapsedMs > 0 ? `${Math.round(elapsedMs / 1000)}s` : '';
                        const tokenStr = totalTokens ? `${totalTokens.toLocaleString()} tokens` : '';
                        const chunkWord = (n) => n === 1 ? 'chunk' : 'chunks';
                        if (pPhase === 'chunking') {
                            let msg = `Splitting into ${totalChunks} ${chunkWord(totalChunks)}`;
                            if (tokenStr) msg += ` — ${tokenStr}`;
                            if (chunkTokens) msg += ` (~${chunkTokens.toLocaleString()} tokens/chunk)`;
                            pushJobEvent({ icon: 'scissors', text: msg, kind: 'chunk_split' });
                            logChatActivity(msg);
                        } else if (pPhase === 'map') {
                            const done = completedChunks + failedChunks;
                            const pct = totalChunks > 0 ? Math.round((done / totalChunks) * 100) : 0;
                            let msg;
                            if (retrying) {
                                msg = `Retrying chunk ${retrying.chunk}/${totalChunks} (attempt ${retrying.attempt}/${retrying.maxRetries}) — ${elapsed}`;
                            } else if (done === 0) {
                                msg = `Analyzing ${totalChunks} ${chunkWord(totalChunks)} in parallel`;
                                if (tokenStr) msg += ` — ${tokenStr} total`;
                            } else {
                                msg = `Analyzed ${completedChunks}/${totalChunks} ${chunkWord(totalChunks)} (${pct}%)`;
                                if (failedChunks) msg += ` — ${failedChunks} failed`;
                                if (elapsed) msg += ` — ${elapsed}`;
                            }
                            pushJobEvent({ icon: 'cpu', text: msg, kind: 'chunk_map' });
                        } else if (pPhase === 'reduce') {
                            let msg = `Synthesizing ${completedChunks} ${chunkWord(completedChunks)} into final response`;
                            if (elapsed) msg += ` — ${elapsed} elapsed`;
                            pushJobEvent({ icon: 'combine', text: msg, kind: 'chunk_reduce' });
                            logChatActivity(msg);
                        } else if (pPhase === 'complete') {
                            const msg = `Streaming synthesized response${elapsed ? ` — completed in ${elapsed}` : ''}`;
                            pushJobEvent({ icon: 'sparkles', text: msg, kind: 'chunk_complete' });
                        }

                        // Stream progress events to client
                        const event = {
                            type: 'chunking_progress',
                            ...progress
                        };
                        try {
                            res.write(`data: ${JSON.stringify(event)}\n\n`);
                        } catch (e) {
                            // Client disconnected
                        }
                    }
                });

                if (mapReduceResult.success) {
                    updateJobPhase('generating');
                    // Stream the synthesized response token by token for consistent UX
                    const words = mapReduceResult.response.split(/(\s+)/);
                    let fullResponse = '';

                    for (const word of words) {
                        fullResponse += word;
                        // Mirror streamed content into the job so a reconnected
                        // client can pick up the synthesized response mid-flow.
                        updateJobPhase('generating', { content: fullResponse });
                        const event = {
                            token: word,
                            choices: [{
                                delta: { content: word },
                                index: 0
                            }]
                        };
                        try {
                            res.write(`data: ${JSON.stringify(event)}\n\n`);
                        } catch (e) {
                            break; // Client disconnected
                        }
                        // Small delay to simulate streaming
                        await new Promise(resolve => setTimeout(resolve, 5));
                    }

                    // If the client disconnected mid-stream, persist the full
                    // synthesized response to the conversation so switching
                    // back shows the completed answer instead of a stub.
                    const jobAtEnd = streamingConversationId ? activeStreamingJobs.get(streamingConversationId) : null;
                    if (streamingConversationId && jobAtEnd && !jobAtEnd.clientConnected && fullResponse) {
                        try {
                            const conversationMsgs = await loadConversationMessages(userId, streamingConversationId);
                            conversationMsgs.push({
                                id: crypto.randomUUID(),
                                role: 'assistant',
                                content: fullResponse,
                                timestamp: new Date().toISOString(),
                                responseTime: Date.now() - streamStartTime,
                                backgroundCompleted: true,
                            });
                            await saveConversationMessages(userId, streamingConversationId, conversationMsgs, { memoryUserId: chatMemId });
                            console.log(`[Chat Stream] Map-reduce background response saved to conversation ${streamingConversationId}`);
                        } catch (saveErr) {
                            console.error(`[Chat Stream] Failed to save map-reduce background response:`, saveErr);
                        }
                    }

                    // Send final event
                    const finalEvent = {
                        done: true,
                        choices: [{
                            delta: {},
                            index: 0,
                            finish_reason: 'stop'
                        }],
                        model: targetModel,
                        contextSize,
                        mapReduce: {
                            enabled: true,
                            chunkCount: mapReduceResult.chunkCount,
                            synthesized: mapReduceResult.synthesized,
                            failedChunks: mapReduceResult.failedChunks || 0
                        }
                    };
                    try { res.write(`data: ${JSON.stringify(finalEvent)}\n\n`); } catch (e) {}
                    try { res.write(`data: [DONE]\n\n`); } catch (e) {}
                    try { res.end(); } catch (e) {}
                    clearStreamingJob();

                    console.log(`[Chat Stream] Map-reduce complete: ${mapReduceResult.chunkCount} chunks, synthesized=${mapReduceResult.synthesized}`);
                    return;
                } else {
                    // Map-reduce failed, return error
                    const errorEvent = {
                        error: mapReduceResult.error || 'Map-reduce processing failed',
                        done: true
                    };
                    try { res.write(`data: ${JSON.stringify(errorEvent)}\n\n`); } catch (e) {}
                    try { res.end(); } catch (e) {}
                    clearStreamingJob();
                    return;
                }
            } catch (mapReduceError) {
                console.error('[Chat Stream] Map-reduce error:', mapReduceError);
                const errorEvent = {
                    error: `Map-reduce processing failed: ${mapReduceError.message}`,
                    done: true
                };
                try { res.write(`data: ${JSON.stringify(errorEvent)}\n\n`); } catch (e) {}
                try { res.end(); } catch (e) {}
                clearStreamingJob();
                return;
            }
        }

        // =====================================================================
        // SANITIZE IMAGE CONTENT FOR NON-VISION MODELS
        // =====================================================================
        // Strip image_url parts from messages — if OCR text was extracted, it's already
        // in the text part. Non-vision models reject image_url content with 500 errors.
        for (let i = 0; i < chatMessages.length; i++) {
            const msg = chatMessages[i];
            if (Array.isArray(msg.content)) {
                const textParts = msg.content.filter(p => p.type === 'text');
                const hasImages = msg.content.some(p => p.type === 'image_url');
                if (hasImages) {
                    // Collapse to plain text string (image data already converted to OCR text at upload)
                    const combinedText = textParts.map(p => p.text || '').join('\n').trim();
                    if (combinedText) {
                        chatMessages[i].content = combinedText;
                        console.log(`[Chat Stream] Stripped image_url parts from message ${i}, kept ${combinedText.length} chars of text`);
                    }
                }
            }
        }

        // =====================================================================
        // NORMAL STREAMING PATH (with automatic continuation + native tools)
        // =====================================================================
        const MAX_AUTO_CONTINUATIONS = 8; // Safety cap to prevent infinite loops
        const CONTINUATION_CONTEXT_CHARS = 3000; // ~750 tokens of tail context for better continuation pickup

        let fullResponse = '';
        let fullReasoning = '';
        let tokenCount = 0;
        let promptTokens = 0;
        let completionTokens = 0;
        let clientConnected = true;
        let continuationCount = 0;

        // --- Native tool calling -------------------------------------------
        // Build the tool catalog once per user turn. Subsequent tool-call
        // rounds within this turn reuse the same catalog.
        const chatTools = require('./services/chatTools');
        // conversationId is plumbed through so per-conv workspace scoping
        // (see sandboxRunner.ensureWorkspace) buckets all skills fired in
        // this turn under `workspaces/<userId>/conv-<id>/`.
        // latestUserText is the last user message extracted to plain text;
        // tools (e.g. base64_decode) can salvage from it when the model
        // invokes them with empty/unusable args.
        let latestUserText = '';
        let latestUserMsgIdx = -1;
        for (let i = chatMessages.length - 1; i >= 0; i--) {
            if (chatMessages[i].role === 'user') {
                const c = chatMessages[i].content;
                if (typeof c === 'string') latestUserText = c;
                else if (Array.isArray(c)) {
                    latestUserText = c.filter(p => p?.type === 'text' && typeof p.text === 'string')
                        .map(p => p.text).join('\n');
                }
                latestUserMsgIdx = i;
                break;
            }
        }

        // Follow-up document context: when the agentic flow did NOT activate
        // this turn (no fresh large upload) but the conversation has
        // previously-indexed documents, the documentId handle is gone from
        // context — it lived only in the rewritten upload-turn user message
        // and the synthetic prime tool messages, NEITHER of which is
        // persisted (the client saves the ORIGINAL user text; the server only
        // saves the assistant reply). Without the handle the model concludes
        // "no document is available" and wanders off to web_search/fetch_url
        // instead of querying the file the user uploaded earlier. Re-establish
        // the handle by listing the conversation's indexed docs and prepending
        // a notice to this turn's user message.
        let followupActiveDocId = null;
        if (!useAgentic && streamingConversationId && latestUserMsgIdx >= 0) {
            try {
                const documentIndex = require('./services/documentIndex');
                const all = await documentIndex.listIndexes(req.userId || userId);
                const convDocs = all.filter(d => d.conversationId === streamingConversationId);
                if (convDocs.length > 0) {
                    const docLines = convDocs.map(d =>
                        `  • documentId="${d.id}"${d.filename ? ` ("${d.filename}")` : ''} — ${d.totalChunks} chunks`
                    ).join('\n');
                    const isOne = convDocs.length === 1;
                    const followupDocNote =
                        `[SYSTEM: ${isOne ? 'A document was' : `${convDocs.length} documents were`} uploaded earlier in THIS conversation and ${isOne ? 'is' : 'are'} still indexed for retrieval. ` +
                        `You CANNOT see the document body in your context, but you CAN read it with the tools below — use these instead of web_search/fetch_url for anything that lives in the uploaded ${isOne ? 'document' : 'documents'}:\n` +
                        `${docLines}\n` +
                        `  • query_document(documentId, query, topK?) — relevance search (use for a section number, "find X", "the page of Y", any targeted lookup)\n` +
                        `  • read_document_chunk(documentId, chunkIndex, count?) — sequential read\n` +
                        `Cite line ranges from the tool results. Do NOT fabricate content the tools didn't return.]\n\n`;

                    const um = chatMessages[latestUserMsgIdx];
                    if (typeof um.content === 'string') {
                        um.content = followupDocNote + um.content;
                    } else if (Array.isArray(um.content)) {
                        const tIdx = um.content.findIndex(p => p?.type === 'text' && typeof p.text === 'string');
                        if (tIdx >= 0) um.content[tIdx].text = followupDocNote + um.content[tIdx].text;
                        else um.content.unshift({ type: 'text', text: followupDocNote });
                    }
                    // With a single indexed doc the reference is unambiguous —
                    // force doc-tool calls onto it so a fumbled/missing id
                    // still resolves. With several, leave resolution to the
                    // model (the note lists every id) + resolveIndex's
                    // most-recent fallback.
                    if (isOne) followupActiveDocId = convDocs[0].id;
                    console.log(`[Chat Stream] Follow-up doc context: ${convDocs.length} indexed doc(s) for conv ${streamingConversationId.slice(0, 8)}…; notice injected${followupActiveDocId ? `, activeDocumentId=${followupActiveDocId}` : ''}`);
                }
            } catch (e) {
                console.warn('[Chat Stream] follow-up doc context lookup failed:', e.message);
            }
        }

        // Account id memory is keyed by — same resolution the routes and the
        // chat retrieval/extraction use, so record_learning writes land where
        // the model later recalls them. When the user has disabled memory, hide
        // record_learning from the catalog so the model can't write either.
        const memUserId = chatMemId;
        const toolMemoryDisabled = await isMemoryDisabledForUser(memUserId);
        const toolCtx = {
            userId: req.userId,
            apiKeyData: req.apiKeyData,
            agentId: req.body?.agentId || null,
            conversationId: conversationId || null,
            memoryUserId: memUserId,
            memoryDisabled: toolMemoryDisabled,
            latestUserText,
            // Document indexed for THIS turn (large user content stashed via
            // documentIndex). query_document / read_document_chunk force their
            // calls onto this id so a model that fumbles the 32-hex handle
            // can't wander onto a stale document from a previous turn. On a
            // follow-up turn (no fresh upload) we instead pin to the
            // conversation's single indexed doc when there is exactly one.
            activeDocumentId: (useAgentic && agenticInfo) ? agenticInfo.documentId : followupActiveDocId,
        };
        let toolCatalog = [];
        try {
            toolCatalog = await chatTools.buildToolCatalog(toolCtx);
        } catch (e) {
            console.warn('[Chat Stream] tool catalog build failed:', e.message);
        }
        // --- Tool router state (see webapp/services/toolRouter.js) -----------
        // The FULL catalog is the source of truth for schemas + name-based
        // dispatch. The router reduces what is ADVERTISED to the model per turn;
        // find_tools + name dispatch keep every dropped tool reachable. Any
        // failure below leaves toolCatalog = the full catalog (fail open).
        const fullToolCatalog = toolCatalog.slice();
        const fullByName = new Map(fullToolCatalog.map(d => [d.function?.name, d]));
        toolCtx.fullToolCatalog = fullToolCatalog;
        toolCtx._forcedToolNames = new Set();      // find_tools pushes discovered names here
        const preflightForcedTools = new Set();    // pre-flights that NAME a tool force-include it
        let advertisedNames = new Set(fullByName.keys());  // grows across rounds
        let routeCompactLevel = null;   // set when routing is active; used to rebuild on grow
        // Doc-analysis pre-step (agentic/follow-up) instructs the model to call
        // query_document / read_document_chunk — force-include them so routing
        // can't drop a tool the server just told the model to use.
        if (toolCtx.activeDocumentId) {
            preflightForcedTools.add('query_document');
            preflightForcedTools.add('read_document_chunk');
        }
        // Memoize the catalog's JSON + token estimate ONCE per turn — it's stable
        // across every tool round (built here, never rebuilt), but was re-
        // JSON.stringify'd (40-60KB) 2-3x per round in the hot loop. The forced-
        // synthesis path empties `toolCatalog` IN PLACE then restores it, so each
        // CONSUMER below still gates on the LIVE `toolCatalog.length` and selects
        // these memoized values only when tools are actually attached — i.e. ''/0
        // during synthesis. `estimateTokens` is the chat-stream-local estimator,
        // matching the original call sites exactly.
        // `let` — recomputed after routing (below) and on each grow-only round.
        let toolCatalogJson = toolCatalog.length ? JSON.stringify(toolCatalog) : '';
        let toolCatalogTokens = toolCatalogJson ? estimateTokens(toolCatalogJson) : 0;
        // Accumulator is reset at the start of every model turn (outer loop).
        let accumulatedToolCalls = [];
        let toolCallRound = 0;
        // Fingerprint + result-hash history across rounds. Used to detect
        // the model calling the same tool with the same args repeatedly
        // and getting the same (usually empty) result — a pathological
        // loop we short-circuit with a nudge instead of burning iterations.
        // Cleared per user turn, not per conversation.
        const toolCallHistory = []; // { fp: 'name:args', resultHash: string }
        // Chip-shaped record of every tool call dispatched this turn, mirroring
        // the client's buildNativeChipEntries() output. Attached to the
        // server-saved assistant message so a turn that completes in the
        // BACKGROUND (user navigated away → clientConnected=false) keeps its
        // tool chips on reload. The foreground path builds chips client-side
        // from the SSE stream; this is the parity copy for the background save.
        const persistedToolChips = [];

        // Skills can carry a `systemPrompt` (set in the Tool editor's
        // "Prompt" field) that the model should see when the tool is
        // called — used to enforce per-tool defaults, output format, or
        // behavior rules. Track which skills have already had their
        // prompt injected this turn; once the model has seen a skill's
        // instructions, repeating them on every subsequent call wastes
        // tokens for no gain.
        const injectedSkillPrompts = new Set();
        const SKILL_PROMPT_CHAR_CAP = 1500;

        // --- Auto-invoke base64_decode on input ---------------------------
        // Models inconsistently pick base64_decode out of a 70+ tool catalog
        // and often guess the decoded value inline. Detect base64 in the
        // latest user message server-side, run the skill, and prepend the
        // decoded values to the user message as a clearly-marked server
        // note so the model answers against ground truth.
        //
        // Earlier attempts injected a synthetic assistant+tool_calls+tool
        // triplet into the message list. That serialized in the chat
        // template as tool-call markers, which some models (gemma4,
        // gpt-oss-style templates on llama.cpp) then echoed as visible
        // content — users saw garbled `<|tool_call|>…<|channel|>…` strings
        // instead of answers. Plain-text injection avoids the template
        // tokenization path entirely. The UI still gets tool_executing +
        // tool_result SSE events for transparency; they're purely
        // frontend-visible and never touch the model's prompt.
        //
        // Skipped silently when base64_decode isn't in the catalog (user
        // disabled it) or no base64 in the message decodes to
        // mostly-printable UTF-8.
        const base64Detector = require('./services/base64Detector');
        const b64PreflightEncoded = new Set();
        const b64CatalogExposed = fullToolCatalog.some(t => t?.function?.name === 'base64_decode');
        if (b64CatalogExposed) {
            try {
                let userText = '';
                let userMsgIdx = -1;
                for (let i = chatMessages.length - 1; i >= 0; i--) {
                    if (chatMessages[i].role === 'user') {
                        userText = base64Detector.extractTextFromContent(chatMessages[i].content);
                        userMsgIdx = i;
                        break;
                    }
                }
                const found = userMsgIdx >= 0 ? base64Detector.findBase64InText(userText) : [];
                if (found.length > 0) {
                    preflightForcedTools.add('base64_decode');
                    const callId = `call_auto_b64_in_${Date.now()}`;
                    const result = {
                        success: true,
                        mode: found.length === 1 ? 'single' : 'scan',
                        count: found.length,
                        results: found,
                        note: `Auto-decoded ${found.length} base64 string(s) detected in user message`,
                    };
                    // UI-only events. Compact arguments (just the count)
                    // so a multi-KB user paste doesn't ship to the frontend
                    // twice.
                    if (clientConnected) {
                        try {
                            res.write(`data: ${JSON.stringify({
                                type: 'tool_executing',
                                tool_call_id: callId,
                                name: 'base64_decode',
                                arguments: JSON.stringify({ candidates: found.length }),
                            })}\n\n`);
                            res.write(`data: ${JSON.stringify({
                                type: 'tool_result',
                                tool_call_id: callId,
                                name: 'base64_decode',
                                preview: JSON.stringify(result).slice(0, 240),
                                result,
                            })}\n\n`);
                        } catch (_) { clientConnected = false; }
                    }
                    // Build a compact decoded-values note. Truncate
                    // individual decoded strings so one huge payload can't
                    // blow the context; the full decoded text is available
                    // in the UI panel via the tool_result event.
                    const MAX_NOTE_DECODED_CHARS = 4000;
                    const bullets = [];
                    let remaining = MAX_NOTE_DECODED_CHARS;
                    for (const f of found) {
                        const encShort = f.encoded.length > 60
                            ? f.encoded.slice(0, 60) + '…'
                            : f.encoded;
                        const perBullet = Math.max(120, Math.min(f.decoded.length, remaining));
                        const decShort = f.decoded.length > perBullet
                            ? f.decoded.slice(0, perBullet) + '…[truncated]'
                            : f.decoded;
                        const layerSuffix = f.layers > 1 ? ` (${f.layers} nested layers)` : '';
                        bullets.push(`- "${encShort}"${layerSuffix} → ${JSON.stringify(decShort)}`);
                        remaining -= decShort.length;
                        if (remaining <= 0) break;
                    }
                    const note = [
                        '[SERVER NOTE: The server auto-decoded base64 strings found in this message. Use these decoded values directly; do not attempt to decode them yourself.]',
                        ...bullets,
                        '',
                    ].join('\n');
                    // Prepend the note to the user message's text content.
                    // Handles both plain-string and vision-array formats.
                    const msg = chatMessages[userMsgIdx];
                    if (typeof msg.content === 'string') {
                        msg.content = `${note}\n${msg.content}`;
                    } else if (Array.isArray(msg.content)) {
                        const textIdx = msg.content.findIndex(p => p?.type === 'text');
                        if (textIdx >= 0) {
                            msg.content[textIdx].text = `${note}\n${msg.content[textIdx].text || ''}`;
                        } else {
                            msg.content.unshift({ type: 'text', text: note });
                        }
                    }
                    for (const f of found) b64PreflightEncoded.add(f.encoded);
                    // Keep base64_decode in the catalog — if a blob slipped
                    // past the detector (split across lines, odd framing)
                    // or the nested peeler bottomed out before fully
                    // unwrapping, the model can still invoke the skill.
                    logChatActivity(`Auto-invoked base64_decode on input (${found.length} candidate(s))`);
                }
            } catch (e) {
                console.warn('[Chat Stream] base64 pre-flight failed:', e.message);
            }
        }

        // --- Knowledge-base file pre-flight ----------------------------------
        // A document added to a Knowledge Base lives ONLY as embedded chunks in
        // the vector store — it is never written to the sandbox filesystem. So
        // when the user says "read I-Health_Receipt.pdf", the model guesses a
        // /workspace path and wastes a read_pdf/read_file call (which 404s)
        // before recovering via search_knowledge_base. A buried tool-description
        // warning isn't reliably obeyed by smaller models, so we deterministically
        // detect KB filenames named in the user's message and inject an explicit
        // up-front note steering the model straight to search_knowledge_base.
        // Skipped silently when the tool isn't in the catalog or no KB filename
        // is referenced.
        if (fullToolCatalog.some(t => t?.function?.name === 'search_knowledge_base')) {
            try {
                let userText = '';
                let userMsgIdx = -1;
                for (let i = chatMessages.length - 1; i >= 0; i--) {
                    if (chatMessages[i].role === 'user') {
                        userText = base64Detector.extractTextFromContent(chatMessages[i].content);
                        userMsgIdx = i;
                        break;
                    }
                }
                if (userMsgIdx >= 0 && userText) {
                    const lcText = userText.toLowerCase();
                    const kbs = await knowledgeBaseService.listKBs(req.userId || userId);
                    const hits = [];
                    const seen = new Set();
                    for (const kb of kbs) {
                        for (const d of (kb.documents || [])) {
                            const fn = d.filename;
                            if (!fn || seen.has(fn.toLowerCase())) continue;
                            // Match the full filename (with extension) verbatim —
                            // specific enough to avoid false positives on common words.
                            if (lcText.includes(fn.toLowerCase())) {
                                seen.add(fn.toLowerCase());
                                hits.push({ filename: fn, kb: kb.name });
                            }
                        }
                    }
                    if (hits.length) {
                        preflightForcedTools.add('search_knowledge_base');
                        const lines = hits.map(h => `- "${h.filename}" is in the knowledge base "${h.kb}".`);
                        const note = [
                            '[SERVER NOTE: The file(s) named below live ONLY in the knowledge base, NOT on the sandbox filesystem. To read their contents call search_knowledge_base (optionally with the knowledge_base name); do NOT call read_pdf / read_file / list_directory on a /workspace path for them — that will fail.]',
                            ...lines,
                            '',
                        ].join('\n');
                        const msg = chatMessages[userMsgIdx];
                        if (typeof msg.content === 'string') {
                            msg.content = `${note}\n${msg.content}`;
                        } else if (Array.isArray(msg.content)) {
                            const textIdx = msg.content.findIndex(p => p?.type === 'text');
                            if (textIdx >= 0) {
                                msg.content[textIdx].text = `${note}\n${msg.content[textIdx].text || ''}`;
                            } else {
                                msg.content.unshift({ type: 'text', text: note });
                            }
                        }
                        logChatActivity(`KB pre-flight: steered ${hits.length} named file(s) to search_knowledge_base`);
                    }
                }
            } catch (e) {
                console.warn('[Chat Stream] KB pre-flight failed:', e.message);
            }
        }

        // --- Tool router: reduce the ADVERTISED catalog to a relevant subset -
        // Runs AFTER the deterministic pre-flights (which force-include any tool
        // they named). Fails OPEN to the full catalog on any error. Only the
        // advertised `tools` array changes; registry/dispatch are untouched.
        try {
            const routeProfile = toolRouter.resolveProfile({
                instance: targetInstance,
                contextSize,
                fullCatalogTokens: toolCatalogTokens,
                reqOverride: req.body?.toolRouter,
            });
            if (routeProfile !== 'off' && fullToolCatalog.length) {
                const sel = await toolRouter.selectForTurn({
                    fullCatalog: fullToolCatalog,
                    query: latestUserText,
                    contextSize,
                    profile: routeProfile,
                    stickyNames: toolRouter.getSticky(streamingConversationId, chatMessages),
                    forcedNames: preflightForcedTools,
                    convId: streamingConversationId,   // prompt-cache-stable selection per conversation
                });
                toolCatalog = sel.tools;
                advertisedNames = sel.advertisedNames;
                routeCompactLevel = routeProfile === 'aggressive' ? 'aggressive' : 'light';
                toolCatalogJson = toolCatalog.length ? JSON.stringify(toolCatalog) : '';
                toolCatalogTokens = toolCatalogJson ? estimateTokens(toolCatalogJson) : 0;
                logChatActivity(`Tool router [${routeProfile}/${sel.mode}]: ${toolCatalog.length}/${fullToolCatalog.length} tools ~${toolCatalogTokens} tok (dropped ${sel.droppedCount})`);
                console.log(`[Chat Stream] Tool router [${routeProfile}/${sel.mode}]: advertised ${toolCatalog.length}/${fullToolCatalog.length} tools (~${toolCatalogTokens} tok, dropped ${sel.droppedCount})`);
            }
        } catch (e) {
            console.warn('[Chat Stream] tool router failed (fail open to full catalog):', e.message);
            toolCatalog = fullToolCatalog.slice();
            toolCatalogJson = toolCatalog.length ? JSON.stringify(toolCatalog) : '';
            toolCatalogTokens = toolCatalogJson ? estimateTokens(toolCatalogJson) : 0;
        }

        // Job was registered at the top of the handler so refresh / switch-back
        // can see prep-phase work. Update the existing record with the live
        // inputMessages snapshot and flip phase to 'waiting' (model about to
        // receive the first request).
        updateJobPhase('waiting', { inputMessages });
        pushJobEvent({
            icon: 'brain',
            text: `Sending request to ${targetModel}`,
            kind: 'waiting',
        });

        // Reasoning-loop recovery — per-turn state. A detected loop no longer
        // dead-stops the turn: streamOneRequest aborts only the looping ROUND
        // and returns a 'reasoning_loop' sentinel; the recovery block in the
        // tool loop nudges the model to break out and re-streams up to
        // REASONING_LOOP_MAX_RETRIES, then forces a tools-and-thinking-
        // suppressed synthesis (gated on reasoningLoopExhausted) so the user
        // still gets a real answer instead of a "rephrase your request" dead
        // end. The detector itself is created PER ROUND inside streamOneRequest
        // (so its granularity cursor resets each round). lastReasoningLoopReason
        // carries the most recent reason out for logging/status.
        // REASONING_LOOP_MAX_RETRIES is module-level + env-tunable.
        let reasoningLoopRetries = 0;
        let reasoningLoopExhausted = false;
        let lastReasoningLoopReason = '';

        // Floor on the per-request output budget. Below this, tool calls
        // reliably truncate mid-JSON. Shared by streamOneRequest's last-resort
        // fit and the outer tool-loop budget math.
        const MIN_OUTPUT_BUDGET = 1024;

        // Last-resort fit: truncate the largest message CONTENTS (head+tail)
        // until `messages` + `tools` leaves at least `reserve` output tokens
        // under contextSize. Operates on a COPY — never mutates the caller's
        // array or the saved conversation. Preserves the system message (idx 0),
        // the last message, vision/array content, and tool_calls structure.
        // This is the authoritative guard because it uses the SAME estimate the
        // request actually sends (stringified messages + tool catalog), so even
        // if the loop's content-only budgeting undercounts structural overhead,
        // the model still gets a usable output budget instead of a 64-token cap.
        const fitMessagesToContext = (messages, toolsTokens, reserve) => {
            const estOf = (msgs) => estimateTokens(JSON.stringify(msgs)) + toolsTokens;
            if (contextSize - estOf(messages) - 200 >= reserve) return { messages, truncated: 0 };
            let copy = messages.slice();
            let truncated = 0;
            const sizable = copy
                .map((m, i) => ({ i, t: estimateTokens(m.content) }))
                .filter(x => x.i !== 0 && x.i !== copy.length - 1
                    && typeof copy[x.i].content === 'string' && x.t > 300)
                .sort((a, b) => b.t - a.t);
            for (const c of sizable) {
                if (contextSize - estOf(copy) - 200 >= reserve) break;
                const m = copy[c.i];
                const text = m.content;
                const over = reserve - (contextSize - estOf(copy) - 200); // tokens to shed
                const targetTokens = Math.max(150, c.t - over - 50);
                // Invert estimateTokens proportionally from the ACTUAL text so the
                // char target matches whatever ratio/margin estimateTokens uses.
                // (A fixed `targetTokens * 3` over-counts by the safety margin and
                // can exceed text.length, skipping the message and leaving the
                // request over budget — defeating the whole guard.)
                const targetChars = Math.floor(text.length * (targetTokens / c.t));
                if (targetChars >= text.length) continue;
                const head = Math.floor(targetChars * 0.5);
                const tail = targetChars - head;
                copy[c.i] = { ...m, content: text.slice(0, head) + '\n…[trimmed to fit context window]…\n' + text.slice(text.length - tail) };
                truncated++;
            }
            return { messages: copy, truncated };
        };

        // Helper: enforce "exactly one system message, at index 0" before a
        // request is serialized to the backend. Several layers legitimately
        // APPEND a system message to the tail of the array — reasoning-loop /
        // announced-action nudges (currentMessages = [...currentMessages, sys])
        // and the forced-synthesis instruction — for recency. Most chat
        // templates render a mid/tail `system` turn fine, but a STRICT template
        // (Qwen-derived and others) hard-codes
        // `raise_exception('System message must be at the beginning.')`, and
        // llama.cpp's tool-call parser generation renders the template with our
        // messages → the raise surfaces as a 400 "Unable to generate parser for
        // this template". Demoting every non-leading system turn to `user`
        // keeps its position (so the nudge stays recent) and content intact
        // while satisfying the guard — a backend-agnostic fix for all models,
        // not just the one that happens to enforce it. Index-0 system is left
        // untouched; vision/array content + tool_calls are preserved (we only
        // rewrite the role).
        const normalizeSystemMessages = (msgs) => {
            if (!Array.isArray(msgs) || msgs.length < 2) return msgs;
            let changed = false;
            const out = msgs.map((m, i) => {
                if (i > 0 && m && m.role === 'system') {
                    changed = true;
                    return { ...m, role: 'user' };
                }
                return m;
            });
            return changed ? out : msgs;
        };

        // Helper: stream one request to the model and return the finish_reason.
        // roundContentStart / roundReasoningStart let the loop detector measure
        // "progress within this round" instead of cumulative fullResponse
        // growth (which would read as "progress" on round 2 of a tool-using
        // turn even if round 2 itself is the one stuck looping).
        const streamOneRequest = (requestMessages, maxTokens, options = {}) => {
            const roundContentStart = options.roundContentStart ?? fullResponse.length;
            const roundReasoningStart = options.roundReasoningStart ?? fullReasoning.length;
            // Per-round extractor for Qwen-style textual tool calls.
            // Buffer state resets between rounds so a stray open tag in
            // round N doesn't bleed into round N+1.
            const textualToolCallExtractor = makeTextualToolCallExtractor();
            // Per-round reasoning-loop detector (granularity cursor resets each
            // round) + a per-round AbortController. On a detected loop we abort
            // ONLY this round's backend generation (sparing the completion
            // budget) and resolve the sentinel 'reasoning_loop' — WITHOUT
            // touching the turn-level streamAbortController, so the outer loop
            // can nudge + re-stream. Turn-level aborts (user cancel via
            // DELETE /streaming) are forwarded to the round controller so a real
            // cancel still stops axios; the forwarder is removed on settle so
            // listeners never accumulate across rounds/continuations/synthesis.
            const roundLoopDetector = makeReasoningLoopDetector();
            const roundAbortController = new AbortController();
            let loopDetectedThisRound = false;
            const onTurnAbort = () => { try { roundAbortController.abort(); } catch (_) {} };
            if (streamAbortController.signal.aborted) roundAbortController.abort();
            else streamAbortController.signal.addEventListener('abort', onTurnAbort, { once: true });
            const cleanupTurnAbortForward = () => {
                try { streamAbortController.signal.removeEventListener('abort', onTurnAbort); } catch (_) {}
            };
            return new Promise(async (resolve, reject) => {
                let lastFinishReason = 'stop';
                // Single idempotent settlement: the first settle wins, so an
                // abort-by-loop 'error' and a racing clean 'end' can neither
                // double-settle nor lose the sentinel. Always cleans up the
                // turn-abort forwarder.
                let settled = false;
                const settle = (isResolve, value) => {
                    if (settled) return;
                    settled = true;
                    cleanupTurnAbortForward();
                    if (isResolve) resolve(value); else reject(value);
                };

                try {
                    // Authoritative last-resort fit: before clamping max_tokens,
                    // shed the largest message CONTENTS until the request leaves
                    // room for at least MIN_OUTPUT_BUDGET output tokens. The
                    // pre-clamp below would otherwise drop max_tokens to its
                    // 64-token floor whenever the history + tool catalog already
                    // fill the context (e.g. a session of large binary file
                    // reads), and every tool call then truncates mid-JSON →
                    // refused → loop. fitMessagesToContext uses the SAME estimate
                    // the request actually sends (stringified messages + catalog)
                    // so it is the final guarantee even if the outer loop's
                    // content-only budgeting undercounts structural overhead.
                    const toolsTokensForFit = toolCatalog.length ? toolCatalogTokens : 0;  // live-guarded: 0 during forced synthesis
                    let sendMessages = requestMessages;
                    {
                        const fitted = fitMessagesToContext(requestMessages, toolsTokensForFit, Math.min(maxTokens, MIN_OUTPUT_BUDGET));
                        if (fitted.truncated > 0) {
                            sendMessages = fitted.messages;
                            console.log(`[Chat Stream] Last-resort fit: truncated ${fitted.truncated} oversized message(s) to guarantee a usable output budget`);
                        }
                    }

                    // Strict-template guard: collapse any tail/mid-array system
                    // turn (nudges, synthesis) down to a single leading system
                    // message so a Qwen-style "System message must be at the
                    // beginning" template can't 400 the request. Applied to the
                    // final array so the token estimate below matches the bytes
                    // actually sent.
                    sendMessages = normalizeSystemMessages(sendMessages);

                    // Final-pass clamp: input == messages + tool catalog. The
                    // upstream responseReserve only counts message tokens, so a
                    // large tool catalog (often ~7k actual sglang tokens on the
                    // full skill catalog) can push the request past
                    // max_model_len here. Estimate JSON char-bytes / 3 over-
                    // counts because tool schemas tokenize very efficiently
                    // (field names = single tokens), so this estimate is
                    // pessimistic and the floor is intentionally low (64) —
                    // a tiny response beats a 400. The chat stream catches
                    // a remaining SglangValidationError below and re-clamps
                    // from the actual input_tokens sglang reports.
                    let actualMaxTokens = maxTokens;
                    try {
                        const messagesJson = JSON.stringify(sendMessages);
                        const toolsJson = toolCatalog.length ? toolCatalogJson : '';  // live-guarded: '' during forced synthesis
                        const inputTokenEstimate = estimateTokens(messagesJson + toolsJson);
                        const headroom = contextSize - inputTokenEstimate - 200;
                        if (actualMaxTokens > headroom) {
                            const clamped = Math.max(64, headroom);
                            console.log(`[Chat Stream] Pre-clamp max_tokens ${actualMaxTokens} → ${clamped} (estimate=${inputTokenEstimate}, ctx=${contextSize}, tools=${toolCatalog.length})`);
                            actualMaxTokens = clamped;
                        }
                    } catch (_) { /* estimation best-effort */ }

                    const requestBody = {
                        model: targetModel,
                        messages: sendMessages,
                        temperature: temperature || 0.7,
                        top_p: effectiveTopP,
                        stream: true,
                        max_tokens: actualMaxTokens,
                        stop: DEFAULT_STOP_STRINGS,
                        // Native tool calling — only attach `tools` when the
                        // catalog has something. Empty arrays confuse some
                        // backends; omitting the key is the safer default.
                        ...(toolCatalog.length ? { tools: toolCatalog } : {}),
                        // forceNoThink: actually disable the model's reasoning
                        // pass on the backend for this request (not just hide it
                        // client-side as `disableThinking` does). On a reasoning-
                        // ON MTP model the `/no_think` prefix is ignored, so a
                        // forced-synthesis round would otherwise spend its whole
                        // budget thinking and emit NO content. chat_template_kwargs
                        // .enable_thinking=false is the lever the Qwen3-MTP
                        // template honors (same as requestModelCompletion). A
                        // template that doesn't read it ignores the kwarg; one
                        // that 4xxs on it is retried without (see catch below).
                        ...(options.forceNoThink ? { chat_template_kwargs: { enable_thinking: false } } : {}),
                    };

                    const response = await axios({
                        method: 'post',
                        url: `http://${targetHost}:${targetPort}/v1/chat/completions`,
                        data: requestBody,
                        responseType: 'stream',
                        signal: roundAbortController.signal
                    });

                    // Persistent buffer across chunks — TCP packet boundaries do not
                    // align with SSE line boundaries. Without buffering, a frame split
                    // across two 'data' events causes JSON.parse to fail silently and
                    // the content tokens inside it to be dropped. StringDecoder also
                    // holds partial multi-byte UTF-8 sequences until the next chunk.
                    const sseDecoder = new StringDecoder('utf8');
                    let sseBuffer = '';
                    response.data.on('data', (chunk) => {
                        // Once a reasoning loop is detected (or the stream has
                        // otherwise settled), drop any late chunks the aborting
                        // backend still emits so they can't append stray
                        // content/reasoning into the round we're recovering.
                        if (settled) return;
                        try {
                            sseBuffer += sseDecoder.write(chunk);
                            const lines = sseBuffer.split('\n');
                            sseBuffer = lines.pop() || ''; // keep incomplete tail for next chunk

                            for (const rawLine of lines) {
                                const line = rawLine.trim();
                                if (!line) continue;
                                if (line.startsWith('data: ')) {
                                    const data = line.slice(6);

                                    if (data === '[DONE]') {
                                        // [DONE] received - resolve will happen in 'end' event
                                        return;
                                    }

                                    try {
                                        const parsed = JSON.parse(data);

                                        // Capture finish_reason from model
                                        if (parsed.choices && parsed.choices[0]?.finish_reason) {
                                            lastFinishReason = parsed.choices[0].finish_reason;
                                        }

                                        if (parsed.choices && parsed.choices[0]?.delta) {
                                            const delta = parsed.choices[0].delta;
                                            // Scrub Harmony control tokens that some templates
                                            // leak as literal text when the model de-rails.
                                            let rawContent = scrubHarmonyTokens(delta.content || '');
                                            let reasoning = scrubHarmonyTokens(delta.reasoning_content || delta.reasoning || '');
                                            // When the user loaded the model with disableThinking=true
                                            // but the model still emits reasoning (the /no_think
                                            // prefix only works on Qwen3/DeepSeek-R1, and even there
                                            // it sometimes leaks), suppress it client-bound so the
                                            // Thinking dropdown doesn't appear. Also strip stray
                                            // <think>...</think> from content for the same reason.
                                            if (disableThinking) {
                                                reasoning = '';
                                                if (rawContent) {
                                                    rawContent = rawContent.replace(/<\/?(?:think|thinking|reasoning|reasoning_engine|antThinking|antml:thinking|scratchpad)\b[^>]*>/gi, '');
                                                }
                                            }

                                            // Qwen text-format tool calls — extract any
                                            // <tool_call>...</tool_call> blocks from content and
                                            // dispatch them as if they had been native tool_calls
                                            // deltas. `passthrough` is the content stream with
                                            // those blocks removed so the UI never sees the raw
                                            // XML. Buffer state inside the extractor handles
                                            // tags split across SSE chunks.
                                            const { passthrough, blocks } = textualToolCallExtractor(rawContent);
                                            const content = passthrough;
                                            if (blocks.length) {
                                                for (const tc of blocks) {
                                                    accumulatedToolCalls.push(tc);
                                                    if (clientConnected) {
                                                        try {
                                                            res.write(`data: ${JSON.stringify({
                                                                type: 'tool_call_delta',
                                                                tool_calls: [{
                                                                    index: accumulatedToolCalls.length - 1,
                                                                    id: tc.id,
                                                                    type: tc.type,
                                                                    function: tc.function,
                                                                }],
                                                            })}\n\n`);
                                                        } catch (_) { clientConnected = false; }
                                                    }
                                                }
                                            }

                                            // Native tool calling — model streams tool_calls as
                                            // delta fragments; accumulate by index across chunks.
                                            if (Array.isArray(delta.tool_calls) && delta.tool_calls.length) {
                                                chatTools.accumulateToolCallDelta(accumulatedToolCalls, delta.tool_calls);
                                                if (clientConnected) {
                                                    try {
                                                        res.write(`data: ${JSON.stringify({
                                                            type: 'tool_call_delta',
                                                            tool_calls: delta.tool_calls,
                                                        })}\n\n`);
                                                    } catch (_) { clientConnected = false; }
                                                }
                                            }

                                            if (content || reasoning) {
                                                if (content) fullResponse += content;
                                                if (reasoning) fullReasoning += reasoning;
                                                tokenCount++;
                                                completionTokens++;

                                                if (streamingConversationId) {
                                                    const job = activeStreamingJobs.get(streamingConversationId);
                                                    if (job) {
                                                        job.content = fullResponse;
                                                        job.reasoning = fullReasoning;
                                                    }
                                                }

                                                if (clientConnected) {
                                                    const event = {
                                                        token: content || undefined,
                                                        choices: [{
                                                            delta: {
                                                                content: content || undefined,
                                                                reasoning: reasoning || undefined
                                                            },
                                                            index: 0
                                                        }]
                                                    };
                                                    try {
                                                        res.write(`data: ${JSON.stringify(event)}\n\n`);
                                                    } catch (writeErr) {
                                                        clientConnected = false;
                                                    }
                                                }

                                                // Reasoning-loop guard. Only triggers when this round
                                                // has produced NO content and NO tool calls — a valid
                                                // turn that happens to have long reasoning sprinkled
                                                // with actual output won't be flagged. On a hit we abort
                                                // ONLY this round (the per-round controller) and resolve
                                                // the 'reasoning_loop' sentinel; the outer recovery block
                                                // nudges the model to break out and re-streams instead of
                                                // dead-stopping the turn. No dead-stop note is written
                                                // here — recovery / forced synthesis owns the messaging.
                                                if (!loopDetectedThisRound) {
                                                    const roundContentLen = fullResponse.length - roundContentStart;
                                                    const noProgress = roundContentLen === 0 && accumulatedToolCalls.length === 0;
                                                    if (noProgress) {
                                                        const reason = roundLoopDetector(fullReasoning.slice(roundReasoningStart));
                                                        if (reason) {
                                                            loopDetectedThisRound = true;
                                                            lastReasoningLoopReason = reason;
                                                            console.warn(`[Chat Stream] Reasoning loop detected — ${reason}; aborting round to recover`);
                                                            roundAbortController.abort();
                                                            settle(true, 'reasoning_loop');
                                                            return;
                                                        }
                                                    }
                                                }
                                            }
                                        }

                                        if (parsed.usage) {
                                            promptTokens = parsed.usage.prompt_tokens || 0;
                                            completionTokens = parsed.usage.completion_tokens || 0;
                                        }
                                        if (parsed.timings) {
                                            promptTokens = (parsed.timings.prompt_n || 0) + (parsed.timings.cache_n || 0);
                                            completionTokens = parsed.timings.predicted_n || 0;
                                        }
                                    } catch (e) {
                                        // Skip invalid JSON chunks
                                    }
                                }
                            }
                        } catch (error) {
                            console.error('Error processing stream chunk:', error);
                        }
                    });

                    response.data.on('end', () => {
                        // If a reasoning loop was detected mid-round, the stream
                        // is being aborted — settle the sentinel and skip the
                        // trailing-buffer drain (it would only re-append the
                        // looped tail we're discarding).
                        if (loopDetectedThisRound) { settle(true, 'reasoning_loop'); return; }
                        // Flush any residual bytes held by StringDecoder (partial
                        // multi-byte UTF-8) and process any trailing buffered line
                        // that didn't end with '\n'.
                        sseBuffer += sseDecoder.end();
                        const trailing = sseBuffer.trim();
                        sseBuffer = '';
                        if (trailing && trailing.startsWith('data: ')) {
                            const data = trailing.slice(6);
                            if (data && data !== '[DONE]') {
                                try {
                                    const parsed = JSON.parse(data);
                                    if (parsed.choices && parsed.choices[0]?.finish_reason) {
                                        lastFinishReason = parsed.choices[0].finish_reason;
                                    }
                                    const delta = parsed.choices?.[0]?.delta;
                                    if (delta) {
                                        let rawContent = scrubHarmonyTokens(delta.content || '');
                                        let reasoning = scrubHarmonyTokens(delta.reasoning_content || delta.reasoning || '');
                                        if (disableThinking) {
                                            reasoning = '';
                                            if (rawContent) {
                                                rawContent = rawContent.replace(/<\/?(?:think|thinking|reasoning|reasoning_engine|antThinking|antml:thinking|scratchpad)\b[^>]*>/gi, '');
                                            }
                                        }
                                        // Pull any final-chunk textual tool calls out
                                        // before the content lands in fullResponse / SSE.
                                        const { passthrough, blocks } = textualToolCallExtractor(rawContent);
                                        const content = passthrough;
                                        for (const tc of blocks) {
                                            accumulatedToolCalls.push(tc);
                                            if (clientConnected) {
                                                try {
                                                    res.write(`data: ${JSON.stringify({
                                                        type: 'tool_call_delta',
                                                        tool_calls: [{
                                                            index: accumulatedToolCalls.length - 1,
                                                            id: tc.id,
                                                            type: tc.type,
                                                            function: tc.function,
                                                        }],
                                                    })}\n\n`);
                                                } catch (_) { clientConnected = false; }
                                            }
                                        }
                                        if (content) fullResponse += content;
                                        if (reasoning) fullReasoning += reasoning;
                                        if ((content || reasoning) && clientConnected) {
                                            try {
                                                res.write(`data: ${JSON.stringify({
                                                    token: content || undefined,
                                                    choices: [{
                                                        delta: {
                                                            content: content || undefined,
                                                            reasoning: reasoning || undefined
                                                        },
                                                        index: 0
                                                    }]
                                                })}\n\n`);
                                            } catch (writeErr) { clientConnected = false; }
                                        }
                                    }
                                } catch (e) { /* ignore trailing parse errors */ }
                            }
                        }
                        // Drain extractor — flushes any safety-tail content held
                        // back to handle a split open tag, and discards any
                        // unclosed <tool_call> block (model abandoned the call).
                        const drained = textualToolCallExtractor.flush();
                        if (drained.passthrough) {
                            fullResponse += drained.passthrough;
                            if (clientConnected) {
                                try {
                                    res.write(`data: ${JSON.stringify({
                                        token: drained.passthrough,
                                        choices: [{
                                            delta: { content: drained.passthrough },
                                            index: 0
                                        }]
                                    })}\n\n`);
                                } catch (_) { clientConnected = false; }
                            }
                        }
                        settle(true, lastFinishReason);
                    });

                    response.data.on('error', (error) => {
                        // A loop-triggered round abort surfaces here as a
                        // CanceledError — resolve the sentinel instead of
                        // rejecting so the outer loop recovers. A turn-level
                        // (user) cancel forwarded to roundAbortController also
                        // lands here; loopDetectedThisRound is false in that
                        // case, so it rejects and the user cancel propagates.
                        if (loopDetectedThisRound) { settle(true, 'reasoning_loop'); return; }
                        settle(false, error);
                    });
                } catch (error) {
                    if (loopDetectedThisRound) { settle(true, 'reasoning_loop'); return; }
                    settle(false, error);
                }
            });
        };

        try {
            // Initial request with original messages.
            // responseReserve is already clamped to leave room for input
            // (see the desiredResponseTokens/responseReserve calculation above),
            // so we always use it — never the raw client-supplied value, which
            // could equal contextSize and make sglang reject the request with
            // "0 input tokens" SglangValidationError.
            const initialMaxTokens = responseReserve;
            // The tool catalog ships with EVERY request but is NOT part of the
            // message list, so the per-round budget math must reserve room for
            // it. Without this, the loop's content-only token count thinks the
            // input fits, but streamOneRequest's accurate estimate (which adds
            // the catalog) then clamps max_tokens to the 64-token floor and
            // every tool call truncates mid-argument. A big skill catalog
            // (100+ tools) is easily 10-15k tokens.
            // (toolCatalogTokens is memoized once per turn at the catalog build
            // above; this loop never empties toolCatalog, so it's the same value.)
            // MIN_OUTPUT_BUDGET (1024) is declared once in the handler scope
            // above and shared with streamOneRequest's last-resort fit.
            updateJobPhase('generating');
            pushJobEvent({
                icon: 'sparkles',
                text: 'Generating response',
                kind: 'generating',
            });
            logChatActivity(`Generating response (context: ${contextSize}, input: ${totalInputTokens} tokens, reserve: ${responseReserve})`);

            // Native-tool-calling outer loop. Each iteration:
            //   1. stream the model's next turn (may auto-continue on length)
            //   2. if it ended with tool_calls, execute them and loop with the
            //      tool results appended to the conversation
            //   3. otherwise, break
            let currentMessages = chatMessages;
            let finishReason = 'stop';
            // Don't gate this loop on clientConnected — when the user
            // refreshes the page or switches conversations, the request
            // closes and clientConnected flips false, but the streaming
            // job is registered in activeStreamingJobs and the response
            // must keep being generated in the background. Every
            // res.write inside the loop already self-guards, so writes
            // to a dead socket are safe.
            // Drop the oldest tool-call round (assistant w/ tool_calls + its
            // tool result messages) until inputs fit `availableContextForInput`.
            // The chunking gate above only sees the user's original turn — once
            // a few web_search / fetch_url rounds have appended their results,
            // input can grow past contextSize even though each individual
            // tool message is capped (TOOL_RESULT_CHAR_CAP ≈ 12 KB). Without
            // this trim, the next streamOneRequest gets max_tokens clamped to
            // 64 (server.js floor) and sglang rejects the whole request with
            // "exceeds maximum context length". Always preserves: system,
            // original user message, and the most recent tool-call round.
            const trimToolHistoryToFit = (messages, budget) => {
                const total = (msgs) => msgs.reduce((s, m) => s + estimateTokens(m.content), 0);
                let dropped = 0, truncated = 0;
                // Phase 1 — drop oldest COMPLETE tool-call rounds (cleanest: keeps
                // message coherence). Always keeps the most recent round.
                while (total(messages) > budget) {
                    const idxs = [];
                    for (let i = 0; i < messages.length; i++) {
                        const m = messages[i];
                        if (m.role === 'assistant' && Array.isArray(m.tool_calls) && m.tool_calls.length > 0) {
                            idxs.push(i);
                        }
                    }
                    if (idxs.length <= 1) break; // keep at least the most recent round
                    const dropStart = idxs[0];
                    const dropEnd = idxs[1] - 1;
                    messages = [...messages.slice(0, dropStart), ...messages.slice(dropEnd + 1)];
                    dropped++;
                }
                // Phase 2 — if STILL over budget (one giant tool result, or a
                // history bloated with large non-tool messages that can't be
                // dropped), truncate the largest message CONTENTS head+tail.
                // Never touches the system message (idx 0), the last message
                // (the live turn), array/vision content, or the tool_calls
                // array — only string `content`. A truncated result beats a
                // 64-token output budget that mangles every later tool call.
                if (total(messages) > budget) {
                    messages = messages.slice();
                    const over = () => total(messages) - budget;
                    const sizable = messages
                        .map((m, i) => ({ i, t: estimateTokens(m.content) }))
                        .filter(x => x.i !== 0 && x.i !== messages.length - 1
                            && typeof messages[x.i].content === 'string' && x.t > 400)
                        .sort((a, b) => b.t - a.t);
                    for (const c of sizable) {
                        if (over() <= 0) break;
                        const m = messages[c.i];
                        const text = m.content;
                        const targetTokens = Math.max(200, c.t - over() - 50);
                        // Proportional inverse of estimateTokens (see fitMessagesToContext)
                        // — a fixed `* 3` over-counts by the safety margin and skips.
                        const targetChars = Math.floor(text.length * (targetTokens / c.t));
                        if (targetChars >= text.length) continue;
                        const head = Math.floor(targetChars * 0.5);
                        const tail = targetChars - head;
                        messages[c.i] = {
                            ...m,
                            content: text.slice(0, head) + '\n…[trimmed to fit context window]…\n' + text.slice(text.length - tail),
                        };
                        truncated++;
                    }
                }
                return { messages, dropped, truncated };
            };

            // One-shot retry latch for the false-completion detector below
            // (claims "saved/created/wrote ... file" but emitted no tool calls).
            let falseCompletionRetried = false;
            // One-shot retry latch for the abandoned-research detector
            // (mid-research turn ends "Let me dig deeper..." / "I'll search
            // for X" without emitting the next tool_call).
            let abandonedResearchRetried = false;
            // One-shot retry latch for the announced-action detector (model
            // narrates a tool-shaped action it is about to take — "let me write
            // Python to parse the log and create the chart", "I'll generate a
            // graph" — but ends the turn with NO tool_call, on round 0 too).
            let announcedActionRetried = false;
            // Set when a round streamed tool-call deltas we could NOT dispatch —
            // almost always a tool call whose arguments were truncated by the
            // round's max_tokens (e.g. search_replace_file / create_file carrying
            // a whole large file). The backend often reports finish_reason 'stop'
            // (not 'tool_calls'/'length') in this case. Without handling it the
            // turn breaks and saves a mid-thought prose tail — the model appears
            // to "stop" having done nothing. Forces synthesis below.
            let toolCallArgsTruncated = false;
            // Per-target truncation counter. The common non-terminating turn is
            // NOT the empty-finalize case above — it is a giant
            // search_replace_file/create_file whose args truncate mid-JSON: the
            // call DOES finalize+dispatch, executeToolCall returns
            // {error:'arguments_truncated'} with a "split it up" hint, and this
            // small model just RE-EMITS the same oversized call every round,
            // grinding to MAX_TOOL_ITERATIONS (50) over several minutes. We count
            // truncations per target file and, after MAX_EDIT_TRUNCATIONS for the
            // same target, stop the loop and deliver directly (download the
            // already-written file, else force synthesis). Env-tunable.
            const truncatedTargetCounts = new Map();
            let largeEditTruncationExhausted = false;
            let largeEditTargetPath = null;
            // Default 1: bail on the FIRST truncation of a large write. A
            // targeted edit (replace_lines / small search_replace_file) fits the
            // round budget and never truncates, so this only fires on the
            // pathological whole-file/large-section rewrite — exactly the call we
            // want to stop retrying. The on-disk file already reflects every
            // SUCCESSFUL edit, so we deliver that immediately instead of grinding.
            const MAX_EDIT_TRUNCATIONS = parseInt(process.env.MAX_EDIT_TRUNCATIONS || '1', 10);
            // Hoisted out of the per-round body: skills don't change mid-turn,
            // so loading and indexing them once per request avoids re-walking
            // the (potentially large) skills file on every tool round.
            const allSkillsForPolicy = await loadSkills().catch(() => []);
            const skillByName = new Map(allSkillsForPolicy.map(s => [s.name, s]));
            const policyCache = new Map();
            const toolPolicy = (toolName) => {
                const cached = policyCache.get(toolName);
                if (cached) return cached;
                // Native handlers take precedence: if a tool is registered in
                // chatTools.toolRegistry, executeToolCall dispatches to the
                // in-process JS handler and never touches the Python skill
                // record — even when a matching default-skill stub exists
                // (e.g. fetch_url, web_search, playwright_fetch all ship
                // comment-only Python stubs purely for catalog/system-prompt
                // purposes). Label by what actually executes.
                let result;
                if (chatTools.toolRegistry?.has(toolName)) {
                    result = { sandboxed: false, source: 'native' };
                } else {
                    const s = skillByName.get(toolName);
                    if (!s) {
                        result = { sandboxed: false, source: 'native' };
                    } else {
                        const wantSandbox = typeof s.sandbox === 'boolean'
                            ? s.sandbox
                            : !!s.userId;
                        result = {
                            sandboxed: !!wantSandbox,
                            source: 'skill',
                            workspace: !!s.workspace,
                            network: s.network || 'none',
                        };
                    }
                }
                policyCache.set(toolName, result);
                return result;
            };
            while (toolCallRound <= chatTools.MAX_TOOL_ITERATIONS) {
                // --- Tool router grow-only expansion (before reset) ----------
                // A tool the model just used, or discovered via find_tools, is
                // advertised on the NEXT round. The advertised set only GROWS
                // mid-turn (never drops a tool mid-use). Reads the PREVIOUS
                // round's accumulatedToolCalls (reset just below). Fail-safe:
                // any error leaves the current catalog unchanged.
                if (routeCompactLevel && advertisedNames && advertisedNames.size < fullByName.size) {
                    try {
                        let grew = false;
                        const addName = (n) => { if (n && fullByName.has(n) && !advertisedNames.has(n)) { advertisedNames.add(n); grew = true; } };
                        for (const c of (accumulatedToolCalls || [])) addName(c?.function?.name);
                        if (toolCtx._forcedToolNames) toolCtx._forcedToolNames.forEach(addName);
                        if (grew) {
                            const rebuilt = [];
                            for (const n of advertisedNames) {
                                if (n === 'find_tools') { rebuilt.push(toolRouter.compactSchema(toolRouter.findToolsDef, routeCompactLevel)); continue; }
                                const def = fullByName.get(n);
                                if (def) rebuilt.push(toolRouter.compactSchema(def, routeCompactLevel));
                            }
                            toolCatalog = rebuilt;
                            toolCatalogJson = toolCatalog.length ? JSON.stringify(toolCatalog) : '';
                            toolCatalogTokens = toolCatalogJson ? estimateTokens(toolCatalogJson) : 0;
                        }
                    } catch (e) { /* keep current catalog */ }
                }
                // Reset per-round state. fullResponse is cumulative for the
                // client stream; roundStart marks where THIS turn's text began
                // so we can feed only this turn's content back as the assistant
                // message when re-prompting after tool execution.
                accumulatedToolCalls = [];
                const roundStart = fullResponse.length;

                // Trim every round (NOT just round > 0): the conversation
                // HISTORY loaded from disk can already exceed the context window
                // on a long session (e.g. many large file reads in a binary
                // analysis), so round 0 needs trimming too. Budget leaves room
                // for the tool catalog + a usable output budget; without the
                // catalog term the loop under-counts input and the next request
                // gets max_tokens clamped to 64 → truncated tool args → loop.
                {
                    const trimBudget = Math.max(
                        2048,
                        contextSize - toolCatalogTokens - MIN_OUTPUT_BUDGET - 200
                    );
                    const trimResult = trimToolHistoryToFit(currentMessages, trimBudget);
                    if (trimResult.dropped > 0 || trimResult.truncated > 0) {
                        currentMessages = trimResult.messages;
                        const parts = [];
                        if (trimResult.dropped) parts.push(`${trimResult.dropped} older tool round(s)`);
                        if (trimResult.truncated) parts.push(`${trimResult.truncated} oversized message(s) truncated`);
                        console.log(`[Chat Stream] Trimmed to fit context (round ${toolCallRound + 1}): ${parts.join(', ')}`);
                        broadcast({
                            type: 'log',
                            level: 'info',
                            message: `Trimmed conversation to fit context window: ${parts.join(', ')}`
                        }, userId);
                    }
                }

                // Recompute the per-round max_tokens budget from the *current*
                // message list AND the tool catalog. initialMaxTokens was sized
                // for the first round's input; after a chain of tool calls,
                // currentMessages grows by up to TOOL_RESULT_CHAR_CAP per round.
                // Subtracting toolCatalogTokens keeps this in sync with
                // streamOneRequest's accurate pre-clamp so the model always gets
                // at least MIN_OUTPUT_BUDGET to emit a complete tool call.
                const roundInputTokens = currentMessages.reduce(
                    (sum, m) => sum + estimateTokens(m.content), 0
                );
                const roundHeadroom = contextSize - roundInputTokens - toolCatalogTokens - 200;
                // Tool-emitting rounds need a BIGGER output budget than a prose
                // answer: a render_chart `data` array or a run_python program with
                // the dataset embedded inline can be many thousands of tokens. The
                // user's prose max_tokens (initialMaxTokens, commonly 8192) is the
                // wrong cap for that — on a 131k-ctx model with ~100k free tokens,
                // capping the round at 8192 truncates the tool-call JSON mid-
                // argument (no trailing brace) → the truncation guard refuses
                // dispatch → the model appears to "stop" without producing the
                // chart/file (observed: "Graph this training run" → model narrates
                // "let me write Python…" then nothing). When tools are attached,
                // let the round use the free context headroom up to
                // TOOL_ROUND_MAX_TOKENS so a complete tool call fits; the final
                // prose synthesis below still respects initialMaxTokens.
                const TOOL_ROUND_MAX_TOKENS = 32768;
                const roundCap = toolCatalog.length
                    ? Math.max(initialMaxTokens, Math.min(TOOL_ROUND_MAX_TOKENS, roundHeadroom))
                    : initialMaxTokens;
                const roundMaxTokens = Math.max(
                    MIN_OUTPUT_BUDGET,
                    Math.min(roundCap, roundHeadroom)
                );

                finishReason = await streamOneRequest(currentMessages, roundMaxTokens);

                // --- Reasoning-loop recovery -------------------------------
                // The model spun in its reasoning stream this round (phrase /
                // verbatim repetition / low-diversity / cap) with no content
                // and no tool call; streamOneRequest aborted just THIS round
                // (sparing the completion budget) and returned the
                // 'reasoning_loop' sentinel. Instead of dead-stopping the turn,
                // nudge the model to stop deliberating and either act or answer,
                // then re-stream — escalating across REASONING_LOOP_MAX_RETRIES.
                // When the budget is spent, fall through to the tools-and-
                // thinking-suppressed forced synthesis below so the user still
                // gets a real answer. The nudge 'continue' does NOT increment
                // toolCallRound (matches the other re-stream detectors); the
                // turn-level retry counter is the only bound.
                if (finishReason === 'reasoning_loop') {
                    // Honor a user cancel that landed DURING the loop: if the
                    // turn-level controller is aborted, do not re-prompt —
                    // break out and let the normal abort/cancel path run.
                    if (streamAbortController.signal.aborted) break;
                    if (reasoningLoopRetries < REASONING_LOOP_MAX_RETRIES) {
                        reasoningLoopRetries++;
                        const escalate = reasoningLoopRetries >= REASONING_LOOP_MAX_RETRIES;
                        logChatActivity(`Reasoning loop (${lastReasoningLoopReason}) — nudging the model to answer (retry ${reasoningLoopRetries}/${REASONING_LOOP_MAX_RETRIES})`);
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    type: 'status',
                                    message: 'Model was over-deliberating — nudging it to respond',
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                        const nudge = escalate
                            ? 'You are repeating your reasoning without making progress. STOP thinking now and immediately write your best direct answer to the user from what you already know. Do not deliberate further. If a tool is strictly required, emit exactly ONE tool_call instead — but do not keep planning.'
                            : 'You appear to be looping in your reasoning without reaching a conclusion. Stop re-planning and commit now: either emit a single tool_call to take the next concrete action, or write your final answer to the user directly. Keep any further reasoning very brief.';
                        currentMessages = [...currentMessages, { role: 'system', content: nudge }];
                        console.warn(`[Chat Stream] Reasoning loop — re-streaming with ${escalate ? 'escalated ' : ''}nudge (retry ${reasoningLoopRetries}/${REASONING_LOOP_MAX_RETRIES})`);
                        continuationCount = 0; // fresh length budget for the re-stream
                        continue; // re-stream WITHOUT incrementing toolCallRound
                    }
                    // Retry budget spent — stop nudging and force a synthesis.
                    reasoningLoopExhausted = true;
                    console.warn(`[Chat Stream] Reasoning loop persisted after ${REASONING_LOOP_MAX_RETRIES} nudge(s) — forcing synthesis`);
                    break; // exit the tool loop → forced-synthesis block below
                }

                // Auto-continuation loop: if model hit length limit, keep going.
                // Skipped when tool calls are accumulated — the slim continuation
                // request below drops the partial tool_calls context entirely
                // (only system + truncated user + responseTail + "Continue"),
                // which corrupts state when the cap was hit mid-arguments.
                // Length-with-pending-tools is handled by the dispatch block
                // below: the truncation guard in chatTools.executeToolCall
                // surfaces a clean retry hint to the model on the next round.
                // Background-streaming: do NOT gate on clientConnected.
                // The user may have refreshed or switched conversations
                // mid-response; we still need to finish generating so
                // the saved message contains the full continuation
                // chain rather than the truncated first chunk.
                while (finishReason === 'length'
                       && continuationCount < MAX_AUTO_CONTINUATIONS
                       && accumulatedToolCalls.length === 0) {
                continuationCount++;
                console.log(`[Chat Stream] Auto-continuing response (${continuationCount}/${MAX_AUTO_CONTINUATIONS}), accumulated ${fullResponse.length} chars so far`);

                // Notify client that we're auto-continuing
                if (clientConnected) {
                    try {
                        res.write(`data: ${JSON.stringify({
                            type: 'auto_continuation',
                            continuation: continuationCount,
                            maxContinuations: MAX_AUTO_CONTINUATIONS
                        })}\n\n`);
                    } catch (writeErr) {
                        clientConnected = false;
                        break;
                    }
                }

                // Build a slim continuation request:
                // - Keep system prompt
                // - Truncated original user message (NOT full content - it was already processed)
                // - Tail of the response so far as assistant context
                // - Continuation instruction
                const systemMsg = chatMessages.find(m => m.role === 'system');
                const lastUserMsg = [...chatMessages].reverse().find(m => m.role === 'user');

                // Take only the tail of the response for context (~500 tokens)
                const responseTail = fullResponse.length > CONTINUATION_CONTEXT_CHARS
                    ? fullResponse.slice(-CONTINUATION_CONTEXT_CHARS)
                    : fullResponse;

                // Truncate user message to avoid blowing the context on continuation
                // The model already processed the full content; it just needs a reminder of the task
                const maxUserMsgChars = Math.min(800, Math.floor(contextSize * 0.3));
                let userMsgContent = '';
                if (lastUserMsg) {
                    const content = typeof lastUserMsg.content === 'string' ? lastUserMsg.content : '';
                    userMsgContent = content.length > maxUserMsgChars
                        ? content.substring(0, maxUserMsgChars) + '\n[...original content truncated for continuation...]'
                        : content;
                }

                const continuationMessages = [];
                if (systemMsg) continuationMessages.push(systemMsg);
                if (userMsgContent) continuationMessages.push({ role: 'user', content: userMsgContent });
                continuationMessages.push({
                    role: 'assistant',
                    content: responseTail
                });
                // Fence-aware continuation: if the response was cut off INSIDE a
                // fenced code block (an odd number of ``` markers so far → an
                // opening fence with no close), the model must continue the code
                // RAW — re-opening a new ```lang fence here mismatches the merged
                // fences and the remainder renders as PLAIN TEXT in the chat
                // (the "code not displaying in a code block" bug on large /
                // continued responses). Tell it to continue inside the block.
                const openFences = (fullResponse.match(/```/g) || []).length;
                const insideCodeBlock = (openFences % 2) === 1;
                continuationMessages.push({
                    role: 'user',
                    content: insideCodeBlock
                        ? 'Continue from where you left off. Your previous text stopped in the MIDDLE of a code block (there is an opening ``` that has not been closed yet). Continue the code DIRECTLY from the exact character it stopped at — do NOT write a new ``` fence, do NOT repeat any earlier lines, and do NOT add any prose or explanation. Output only the remaining code, then add a single closing ``` once the code is complete.'
                        : 'Continue from where you left off. Do not repeat what you already said, just continue directly.'
                });

                // Calculate available tokens for this continuation
                const continuationInputTokens = continuationMessages.reduce(
                    (sum, msg) => sum + estimateTokens(msg.content), 0
                );
                const continuationMaxTokens = Math.max(
                    512, // minimum useful response
                    contextSize - continuationInputTokens - 200 // leave buffer
                );

                try {
                    finishReason = await streamOneRequest(continuationMessages, continuationMaxTokens);
                } catch (contErr) {
                    // Continuation failed (e.g., 400 from model) - stop gracefully instead of crashing
                    console.error(`[Chat Stream] Auto-continuation ${continuationCount} failed:`, contErr.message);
                    finishReason = 'stop'; // Break the loop gracefully
                }
            }

            if (continuationCount > 0) {
                console.log(`[Chat Stream] Auto-continuation complete after ${continuationCount} continuation(s), total ${fullResponse.length} chars`);
            }

                // --- Tool-call dispatch (native) ---------------------------
                // If the model's turn ended with tool_calls, execute each
                // tool, append the assistant+tool messages to the conversation,
                // and loop back to let the model continue with tool results.
                //
                // Also dispatch when finish_reason is 'length' and tool calls
                // accumulated — the cap was hit mid-arguments JSON, so the
                // last tool call is truncated. The truncation guard in
                // chatTools.executeToolCall returns a clean retry hint for
                // the damaged call; any other calls in the same turn that
                // closed cleanly run normally. Without this, the partial
                // tool_calls would silently be discarded when the outer
                // loop breaks at the bottom.
                if (accumulatedToolCalls.length
                    && (finishReason === 'tool_calls' || finishReason === 'length' || finishReason === 'stop')) {
                    // Include 'stop': Qwen3-MTP on llama.cpp streams a COMPLETE
                    // tool call and then reports finish_reason 'stop' instead of
                    // 'tool_calls'. The old gate skipped those, so a perfectly
                    // good tool call never ran and the turn stalled.
                    const finalizedCalls = chatTools.finalizeToolCalls(accumulatedToolCalls);
                    if (!finalizedCalls.length) {
                        // Tool-call deltas were present but unfinalizable — the
                        // args were truncated mid-JSON (a too-large edit). Don't
                        // silently save a mid-thought tail; force synthesis so the
                        // model writes the result (e.g. the full corrected code)
                        // from context instead of via a tool call that can't fit.
                        toolCallArgsTruncated = true;
                        break;
                    }

                    const toolNames = finalizedCalls.map(c => c?.function?.name || c?.name).filter(Boolean).join(', ');
                    logChatActivity(`→ ${finalizedCalls.length} tool${finalizedCalls.length === 1 ? '' : 's'}${toolNames ? `: ${toolNames}` : ''} (round ${toolCallRound + 1})`);
                    // toolPolicy was hoisted to before the outer loop so the
                    // (potentially large) skills file is read once per request
                    // instead of once per round. policyCache memoizes per name.
                    const toolResultMessages = [];
                    // Skill prompts collected this round — emitted as one
                    // transient system message after the tool results so the
                    // model's next turn sees per-tool behavior rules.
                    const pendingSkillPrompts = [];

                    // PARALLEL DISPATCH (added 2026-05-27): when the model
                    // emits multiple tool_calls in a single round (fetch_url
                    // x 3 after a web_search, parallel web_search + fetch_url,
                    // etc.), run them concurrently with a bounded pool
                    // instead of awaiting each in turn. Loop-detection state
                    // is snapshotted up front so all parallel calls see the
                    // SAME prior history; same-round duplicates collapse to a
                    // single execution shared between callers.
                    const TOOL_PARALLELISM = 6;
                    const historySnapshot = toolCallHistory.slice();
                    const SEARCH_ENGINE_HOST_RE = /^(?:https?:\/\/)?(?:www\.|search\.)?(?:duckduckgo\.com\/html|bing\.com\/search|search\.brave\.com\/search|google\.com\/search|google\.[a-z.]+\/search|yandex\.com\/search|search\.yahoo\.com)/i;
                    const MUTATING_TARGET_EXTRACTORS = {
                        create_file:       a => a?.filePath || a?.path,
                        update_file:       a => a?.filePath || a?.path,
                        append_to_file:    a => a?.filePath || a?.path,
                        delete_file:       a => a?.filePath || a?.path,
                        move_file:         a => a?.destPath || a?.destination || a?.dest,
                        copy_file:         a => a?.destPath || a?.destination || a?.dest,
                        create_directory:  a => a?.dirPath || a?.path,
                        create_pdf:        a => a?.filePath || a?.outputPath,
                        create_xlsx:       a => a?.filePath || a?.outputPath,
                        html_to_pdf:       a => a?.filePath || a?.outputPath,
                        make_downloadable: a => a?.filePath || a?.path,
                    };
                    const webSearchBlockedCount = historySnapshot.filter(
                        h => h.toolName === 'web_search' && h.searchBlocked).length;
                    const scraplingSearchCount = historySnapshot.filter(
                        h => h.toolName === 'scrapling_fetch' && h.searchEngineHost).length;

                    // Pre-resolve per-call metadata (policy + fp + nudge
                    // decisions) and emit tool_executing in original order.
                    const perCall = finalizedCalls.map(call => {
                        const policy = toolPolicy(call.function.name);
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    type: 'tool_executing',
                                    tool_call_id: call.id,
                                    name: call.function.name,
                                    arguments: call.function.arguments,
                                    sandboxed: policy.sandboxed,
                                    source: policy.source,
                                    ...(policy.source === 'skill' ? { network: policy.network, workspace: policy.workspace } : {}),
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                        let targetKey = null;
                        const targetExtractor = MUTATING_TARGET_EXTRACTORS[call.function.name];
                        if (targetExtractor) {
                            try {
                                const parsedArgs = JSON.parse(call.function.arguments || '{}');
                                const target = targetExtractor(parsedArgs);
                                if (target) targetKey = `${call.function.name}:target=${target}`;
                            } catch { /* malformed args — fall back to full-args fp */ }
                        }
                        const fp = targetKey || `${call.function.name}:${call.function.arguments || ''}`;
                        const priorHits = historySnapshot.filter(h => h.fp === fp);
                        const targetRepeat = !!targetKey && priorHits.length >= 1;
                        const argRepeat = !targetKey && priorHits.length >= 2 &&
                            priorHits[priorHits.length - 1].resultHash === priorHits[priorHits.length - 2].resultHash;

                        const callEffName = webEffectiveName(call.function.name, call.function.arguments);
                        const webSearchBlocked = callEffName === 'web_search' &&
                            webSearchBlockedCount >= 2;
                        let scraplingSearchUrl = null;
                        if (call.function.name === 'scrapling_fetch') {
                            try {
                                const u = String(JSON.parse(call.function.arguments || '{}').url || '');
                                if (SEARCH_ENGINE_HOST_RE.test(u)) scraplingSearchUrl = u;
                            } catch { /* */ }
                        }
                        const scraplingSearchLoop = !!scraplingSearchUrl && scraplingSearchCount >= 2;

                        let nudge = null;
                        if (webSearchBlocked || scraplingSearchLoop) {
                            let q = '';
                            try {
                                if (callEffName === 'web_search') {
                                    q = String(JSON.parse(call.function.arguments || '{}').query || '').slice(0, 200);
                                } else if (scraplingSearchUrl) {
                                    const m = scraplingSearchUrl.match(/[?&]q=([^&#]+)/i);
                                    if (m) q = decodeURIComponent(m[1].replace(/\+/g, ' ')).slice(0, 200);
                                }
                            } catch { /* */ }
                            const qEnc = encodeURIComponent(q || '');
                            const leadLine = scraplingSearchLoop
                                ? `STOP routing scrapling_fetch through search-engine pages — DuckDuckGo / Bing / Brave / Google all return JS-only result lists that have no real content for you to read. `
                                : `STOP calling web_search — it has been rate-limited multiple times this turn and will keep failing for the rest of this turn. `;
                            const nudgeText =
                                leadLine +
                                `Pivot to the ARTIFACT or KNOWN SOURCE instead of a search loop:\n` +
                                `1. If you are investigating a named package, fetch the registry record directly with fetch_url, then download and extract the tarball:\n` +
                                `   - npm: GET https://registry.npmjs.org/<pkg> (JSON metadata, find dist.tarball) → fetch_url that .tgz → tar_extract / extract_archive → read_file on the unpacked files.\n` +
                                `   - PyPI: GET https://pypi.org/pypi/<pkg>/json → urls[*].url.\n` +
                                `   - GitHub: fetch_url https://github.com/<owner>/<repo>/archive/refs/heads/<branch>.tar.gz (or use a specific commit/tag).\n` +
                                `2. If you already know the likely source domain (vendor docs, advisory site, blog), call fetch_url or scrapling_fetch on THAT domain directly — never a search-engine URL.\n` +
                                `3. Only if neither applies, retry scrapling_fetch on a search engine ONCE with a narrower query: scrapling_fetch({"url":"https://duckduckgo.com/html/?q=${qEnc}"}).\n` +
                                `Do what you told the user you were going to do — if you said "let me fetch the tarball / package / file directly", do that next, not another search.`;
                            nudge = {
                                error: scraplingSearchLoop ? 'scrapling_search_loop_pivot_to_artifact' : 'web_search_blocked_pivot_to_artifact',
                                message: nudgeText,
                                rate_limited_count: webSearchBlockedCount,
                                search_engine_scrapes: scraplingSearchCount,
                            };
                            console.warn(`[Chat Stream] ${nudge.error}: ${nudge.rate_limited_count} web_search blocks, ${nudge.search_engine_scrapes} search-engine scrapes`);
                        } else if (targetRepeat || argRepeat) {
                            const fileTools = new Set(['read_file', 'tail_file', 'head_file']);
                            const webTools = new Set(['web_search', 'fetch_url']);
                            const loopingToolName = call.function.name;
                            let nudgeText;
                            if (targetRepeat) {
                                const target = targetKey.split('target=')[1];
                                nudgeText = `You already called ${loopingToolName} for "${target}" this turn — that write succeeded. Do not call ${loopingToolName} again for the same target. Either move on to a different file, or stop calling tools and write your final answer to the user describing what you produced.`;
                            } else if (fileTools.has(loopingToolName)) {
                                nudgeText = `You've already called ${loopingToolName} with these arguments and it failed or returned no useful data. The path may not exist — call list_directory on the parent first, or stop and tell the user the file is not accessible.`;
                            } else if (webTools.has(loopingToolName)) {
                                nudgeText = `You've already searched for this with the same query. Try different keywords, or stop and answer with what you have.`;
                            } else {
                                nudgeText = `You've already called ${loopingToolName} with these arguments. Either change the arguments or stop calling tools and write your answer now.`;
                            }
                            if (toolCallRound > 8) {
                                nudgeText += ` You've used 8+ tool calls this turn. Wrap up and answer.`;
                            }
                            nudge = {
                                error: 'loop_detected',
                                message: nudgeText,
                                previous_call_count: priorHits.length,
                            };
                            console.warn(`[Chat Stream] Loop detected for ${call.function.name} (${targetRepeat ? 'target-repeat' : 'arg-repeat'}); short-circuited with nudge after ${priorHits.length} prior call(s)`);
                        }
                        return { call, policy, fp, nudge };
                    });

                    // Same-round dedupe: collapse identical (name, args)
                    // calls so we only run the work once and share the result.
                    const dispatchCache = new Map();
                    const dispatchKey = (call) => `${call.function.name} ${call.function.arguments || ''}`;
                    const runDispatchPool = async (items, n, work) => {
                        const out = new Array(items.length);
                        let next = 0;
                        const workers = new Array(Math.min(n, items.length)).fill(0).map(async () => {
                            while (true) {
                                const i = next++;
                                if (i >= items.length) return;
                                out[i] = await work(items[i], i);
                            }
                        });
                        await Promise.all(workers);
                        return out;
                    };

                    const parallelStart = Date.now();
                    const dispatched = await runDispatchPool(perCall, TOOL_PARALLELISM, async ({ call, nudge }) => {
                        if (nudge) {
                            return {
                                tool_call_id: call.id,
                                role: 'tool',
                                name: call.function.name,
                                content: JSON.stringify(nudge),
                            };
                        }
                        const k = dispatchKey(call);
                        // Sticky: remember the tool this conversation used (by its
                        // effective inner op for `web`) so the router keeps it
                        // advertised on later turns.
                        try { toolRouter.recordConversationToolUse(streamingConversationId, webEffectiveName(call.function.name, call.function.arguments)); } catch (_) {}
                        let p = dispatchCache.get(k);
                        if (!p) {
                            p = chatTools.executeToolCall(call, toolCtx);
                            dispatchCache.set(k, p);
                            return p;
                        }
                        // Duplicate call: await the original execution and
                        // clone the result message with this call's id so the
                        // backend matches it to the right tool_call.
                        const shared = await p;
                        return { ...shared, tool_call_id: call.id };
                    });
                    if (finalizedCalls.length > 1) {
                        console.log(`[Chat Stream] Parallel dispatch: ${finalizedCalls.length} calls in ${Date.now() - parallelStart}ms`);
                    }

                    // Per-call post-processing (sequential, order-preserved):
                    // skill-prompt injection, size cap, history append,
                    // toolResultMessages push, tool_result SSE emit.
                    const TOOL_RESULT_CHAR_CAP = 24_000;
                    for (let idx = 0; idx < perCall.length; idx++) {
                        const { call, policy, fp } = perCall[idx];
                        let resultMsg = dispatched[idx];

                        // Skill `systemPrompt` injection.
                        const callName = call.function.name;
                        if (!chatTools.toolRegistry.has(callName) && !injectedSkillPrompts.has(callName)) {
                            try {
                                const all = await loadSkills();
                                const scoped = filterByUserId(all, toolCtx?.userId);
                                const skill = scoped.find(s => safeToolName(s.name) === callName);
                                if (skill && typeof skill.systemPrompt === 'string' && skill.systemPrompt.trim()) {
                                    let prompt = skill.systemPrompt.trim();
                                    if (prompt.length > SKILL_PROMPT_CHAR_CAP) {
                                        prompt = prompt.slice(0, SKILL_PROMPT_CHAR_CAP) + '…';
                                    }
                                    pendingSkillPrompts.push({ name: skill.name, prompt });
                                    injectedSkillPrompts.add(callName);
                                    console.log(`[Chat Stream] Injecting skill systemPrompt for "${skill.name}" (${prompt.length} chars)`);
                                }
                            } catch (e) {
                                console.warn(`[Chat Stream] Skill prompt lookup failed for ${callName}: ${e.message}`);
                            }
                        }

                        // Per-tool-result size cap.
                        if (typeof resultMsg.content === 'string' && resultMsg.content.length > TOOL_RESULT_CHAR_CAP) {
                            const original = resultMsg.content.length;
                            resultMsg = {
                                ...resultMsg,
                                content: resultMsg.content.slice(0, TOOL_RESULT_CHAR_CAP) +
                                    `\n\n[TRUNCATED — only first ${TOOL_RESULT_CHAR_CAP} characters of ${original} shown (~${Math.round(TOOL_RESULT_CHAR_CAP / 4)} tokens). ` +
                                    `Request a narrower scope if you need more — re-call ${call.function.name} with ` +
                                    `(e.g. a specific entry path, a smaller line range, an entryPath / startLine+endLine arg).]`,
                            };
                            console.warn(`[Chat Stream] Capped ${call.function.name} result: ${original} -> ${TOOL_RESULT_CHAR_CAP} chars`);
                        }
                        // Record fingerprint + result hash for future loop checks.
                        try {
                            const rh = crypto.createHash('sha1')
                                .update(String(resultMsg.content || ''))
                                .digest('hex')
                                .slice(0, 16);
                            // Record the EFFECTIVE inner op for a `web` call so the
                            // rate-limit/loop/experience-memory consumers keyed on
                            // 'web_search'/'fetch_url' keep working post-consolidation.
                            const recName = webEffectiveName(call.function.name, call.function.arguments);
                            let searchBlocked = false;
                            if (recName === 'web_search') {
                                try {
                                    const parsed = JSON.parse(resultMsg.content || '{}');
                                    const errStr = String(parsed?.error || '');
                                    searchBlocked = /rate-limited|fallbacks also failed|blocked/i.test(errStr) ||
                                                    parsed?.count === 0;
                                } catch (_) { /* */ }
                            }
                            let searchEngineHost = false;
                            if (call.function.name === 'scrapling_fetch') {
                                try {
                                    const u = String(JSON.parse(call.function.arguments || '{}').url || '');
                                    searchEngineHost = SEARCH_ENGINE_HOST_RE.test(u);
                                } catch (_) { /* */ }
                            }
                            toolCallHistory.push({
                                fp,
                                resultHash: rh,
                                toolName: recName,
                                searchBlocked,
                                searchEngineHost,
                            });
                            if (toolCallHistory.length > 40) toolCallHistory.shift();
                        } catch (_) { /* */ }
                        toolResultMessages.push(resultMsg);
                        // Bound large-edit truncation loops (see truncatedTargetCounts
                        // above). When this dispatched call returned
                        // {error:'arguments_truncated'}, count it per TARGET FILE.
                        // The args are truncated JSON so JSON.parse fails — pull the
                        // path field by regex (it is early in the object, before the
                        // truncation point). After MAX_EDIT_TRUNCATIONS on one target,
                        // flag exhaustion so the outer loop breaks to direct delivery.
                        try {
                            const wasTruncated = (typeof resultMsg.content === 'string') && resultMsg.content.includes('arguments_truncated');
                            if (wasTruncated) {
                                const rawA = call.function.arguments || '';
                                const mPath = rawA.match(/"(?:filePath|path|outputPath|destPath)"\s*:\s*"([^"]+)"/);
                                const tgt = mPath ? mPath[1] : call.function.name;
                                const c = (truncatedTargetCounts.get(tgt) || 0) + 1;
                                truncatedTargetCounts.set(tgt, c);
                                console.warn(`[Chat Stream] arguments_truncated for "${tgt}" (attempt ${c}/${MAX_EDIT_TRUNCATIONS})`);
                                if (c >= MAX_EDIT_TRUNCATIONS) {
                                    largeEditTruncationExhausted = true;
                                    if (mPath) largeEditTargetPath = tgt;
                                }
                            }
                        } catch (_) { /* best-effort */ }
                        // Accumulate a chip record for the background-save path
                        // (mirrors the client's buildNativeChipEntries). Runs
                        // regardless of clientConnected so a turn that finishes
                        // while the user is away keeps its tool chips on reload.
                        try {
                            let parsedForChip = null;
                            if (typeof resultMsg.content === 'string') {
                                try { parsedForChip = JSON.parse(resultMsg.content); } catch { /* non-JSON result */ }
                            }
                            let parsedArgsForChip = null, argPreview = '';
                            try {
                                parsedArgsForChip = JSON.parse(call.function.arguments || '{}');
                                argPreview = Object.entries(parsedArgsForChip)
                                    .map(([k, v]) => `${k}: ${String(v).slice(0, 60)}`).join(', ');
                            } catch { argPreview = String(call.function.arguments || '').slice(0, 80); }
                            const failedChip = !!(parsedForChip && (parsedForChip.error || parsedForChip.success === false));
                            const chipArtifacts = (parsedForChip && Array.isArray(parsedForChip._artifacts))
                                ? parsedForChip._artifacts
                                    .filter(a => a && typeof a.url === 'string' && typeof a.name === 'string')
                                    .map(a => ({ name: a.name, size: a.size, url: a.url, runId: a.runId }))
                                : null;
                            persistedToolChips.push({
                                type: 'native_tool_call',
                                label: call.function.name || 'tool',
                                query: argPreview,
                                args: parsedArgsForChip,
                                status: failedChip ? 'failed' : 'success',
                                error: failedChip ? String(parsedForChip.error || 'failed').slice(0, 300) : undefined,
                                preview: String(resultMsg.content || '').slice(0, 240),
                                chartSpec: (parsedForChip && parsedForChip.chartSpec) || undefined,
                                chartSummary: (parsedForChip && typeof parsedForChip.summary === 'string') ? parsedForChip.summary : undefined,
                                artifacts: (chipArtifacts && chipArtifacts.length) ? chipArtifacts : undefined,
                                sandboxed: policy.sandboxed,
                                sandboxSource: policy.source,
                                sandboxNetwork: policy.source === 'skill' ? policy.network : undefined,
                            });
                        } catch (_) { /* chip accumulation is best-effort */ }
                        if (clientConnected) {
                            try {
                                const preview = String(resultMsg.content || '').slice(0, 240);
                                let parsedResult = null;
                                if (resultMsg.content && typeof resultMsg.content === 'string') {
                                    try { parsedResult = JSON.parse(resultMsg.content); } catch { /* */ }
                                }
                                const RESULT_SIZE_CAP = 32 * 1024;
                                const isChartTool = call?.function?.name === 'render_chart';
                                const resultPayload = parsedResult && (isChartTool || Buffer.byteLength(resultMsg.content) < RESULT_SIZE_CAP)
                                    ? parsedResult
                                    : undefined;
                                res.write(`data: ${JSON.stringify({
                                    type: 'tool_result',
                                    tool_call_id: call.id,
                                    name: call.function.name,
                                    preview,
                                    sandboxed: policy.sandboxed,
                                    source: policy.source,
                                    ...(policy.source === 'skill' ? { network: policy.network } : {}),
                                    ...(resultPayload !== undefined ? { result: resultPayload } : {}),
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                    }

                    // Build the next round's message list. The assistant
                    // message must carry ONLY this turn's generated content
                    // (not the cumulative stream) alongside its tool_calls.
                    const turnContent = fullResponse.slice(roundStart);
                    // Sanitize tool_calls arguments before re-shipping. When
                    // the model hit its output cap mid-arguments (handled
                    // above by the truncation guard in executeToolCall),
                    // the call's `arguments` string is incomplete JSON.
                    // Some backends (sglang in particular) return 500 when
                    // they re-parse an assistant turn whose tool_calls
                    // carry malformed JSON — which surfaces in the chat UI
                    // as "Request failed with status code 500" / response
                    // cut off. Replace any unparseable args with '{}'; the
                    // matching tool result already conveys the truncation
                    // error to the model so context isn't lost.
                    const safeToolCalls = finalizedCalls.map(tc => {
                        const a = tc?.function?.arguments;
                        if (typeof a !== 'string') return tc;
                        try { JSON.parse(a); return tc; }
                        catch (_) {
                            return {
                                ...tc,
                                function: { ...tc.function, arguments: '{}' },
                            };
                        }
                    });
                    // If any skill in this round carried a Prompt, emit one
                    // combined system message after the tool results. Keep
                    // it short and labeled per-skill so the model can
                    // attribute the rules to the right tool.
                    const skillPromptMsg = pendingSkillPrompts.length
                        ? {
                            role: 'system',
                            content: pendingSkillPrompts
                                .map(p => `Instructions for "${p.name}": ${p.prompt}`)
                                .join('\n\n'),
                        }
                        : null;
                    currentMessages = [
                        ...currentMessages,
                        {
                            role: 'assistant',
                            content: turnContent || null,
                            tool_calls: safeToolCalls,
                        },
                        ...toolResultMessages,
                        ...(skillPromptMsg ? [skillPromptMsg] : []),
                    ];
                    // Bound the truncation grind: the same target file truncated
                    // MAX_EDIT_TRUNCATIONS times. Stop retrying the oversized call
                    // and break to the direct-delivery / forced-synthesis block
                    // (currentMessages above already carries the full context).
                    if (largeEditTruncationExhausted) {
                        console.warn(`[Chat Stream] Large-edit truncation limit hit (target "${largeEditTargetPath || '?'}") after ${toolCallRound + 1} round(s) — stopping tool loop, delivering directly`);
                        break; // exits the while → forced-synthesis / artifact-delivery block
                    }
                    toolCallRound++;
                    continuationCount = 0; // fresh length budget for next turn
                    continue;
                }

                // False-completion detector: model claims a file action
                // ("saved", "created", "wrote") in prose without ever
                // calling a file-write tool. Inject a corrective system
                // message and re-stream once. Capped at one retry.
                if (toolCallRound === 0 && !falseCompletionRetried) {
                    const claimedAction = /\b(saved|created|wrote|generated|exported)\b.*\b(file|to disk|to[\s].*\.(?:txt|md|json|py|csv|xlsx|html))/i.test(fullResponse || '');
                    if (claimedAction) {
                        falseCompletionRetried = true;
                        console.warn('[Chat Stream] False-completion detected — injecting corrective system message and retrying');
                        currentMessages = [
                            ...currentMessages,
                            {
                                role: 'system',
                                content: 'Your previous turn claimed a file action ("saved"/"created"/"wrote") but you did not call a tool. If a file action was needed, call the appropriate tool now. If not, restate plainly what you actually did without claiming file operations.',
                            },
                        ];
                        continue; // re-stream
                    }
                }

                // Abandoned-research detector: after at least one round of
                // tool use, the model ends its turn with a planning verb
                // ("Let me dig deeper", "I'll search for X next") instead
                // of either emitting the next tool_call or writing the
                // final summary. Common with small local LLMs — they
                // narrate intent in prose but the structured tool_call
                // never lands. Without this guard the user sees a partial
                // response and has to manually click Continue.
                if (toolCallRound > 0 && !abandonedResearchRetried) {
                    const trimmed = (fullResponse || '').trim();
                    const tail = trimmed.slice(-220);
                    // Trailing planning verb (e.g. "let me dig", "i'll fetch",
                    // "next, i'll search"). Excludes legitimate narrative
                    // verbs ("explain", "summarize", "know", "see") that
                    // appear in real conclusions.
                    const planSubject = /\b(?:let\s+me|i['’]?ll|i\s+will|next,?\s*i['’]?ll|i\s+should(?:\s+also)?|let['’]?s)\s+/i;
                    const planVerb = /\b(?:dig|search(?:\s+for)?|fetch|look\s+(?:up|into|at|for)|check|grab|find|examine|investigate|review|gather|pull|retrieve|explore|verify|confirm|try|do|re-?read|read|inspect|trace|parse|scan|open|view|load|study|map|locate|understand\s+the)\b/i;
                    const isShort = trimmed.length < 800;
                    if (isShort && planSubject.test(tail) && planVerb.test(tail)) {
                        abandonedResearchRetried = true;
                        const snippet = tail.replace(/\s+/g, ' ').slice(-140);
                        console.warn(`[Chat Stream] Abandoned-research detected after ${toolCallRound} tool round(s) — re-streaming with nudge. Tail: "${snippet}"`);
                        currentMessages = [
                            ...currentMessages,
                            {
                                role: 'system',
                                content: 'You ended your last turn announcing more work ("' + snippet + '") but did not actually emit the tool_call. Either call the tool now to follow through, OR write the final answer to the user using the tool results already in this conversation. Do not narrate plans without executing them — the runtime only acts on real tool_calls.',
                            },
                        ];
                        continue; // re-stream
                    }
                }

                // Announced-action detector: the model described a tool-shaped
                // action it was ABOUT to take ("let me write Python to parse the
                // log and create the chart", "I'll generate a graph", "let me
                // plot this") but ended the turn with NO tool_call — common with
                // reasoning-on local models on ROUND 0, where they narrate the
                // plan in prose and emit EOS without ever calling render_chart /
                // run_python / create_file. None of the detectors above catch
                // this: abandoned-research requires toolCallRound > 0 and uses
                // research verbs (dig/search/fetch), and false-completion only
                // matches PAST-tense file claims. So "Graph this training run"
                // → the model says "let me write Python to create the chart" →
                // EOS → user sees narration and never gets the chart. Nudge once
                // to actually emit the tool_call. Conservative: requires an
                // intent phrase + a creation verb + a concrete artifact target
                // in the tail, a short turn, and zero tool_calls this round.
                if (!announcedActionRetried && accumulatedToolCalls.length === 0) {
                    const trimmed = (fullResponse || '').trim();
                    const tail = trimmed.slice(-320);
                    const intent = /\b(?:let\s+me|let['’]?s|i['’]?ll|i\s+will|i\s+can|i\s+am\s+going\s+to|i['’]?m\s+going\s+to|i['’]?m\s+gonna|here['’]?s|now\s+i['’]?ll|now\s+let['’]?s)\b/i;
                    const actionVerb = /\b(?:writ(?:e|ing)|creat(?:e|ing)|generat(?:e|ing)|build(?:ing)?|mak(?:e|ing)|plot(?:t(?:ed|ing))?|graph(?:ing)?|chart(?:ing)?|render(?:ing)?|draw(?:ing)?|produc(?:e|ing)|comput(?:e|ing)|calculat(?:e|ing)|pars(?:e|ing)|run(?:ning)?|execut(?:e|ing)|cod(?:e|ing)|extract(?:ing)?|fix(?:ing)?|implement(?:ing)?|updat(?:e|ing)|edit(?:ing)?|modif(?:y|ying)|rewrit(?:e|ing)|refactor(?:ing)?|appl(?:y|ying)|add(?:ing)?)\b/i;
                    const target = /\b(chart|graph|plot|figure|visuali[sz]ation|diagram|file|code|script|python|table|spreadsheet|csv|pdf|image|document)\b/i;
                    const isShort = trimmed.length < 1400;
                    if (isShort && intent.test(tail) && actionVerb.test(tail) && target.test(tail)) {
                        announcedActionRetried = true;
                        const snippet = tail.replace(/\s+/g, ' ').slice(-160);
                        console.warn(`[Chat Stream] Announced-action-without-tool detected (round ${toolCallRound}) — re-streaming with nudge. Tail: "${snippet}"`);
                        currentMessages = [
                            ...currentMessages,
                            {
                                role: 'system',
                                content: 'You described an action you were going to take ("' + snippet + '") but did NOT emit the tool_call, so nothing actually happened and the user got no result. The runtime only acts on real tool_calls — narrating a plan does nothing. Call the appropriate tool NOW with the full arguments: to produce a chart, call render_chart; to run code, call run_python; to write a file, call create_file. Do not describe what you would do — emit the tool_call.',
                            },
                        ];
                        continue; // re-stream
                    }
                }

                // Normal end — no tool calls. Exit outer loop.
                break;
            } // end tool-call outer loop

            // Forced synthesis triggers in two distinct situations:
            //
            // 1. We hit MAX_TOOL_ITERATIONS with the model still asking for
            //    tool calls. Historic trigger — model wants more tools but
            //    we cut it off; need to force it to write text now.
            //
            // 2. The model exited the tool loop before the cap but with
            //    EMPTY fullResponse. Observed on gemma-4 after 5 real tool
            //    calls, where round 6 emits `finish_reason=tool_calls`
            //    with malformed/empty args (accumulator drops them) or
            //    `finish_reason=stop` with zero content. Outer loop breaks,
            //    user sees tool chips run and then nothing — no summary,
            //    no answer. Re-run with tools suppressed so the model has
            //    to write text from the tool results already in context.
            //
            // 4. A reasoning loop persisted through every nudge retry
            //    (reasoningLoopExhausted). This is now ALSO a forced-synthesis
            //    trigger: rather than dead-stopping, we suppress tools AND
            //    thinking (/no_think) and make the model answer from what it
            //    has. Handled in the trigger below + the synthesis message.
            const hitIterationCap = toolCallRound > chatTools.MAX_TOOL_ITERATIONS
                && (finishReason === 'tool_calls'
                    || (finishReason === 'length' && accumulatedToolCalls.length > 0));
            const exitedEmptyAfterTools = toolCallRound > 0 && !fullResponse.trim();
            // 3. The model walked through many tool calls narrating each step
            //    ("Let me try X", "Now let me Y:") and then stopped mid-thought
            //    with the trailing text ending on a sentence-fragment marker
            //    (':', '—', ';', etc.) and no final tool_call. Cumulative
            //    fullResponse is non-empty (so exitedEmptyAfterTools misses it),
            //    but the user sees a long running narration that never lands an
            //    actual answer. Force synthesis so the model has to summarize
            //    what it did and didn't accomplish. Conservative: only triggers
            //    after at least 2 tool rounds — short answers like "Steps:" on
            //    a single-round response are uncommon enough to ignore, and
            //    most legitimate completions end with a period, code fence, or
            //    closing bracket.
            const trailing = fullResponse.replace(/\s+$/, '');
            const endsMidThought = trailing.length > 0
                && /[:;—–]\s*$/.test(trailing.slice(-4));
            const exitedMidThought = toolCallRound > 1 && endsMidThought
                && accumulatedToolCalls.length === 0;
            if (hitIterationCap || exitedEmptyAfterTools || exitedMidThought || reasoningLoopExhausted || toolCallArgsTruncated || largeEditTruncationExhausted) {
                if (reasoningLoopExhausted) {
                    console.warn(`[Chat Stream] Reasoning loop exhausted — forcing tools+thinking-suppressed synthesis`);
                } else if (largeEditTruncationExhausted) {
                    console.warn(`[Chat Stream] Large-edit truncation exhausted — delivering already-written file / forcing synthesis`);
                } else if (toolCallArgsTruncated) {
                    console.warn(`[Chat Stream] Tool-call arguments truncated (could not finalize/dispatch) — forcing synthesis so the model writes the result directly`);
                } else if (hitIterationCap) {
                    console.warn(`[Chat Stream] Max tool iterations (${chatTools.MAX_TOOL_ITERATIONS}) reached — forcing synthesis`);
                } else if (exitedMidThought) {
                    console.warn(`[Chat Stream] Tool loop exited mid-thought after ${toolCallRound} tool call(s) — forcing synthesis (trail: ${JSON.stringify(trailing.slice(-60))})`);
                } else {
                    console.warn(`[Chat Stream] Tool loop exited with empty response after ${toolCallRound} tool call(s) — forcing synthesis`);
                }
                // Run synthesis when the client is connected OR when the turn
                // must still generate into fullResponse for a BACKGROUND turn so
                // it persists a real answer instead of a blank/partial bubble
                // (reasoning loop, or a truncated tool call that left only a
                // mid-thought prose tail). res.write calls self-guard on
                // clientConnected.
                if (clientConnected || reasoningLoopExhausted || toolCallArgsTruncated || largeEditTruncationExhausted) {
                    // Snapshot the content BEFORE synthesis so we can tell whether
                    // the synthesis actually produced anything NEW. The pre-synth
                    // fullResponse is just the mid-thought narration / partial tail
                    // that triggered synthesis in the first place, so "synthesis
                    // added nothing" must drive the soft-note fallback — gating it
                    // on `!fullResponse.trim()` (old behavior) missed the common
                    // case where the model left narration but no real answer.
                    const preSynthLen = fullResponse.length;
                    // Direct artifact delivery: we bailed because a large file edit
                    // kept truncating, but the file is ALREADY written in this
                    // conversation's workspace. Surface it as a download chip
                    // instead of forcing the model to echo ~20k tokens (slow +
                    // truncation-prone). Best-effort — on any failure we fall
                    // through to inline synthesis so the turn still delivers.
                    let deliveredViaArtifact = false;
                    if (largeEditTruncationExhausted && largeEditTargetPath) {
                        try {
                            const dlCall = {
                                id: `call_dl_${toolCallRound}_${fullResponse.length}`,
                                type: 'function',
                                function: { name: 'make_downloadable', arguments: JSON.stringify({ sourcePath: largeEditTargetPath }) },
                            };
                            if (clientConnected) {
                                try { res.write(`data: ${JSON.stringify({ type: 'tool_executing', tool_call_id: dlCall.id, name: 'make_downloadable', arguments: dlCall.function.arguments, sandboxed: true, source: 'skill' })}\n\n`); } catch (_) { clientConnected = false; }
                            }
                            const dlResult = await chatTools.executeToolCall(dlCall, toolCtx);
                            let dlParsed = null;
                            try { dlParsed = JSON.parse(dlResult.content || '{}'); } catch (_) { /* */ }
                            if (dlParsed && dlParsed.success) {
                                const arts = Array.isArray(dlParsed._artifacts)
                                    ? dlParsed._artifacts.filter(a => a && a.url && a.name).map(a => ({ name: a.name, size: a.size, url: a.url, runId: a.runId }))
                                    : null;
                                persistedToolChips.push({
                                    type: 'native_tool_call',
                                    label: 'make_downloadable',
                                    query: `sourcePath: ${largeEditTargetPath}`,
                                    args: { sourcePath: largeEditTargetPath },
                                    status: 'success',
                                    preview: String(dlResult.content || '').slice(0, 240),
                                    artifacts: (arts && arts.length) ? arts : undefined,
                                    sandboxed: true,
                                    sandboxSource: 'skill',
                                });
                                if (clientConnected) {
                                    try { res.write(`data: ${JSON.stringify({ type: 'tool_result', tool_call_id: dlCall.id, name: 'make_downloadable', preview: String(dlResult.content || '').slice(0, 240), sandboxed: true, source: 'skill', result: dlParsed })}\n\n`); } catch (_) { clientConnected = false; }
                                }
                                deliveredViaArtifact = true;
                                console.log(`[Chat Stream] Delivered "${largeEditTargetPath}" as a download artifact instead of echoing it inline`);
                            }
                        } catch (e) {
                            console.warn('[Chat Stream] Artifact delivery failed, falling back to inline synthesis:', e.message);
                        }
                    }
                    try {
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    type: 'status',
                                    message: reasoningLoopExhausted
                                        ? 'Model kept over-deliberating — forcing a direct answer'
                                        : deliveredViaArtifact
                                        ? 'The edit was too large to paste — attaching the updated file as a download'
                                        : (toolCallArgsTruncated || largeEditTruncationExhausted)
                                        ? 'That edit was too large to apply in one step — writing the result directly'
                                        : 'Tool call budget exhausted — synthesizing from collected results',
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                        // For an exhausted reasoning loop, prepend /no_think (when
                        // the model honors it) so the synthesis itself can't loop
                        // again, and tell it plainly to stop deliberating.
                        // /no_think on EVERY forced-synthesis path (not just the
                        // loop/truncation ones): a reasoning-ON model that reached
                        // synthesis must produce a direct answer, not think again.
                        // Belt-and-braces with the forceNoThink kwarg below.
                        const loopSynthPrefix = modelSupportsNoThinkPrefix(targetModel) ? '/no_think\n' : '';
                        const synthesisMessages = [
                            ...currentMessages,
                            {
                                role: 'user',
                                content: deliveredViaArtifact
                                    ? loopSynthPrefix +
                                      'The complete updated file has ALREADY been attached to this conversation as a downloadable file ' +
                                      '(it was too large to paste inline). Do NOT paste the file contents and do NOT call any tools. ' +
                                      'In 2-4 short sentences, tell the user the updated file is available as a download below and ' +
                                      'summarize the specific edits you applied.'
                                    : reasoningLoopExhausted
                                    ? loopSynthPrefix +
                                      'You kept repeating your reasoning without ever answering. Stop deliberating completely. ' +
                                      'Write the best direct answer you can RIGHT NOW using what is already in this conversation. ' +
                                      'Do not call any tools and do not think out loud — just give the answer, even if brief or partial.'
                                    : (toolCallArgsTruncated || largeEditTruncationExhausted)
                                    ? loopSynthPrefix +
                                      'Your last tool call could NOT run: its arguments were too large and got cut off mid-way. ' +
                                      'Do NOT call any tools now. Instead, deliver the result DIRECTLY to the user in this message. ' +
                                      'If you were editing or writing a file, output the COMPLETE updated file content in a single ' +
                                      'fenced code block (with the correct language tag) — do not abbreviate, do not use "// ... rest ' +
                                      'unchanged" placeholders, include the whole thing. Use the file contents already in this ' +
                                      'conversation as your starting point and apply the changes you intended.'
                                    : hitIterationCap
                                    ? 'You have reached the maximum number of tool calls allowed for this turn. ' +
                                      'Synthesize your final answer now from the tool results already in this conversation — ' +
                                      'do not request any more tools. If some information is missing, state that clearly ' +
                                      'and summarize what you did find.'
                                    : loopSynthPrefix +
                                      'You have called several tools and now must write your actual answer — STOP planning ' +
                                      'and DELIVER it in THIS message. Do not call any more tools and do not say "let me…". ' +
                                      'If the task was to write or edit code or a file, output the COMPLETE result now in a ' +
                                      'single fenced code block (correct language tag, the whole file/section, no "// ... rest ' +
                                      'unchanged" placeholders), using the file/tool contents already in this conversation. ' +
                                      'Otherwise answer the original question directly from the tool results. You MUST produce ' +
                                      'the answer now.',
                            },
                        ];
                        // Suppress the tools catalog for this last round so
                        // the backend can't re-offer function calls. The
                        // closure captures toolCatalog by reference; mutating
                        // it in place is enough for the next streamOneRequest.
                        const savedCatalog = toolCatalog.slice();
                        toolCatalog.length = 0;
                        try {
                            // Same per-round budget recomputation as the main
                            // tool loop — synthesisMessages is currentMessages
                            // plus a forcing user note, so its size has drifted
                            // from initialMaxTokens' assumptions.
                            const synthInputTokens = synthesisMessages.reduce(
                                (sum, m) => sum + estimateTokens(m.content), 0
                            );
                            // Allow synthesis to use real context headroom (up to
                            // 32k) so it can emit a LARGE deliverable — a full
                            // rewritten file. initialMaxTokens is often the client's
                            // prose max_tokens (e.g. 8192), far too small to fit a
                            // whole file, so the code block would truncate mid-way.
                            const synthHeadroom = contextSize - synthInputTokens - 200;
                            // Artifact delivery only needs a short prose summary; an
                            // inline deliverable needs real headroom (up to 32k) so a
                            // full file fits instead of truncating mid-code-block.
                            const synthMaxTokens = deliveredViaArtifact
                                ? Math.max(512, Math.min(2048, synthHeadroom))
                                : Math.max(512, Math.min(Math.max(initialMaxTokens, 32768), synthHeadroom));
                            // Actually turn OFF the model's reasoning pass for the
                            // synthesis (not just hide it). On a reasoning-ON Qwen3-
                            // MTP model the synthesis would otherwise spend its whole
                            // budget thinking and emit NO content — the exact failure
                            // behind "did a bunch of work, produced nothing". The
                            // kwarg is honored by the Qwen template; a backend that
                            // 4xxs on it gets one retry without (mirrors
                            // requestModelCompletion's enable_thinking fallback).
                            const synthNoThink = modelSupportsNoThinkPrefix(targetModel);
                            let synthFinish = 'stop';
                            try {
                                synthFinish = await streamOneRequest(synthesisMessages, synthMaxTokens, { forceNoThink: synthNoThink });
                            } catch (noThinkErr) {
                                const status = noThinkErr?.response?.status;
                                if (synthNoThink && status >= 400 && status < 500 && !fullResponse.trim()) {
                                    console.warn('[Chat Stream] Forced-synthesis enable_thinking kwarg rejected (' + status + ') — retrying without it');
                                    synthFinish = await streamOneRequest(synthesisMessages, synthMaxTokens);
                                } else {
                                    throw noThinkErr;
                                }
                            }
                            // Continue an INLINE deliverable that hit the token cap
                            // mid-code-block (synthesis is a single streamOneRequest
                            // with no auto-continuation of its own). Bounded by
                            // MAX_AUTO_CONTINUATIONS; skipped for artifact delivery
                            // (its 2-4 sentence summary never needs continuing).
                            let synthCont = 0;
                            while (!deliveredViaArtifact && synthFinish === 'length' && synthCont < MAX_AUTO_CONTINUATIONS) {
                                synthCont++;
                                const sysMsg = synthesisMessages.find(m => m.role === 'system');
                                const contMsgs = [];
                                if (sysMsg) contMsgs.push(sysMsg);
                                contMsgs.push({ role: 'assistant', content: fullResponse.slice(-CONTINUATION_CONTEXT_CHARS) });
                                contMsgs.push({ role: 'user', content: (loopSynthPrefix || '') + 'Continue the output from EXACTLY where you left off — do not repeat any earlier text and do not add commentary. Just continue the file/code, and end with the closing ``` fence when it is complete.' });
                                const contIn = contMsgs.reduce((s, m) => s + estimateTokens(m.content), 0);
                                const contBudget = Math.max(512, Math.min(32768, contextSize - contIn - 200));
                                try { synthFinish = await streamOneRequest(contMsgs, contBudget, { forceNoThink: synthNoThink }); }
                                catch (e) { console.warn('[Chat Stream] Synthesis continuation failed:', e.message); break; }
                            }
                            if (!deliveredViaArtifact && synthFinish === 'length') {
                                const note = '\n\n_[The output above may be cut off at the length limit — ask me to "continue from where you left off", or ask for it as a downloadable file.]_';
                                fullResponse += note;
                                if (streamingConversationId) { const job = activeStreamingJobs.get(streamingConversationId); if (job) job.content = fullResponse; }
                                if (clientConnected) { try { res.write(`data: ${JSON.stringify({ choices: [{ delta: { content: note }, index: 0 }] })}\n\n`); } catch (_) { clientConnected = false; } }
                            }
                        } finally {
                            toolCatalog.length = 0;
                            toolCatalog.push(...savedCatalog);
                        }
                    } catch (synthErr) {
                        console.warn('[Chat Stream] Forced synthesis failed:', synthErr.message);
                    }
                    // Last-resort note: if the forced synthesis STILL produced
                    // nothing (ANY trigger, not just a persisted reasoning loop).
                    // Without this the turn persists a BLANK assistant bubble, so
                    // a follow-up "continue" has zero prior content to build on and
                    // the model restarts from scratch — exactly the reported
                    // "started over with no context". Writing a note guarantees the
                    // saved conversation always carries something. Mutate
                    // fullResponse unconditionally (covers backgrounded turns);
                    // gate only the SSE on clientConnected.
                    const synthAddedContent = fullResponse.length > preSynthLen;
                    if (!synthAddedContent) {
                        const soft = reasoningLoopExhausted
                            ? '_[I got stuck repeating my reasoning and could not converge on an answer. Try rephrasing the request, breaking it into smaller steps, or switching to a different model.]_'
                            : '_[I worked through this but did not produce a final answer — I may have spent the turn researching or planning without writing the result. Try asking again (e.g. "write the full updated file now"), or break the request into smaller steps.]_';
                        fullResponse += soft;
                        if (streamingConversationId) {
                            const job = activeStreamingJobs.get(streamingConversationId);
                            if (job) job.content = fullResponse;
                        }
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    choices: [{ delta: { content: soft }, index: 0 }],
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                    }
                }
            }

            // --- Misrouted-reasoning fix ------------------------------
            // Some llama.cpp chat templates (observed on Gemma-4 family)
            // route the entire response to delta.reasoning_content when
            // the model emits a `[{"thought": "..."}]` JSON preamble.
            // Result: persisted message has content="" and reasoning=
            // <the full answer>. UI shows the whole thing inside the
            // Thinking dropdown and never renders the main bubble.
            //
            // Detect the preamble signature, strip it, and move the
            // remainder into content. Emit a `reasoning_reclassified`
            // SSE event so the streaming client can swap its local
            // state before finalizing the message (otherwise the in-
            // session bubble stays stuck in the Thinking panel).
            if (!fullResponse.trim() && fullReasoning) {
                const THOUGHT_PREFIX = /^\s*\[\s*(?:\{\s*"thought"\s*:\s*"[^"]*"\s*\}\s*,?\s*)+\]\s*/;
                const match = fullReasoning.match(THOUGHT_PREFIX);
                if (match) {
                    const remainder = fullReasoning.slice(match[0].length);
                    if (remainder.trim()) {
                        console.log(`[Chat Stream] Misrouted content detected: ${remainder.length} chars in reasoning → moving to content`);
                        fullResponse = remainder;
                        fullReasoning = '';
                        if (streamingConversationId) {
                            const job = activeStreamingJobs.get(streamingConversationId);
                            if (job) {
                                job.content = fullResponse;
                                job.reasoning = '';
                            }
                        }
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    type: 'reasoning_reclassified',
                                    content: remainder,
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                    }
                }
            }

            // --- Auto-invoke base64_decode on output ------------------
            // If the model's final response contains base64 the
            // pre-flight didn't already cover (e.g. the model quoted
            // an encoded blob and offered a hallucinated "decoding"),
            // run the skill against the response and push a
            // tool_result SSE event so the UI surfaces the real
            // decoded values. The response text itself is left as the
            // model wrote it — the tool_result sits alongside as a
            // trustworthy ground-truth panel.
            if (fullResponse && b64CatalogExposed) {
                try {
                    const found = base64Detector
                        .findBase64InText(fullResponse)
                        .filter(f => !b64PreflightEncoded.has(f.encoded));
                    if (found.length > 0) {
                        const call = {
                            id: `call_auto_b64_out_${Date.now()}`,
                            type: 'function',
                            function: {
                                name: 'base64_decode',
                                arguments: JSON.stringify({ text: fullResponse }),
                            },
                        };
                        const result = {
                            success: true,
                            mode: found.length === 1 ? 'single' : 'scan',
                            count: found.length,
                            results: found,
                            note: `Auto-decoded ${found.length} base64 string(s) found in response`,
                            source: 'response',
                        };
                        if (clientConnected) {
                            try {
                                res.write(`data: ${JSON.stringify({
                                    type: 'tool_executing',
                                    tool_call_id: call.id,
                                    name: 'base64_decode',
                                    arguments: call.function.arguments,
                                })}\n\n`);
                                res.write(`data: ${JSON.stringify({
                                    type: 'tool_result',
                                    tool_call_id: call.id,
                                    name: 'base64_decode',
                                    preview: JSON.stringify(result).slice(0, 240),
                                    result,
                                })}\n\n`);
                            } catch (_) { clientConnected = false; }
                        }
                        logChatActivity(`Auto-invoked base64_decode on response (${found.length} candidate(s))`);
                    }
                } catch (e) {
                    console.warn('[Chat Stream] base64 post-flight failed:', e.message);
                }
            }
        } catch (streamError) {
            const isAborted = streamAbortController.signal.aborted || streamError.name === 'AbortError' || streamError.code === 'ERR_CANCELED';
            if (isAborted) {
                console.log(`[Chat Stream] Stream aborted by user for conversation ${streamingConversationId}`);
            } else {
                console.error('Stream error:', streamError);
                if (clientConnected && !res.writableEnded) {
                    // Translate DNS failures for the model hostname into an
                    // actionable message. axios/dockerode raises EAI_AGAIN or
                    // ENOTFOUND when the container is gone from the Docker
                    // network — usually because it crashed or was OOM-killed
                    // between requests. The raw getaddrinfo error is confusing
                    // in the chat UI; tell the user what actually happened.
                    const rawCode = streamError.code || streamError.cause?.code;
                    const isDnsFailure = rawCode === 'EAI_AGAIN' || rawCode === 'ENOTFOUND';
                    const isRefused = rawCode === 'ECONNREFUSED' || rawCode === 'ECONNRESET';
                    let friendly = streamError.message;
                    if (isDnsFailure || isRefused) {
                        const inst = targetInstance;
                        const status = inst?.status;
                        friendly = status === 'oom_killed'
                            ? `Model container was killed by the OOM killer. Reload the model with a smaller context size (current: ${inst?.config?.contextSize ?? 'unknown'}) and try again.`
                            : `Model container is not reachable (${rawCode}). It likely crashed or was stopped — reload it from the Running Instances panel and retry.`;
                    }
                    const errorEvent = { error: friendly, done: true };
                    try {
                        res.write(`data: ${JSON.stringify(errorEvent)}\n\n`);
                    } catch (writeErr) { /* client disconnected */ }
                }
            }
        }

        // Save the completed assistant response to disk on every successful
        // stream, regardless of whether the client is still connected.
        //
        // The old guard (!clientConnected) trusted the client to POST its
        // own save once it received [DONE]. In practice, if the user
        // refreshed the tab or switched conversations in the ~100 ms
        // window between [DONE] arriving and the fire-and-forget save POST
        // landing, the save was aborted by the page unload and the whole
        // response was lost. By saving server-side too we turn this into
        // a belt-and-suspenders: disk is up-to-date before the client even
        // sees [DONE], and the client's subsequent POST overwrites with
        // the same array — idempotent, no duplicate assistant turn.
        //
        // Aborted streams still skip; the DELETE /streaming cancel
        // endpoint handles partial-response persistence for those.
        const wasAborted = streamAbortController.signal.aborted;
        // User-cancelled aborts skip this save — DELETE /streaming handles
        // persistence for those. A reasoning loop no longer aborts the
        // turn-level controller (it recovers in-place), so the normal
        // !wasAborted path persists the recovered/synthesized answer (or the
        // last-resort note) just like any other completed turn.
        if (!wasAborted && streamingConversationId && fullResponse) {
            try {
                const conversationMsgs = await loadConversationMessages(userId, streamingConversationId);
                // Only append if the last message isn't already this
                // assistant turn (guards against a racing client-save
                // having landed first with a slightly different id).
                const last = conversationMsgs[conversationMsgs.length - 1];
                const alreadyPresent = last && last.role === 'assistant' &&
                    typeof last.content === 'string' &&
                    last.content.length >= fullResponse.length - 2 &&
                    last.content.slice(0, 200) === fullResponse.slice(0, 200);
                if (!alreadyPresent) {
                    const assistantMessage = {
                        id: crypto.randomUUID(),
                        role: 'assistant',
                        content: fullResponse,
                        reasoning: fullReasoning || undefined,
                        timestamp: new Date().toISOString(),
                        responseTime: Date.now() - streamStartTime,
                        tokenCount: completionTokens,
                        // Persist the tool chips so a background-completed turn
                        // (user navigated away) shows them on reload — the
                        // foreground commit does this client-side; this is the
                        // parity for the server-side save.
                        toolCalls: persistedToolChips.length ? persistedToolChips : undefined,
                        backgroundCompleted: !clientConnected
                    };
                    conversationMsgs.push(assistantMessage);
                    await saveConversationMessages(userId, streamingConversationId, conversationMsgs, { memoryUserId: chatMemId });
                    console.log(`[Chat Stream] Response saved to ${streamingConversationId} (clientConnected=${clientConnected})`);
                }
            } catch (saveErr) {
                console.error(`[Chat Stream] Failed to save response:`, saveErr);
            }
        }

        // Record/refine the EXPERIENCE memory for THIS turn's activity (the
        // model's persona). Fire-and-forget — must never block the response.
        // Captures the successful tool path so the next similar task front-loads
        // what worked and skips re-exploration → fewer tool calls, faster.
        // Skipped on an exhausted reasoning loop — its tool path is degenerate
        // (the model never converged) and would poison the procedure store.
        if (streamingConversationId && !streamAbortController.signal.aborted && !reasoningLoopExhausted) {
            recordTurnActivity({
                userId: chatMemId,
                conversationId: streamingConversationId,
                toolChips: persistedToolChips,
                userText: latestUserText,
                attachments: req.body?.attachments,
            }).catch(() => {});
        }

        // Clean up the streaming job
        if (streamingConversationId) {
            activeStreamingJobs.delete(streamingConversationId);
        }

        // Send final event to client
        if (clientConnected && !res.writableEnded) {
            const actualFinishReason = (continuationCount >= MAX_AUTO_CONTINUATIONS) ? 'length' : 'stop';
            const finalEvent = {
                done: true,
                choices: [{
                    delta: {},
                    index: 0,
                    finish_reason: actualFinishReason
                }],
                tokens: {
                    prompt_tokens: promptTokens,
                    completion_tokens: completionTokens,
                    total_tokens: promptTokens + completionTokens
                },
                usage: {
                    prompt_tokens: promptTokens,
                    completion_tokens: completionTokens,
                    total_tokens: promptTokens + completionTokens
                },
                model: targetModel,
                contextSize: contextSize,
                ...(continuationCount > 0 && {
                    autoContinuation: {
                        continuations: continuationCount,
                        maxReached: continuationCount >= MAX_AUTO_CONTINUATIONS
                    }
                }),
                ...(toolCallRound > 0 && {
                    toolCalls: {
                        rounds: toolCallRound,
                        maxReached: toolCallRound > chatTools.MAX_TOOL_ITERATIONS,
                    },
                }),
                // Include content continuation info if input content was truncated
                ...(contentTruncated && {
                    continuation: {
                        hasMore: true,
                        ...truncationInfo,
                        message: `Content was split into ${truncationInfo.totalChunks} chunks. Processed chunk ${truncationInfo.currentChunk}. ~${truncationInfo.remainingTokens.toLocaleString()} tokens remaining.`
                    }
                }),
                // Include AIMem compression info if applied
                ...(aimemApplied && {
                    aimem: {
                        compressed: true,
                        tokensSaved: aimemStats?.tokens_saved || 0,
                        reductionPct: aimemStats?.reduction_pct || 0
                    }
                }),
                // Include agentic indexing info if applied
                ...(useAgentic && agenticInfo && {
                    agentic: {
                        documentId: agenticInfo.documentId,
                        totalChunks: agenticInfo.totalChunks,
                        totalChars: agenticInfo.totalChars,
                    }
                })
            };
            try {
                res.write(`data: ${JSON.stringify(finalEvent)}\n\n`);
            } catch (writeErr) { /* client disconnected */ }

            // If there's remaining content, store it for continuation
            if (remainingContent && req.body.conversationId) {
                contentContinuationQueue.set(req.body.conversationId, {
                    content: remainingContent,
                    processedChunks: truncationInfo?.currentChunk || 1,
                    totalChunks: truncationInfo?.totalChunks || 1,
                    contextSize,
                    modelName: targetModel,
                    timestamp: Date.now()
                });
                console.log(`[Chat Stream] Queued ${remainingContent.length} chars for continuation (conversation: ${req.body.conversationId})`);
            }

            try {
                res.write(`data: [DONE]\n\n`);
            } catch (writeErr) { /* client disconnected */ }

            // Update token usage stats
            if (req.apiKeyData) {
                const stats = apiKeyUsageStats.get(req.apiKeyData.id);
                if (stats && stats.requests.length > 0) {
                    const totalTokens = promptTokens + completionTokens;
                    const lastReq = stats.requests[stats.requests.length - 1];
                    lastReq.tokens = totalTokens;
                    stats.tokenCount += totalTokens;
                    apiKeyUsageStats.set(req.apiKeyData.id, stats);
                }
            }

            // Broadcast chat request completion to logs
            const chatResponseTimeMs = Date.now() - streamStartTime;
            const chatTotalTokens = promptTokens + completionTokens;
            const elapsed = chatResponseTimeMs >= 1000 ? `${(chatResponseTimeMs / 1000).toFixed(1)}s` : `${chatResponseTimeMs}ms`;
            broadcast({
                type: 'log',
                message: `[Chat] ${chatWho} ← ${chatTotalTokens} tokens (${promptTokens}+${completionTokens}, ${elapsed})`,
                level: 'success',
                targetUserId: req.userId
            });

            try {
                res.end();
            } catch (endErr) { /* client disconnected */ }
        }

        // Handle client disconnect - DON'T destroy stream, let it continue in background
        req.on('close', () => {
            clientConnected = false;
            // Update the job to mark client as disconnected
            if (streamingConversationId) {
                const job = activeStreamingJobs.get(streamingConversationId);
                if (job) {
                    job.clientConnected = false;
                    console.log(`[Chat Stream] Client disconnected for conversation ${streamingConversationId}, continuing in background...`);
                }
            }
        });

    } catch (error) {
        // Build detailed error message for debugging and user feedback
        let errorMessage = 'Failed to get response from model';
        let errorDetails = '';

        // Handle stream response data (axios returns streams when responseType is 'stream')
        if (error.response?.data && typeof error.response.data.on === 'function') {
            // It's a stream - read it to get the error message
            try {
                const chunks = [];
                for await (const chunk of error.response.data) {
                    chunks.push(chunk);
                }
                const errorBody = Buffer.concat(chunks).toString('utf8');
                console.error('Chat stream error:', error.message, '| Status:', error.response?.status, '| Response:', errorBody);

                // Try to parse as JSON
                try {
                    const parsed = JSON.parse(errorBody);
                    errorDetails = parsed.error?.message || parsed.error || errorBody;
                } catch (e) {
                    errorDetails = errorBody;
                }
            } catch (streamErr) {
                console.error('Chat stream error:', error.message, '| Status:', error.response?.status, '| Could not read stream');
                errorDetails = error.message;
            }
        }
        // Extract error details from various sources (non-stream responses)
        else if (error.response?.data?.error?.message) {
            errorDetails = error.response.data.error.message;
            console.error('Chat stream error:', error.message, '| Status:', error.response?.status, '| Response:', errorDetails);
        } else if (error.response?.data?.error) {
            errorDetails = typeof error.response.data.error === 'string'
                ? error.response.data.error
                : JSON.stringify(error.response.data.error);
            console.error('Chat stream error:', error.message, '| Status:', error.response?.status, '| Response:', errorDetails);
        } else if (error.response?.data) {
            try {
                errorDetails = typeof error.response.data === 'string'
                    ? error.response.data
                    : JSON.stringify(error.response.data);
                console.error('Chat stream error:', error.message, '| Status:', error.response?.status, '| Response:', errorDetails);
            } catch (e) {
                errorDetails = 'Error response could not be parsed';
            }
        } else if (error.message) {
            errorDetails = error.message;
            console.error('Chat stream error:', error.message, '| Status:', error.response?.status);
        } else {
            console.error('Chat stream error: Unknown error', '| Status:', error.response?.status);
        }

        // Categorize error types for better messages
        if (error.code === 'ECONNREFUSED' || error.code === 'ENOTFOUND') {
            errorMessage = 'Model service is not responding. It may be starting up or has crashed.';
        } else if (error.code === 'ETIMEDOUT' || error.code === 'ESOCKETTIMEDOUT') {
            errorMessage = 'Model service timed out. The request may be too large.';
        } else if (errorDetails.toLowerCase().includes('context') || errorDetails.toLowerCase().includes('token')) {
            errorMessage = 'Context window exceeded. Try reducing message length or clearing history.';
        } else if (errorDetails.toLowerCase().includes('memory') || errorDetails.toLowerCase().includes('oom') || errorDetails.toLowerCase().includes('cuda')) {
            errorMessage = 'Model ran out of memory. Try reducing context size or using a smaller model.';
        } else if (errorDetails.toLowerCase().includes('parse') || errorDetails.toLowerCase().includes('decode') || errorDetails.toLowerCase().includes('encoding')) {
            errorMessage = 'Failed to process input. The file may contain unsupported characters.';
        } else if (error.response?.status === 502 || error.response?.status === 503) {
            errorMessage = 'Model backend unavailable. Please wait for it to finish loading.';
        } else if (errorDetails) {
            // Use the detailed error if available
            errorMessage = errorDetails.length > 200 ? errorDetails.substring(0, 200) + '...' : errorDetails;
        }

        if (!res.writableEnded) {
            // Send error as SSE event with details
            const errorEvent = {
                error: {
                    message: errorMessage,
                    details: errorDetails.length > 500 ? errorDetails.substring(0, 500) : errorDetails,
                    code: error.code || error.response?.status || 'UNKNOWN'
                },
                done: true
            };
            res.write(`data: ${JSON.stringify(errorEvent)}\n\n`);
            res.end();
        }

        // If we registered a streaming job before the failure, clear it so
        // reconnecting clients don't see a ghost "in-progress" response.
        // streamingConversationId is scoped to the try block above, so pull
        // it from req.body directly here.
        const failedConvId = req.body.conversationId;
        if (failedConvId) {
            activeStreamingJobs.delete(failedConvId);
        }
    }
});

// Reusable, non-streaming chat-completion against a loaded model. Extracted
// so the automation engine (and any future internal caller) can run a prompt
// through the current model without going back out over HTTP. Combines the
// running-instance resolution used by the /v1 proxy with the max_tokens clamp
// from /api/complete (sglang/llama.cpp reject input+max_tokens > contextSize).
//   opts: { messages:[{role,content}], model?, temperature?, maxTokens?, userId? }
//   returns: the assistant text (string)
async function requestModelCompletion({ messages, model, temperature, maxTokens, disableThinking } = {}) {
    if (!Array.isArray(messages) || messages.length === 0) {
        throw new Error('messages[] is required');
    }
    // Prefer a running instance; match by name when one is requested.
    const running = Array.from(modelInstances.values()).filter(i => i.status === 'running');
    let targetInstance;
    if (model) {
        targetInstance = running.find(i => i.modelName === model)
            || modelInstances.get(model)
            || running[0];
    } else {
        targetInstance = running[0] || Array.from(modelInstances.values())[0];
    }
    if (!targetInstance) {
        throw new Error('No running models. Load a model first.');
    }

    const targetModel = model || targetInstance.modelName || 'default';
    const targetHost = targetInstance.containerName || 'host.docker.internal';
    const targetPort = targetInstance.internalPort || targetInstance.port;

    const contextSize = (targetInstance.config && (targetInstance.config.contextSize || targetInstance.config.maxModelLen)) || 4096;
    const inputChars = messages.reduce((n, m) => n + String(m.content || '').length, 0);
    const estimatedInputTokens = Math.ceil(inputChars / 4);
    const safetyMargin = 200;
    const minResponse = Math.min(512, Math.max(64, Math.floor(contextSize * 0.1)));
    const available = Math.max(minResponse, contextSize - estimatedInputTokens - safetyMargin);
    const safeMaxTokens = maxTokens
        ? Math.min(maxTokens, available)
        : Math.min(Math.max(2048, Math.floor(contextSize * 0.2)), available);

    const requestBody = {
        model: targetModel,
        messages,
        temperature: temperature != null ? temperature : 0.7,
        max_tokens: safeMaxTokens,
        stop: DEFAULT_STOP_STRINGS
    };
    // Suppress chain-of-thought for structured/utility calls (workflow build /
    // edit / repair, summaries, classifiers). On a reasoning model the thinking
    // trace otherwise consumes the max_tokens budget BEFORE the answer (content)
    // is emitted → finish_reason "length", EMPTY content, and the caller falls
    // back to reasoning prose → the intermittent "no recognizable nodes" build
    // failures + garbage summaries. `chat_template_kwargs.enable_thinking=false`
    // is the Qwen3 lever (the only one this MTP model honors — /no_think and
    // reasoning_effort are ignored); harmless on templates that don't read it.
    if (disableThinking) requestBody.chat_template_kwargs = { ...(requestBody.chat_template_kwargs || {}), enable_thinking: false };

    const post = (body) => axios.post(`http://${targetHost}:${targetPort}/v1/chat/completions`, body, { timeout: 300000 });
    let response;
    try {
        response = await post(requestBody);
    } catch (err) {
        // A backend that rejects the thinking-disable hint must not break the call.
        if (disableThinking && err && err.response && err.response.status >= 400 && err.response.status < 500) {
            const { chat_template_kwargs, ...rest } = requestBody;
            response = await post(rest);
        } else throw err;
    }
    const choice = response.data && response.data.choices && response.data.choices[0];
    const msg = choice && choice.message;
    return {
        content: (msg && msg.content) || '',
        reasoningContent: (msg && msg.reasoning_content) || '',
        finishReason: (choice && choice.finish_reason) || null,
    };
}

// String-returning wrapper — back-compat for every existing caller. Falls back to
// the reasoning trace only when there is no content (some models put the whole
// answer there); structured callers that must NOT accept reasoning prose use
// requestModelCompletion + content directly (see generateBuilderSpec).
async function runModelCompletion(opts = {}) {
    const r = await requestModelCompletion(opts);
    return r.content || r.reasoningContent || '';
}

// Simplified completion endpoint
app.post('/api/complete', requireAuth, async (req, res) => {
    const { prompt, model, temperature, maxTokens } = req.body;

    if (!prompt) {
        return res.status(400).json({ error: 'Prompt is required' });
    }

    // Check permission
    if (!checkPermission(req.apiKeyData, 'query')) {
        return res.status(403).json({ error: 'Query permission required' });
    }

    try {
        // Find first running instance or use specified model
        let targetModel = model;
        let targetInstance = null;

        if (!model) {
            targetInstance = Array.from(modelInstances.values())[0];
            if (!targetInstance) {
                return res.status(400).json({ error: 'No running models. Please load a model first.' });
            }
            targetModel = targetInstance.modelName || 'default';
        } else {
            targetInstance = modelInstances.get(model);
            if (!targetInstance) {
                return res.status(400).json({ error: `Model ${model} is not running. Please load it first.` });
            }
        }

        // Use container name for Docker network communication
        const targetHost = targetInstance.containerName || `host.docker.internal`;
        const targetPort = targetInstance.internalPort || targetInstance.port;

        // Load system prompt for this model
        const systemPrompts = await loadSystemPrompts();
        const systemPrompt = systemPrompts[targetModel] || '';

        // Prepend system prompt if one exists
        let finalPrompt = prompt;
        if (systemPrompt) {
            finalPrompt = `${systemPrompt}\n\n${prompt}`;
        }

        // Compute a safe max_tokens value. sglang rejects the request if
        // input_tokens + max_tokens > contextSize, so we always clamp to the
        // space actually available for generation.
        const contextSize = (targetInstance.config && (targetInstance.config.contextSize || targetInstance.config.maxModelLen)) || 4096;
        const estimatedInputTokens = Math.ceil(finalPrompt.length / 4);
        const safetyMargin = 200;
        const minResponse = Math.min(512, Math.max(64, Math.floor(contextSize * 0.1)));
        const available = Math.max(minResponse, contextSize - estimatedInputTokens - safetyMargin);
        const safeMaxTokens = maxTokens
            ? Math.min(maxTokens, available)
            : Math.min(Math.max(2048, Math.floor(contextSize * 0.2)), available);

        const requestBody = {
            model: targetModel,
            prompt: finalPrompt,
            temperature: temperature || 0.7,
            max_tokens: safeMaxTokens
        };

        const response = await axios.post(`http://${targetHost}:${targetPort}/v1/completions`, requestBody);

        // Simplify response
        const choice = response.data.choices[0];
        let text = choice.text || '';

        // Handle different finish reasons with specific messages
        if (!text) {
            if (choice.finish_reason === 'length') {
                return res.status(400).json({
                    success: false,
                    error: 'Not enough tokens: The response was truncated because the token limit was reached. Please increase maxTokens in your request.'
                });
            } else if (choice.finish_reason === 'content_filter') {
                return res.status(400).json({
                    success: false,
                    error: 'Content filtered: The response was blocked by content filtering.'
                });
            } else {
                return res.status(500).json({
                    success: false,
                    error: 'Empty response: The model returned no content. This may indicate an issue with the model or prompt.'
                });
            }
        }

        res.json({
            success: true,
            completion: text,
            model: targetModel,
            tokens: response.data.usage
        });
    } catch (error) {
        console.error('Completion error:', error.message);

        // Check for specific error types
        const errorMessage = error.response?.data?.error?.message || error.message || '';

        // Context window exceeded. "too many tokens" / "maximum context" are the
        // backend's phrasings for "the request doesn't fit the window" — that's a
        // CONTEXT overflow, NOT a rate limit. They used to fall through to the 429
        // branch below and surface as a misleading "rate limit exceeded" (e.g.
        // when an agent's tool catalog + history outgrew the model's window).
        if (/context|too long|exceed|too many tokens|maximum context|n_ctx|too large|doesn'?t fit|won'?t fit/i.test(errorMessage)) {
            return res.status(400).json({
                success: false,
                error: 'Context window exceeded: the request (messages + tools) is larger than the model\'s context window. Reduce the input — shorten the conversation, send fewer tools/skills, or load the model with a larger context size.'
            });
        }

        // Genuine rate limit (a per-key limit or an upstream throttle) — distinct
        // from a context overflow, which is handled above.
        if (/rate limit|too many requests/i.test(errorMessage)) {
            return res.status(429).json({
                success: false,
                error: 'Rate limit exceeded: too many requests in a short window. Wait and retry, or raise the key\'s rate limit.'
            });
        }

        res.status(500).json({
            success: false,
            error: 'Failed to get completion from model',
            details: error.message
        });
    }
});

// ============================================================================
// MODEL DELETION ENDPOINT
// ============================================================================

app.delete('/api/models/:modelName', requireAuth, async (req, res) => {
    // Check permission
    if (!checkPermission(req.apiKeyData, 'models')) {
        return res.status(403).json({ error: 'Models permission required' });
    }
    const { modelName } = req.params;

    if (!isValidModelName(modelName)) {
        return res.status(400).json({ error: 'Invalid model name' });
    }

    console.log(`Request to delete model: ${modelName}`);

    try {
        // Stop instance if running
        if (modelInstances.has(modelName)) {
            broadcast({ type: 'log', message: `Stopping instance for ${modelName}...` });
            const instance = modelInstances.get(modelName);
            const container = docker.getContainer(instance.containerId);

            try {
                const containerInfo = await container.inspect();
                if (containerInfo.State.Running) {
                    try {
                        await container.kill();
                    } catch (killErr) {
                        await container.stop({ t: 5 }).catch(() => {});
                    }
                }
                await new Promise(resolve => setTimeout(resolve, 500));
                await container.remove({ force: true, v: true });
            } catch (containerErr) {
                console.log(`Container cleanup issue for ${modelName}:`, containerErr.message);
            }

            modelInstances.delete(modelName);
            if (modelInstances.size === 0) stopSystemMonitoring();
            broadcast({ type: 'log', message: `Instance stopped.` });
        }

        // Delete model directory
        const modelPath = path.join('/models', modelName);
        broadcast({ type: 'log', message: `Deleting model directory ${modelPath}...` });
        await fs.rm(modelPath, { recursive: true, force: true });
        broadcast({ type: 'log', message: `Model directory deleted.` });

        res.json({ message: `Model ${modelName} deleted successfully` });
    } catch (error) {
        console.error(`Error deleting model ${modelName}:`, error.message);
        res.status(500).json({ error: `Failed to delete model ${modelName}: ${error.message}` });
    }
});

// ============================================================================
// APPS MANAGEMENT ENDPOINTS
// ============================================================================

// Helper function to map app names to their docker-compose services
// Returns services in the order they should be operated (for stop: proxy first, then app)
function getAppServices(appName) {
    const serviceMap = {};
    return serviceMap[appName] || [appName];
}

// Helper function to restart a docker compose service using dockerode
async function runDockerComposeCommand(command, serviceName) {
    if (command !== 'restart' && command !== 'start' && command !== 'stop') {
        throw new Error(`Unsupported command: ${command}. Only restart, start, and stop are supported.`);
    }

    try {
        // List all containers
        const containers = await docker.listContainers({ all: true });

        // Find container by service name (compose services have names like "modelserver-servicename-1")
        const serviceContainer = containers.find(c =>
            c.Names.some(n => n.includes(serviceName))
        );

        if (!serviceContainer) {
            throw new Error(`Container for service ${serviceName} not found`);
        }

        const container = docker.getContainer(serviceContainer.Id);

        // Execute the requested command
        try {
            if (command === 'restart') {
                await container.restart();
            } else if (command === 'start') {
                await container.start();
            } else if (command === 'stop') {
                await container.stop();
            }
        } catch (cmdError) {
            // Handle "already started" (304) as success for start command
            if (command === 'start' && cmdError.statusCode === 304) {
                return { success: true, output: `${serviceName} was already running` };
            }
            // Handle "already stopped" (304) as success for stop command
            if (command === 'stop' && cmdError.statusCode === 304) {
                return { success: true, output: `${serviceName} was already stopped` };
            }
            throw cmdError;
        }

        return { success: true, output: `${command} completed for ${serviceName}` };
    } catch (error) {
        throw new Error(`Failed to ${command} ${serviceName}: ${error.message}`);
    }
}

// Helper function to get service status
async function getServiceStatus(serviceName) {
    try {
        const containers = await docker.listContainers({ all: true });
        const serviceContainer = containers.find(c =>
            c.Names.some(n => n.includes(serviceName))
        );

        if (!serviceContainer) {
            return { status: 'not_found', container: null };
        }

        const container = docker.getContainer(serviceContainer.Id);
        const inspect = await container.inspect();

        return {
            status: inspect.State.Running ? 'running' : 'stopped',
            container: {
                id: serviceContainer.Id,
                name: serviceContainer.Names[0],
                state: inspect.State.Status,
                startedAt: inspect.State.StartedAt,
                ports: serviceContainer.Ports
            }
        };
    } catch (error) {
        return { status: 'error', error: error.message };
    }
}

// Helper function to get the host IP address
function getHostIp() {
    // Try to get host IP from environment variable
    if (process.env.HOST_IP) {
        return process.env.HOST_IP;
    }

    // Try to resolve host.docker.internal to get the host IP
    try {
        const dns = require('dns');
        const addresses = dns.lookup('host.docker.internal', (err, address) => {
            if (!err && address) {
                return address;
            }
        });
    } catch (e) {
        // Ignore DNS errors
    }

    const interfaces = os.networkInterfaces();
    // Look for non-internal IPv4 address, skipping Docker bridge networks
    for (const name of Object.keys(interfaces)) {
        for (const iface of interfaces[name]) {
            // Skip internal (loopback), non-IPv4, and Docker bridge networks (172.16.0.0/12)
            if (iface.family === 'IPv4' && !iface.internal) {
                const ip = iface.address;
                // Skip Docker bridge networks (172.16.0.0 - 172.31.255.255)
                const parts = ip.split('.');
                if (parts[0] === '172' && parseInt(parts[1]) >= 16 && parseInt(parts[1]) <= 31) {
                    continue; // Skip Docker network
                }
                // Also skip 10.x.x.x Docker networks
                if (parts[0] === '10') {
                    continue;
                }
                return ip;
            }
        }
    }
    // Fallback to localhost if no external IP found
    return 'localhost';
}

