// ============================================================================
// SYSTEM RESET ENDPOINT
// ============================================================================

app.post('/api/system/reset', requireAdmin, async (req, res) => {

    const { confirmation } = req.body;

    // Require explicit confirmation
    if (confirmation !== 'RESET') {
        return res.status(400).json({ error: 'Invalid confirmation. Please type "RESET" to confirm.' });
    }

    broadcast({ type: 'log', message: '=== SYSTEM RESET INITIATED ===' });
    broadcast({ type: 'log', message: 'This will stop all instances and delete all models...' });

    try {
        // Step 1: Stop all sglang instances
        broadcast({ type: 'log', message: 'Step 1/4: Stopping all sglang instances...' });
        const instanceNames = Array.from(modelInstances.keys());

        for (const modelName of instanceNames) {
            try {
                const instance = modelInstances.get(modelName);
                if (instance) {
                    broadcast({ type: 'log', message: `  Stopping ${modelName}...` });
                    const container = docker.getContainer(instance.containerId);

                    try {
                        const containerInfo = await container.inspect();
                        if (containerInfo.State.Running) {
                            await container.kill().catch(() => container.stop({ t: 5 }));
                        }
                        await new Promise(resolve => setTimeout(resolve, 500));
                        await container.remove({ force: true, v: true });
                    } catch (containerErr) {
                        // Container might not exist, continue
                    }

                    modelInstances.delete(modelName);
                    if (modelInstances.size === 0) stopSystemMonitoring();
                }
            } catch (error) {
                broadcast({ type: 'log', message: `  Warning: ${error.message}` });
            }
        }
        broadcast({ type: 'log', message: '  All instances stopped.' });

        // Step 2: Delete all model directories (except .modelserver)
        broadcast({ type: 'log', message: 'Step 2/4: Deleting all model directories...' });
        const modelsDir = '/models';

        try {
            const entries = await fs.readdir(modelsDir, { withFileTypes: true });
            const modelDirs = entries.filter(dirent =>
                dirent.isDirectory() &&
                !dirent.name.startsWith('.') &&
                !dirent.name.startsWith('models--')
            );

            for (const dirent of modelDirs) {
                const modelPath = path.join(modelsDir, dirent.name);
                broadcast({ type: 'log', message: `  Deleting ${dirent.name}...` });
                await fs.rm(modelPath, { recursive: true, force: true });
            }
            broadcast({ type: 'log', message: `  Deleted ${modelDirs.length} model(s).` });
        } catch (error) {
            broadcast({ type: 'log', message: `  Warning: ${error.message}` });
        }

        // Step 3: Docker cleanup
        broadcast({ type: 'log', message: 'Step 3/4: Running Docker cleanup...' });

        // Prune stopped sglang containers
        try {
            broadcast({ type: 'log', message: '  Removing stopped sglang containers...' });
            const containers = await docker.listContainers({ all: true });
            const sglangContainers = containers.filter(c => c.Names.some(n => n.includes('sglang-')));

            for (const containerInfo of sglangContainers) {
                try {
                    const container = docker.getContainer(containerInfo.Id);
                    const inspect = await container.inspect();
                    if (!inspect.State.Running) {
                        await container.remove({ force: true, v: true });
                        broadcast({ type: 'log', message: `    Removed ${containerInfo.Names[0]}` });
                    }
                } catch (err) {
                    // Container might be already removed
                }
            }
        } catch (error) {
            broadcast({ type: 'log', message: `  Warning: ${error.message}` });
        }

        // Prune unused images (optional - commented out to preserve base images)
        // broadcast({ type: 'log', message: '  Pruning unused Docker images...' });
        // await docker.pruneImages({ filters: { dangling: { false: true } } });

        broadcast({ type: 'log', message: '  Docker cleanup complete.' });

        // Step 4: Verification
        broadcast({ type: 'log', message: 'Step 4/4: Verifying reset...' });
        const remainingModels = await fs.readdir(modelsDir, { withFileTypes: true });
        const modelCount = remainingModels.filter(d =>
            d.isDirectory() && !d.name.startsWith('.') && !d.name.startsWith('models--')
        ).length;

        broadcast({ type: 'log', message: `  Remaining models: ${modelCount}` });
        broadcast({ type: 'log', message: `  Running instances: ${modelInstances.size}` });

        broadcast({ type: 'log', message: '=== SYSTEM RESET COMPLETE ===' });
        broadcast({ type: 'status', message: 'System reset complete. All models deleted and instances stopped.' });

        res.json({
            success: true,
            message: 'System reset complete',
            details: {
                instancesStopped: instanceNames.length,
                modelsDeleted: modelDirs ? modelDirs.length : 0,
                remainingModels: modelCount,
                remainingInstances: modelInstances.size
            }
        });
    } catch (error) {
        console.error('System reset error:', error);
        broadcast({ type: 'log', message: `ERROR: ${error.message}`, level: 'error' });
        res.status(500).json({ error: 'System reset failed', details: error.message });
    }
});

// ============================================================================
// INITIALIZATION - Create default API keys
// ============================================================================

// Known default skills that touch the filesystem — these get opted into the
// workspace sandbox automatically. Non-exhaustive; skills not on this list
// keep their current behavior (in-process for built-ins, per-policy for
// user-created). Centralized here so it's easy to extend.
const WORKSPACE_SANDBOX_DEFAULTS = new Set([
    // file ops
    'create_file', 'update_file', 'read_file', 'delete_file',
    'create_directory', 'delete_directory', 'list_directory',
    'move_file', 'copy_file', 'append_to_file',
    'tail_file', 'head_file', 'search_files', 'search_replace_file',
    'diff_files', 'grep_code', 'outline_file', 'replace_lines',
    // Disk-read siblings of read_file that were missing the workspace mount, so
    // they ran in-process and 404'd on /workspace/... paths (a file the model
    // had just written into /workspace/artifacts/ reported "not found"). They
    // read a workspace file by path exactly like read_file — they need the mount.
    'get_file_metadata', 'read_email_file',
    // make a workspace file downloadable — copies into /workspace/artifacts/
    'make_downloadable',
    // send a workspace file to telegram/slack/http (reads /workspace/artifacts)
    'send_file',
    // download_file lives in NETWORK_SANDBOX_DEFAULTS too — it's listed here
    // so the migration also flips workspace=true. Without the workspace mount,
    // the file lands in the per-call tmpfs `/tmp` and evaporates the moment
    // the sandbox container exits, leaving every subsequent skill (extract,
    // read, hash, ...) staring at ENOENT.
    'download_file',
    // download_html saves a page's raw HTML into /workspace so later tools
    // (read_file/grep_code/parse_html) can parse it — needs the workspace mount.
    'download_html',
    // download_video writes the .mp4 into /workspace/artifacts/ (yt-dlp) — needs
    // the workspace mount so the file persists and surfaces as a download chip.
    'download_video',
    // archives — names match the actual entries in default-skills.json
    // (`tar_extract`/`tar_create`/`unzip_file`/`zip_files`). The previous
    // `create_archive`/`extract_archive` entries were dead names: no
    // matching skill, so the workspace flag never landed and these ran
    // in-process against the webapp container's filesystem instead of
    // the per-conversation /workspace.
    'tar_extract', 'tar_create', 'unzip_file', 'zip_files',
    // pdf / docs generation + reading. create_pdf & create_docx both accept a
    // `contentFile` workspace path for long bodies — they MUST mount /workspace
    // so that file (written via create_file/append_to_file in the same bucket)
    // is visible at render time. create_docx was previously missing here, so its
    // contentFile path silently 404'd.
    'create_pdf', 'create_docx', 'html_to_pdf', 'markdown_to_html',
    'read_pdf', 'pdf_page_count', 'pdf_to_images',
    // email generation (.eml) — needs workspace mount to attach files
    // the user/model already wrote into /workspace.
    'create_email',
    // image manipulation (Pillow), spreadsheet read (openpyxl), SQL (sqlite3).
    // create_xlsx accepts a `rowsFile` /workspace JSON path for large datasets,
    // so it MUST mount /workspace for that file to be visible at render time
    // (mirrors create_pdf/create_docx + contentFile). It already prefers
    // /workspace/artifacts/ for output when the mount is present.
    'transform_image', 'read_xlsx', 'create_xlsx', 'query_sqlite',
    // per-workflow change tracking — keeps snapshot history in a /workspace
    // SQLite db so it can diff a page/API against the previous run.
    'track_changes',
    // chart rendering (matplotlib, headless) — must run in the sandbox (where
    // matplotlib lives) and mount /workspace so the PNG it writes into
    // /workspace/artifacts/ becomes a downloadable artifact AND is readable by
    // a later create_pdf in the same bucket (graphs embedded into a report).
    'chart_plot',
    // audio transcription (faster-whisper, small.en bundled in sandbox image)
    'transcribe_audio',
    // image format conversion (Pillow) reads inputPath and writes outputPath
    // under /workspace; screenshot writes savePath there. Without the mount the
    // file lands in the per-run tmpfs and vanishes / can't be read back — the
    // same class of bug as download_file. (screenshot additionally needs a
    // display the headless sandbox lacks, so it stays non-functional regardless;
    // this just fixes the path/mount half.)
    'convert_image', 'screenshot',
]);

// NETWORK-requiring default skills. These get sandboxed with an allowlist
// so the model can still use them. Each entry declares the egress hostnames
// the skill actually needs — everything else is blocked by the egress proxy.
// '*' means "any public host" — the egress proxy still blocks private/
// internal IPs (RFC1918, loopback, link-local, single-label hostnames)
// regardless of how wide the allowlist is.
//
// `legacyAllowlists` lists prior built-in defaults that should be auto-upgraded
// when seen on existing installs. A user-customized allowlist that doesn't
// match any legacy entry is preserved (operator intent wins).
const NETWORK_SANDBOX_DEFAULTS = {
    download_file:   { allowlist: ['*'], note: 'arbitrary URL download; tighten if policy allows' },
    download_html:   { allowlist: ['*'], note: 'fetches a page HTML into the workspace; user-supplied URLs' },
    download_video:  { allowlist: ['*'], note: 'yt-dlp download of user-supplied video URLs (pip-installs yt-dlp on first use)' },
    parse_rss:       { allowlist: ['*'], note: 'fetches an RSS/Atom feed URL and parses it to items; user-supplied feed URLs' },
    send_file:       { allowlist: ['*'], note: 'uploads a workspace file to telegram/slack/user URL' },
    fetch_url:       { allowlist: ['*'], note: 'user-supplied URLs' },
    http_request:    { allowlist: ['*'], note: 'user-supplied URLs' },
    web_search:      { allowlist: ['duckduckgo.com', 'html.duckduckgo.com', 'www.bing.com'] },
    playwright_fetch: { allowlist: ['*'], note: 'user-supplied URLs; browser renders' },
    dns_lookup:      { allowlist: [] }, // doesn't use HTTP proxy; noop
    // Code-execution skills — the model needs general public internet so it
    // can pip install, fetch arbitrary APIs, run yt-dlp, etc. Private/internal
    // network access still blocked by the egress proxy's resolvesPublicly check.
    run_python:      { allowlist: ['*'], note: 'general code execution; pip + requests + yt-dlp' },
    run_node:        { allowlist: ['*'], note: 'general code execution; npm install + fetch' },
    run_npm:         {
        allowlist: ['*'],
        legacyAllowlists: [
            // Pre-public-egress narrow default — postinstall scripts and
            // git+https deps were silently failing. Auto-upgrade.
            ['registry.npmjs.org', 'registry.npmjs.com', '*.npmjs.org', '*.npmjs.com'],
        ],
        note: 'npm registry + postinstall fetches + git+https deps',
    },
};

/** Walk existing skills and opt-in known defaults to sandbox + workspace /
 *  allowlisted-network. Idempotent — safe to run at every boot. Never
 *  clobbers a skill that already has sandbox/workspace explicitly set. */
async function migrateDefaultSkillsToSandbox() {
    try {
        const skills = await loadSkills();
        let dirty = 0;
        for (const s of skills) {
            if (!s || !s.name) continue;
            // User-created skills (have a userId) are left alone — their
            // default is already sandbox=true per executePythonSkill's policy.
            if (s.userId) continue;
            let changed = false;

            if (NETWORK_SANDBOX_DEFAULTS[s.name]) {
                // Network-requiring defaults take precedence over the
                // workspace-only set: a skill may be in both lists (e.g.
                // run_python is workspace=true AND needs egress) and we
                // want the network policy applied.
                const spec = NETWORK_SANDBOX_DEFAULTS[s.name];
                if (s.sandbox !== true) { s.sandbox = true; changed = true; }
                if (WORKSPACE_SANDBOX_DEFAULTS.has(s.name) && s.workspace !== true) {
                    s.workspace = true; changed = true;
                }
                // Upgrade legacy network='none' to 'allowlist' so skills
                // that recently gained egress (run_python with allowlist=['*'])
                // actually receive it on existing installs. User-customized
                // tiers (e.g. operator manually narrowed to specific hosts)
                // are preserved.
                if (!s.network || s.network === 'none') {
                    s.network = 'allowlist';
                    s.allowlist = spec.allowlist;
                    changed = true;
                } else if (!s.allowlist) {
                    s.allowlist = spec.allowlist;
                    changed = true;
                } else if (Array.isArray(spec.legacyAllowlists) && Array.isArray(s.allowlist)) {
                    // Upgrade legacy built-in default allowlists. Order-insensitive
                    // exact-set match so a user who manually narrowed the list
                    // (different entries) keeps their custom choice.
                    const cur = [...s.allowlist].map(String).sort();
                    for (const legacy of spec.legacyAllowlists) {
                        const leg = [...legacy].map(String).sort();
                        if (cur.length === leg.length && cur.every((v, i) => v === leg[i])) {
                            s.allowlist = spec.allowlist;
                            changed = true;
                            break;
                        }
                    }
                }
            } else if (WORKSPACE_SANDBOX_DEFAULTS.has(s.name)) {
                if (s.sandbox !== true)   { s.sandbox = true;   changed = true; }
                if (s.workspace !== true) { s.workspace = true; changed = true; }
                if (!s.network) { s.network = 'none'; changed = true; }
            }
            if (changed) dirty++;
        }
        if (dirty) {
            await saveSkills(skills);
            console.log(`[skill-migration] flagged ${dirty} default skill(s) for sandbox/workspace`);
        }
    } catch (e) {
        console.error('[skill-migration] failed (non-fatal):', e.message);
    }
}

// Sync new default skills into an existing install. `initializeDefaultSkills`
// short-circuits when skills.json is non-empty (the seed has already run at
// least once), so new entries in default-skills.json would otherwise never
// reach existing users. This compares on-disk skills by name against the
// current default-skills.json template and appends anything missing —
// idempotent, safe to run every boot. Does NOT modify or delete existing
// skills, only adds new ones.
async function addMissingDefaultSkills() {
    try {
        const defaultSkillsPath = path.join(__dirname, 'default-skills.json');
        const template = JSON.parse(await fs.readFile(defaultSkillsPath, 'utf8'));
        const skills = await loadSkills();
        const byName = new Map(skills.filter(s => !s.userId).map(s => [s.name, s]));

        // Apply sandbox/workspace/network policy. NETWORK first — a skill in
        // BOTH sets (e.g. download_file) needs network=allowlist (not none) while
        // still getting the workspace mount.
        const applyPolicy = (out) => {
            if (NETWORK_SANDBOX_DEFAULTS[out.name]) {
                const spec = NETWORK_SANDBOX_DEFAULTS[out.name];
                out.sandbox = true;
                out.network = out.network || 'allowlist';
                out.allowlist = out.allowlist || spec.allowlist;
                if (WORKSPACE_SANDBOX_DEFAULTS.has(out.name)) out.workspace = true;
            } else if (WORKSPACE_SANDBOX_DEFAULTS.has(out.name)) {
                out.sandbox = true;
                out.workspace = true;
                out.network = out.network || 'none';
            }
            return out;
        };

        const added = [];
        const updated = [];
        for (const t of template) {
            if (!t || !t.name) continue;
            const existing = byName.get(t.name);
            if (!existing) {
                skills.push(applyPolicy({
                    id: crypto.randomBytes(16).toString('hex'),
                    ...t,
                    createdAt: new Date().toISOString(),
                    updatedAt: new Date().toISOString(),
                }));
                added.push(t.name);
            } else if ((existing.code || '') !== (t.code || '')
                       || (existing.description || '') !== (t.description || '')
                       || (t.systemPrompt !== undefined && (existing.systemPrompt || '') !== (t.systemPrompt || ''))
                       || (t.timeoutMs !== undefined && existing.timeoutMs !== t.timeoutMs)
                       || (t.memory !== undefined && existing.memory !== t.memory)
                       || (t.cpus !== undefined && existing.cpus !== t.cpus)) {
                // The managed default's definition changed in the template —
                // refresh it in place (preserve id/createdAt/userId/enabled).
                // Default (no-userId) skills are an app-managed catalog; this is
                // how shipped-skill fixes reach already-installed instances.
                existing.code = t.code;
                existing.description = t.description;
                existing.parameters = t.parameters;
                if (t.type !== undefined) existing.type = t.type;
                if (t.systemPrompt !== undefined) existing.systemPrompt = t.systemPrompt;
                // Resource overrides (e.g. download_video needs a longer
                // timeoutMs for pip-install + a full video download). Synced
                // here so shipped tweaks reach already-installed instances.
                if (t.timeoutMs !== undefined) existing.timeoutMs = t.timeoutMs;
                if (t.memory !== undefined) existing.memory = t.memory;
                if (t.cpus !== undefined) existing.cpus = t.cpus;
                existing.updatedAt = new Date().toISOString();
                applyPolicy(existing);
                updated.push(t.name);
            } else {
                // No template (code/desc/resource) diff, but still ENFORCE the
                // workspace/network policy — the WORKSPACE_/NETWORK_SANDBOX_DEFAULTS
                // sets can change without a code change (e.g. a skill newly added
                // to the workspace set), and without this an already-installed
                // managed skill would never get its mount/network flags flipped.
                const before = JSON.stringify([existing.workspace, existing.network, existing.sandbox, existing.allowlist || null]);
                applyPolicy(existing);
                if (JSON.stringify([existing.workspace, existing.network, existing.sandbox, existing.allowlist || null]) !== before) {
                    existing.updatedAt = new Date().toISOString();
                    updated.push(t.name);
                }
            }
        }
        if (!added.length && !updated.length) return;
        await saveSkills(skills);
        console.log(`[skill-migration] default skills — added: [${added.join(', ')}] updated: [${updated.join(', ')}]`);
    } catch (e) {
        console.error('[skill-migration] addMissingDefaultSkills failed (non-fatal):', e.message);
    }
}

// Force-refresh the code (and a few sibling fields) of named built-in skills
// from the current template, even if a skill with the same name already
// exists on disk. Used to ship correctness/security fixes to skills the
// user already has installed — addMissingDefaultSkills only ADDs missing
// entries, so without this the patched code never reaches existing users.
//
// Only refreshes built-in skills (no userId). User-created skills with the
// same name are left alone. Idempotent — safe to run every boot.
const REFRESH_STALE_SKILLS = new Set([
    // calculate — added BitXor/BitAnd/BitOr/LShift/RShift/Invert support and
    // hex/bin/char output for integer results. Older installs have the
    // pre-bitwise code on disk and would still fail on `0xf1 ^ 0xff`.
    'calculate',
    // base64_decode — widened the accepted parameter alias list from
    // text/encodedData/data to also include input/string/value/content/
    // payload/b64/encoded. Without this refresh, existing installs keep
    // the narrow list and the model still fails when it guesses an
    // unsupported parameter name (e.g. 'input').
    'base64_decode',
    // Disk-read skills — extended the "file not found" message to
    // point the model at inline === FILE N === blocks when an upload
    // was the actual source. Without this refresh, the model wastes
    // turns calling search_files / list_directory after the first
    // miss instead of reading the inline content already in context.
    'read_file',
    'read_email_file',
    'get_file_metadata',
    'hash_file',
    'tail_file',
    'head_file',
    // run_npm — initial version inherited $HOME from the sandbox user
    // (/home/sandbox, doesn't exist) and crashed with ENOENT on the
    // very first call. Refreshed code redirects HOME + npm cache /
    // prefix / userconfig into /tmp so npm has a writable scratch dir.
    'run_npm',
    // create_pdf / create_docx / create_xlsx — original templates were
    // stub-only; the server-side code body was just comments.
    // Refreshed code is real reportlab / docx /
    // openpyxl implementations that write to /artifacts so the chat UI
    // can surface a download button.
    'create_pdf',
    'create_docx',
    'create_xlsx',
    // create_file / move_file / copy_file / run_python / run_node —
    // systemPrompt updated to teach the /workspace/artifacts/ download
    // convention. Code body is unchanged so the original refresh logic
    // (which skipped when `s.code === t.code`) wouldn't have propagated
    // the prompt fix; the refresh check now also fires on description /
    // systemPrompt drift.
    'create_file',
    'move_file',
    'copy_file',
    'run_python',
    'run_node',
    // run_npm — systemPrompt updated when egress widened from npmjs-only
    // to public allowlist (postinstall scripts + git deps now succeed).
    'run_npm',
    // grep_code — pre-fix the skill defaulted `directory` to `.`, which
    // resolved to the harness's /work cwd (containing only skill.py +
    // params.json) when the model omitted the param. New code defaults to
    // USER_WORKSPACE, expands excludeDirs to skip .deps/pip caches, and
    // returns a clearer error when an outside-workspace path was rewritten
    // and now points at a non-existent /workspace/<basename>.
    'grep_code',
    // outline_file / replace_lines — "file not found" error extended with
    // the sandbox-boundary hint so the model stops retrying outside-
    // workspace absolute paths (which the path normalizer silently rewrites
    // to /workspace/<basename>). Same UX fix as grep_code.
    'outline_file',
    'replace_lines',
    // File-op family — workspace-hint treatment on FileNotFoundError /
    // Directory-not-found / generic-exception paths so the model self-
    // corrects after a path-rewrite. read_file / head_file / tail_file are
    // also in the disk-read group above (Set dedupes); listing them here
    // keeps the rationale colocated with the rest of the family.
    // move_file / copy_file additionally got explicit collision detection —
    // when normalizePathArgs rewrites two different host paths to the same
    // /workspace/<basename>, shutil would silently SameFile-error. update_file
    // gained a try/except (had none before) so a missing parent dir produces
    // a clean error instead of a raw traceback. diff_files /
    // search_replace_file now check existence upfront so they can name the
    // offending path.
    'delete_file',
    'delete_directory',
    'update_file',
    'append_to_file',
    'search_replace_file',
    'diff_files',
    'move_file',
    'copy_file',
    // transcribe_audio — bundled whisper model bumped from tiny.en to
    // small.en for noticeably better lyrics/music accuracy. Default
    // beamSize also bumped from 1 (greedy) to 5 (canonical Whisper
    // beam). Without this refresh, existing installs keep pointing at
    // /opt/whisper-models/tiny.en, which the rebuilt sandbox image no
    // longer ships — transcribe would fail with "model load failed".
    'transcribe_audio',
    // read_pdf / pdf_page_count / pdf_to_images / markdown_to_html /
    // html_to_pdf — these landed as Koda-CLI client-side stubs whose
    // stored `code` was just a comment header. The sandbox harness at
    // sandboxRunner.js calls `execute(_params)`, which raised
    // `NameError: name 'execute' is not defined` on every invocation.
    // Refreshed code is real pypdf / pdf2image / markdown / WeasyPrint
    // implementations that write artifacts to /workspace/artifacts/ so
    // the chat UI's download chip path works. Sandbox image gained
    // poppler-utils + pango/cairo system libs + pypdf/pdf2image/
    // markdown/weasyprint in the same change.
    'read_pdf',
    'pdf_page_count',
    'pdf_to_images',
    'markdown_to_html',
    'html_to_pdf',
]);

async function refreshStaleDefaultSkills() {
    try {
        const defaultSkillsPath = path.join(__dirname, 'default-skills.json');
        const template = JSON.parse(await fs.readFile(defaultSkillsPath, 'utf8'));
        const templateByName = new Map(template.map(t => [t.name, t]));
        const skills = await loadSkills();
        let dirty = 0;
        for (const s of skills) {
            if (!s || !s.name || s.userId) continue;
            if (!REFRESH_STALE_SKILLS.has(s.name)) continue;
            const t = templateByName.get(s.name);
            if (!t || !t.code) continue;
            // Refresh when ANY of code, description, systemPrompt, or
            // parameters drift — description-only fixes (e.g. teaching
            // the /workspace/artifacts/ download convention) won't reach
            // existing installs if we only refresh on code change.
            const codeDrift = s.code !== t.code;
            const descDrift = !!t.description && s.description !== t.description;
            const promptDrift = !!t.systemPrompt && s.systemPrompt !== t.systemPrompt;
            const paramsDrift = !!t.parameters
                && JSON.stringify(s.parameters || {}) !== JSON.stringify(t.parameters);
            if (!codeDrift && !descDrift && !promptDrift && !paramsDrift) continue;
            s.code = t.code;
            if (t.description) s.description = t.description;
            if (t.systemPrompt) s.systemPrompt = t.systemPrompt;
            if (t.parameters) s.parameters = t.parameters;
            s.updatedAt = new Date().toISOString();
            dirty++;
        }
        if (dirty) {
            await saveSkills(skills);
            console.log(`[skill-migration] refreshed ${dirty} stale built-in skill(s) from template: ${[...REFRESH_STALE_SKILLS].join(', ')}`);
        }
    } catch (e) {
        console.error('[skill-migration] refreshStaleDefaultSkills failed (non-fatal):', e.message);
    }
}

async function initializeDefaultSkills() {
    try {
        await ensureDataDir();
        const skills = await loadSkills();

        // Existing install — opt in known defaults to sandbox/workspace,
        // sync any new defaults from the template, and refresh code for
        // built-ins on the stale list. Harmless no-op when fully migrated.
        // Runs BEFORE the early-return so all migrations reach older installs.
        if (skills.length > 0) {
            await migrateDefaultSkillsToSandbox();
            await addMissingDefaultSkills();
            await refreshStaleDefaultSkills();
            return;
        }

        console.log('Initializing default Python skills...');

        // Load default skills from JSON file
        const defaultSkillsPath = path.join(__dirname, 'default-skills.json');
        const defaultSkillsJson = await fs.readFile(defaultSkillsPath, 'utf8');
        const defaultSkillsTemplate = JSON.parse(defaultSkillsJson);

        // Add IDs, timestamps, AND sandbox/workspace flags for known
        // file-op / network-requiring default skills. Same logic as the
        // migration, applied up-front on first install. NETWORK first so
        // skills in both sets keep their egress policy AND get the workspace
        // mount; the previous if/else order silently downgraded
        // network-requiring + workspace-needing skills to network=none.
        const defaultSkills = defaultSkillsTemplate.map(skill => {
            const out = {
                id: crypto.randomBytes(16).toString('hex'),
                ...skill,
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
            };
            if (NETWORK_SANDBOX_DEFAULTS[out.name]) {
                const spec = NETWORK_SANDBOX_DEFAULTS[out.name];
                out.sandbox = true;
                out.network = out.network || 'allowlist';
                out.allowlist = out.allowlist || spec.allowlist;
                if (WORKSPACE_SANDBOX_DEFAULTS.has(out.name)) {
                    out.workspace = true;
                }
            } else if (WORKSPACE_SANDBOX_DEFAULTS.has(out.name)) {
                out.sandbox = true;
                out.workspace = true;
                out.network = out.network || 'none';
            }
            return out;
        });

        // Save skills
        await saveSkills(defaultSkills);
        console.log(`✓ Created ${defaultSkills.length} default Python skills`);

    } catch (error) {
        console.error('Error initializing default skills:', error);
    }
}

