async function initializeDefaultApiKeys() {
    try {
        await ensureDataDir();
        const keys = await loadApiKeys();
        let keysCreated = false;

        // Check if chat integration key exists (for Model Chat on port 3002)
        // Also check for legacy name to avoid creating duplicates
        let chatKeyExists = keys.find(k => k.name === 'Model Chat Key' || k.name === 'OpenWebUI Integration Key');
        if (!chatKeyExists) {
            const chatKey = {
                id: crypto.randomUUID(),
                name: 'Model Chat Key',
                key: generateApiKey(),
                secret: generateApiSecret(),
                bearerOnly: true,
                permissions: ['query', 'models'],
                rateLimitRequests: null,
                rateLimitTokens: null,
                active: true,
                createdAt: new Date().toISOString()
            };
            keys.push(chatKey);
            console.log('');
            console.log('========================================');
            console.log('  Model Chat Key Created');
            console.log('========================================');
            console.log(`Bearer Token: ${chatKey.key}`);
            console.log('');
            keysCreated = true;
        }

        // Save API keys if any were created
        if (keysCreated) {
            await saveApiKeys(keys);
        }
    } catch (error) {
        console.error('Error initializing default API keys:', error);
    }
}

// ============================================================================
// CLI INSTALL SCRIPT ENDPOINT
// ============================================================================

/**
 * Validates and sanitizes the host header to prevent injection attacks.
 * Only allows valid hostname:port format.
 */
function sanitizeHost(hostHeader) {
    if (!hostHeader) return 'localhost:3001';

    // Only allow alphanumeric, dots, hyphens, colons (for port), and brackets (for IPv6)
    const sanitized = hostHeader.replace(/[^a-zA-Z0-9.:[\]-]/g, '');

    // Validate format: hostname or hostname:port or IP or [IPv6]:port
    const validHostPattern = /^([a-zA-Z0-9.-]+|\[[a-fA-F0-9:]+\])(:[0-9]{1,5})?$/;
    if (!validHostPattern.test(sanitized)) {
        return 'localhost:3001';
    }

    return sanitized;
}

// ============================================================================
// Pi (pi.dev) auto-config — returns a settings.json snippet, the bundled
// extension files, and a copy-paste install script that drops the extension
// at ~/.pi/agent/extensions/modelserver/. The caller's host header is the
// canonical base URL, sanitized through sanitizeHost above.
// ============================================================================

const PI_EXTENSION_DIR = path.join(__dirname, 'pi-extension');
const PI_INSTALL_SCRIPT_PATH = path.join(PI_EXTENSION_DIR, 'install.sh');

function piBaseUrlForRequest(req) {
    const host = sanitizeHost(req.get('host'));
    const protocol = (req.protocol === 'http' || req.protocol === 'https') ? req.protocol : 'https';
    return `${protocol}://${host}`;
}

// Load install.sh from disk and substitute the placeholder with the
// caller's actual base URL. Cached read on disk error since install.sh
// is small and rarely changes.
async function buildPiInstallScript(baseUrl) {
    const raw = await fs.readFile(PI_INSTALL_SCRIPT_PATH, 'utf8');
    return raw.replace(/__MODELSERVER_BASE_URL__/g, baseUrl);
}

// Bash-pipeable installer. Curl this with the bearer key and pipe to
// bash — the script handles MITM TLS, missing/old Node, missing Pi,
// missing curl, broken sudo, and is idempotent across re-runs.
app.get('/api/pi/install', requireAuth, async (req, res) => {
    try {
        const baseUrl = piBaseUrlForRequest(req);
        const script = await buildPiInstallScript(baseUrl);
        res.setHeader('Content-Type', 'text/x-shellscript; charset=utf-8');
        res.send(script);
    } catch (err) {
        console.error('[pi-install] error:', err);
        res.status(500).json({ error: 'Failed to load install script' });
    }
});

app.get('/api/pi/extension/:file', requireAuth, async (req, res) => {
    const allowed = new Set(['modelserver.ts', 'package.json', 'README.md', 'install.sh']);
    const file = req.params.file;
    if (!allowed.has(file)) {
        return res.status(404).json({ error: 'Unknown extension file' });
    }
    try {
        const filePath = path.join(PI_EXTENSION_DIR, file);
        let content = await fs.readFile(filePath, 'utf8');
        // install.sh and modelserver.ts both have __MODELSERVER_BASE_URL__
        // placeholders. Substitute on the way out so the served file is
        // self-contained — install.sh works as a curl|bash, and the
        // extension still phones home correctly when the user forgets
        // to export MODELSERVER_BASE_URL in their shell.
        if (file === 'install.sh' || file === 'modelserver.ts') {
            content = content.replace(/__MODELSERVER_BASE_URL__/g, piBaseUrlForRequest(req));
        }
        const contentType = file.endsWith('.json') ? 'application/json'
            : file.endsWith('.md') ? 'text/markdown; charset=utf-8'
            : file.endsWith('.sh') ? 'text/x-shellscript; charset=utf-8'
            : 'text/typescript; charset=utf-8';
        res.setHeader('Content-Type', contentType);
        res.send(content);
    } catch (err) {
        console.error('[pi-extension] read failed:', err);
        res.status(500).json({ error: 'Failed to read extension file' });
    }
});

// ============================================================================
// OPENAI-COMPATIBLE API PROXY (Requires auth, forwards to sglang instances)
// ============================================================================

// Proxy all /v1/* requests to sglang instances with authentication
app.all('/v1/*', requireAuth, async (req, res) => {
    try {
        // Log authentication details for debugging
        const authType = req.apiKeyData?.bearerOnly ? 'Bearer Token' : 'API Key';
        const authName = req.apiKeyData?.name || 'Unknown';
        console.log(`[Proxy Auth] ${authType} (${authName}) accessing ${req.method} ${req.originalUrl}`);

        // Check permission
        if (!checkPermission(req.apiKeyData, 'query')) {
            console.log(`[Proxy] Permission denied for ${authName}`);
            return res.status(403).json({ error: 'Query permission required' });
        }

        // Get first running instance. Filter to status === 'running' so a
        // stopped/exited instance still in the Map (e.g. user stopped the
        // container directly, or boot-time sync hasn't pruned it) doesn't
        // get picked and cause ENOTFOUND on its dead container name.
        const allInstances = Array.from(modelInstances.values());
        const instances = allInstances.filter(i => i && i.status === 'running');
        if (instances.length === 0) {
            console.log(`[Proxy] No running instances found (${allInstances.length} tracked, none in 'running' state)`);
            return res.status(503).json({ error: 'No models are currently running. Please load a model first.' });
        }

        // Prefer an instance whose modelName/repoId matches the request body's
        // `model` field if the client sent one — keeps multi-instance setups
        // routing predictably.
        const requestedModel = req.body && typeof req.body.model === 'string' ? req.body.model : null;
        const matched = requestedModel
            ? instances.find(i => i.config?.hfRepoId === requestedModel || i.containerName === `sglang-${requestedModel}` || i.containerName === `llamacpp-${requestedModel}`)
            : null;
        const firstInstance = matched || instances[0];
        // Use container name to reach sglang via Docker network
        // Fall back to host.docker.internal for backwards compatibility
        const targetHost = firstInstance.containerName || `host.docker.internal`;
        const targetPort = firstInstance.internalPort || firstInstance.port;
        const targetUrl = `http://${targetHost}:${targetPort}${req.originalUrl}`;

        console.log(`[Proxy] Forwarding to ${targetUrl}`);

        // Special handling for GET /v1/models — sglang and llama.cpp both
        // omit context_window from this response, so Pi (and any other
        // OpenAI-compatible client that reads it) defaults to 32768 and
        // throttles itself even when the loaded model has a much larger
        // window. Augment each entry with contextSize from the matched
        // instance config so Pi's status line reflects reality.
        if (req.method === 'GET' && req.path === '/v1/models') {
            try {
                const upstream = await axios.get(targetUrl, { timeout: 8000 });
                const ctxFromConfig = firstInstance.config?.contextSize
                    || firstInstance.config?.maxModelLen
                    || null;
                const data = upstream.data;
                if (data && Array.isArray(data.data) && ctxFromConfig) {
                    data.data = data.data.map((m) => ({
                        context_window: ctxFromConfig,
                        max_tokens: Math.max(1024, Math.floor(ctxFromConfig / 8)),
                        ...m,
                        // Re-set after spread so a backend-supplied value
                        // doesn't override our authoritative one when it's
                        // the stale 32768 default.
                        context_window: ctxFromConfig,
                        max_tokens: Math.max(1024, Math.floor(ctxFromConfig / 8)),
                    }));
                }
                Object.entries(upstream.headers || {}).forEach(([k, v]) => {
                    if (!['transfer-encoding','content-length','connection','keep-alive'].includes(k.toLowerCase())) {
                        res.setHeader(k, v);
                    }
                });
                return res.status(upstream.status).json(data);
            } catch (err) {
                console.warn(`[Proxy] /v1/models augmentation failed (${err.message}); falling through to passthrough`);
                // fall through to the generic non-streaming path below
            }
        }

        // Check if this is a streaming request (handle both boolean and string "true")
        const streamParam = req.body?.stream;
        const isStreaming = streamParam === true || streamParam === 'true';
        if (req.body && streamParam !== undefined) {
            console.log(`[Proxy] Stream parameter:`, streamParam, `(type: ${typeof streamParam}, isStreaming: ${isStreaming})`);
        }

        // Surface external chat-completions calls (Pi, OpenAI SDK clients,
        // scripts) in the Process Logs tab. Skip /v1/models polls (handled
        // above) — they're noisy and never carry usage.
        if (req.apiKeyData && req.path !== '/v1/models') {
            try {
                const msgCount = Array.isArray(req.body?.messages) ? req.body.messages.length : 0;
                const toolCount = Array.isArray(req.body?.tools) ? req.body.tools.length : 0;
                broadcast({
                    type: 'log',
                    message: `[Pi/API] ${authName} → ${req.method} ${req.path} (${msgCount} msgs${toolCount ? `, ${toolCount} tools` : ''}${isStreaming ? ', stream' : ''})`,
                    level: 'info',
                    targetUserId: req.userId
                });
            } catch (_) { /* ignore */ }
        }

        // ── Pi memory bridge ────────────────────────────────────────────────
        // For Pi (bearerOnly key) POSTing chat completions: (1) record the
        // experience from the most-recently completed task, then (2) inject the
        // persona/experience so this turn reuses what worked. Gated to bearer
        // callers so raw OpenAI-SDK clients keep the transparent passthrough.
        // Mutating req.body.messages here is picked up by BOTH branches below
        // (streaming clones req.body; non-streaming sends it directly).
        const piMemId = req.userId || req.apiKeyData?.id;
        if (req.method === 'POST'
            && req.path === '/v1/chat/completions'
            && req.apiKeyData?.bearerOnly === true
            && piMemId
            && Array.isArray(req.body?.messages)
            && req.body.messages.length) {
            // (1) build persona from Pi usage (fire-and-forget). Pass a shallow
            // snapshot so the async walk can't race with (2) mutating the array.
            recordV1TurnActivity(piMemId, req.apiKeyData, req.body.messages.slice()).catch(() => {});
            // (2) inject persona into THIS request (awaited — must land before
            // forward). Bounded by a timeout so a slow/large memory read can
            // never stall the proxy: on timeout we forward without memory.
            try {
                const injected = await Promise.race([
                    injectPersonaForV1(req, firstInstance),
                    new Promise(resolve => setTimeout(() => resolve(null), 2000)),
                ]);
                if (injected && injected.count) {
                    logUserActivity(piMemId,
                        `Pi memory: injected ${injected.count} (${injected.procedures} experience, ${injected.learnings} learnings, ${injected.facts} facts, ${injected.tokens} tok)` +
                        (injected.activityHint ? ` [activity: ${injected.activityHint}]` : ''));
                }
            } catch (e) { console.warn('[Pi/Memory] injection skipped:', e.message); }
        }

        if (isStreaming) {
            // Handle streaming response
            console.log('[Proxy] Streaming request detected');

            // Ask the backend to emit a final usage chunk so we can attribute
            // tokens to the API key. sglang + llama.cpp's OpenAI-compatible
            // modes both honor `stream_options.include_usage`; backends that
            // don't recognize it ignore the field. Without this, streaming
            // calls record `tokens: 0` and the per-key usage stays at 0/max.
            const upstreamBody = (req.body && typeof req.body === 'object') ? { ...req.body } : req.body;
            if (upstreamBody && typeof upstreamBody === 'object') {
                upstreamBody.stream_options = {
                    ...(upstreamBody.stream_options || {}),
                    include_usage: true,
                };
            }

            // Abort the upstream generation if the client (Pi, OpenAI SDK,
            // etc.) disconnects mid-stream. Without this the backend keeps
            // decoding to max_tokens for a dead connection; on a single-slot
            // llama.cpp that abandoned generation BLOCKS the next request,
            // so the client's next turn sits "processing" while the model
            // burns cycles on work nobody will read. Destroying the upstream
            // socket makes llama.cpp/sglang cancel the slot immediately.
            const upstreamAbort = new AbortController();
            const response = await axios({
                method: req.method,
                url: targetUrl,
                data: upstreamBody,
                headers: {
                    'Content-Type': req.headers['content-type'] || 'application/json',
                },
                responseType: 'stream',
                // Prevent axios from decompressing - let it pass through raw
                decompress: false,
                signal: upstreamAbort.signal,
            });

            // Set chunked transfer encoding for streaming
            res.setHeader('Transfer-Encoding', 'chunked');
            res.setHeader('Content-Type', response.headers['content-type'] || 'text/event-stream');
            res.setHeader('Cache-Control', 'no-cache');
            res.setHeader('Connection', 'keep-alive');

            // Disable timeouts for streaming responses
            req.setTimeout(0);
            res.setTimeout(0);
            if (req.socket) req.socket.setTimeout(0);

            // Forward other response headers (excluding hop-by-hop headers)
            const headersToSkip = ['transfer-encoding', 'content-length', 'connection', 'keep-alive', 'content-type', 'cache-control'];
            Object.keys(response.headers).forEach(key => {
                if (!headersToSkip.includes(key.toLowerCase())) {
                    res.setHeader(key, response.headers[key]);
                }
            });

            // Set status code
            res.status(response.status);

            // Manually forward each chunk and tap the SSE for the final
            // `usage.total_tokens` value. We track the last seen usage and
            // commit it once on stream end so multiple incremental usage
            // chunks (some backends emit them) don't double-count the key.
            let lineBuffer = '';
            let lastSeenTotalTokens = null;
            let upstreamDone = false;
            let clientAborted = false;

            // Client gone before the stream finished → kill the upstream so
            // the backend stops generating and frees the slot for the next
            // turn. res 'close' fires on both normal end and disconnect, so
            // gate on upstreamDone to avoid aborting an already-finished call.
            res.on('close', () => {
                if (upstreamDone) return;
                clientAborted = true;
                console.log(`[Proxy] Client disconnected mid-stream — aborting upstream for ${authName}`);
                try { upstreamAbort.abort(); } catch (_) { /* ignore */ }
                try { response.data.destroy(); } catch (_) { /* ignore */ }
            });

            response.data.on('data', (chunk) => {
                try { res.write(chunk); } catch (_) { /* client disconnected */ }
                try {
                    lineBuffer += chunk.toString('utf8');
                    let nlIdx;
                    while ((nlIdx = lineBuffer.indexOf('\n')) >= 0) {
                        const line = lineBuffer.slice(0, nlIdx).trimEnd();
                        lineBuffer = lineBuffer.slice(nlIdx + 1);
                        if (!line.startsWith('data:')) continue;
                        const payload = line.slice(5).trim();
                        if (!payload || payload === '[DONE]') continue;
                        try {
                            const obj = JSON.parse(payload);
                            const t = obj?.usage?.total_tokens;
                            if (typeof t === 'number') lastSeenTotalTokens = t;
                        } catch (_) { /* skip malformed chunk */ }
                    }
                } catch (_) { /* parsing must never break the pipe */ }
            });

            // Handle stream errors
            response.data.on('error', (error) => {
                upstreamDone = true;
                // The abort/destroy we issue on client disconnect surfaces here
                // as an AbortError/ECONNRESET — expected teardown, not a fault.
                if (clientAborted) {
                    console.log('[Proxy] Upstream stream closed after client disconnect');
                    if (!res.writableEnded) res.end();
                    return;
                }
                console.error('[Proxy] Stream error:', error.message);
                if (!res.headersSent) {
                    res.status(500).json({ error: 'Stream error', details: error.message });
                } else {
                    res.end();
                }
            });

            // Handle stream end — commit token usage now that we've seen the
            // final chunk. This is the missing leg that left /v1/* streaming
            // requests recording 0 tokens against the API key.
            response.data.on('end', () => {
                upstreamDone = true;
                if (lastSeenTotalTokens != null && req.apiKeyData) {
                    const stats = apiKeyUsageStats.get(req.apiKeyData.id);
                    if (stats && stats.requests.length > 0) {
                        const lastReq = stats.requests[stats.requests.length - 1];
                        lastReq.tokens = lastSeenTotalTokens;
                        stats.tokenCount += lastSeenTotalTokens;
                        apiKeyUsageStats.set(req.apiKeyData.id, stats);
                        console.log(`[Proxy] Tracked ${lastSeenTotalTokens} tokens (stream) for ${req.apiKeyData.name}`);
                        try {
                            broadcast({
                                type: 'log',
                                message: `[Pi/API] ${req.apiKeyData.name} ← ${lastSeenTotalTokens} tokens`,
                                level: 'success',
                                targetUserId: req.userId
                            });
                        } catch (_) { /* ignore */ }
                    }
                }
                if (!res.writableEnded) {
                    res.end();
                }
            });
        } else {
            // Handle non-streaming response (for token counting)
            const response = await axios({
                method: req.method,
                url: targetUrl,
                data: req.body,
                headers: {
                    'Content-Type': req.headers['content-type'] || 'application/json',
                }
            });

            // Track token usage
            if (response.data && (response.data.usage || response.data.tokens)) {
                const tokens = response.data.usage?.total_tokens || response.data.tokens?.total_tokens || 0;
                if (tokens > 0 && req.apiKeyData) {
                    const stats = apiKeyUsageStats.get(req.apiKeyData.id) || {
                        requestCount: 0,
                        tokenCount: 0,
                        lastUsed: Date.now(),
                        requests: []
                    };
                    stats.tokenCount += tokens;
                    const lastReq = stats.requests[stats.requests.length - 1];
                    if (lastReq) {
                        lastReq.tokens = tokens;
                    }
                    apiKeyUsageStats.set(req.apiKeyData.id, stats);
                    console.log(`[Proxy] Tracked ${tokens} tokens for ${req.apiKeyData.name}`);
                    try {
                        broadcast({
                            type: 'log',
                            message: `[Pi/API] ${req.apiKeyData.name} ← ${tokens} tokens`,
                            level: 'success',
                            targetUserId: req.userId
                        });
                    } catch (_) { /* ignore */ }
                }
            }

            // Forward response headers (excluding hop-by-hop headers)
            const headersToSkip = ['transfer-encoding', 'content-length', 'connection', 'keep-alive'];
            Object.keys(response.headers).forEach(key => {
                if (!headersToSkip.includes(key.toLowerCase())) {
                    res.setHeader(key, response.headers[key]);
                }
            });

            // Forward status code and data
            res.status(response.status).json(response.data);
        }
    } catch (error) {
        console.error('[Proxy] Error:', error.message);
        if (error.response) {
            const status = error.response.status;
            console.error('[Proxy] Response status:', status);
            // Streaming proxy requests use responseType:'stream', so an upstream
            // error body arrives as a Node stream (IncomingMessage), NOT parsed
            // JSON. JSON.stringify-ing it throws "Converting circular structure"
            // (socket → _httpMessage → ClientRequest → socket) and, since we're
            // already in the catch, surfaces as an unhandledRejection. Drain the
            // stream to text first; parse as JSON when possible.
            let data = error.response.data;
            if (data && typeof data.pipe === 'function') {
                data = await new Promise((resolve) => {
                    let buf = '';
                    data.on('data', (c) => { if (buf.length < 64 * 1024) buf += c.toString('utf8'); });
                    data.on('end', () => resolve(buf));
                    data.on('error', () => resolve(buf));
                });
                try { data = JSON.parse(data); } catch (_) { /* keep as raw text */ }
            }
            try {
                console.error('[Proxy] Response data:', typeof data === 'string' ? data : JSON.stringify(data));
            } catch (_) { /* never let logging crash the handler */ }
            if (!res.headersSent) {
                if (data && typeof data === 'object') {
                    res.status(status).json(data);
                } else if (typeof data === 'string' && data) {
                    res.status(status).json({ error: 'Proxy error', details: data });
                } else {
                    res.status(status).json({ error: 'Proxy error', details: error.message });
                }
            } else if (!res.writableEnded) {
                res.end();
            }
        } else if (!res.headersSent) {
            res.status(500).json({
                error: 'Failed to proxy request to sglang',
                details: error.message
            });
        } else if (!res.writableEnded) {
            res.end();
        }
    }
});

// ============================================================================
// KNOWLEDGE BASE (RAG) ROUTES
// ============================================================================
// Per-user document collections with semantic retrieval. Owners manage their
// own KBs; admins see and manage all. Embedding + top-k search run in the
// resident kb_engine subprocess (via knowledgeBaseService) so only a few
// relevant snippets ever enter the chat context, regardless of KB size.

// Attach the owner's username to each KB record (for the admin "all KBs" view).
async function decorateKbOwners(list) {
    const usersById = new Map();
    try {
        const users = await getAllUsers();
        for (const u of users) usersById.set(String(u.id), u);
    } catch (_) { /* fall back to raw owner id */ }
    return list.map((kb) => ({
        ...kb,
        ownerName: kb.userId ? (usersById.get(String(kb.userId))?.username || 'unknown') : 'global',
    }));
}

// Load a KB and enforce ownership (admins bypass). Sends the error + returns
// null when access is denied so the caller can `if (!kb) return;`.
async function loadOwnedKB(req, res) {
    const kb = await knowledgeBaseService.getKB(req.params.id);
    if (!kb) { res.status(404).json({ error: 'Knowledge base not found' }); return null; }
    if (!callerIsAdmin(req) && !checkOwnership(kb, req.userId)) {
        res.status(403).json({ error: 'Not authorized for this knowledge base' });
        return null;
    }
    return kb;
}

// List KBs — own, or all for admins.
app.get('/api/knowledge-bases', requireAuth, async (req, res) => {
    try {
        const isAdmin = callerIsAdmin(req);
        const list = await knowledgeBaseService.listKBs(req.userId, { all: isAdmin });
        res.json({ knowledgeBases: await decorateKbOwners(list), isAdmin });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Create a KB.
app.post('/api/knowledge-bases', requireAuth, async (req, res) => {
    try {
        const { name, description } = req.body || {};
        if (!name || !String(name).trim()) {
            return res.status(400).json({ error: 'name is required' });
        }
        const kb = await knowledgeBaseService.createKB({
            name: String(name).trim(), description, userId: req.userId,
        });
        res.status(201).json({ knowledgeBase: kb });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// KB details + documents + live engine stats.
app.get('/api/knowledge-bases/:id', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        let stats = null;
        try { stats = await knowledgeBaseService.stats(kb); } catch (_) { /* engine may be warming */ }
        res.json({ knowledgeBase: kb, documents: kb.documents || [], stats });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Rename / edit description.
app.patch('/api/knowledge-bases/:id', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        const patch = {};
        if (req.body?.name != null) patch.name = String(req.body.name).slice(0, 200);
        if (req.body?.description != null) patch.description = String(req.body.description).slice(0, 2000);
        const updated = await knowledgeBaseService.updateKB(kb.id, patch);
        res.json({ knowledgeBase: updated });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Delete a KB (removes its vectors + files).
app.delete('/api/knowledge-bases/:id', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        await knowledgeBaseService.deleteKB(kb.id);
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Upload + index a document (base64 JSON body, mirrors /api/chat/upload).
app.post('/api/knowledge-bases/:id/documents', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        const { filename, content, mimeType, text } = req.body || {};
        if (!content && !text) {
            return res.status(400).json({ error: 'content (base64) or text is required' });
        }
        if (content && content.length > 50 * 1024 * 1024) {
            return res.status(413).json({ error: 'File too large. Maximum size is 50MB.' });
        }
        const buffer = content ? Buffer.from(content, 'base64') : null;
        const docId = crypto.randomBytes(12).toString('hex');
        const safeName = String(filename || 'document.txt').slice(0, 255);
        const result = await knowledgeBaseService.ingestDocument(kb, {
            docId, filename: safeName, buffer, mimeType, text,
        });
        if (!result.chunkCount) {
            return res.status(422).json({ error: 'No extractable text found in this document.', ...result });
        }
        const doc = {
            docId,
            filename: safeName,
            mimeType: mimeType || '',
            size: buffer ? buffer.length : (text ? Buffer.byteLength(text) : 0),
            chunkCount: result.chunkCount,
            chars: result.chars,
            addedAt: new Date().toISOString(),
        };
        let stats = null; try { stats = await knowledgeBaseService.stats(kb); } catch (_) {}
        const updated = await knowledgeBaseService.addDocumentMeta(kb.id, doc, {
            chunkCount: stats ? stats.chunkCount : undefined,
            embeddingModel: stats ? stats.model : undefined,
        });
        res.status(201).json({ document: doc, knowledgeBase: updated, stats });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Remove a document from a KB.
app.delete('/api/knowledge-bases/:id/documents/:docId', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        await knowledgeBaseService.deleteDocument(kb, req.params.docId);
        let stats = null; try { stats = await knowledgeBaseService.stats(kb); } catch (_) {}
        const updated = await knowledgeBaseService.removeDocumentMeta(kb.id, req.params.docId, {
            chunkCount: stats ? stats.chunkCount : undefined,
        });
        res.json({ success: true, knowledgeBase: updated, stats });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Query a KB (UI test box; the chat tool calls the service directly).
app.post('/api/knowledge-bases/:id/search', requireAuth, async (req, res) => {
    try {
        const kb = await loadOwnedKB(req, res); if (!kb) return;
        const { query, k } = req.body || {};
        if (!query || !String(query).trim()) {
            return res.status(400).json({ error: 'query is required' });
        }
        const topK = Math.min(Math.max(parseInt(k) || 6, 1), 50);
        const results = await knowledgeBaseService.search(kb, String(query), topK);
        res.json({ results, query });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// ============================================================================
// ACCOUNT MEMORY — CRUD for the webapp Memory tab
// ============================================================================
// Memories are account-scoped (one set per user), managed here and surfaced to
// the chat model via injection + the record_learning tool. Auth + ownership
// only (no special permission, like knowledge bases); admins see/manage all and
// the list is decorated with ownerName. Routes sit BEFORE the 404/error
// middleware (same placement rule as the knowledge-base routes).

// Account id that memory is keyed by. Resolves to the owning ACCOUNT in every
// auth mode: a web session uses `req.user.id`; an API-key/Bearer caller uses
// `req.userId` (= `keyData.userId`, the account that created the key). Only an
// UNASSOCIATED key (no `userId`) falls back to its own key id, preserving
// isolation. This mirrors the `/v1` persona bridge (`injectPersonaForV1`), so a
// key minted in a web session shares ONE persona with the web chat instead of a
// blank per-key bucket. The chat stream, Memory-tab routes, `record_learning`,
// and experience recording all resolve memory identity through this helper, so
// reads and writes never diverge. NOTE: this is deliberately DECOUPLED from
// conversation ownership (conversations stay keyed by the chat stream's own
// `userId`) — switching memory to the account must not move or hide an API
// caller's existing conversations.
function memAccountId(req) {
    return req.user?.id || req.userId || req.apiKeyData?.id || 'default';
}

// Attach ownerName to each memory for the admin view (mirrors decorateKbOwners).
async function decorateMemoryOwners(list) {
    const usersById = new Map();
    try {
        const users = await getAllUsers();
        for (const u of users) usersById.set(String(u.id), u);
    } catch (_) { /* fall back to raw owner id */ }
    return list.map((m) => ({
        ...m,
        ownerName: m.userId ? (usersById.get(String(m.userId))?.username || 'unknown') : 'global',
    }));
}

// Load a memory and enforce ownership (admins bypass). Sends the error +
// returns null on denial so the caller can `if (!mem) return;`.
async function loadOwnedMemory(req, res) {
    const mem = await memoryService.getMemory(req.params.id);
    if (!mem) { res.status(404).json({ error: 'Memory not found' }); return null; }
    if (!callerIsAdmin(req) && mem.userId !== memAccountId(req)) {
        res.status(403).json({ error: 'Not authorized for this memory' });
        return null;
    }
    return mem;
}

// List memories — own, or all for admins. Triggers legacy migration first so
// the tab shows imported per-conversation memories immediately.
app.get('/api/memories', requireAuth, async (req, res) => {
    try {
        try { await memoryService.migrateLegacyForUser(memAccountId(req)); } catch (_) { /* best-effort */ }
        const isAdmin = callerIsAdmin(req);
        const list = await memoryService.listMemories(memAccountId(req), { all: isAdmin });
        // Newest-updated first for a useful default order in the UI.
        list.sort((a, b) => (b.updatedAt || '').localeCompare(a.updatedAt || ''));
        res.json({ memories: await decorateMemoryOwners(list), isAdmin });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Create a memory by hand (source 'manual').
app.post('/api/memories', requireAuth, async (req, res) => {
    try {
        const text = String(req.body?.text || '').trim();
        if (!text) return res.status(400).json({ error: 'text is required' });
        if (text.length > memoryService.MEMORY_TEXT_MAX) {
            return res.status(400).json({ error: `text too long (max ${memoryService.MEMORY_TEXT_MAX} chars)` });
        }
        const type = req.body?.type && memoryService.VALID_TYPES.has(req.body.type) ? req.body.type : null;
        const impact = req.body?.impact && memoryService.VALID_IMPACTS.has(req.body.impact) ? req.body.impact : null;
        const keywords = extractQueryKeywords(text);
        const mem = await memoryService.createMemory({
            userId: memAccountId(req),
            text,
            keywords,
            tokens: Math.ceil(text.length / 3),
            score: 5,                 // manual entries are deliberately high-value
            source: 'manual',
            type,
            impact,
        });
        res.status(201).json({ memory: mem });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Prune "scratch" facts — auto-extracted FACTS that aren't durable memories
// about the user but one-off conversation leftovers (task-specific state, "since
// I don't have the file…", transient context). The local model judges each in
// batches; only AUTO, non-pinned, non-procedure facts are eligible, so manual
// entries / preferences / experience are never at risk. Conservative: drops only
// what the model explicitly flags; no model running → no-op.
async function pruneScratchFacts(userId, { apply }) {
    const all = await memoryService.listMemories(userId);
    const facts = all.filter(m => m.source === 'auto' && (m.type || 'fact') === 'fact' && !m.pinned);
    if (!facts.length) return { candidates: 0, dropped: 0, sample: [] };
    let running = false;
    for (const inst of modelInstances.values()) if (inst.status === 'running') { running = true; break; }
    if (!running) return { candidates: facts.length, dropped: 0, sample: [], note: 'no model running — skipped' };

    const SYS = 'You audit stored long-term "memories". KEEP durable facts about the USER: identity, life, work, projects, environment, accounts, tools, and the WORK/PROJECT domains they operate in (e.g. they regularly do malware analysis for their job — that is a work fact, keep it). DROP: (a) PASSIVE interests / hobbies / topics they were merely curious about ("the user is interested in <show/game/topic>", "is a fan of X", "enjoys watching Y") — these are not actionable; (b) a ONE-OFF task they asked about once ("looking for streaming sites for movie X", "renting a hand truck"); (c) transient session state / scratch ("since I don\'t have the file…", "the SVG isn\'t on disk", a single past artifact\'s byte size); (d) a specific date/time or live-news item; (e) content the ASSISTANT produced (article quotes, code/templates, citations, news write-ups). When unsure whether something is a durable WORK fact or a passive interest, prefer to DROP passive interests but KEEP work/identity facts. Reply with ONLY a JSON array of the item NUMBERS to DROP. If none, reply [].';
    const drop = new Set();
    const CHUNK = 25;
    for (let i = 0; i < facts.length; i += CHUNK) {
        const batch = facts.slice(i, i + CHUNK);
        const numbered = batch.map((m, j) => `${j + 1}. ${m.text}`).join('\n');
        let raw;
        try {
            raw = await Promise.race([
                runModelCompletion({ messages: [{ role: 'system', content: SYS }, { role: 'user', content: numbered }], temperature: 0, maxTokens: 220, disableThinking: true }),
                new Promise((_, rej) => { const t = setTimeout(() => rej(new Error('prune timeout')), 25000); if (t.unref) t.unref(); }),
            ]);
        } catch (_) { continue; }                            // batch failed → keep this batch
        const stripped = String(raw || '').replace(/<(think|thinking|reasoning|reasoning_engine)>[\s\S]*?<\/\1>/gi, '');
        const m = stripped.match(/\[[\s\S]*?\]/);
        if (!m) continue;
        let arr; try { arr = JSON.parse(m[0]); } catch (_) { continue; }
        if (!Array.isArray(arr)) continue;
        for (const n of arr) { const idx = Number(n) - 1; if (idx >= 0 && batch[idx]) drop.add(batch[idx].id); }
    }
    const dropIds = [...drop];
    const sample = facts.filter(f => drop.has(f.id)).slice(0, 15).map(f => (f.text || '').slice(0, 85));
    if (apply) { for (const id of dropIds) { try { await memoryService.deleteMemory(id); } catch (_) { /* continue */ } } }
    return { candidates: facts.length, dropped: dropIds.length, sample };
}

// Maintenance: clean junk + consolidate near-duplicates for the CALLER'S OWN
// account. Dry-run by default (apply:false) → returns what WOULD change so the
// user can review before committing. apply:true performs it. Owner-scoped via
// memAccountId — never touches another account's memories.
//   body: { apply?, llm?, minSem?, mergeProcedures?, pruneScratch? }
app.post('/api/memories/maintenance', requireAuth, async (req, res) => {
    try {
        const userId = memAccountId(req);
        if (!userId || userId === 'default') return res.status(400).json({ error: 'no account memory context' });
        const apply = req.body?.apply === true;
        const useLlm = req.body?.llm !== false;
        const minSem = (typeof req.body?.minSem === 'number' && req.body.minSem > 0 && req.body.minSem < 1) ? req.body.minSem : undefined;

        const all = await memoryService.listMemories(userId);
        const before = all.length;

        // 1) JUNK — AUTO-extracted non-procedure lines the (strengthened) junk
        // filter flags, PLUS passive consumption-interest statements ("user is
        // interested in X", "is a fan of Y") which the user does not want stored.
        // Never deletes manual/user-authored or procedures.
        // Deterministic request-junk detector — runs REGARDLESS of model
        // availability (pruneScratchFacts needs a loaded model and bails without
        // one, which is exactly when bare-request facts accrete unaudited). Flags
        // only an AUTO fact that LEADS with a request to the assistant AND carries
        // no durable first/second-person predicate or stable identifier — i.e. a
        // one-off task ask ("Give me all the info for the Diablo 4 patch"), never a
        // fact about the user. "When unsure, KEEP."
        const isRequestJunk = (m) => {
            const t = String(m.text || '');
            return m.source === 'auto' && m.type === 'fact' && !m.pinned
                && looksLikeRequest(t)
                && !/\b(i (am|use|prefer|work|run|need|have|like|want)|i'?m|my )\b/i.test(t)         // no first/second-person durable predicate
                && !/(\d{1,3}(\.\d{1,3}){3}|cve-\d|\/[\w./-]+|[a-z0-9.-]+\.(com|net|org|io|in|dev|app|gov))\b/i.test(t); // no IP/CVE/path/domain
        };
        const junk = all.filter(m => m.source === 'auto' && m.type !== 'procedure'
            && (isJunkMemoryLine(String(m.text || '')) || isLowValueInterest(String(m.text || '')) || isRequestJunk(m)));
        const junkSample = junk.slice(0, 15).map(m => ({ id: m.id, type: m.type, text: (m.text || '').slice(0, 90) }));
        if (apply) {
            for (const m of junk) { try { await memoryService.deleteMemory(m.id); } catch (_) { /* continue */ } }
        }

        // 2) CONSOLIDATE near-duplicate clusters. LLM-author the merged text when
        // a model is running (else keep-strongest). Force the pass (auto:false).
        const mergeText = useLlm ? (async (members) => {
            let running = false;
            for (const inst of modelInstances.values()) if (inst.status === 'running') { running = true; break; }
            if (!running) return null;                       // → keep strongest member's text
            const lines = members.map((x, i) => `${i + 1}. ${x.text}`).join('\n');
            const raw = await Promise.race([
                runModelCompletion({
                    messages: [
                        { role: 'system', content: 'You merge several memory notes that are about the SAME thing into ONE concise note with the same meaning and no duplication. Keep it a single short statement about the user or their preference. Output ONLY the merged note, no preamble, no list.' },
                        { role: 'user', content: lines },
                    ], temperature: 0, maxTokens: 160, disableThinking: true,
                }),
                new Promise((_, rej) => { const t = setTimeout(() => rej(new Error('merge timeout')), 20000); if (t.unref) t.unref(); }),
            ]);
            const text = String(raw || '').replace(/<(think|thinking|reasoning|reasoning_engine)>[\s\S]*?<\/\1>/gi, '').trim();
            return (text && !isJunkMemoryLine(text)) ? text : null;
        }) : null;

        const consol = await memoryService.consolidateUser(userId, { apply, mergeText, ...(minSem ? { minSem } : {}) });

        // 3) PROCEDURE merge (opt-in) — collapse same-activity duplicate recipes.
        const procResult = req.body?.mergeProcedures
            ? await memoryService.consolidateProcedures(userId, { apply, ...(minSem ? { minSem } : {}) })
            : null;

        // 4) SCRATCH-FACT prune (opt-in, LLM judges durable-vs-one-off).
        const pruneResult = req.body?.pruneScratch
            ? await pruneScratchFacts(userId, { apply })
            : null;

        // 5) LINK related (opt-in) — connect clearly-related EXISTING memories
        // (cosine ≥ minSem + shared-keyword anchor, bounded per memory) so they
        // surface together at retrieval (1-hop link expansion). Backfills the
        // links the auto-linker only creates for memories added going forward.
        // Needs the embedding engine; engine down → no-op.
        const linkResult = req.body?.linkRelated
            ? await memoryService.linkRelatedMemories(userId, { apply, ...(minSem ? { minSem } : {}) })
            : null;

        const removedCount = junk.length
            + (consol.merged || consol.merges.reduce((n, x) => n + x.dropped.length, 0))
            + (procResult ? (procResult.merged || procResult.merges.reduce((n, x) => n + x.dropped.length, 0)) : 0)
            + (pruneResult ? pruneResult.dropped : 0);
        const after = apply
            ? await memoryService.countForUser(userId).catch(() => before - removedCount)
            : before;                                        // dry-run: store unchanged

        res.json({
            apply,
            before,
            after: apply ? after : undefined,
            projectedAfter: apply ? undefined : before - removedCount,
            junk: { count: junk.length, sample: junkSample },
            consolidation: {
                clusters: consol.clusters,
                merged: apply ? consol.merged : consol.merges.reduce((n, x) => n + x.dropped.length, 0),
                sample: consol.merges.slice(0, 10),
            },
            procedures: procResult ? {
                groups: procResult.groups,
                merged: apply ? procResult.merged : procResult.merges.reduce((n, x) => n + x.dropped.length, 0),
                sample: procResult.merges.slice(0, 10),
            } : undefined,
            scratchPrune: pruneResult ? {
                candidates: pruneResult.candidates,
                dropped: pruneResult.dropped,
                note: pruneResult.note,
                sample: pruneResult.sample,
            } : undefined,
            linkRelated: linkResult ? {
                scanned: linkResult.scanned,
                proposed: linkResult.proposed,
                linked: apply ? linkResult.linked : 0,
                sample: linkResult.pairs.slice(0, 12),
            } : undefined,
        });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Get one memory.
app.get('/api/memories/:id', requireAuth, async (req, res) => {
    try {
        const mem = await loadOwnedMemory(req, res); if (!mem) return;
        res.json({ memory: mem });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Edit a memory's text / type / impact. Re-derives keywords + tokens on text
// change so retrieval scoring stays consistent with the extractor.
app.patch('/api/memories/:id', requireAuth, async (req, res) => {
    try {
        const mem = await loadOwnedMemory(req, res); if (!mem) return;
        const patch = {};
        if (req.body?.text != null) {
            const text = String(req.body.text).trim();
            if (!text) return res.status(400).json({ error: 'text cannot be empty' });
            if (text.length > memoryService.MEMORY_TEXT_MAX) {
                return res.status(400).json({ error: `text too long (max ${memoryService.MEMORY_TEXT_MAX} chars)` });
            }
            patch.text = text;
            patch.keywords = extractQueryKeywords(text);
            patch.tokens = Math.ceil(text.length / 3);
        }
        if (req.body?.type !== undefined) patch.type = req.body.type;
        if (req.body?.impact !== undefined) patch.impact = req.body.impact;
        // User flags: pinned = never pruned; muted = stored but never injected.
        if (req.body?.pinned !== undefined) patch.pinned = req.body.pinned === true;
        if (req.body?.muted !== undefined) patch.muted = req.body.muted === true;
        const updated = await memoryService.updateMemory(mem.id, patch);
        res.json({ memory: updated });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Delete one memory.
app.delete('/api/memories/:id', requireAuth, async (req, res) => {
    try {
        const mem = await loadOwnedMemory(req, res); if (!mem) return;
        await memoryService.deleteMemory(mem.id);
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Connect / disconnect two memories (bidirectional). Both must belong to the
// caller's account (admins bypass). body: { targetId, unlink? }.
app.post('/api/memories/:id/link', requireAuth, async (req, res) => {
    try {
        const mem = await loadOwnedMemory(req, res); if (!mem) return;
        const targetId = String(req.body?.targetId || '').trim();
        if (!targetId) return res.status(400).json({ error: 'targetId is required' });
        if (targetId === mem.id) return res.status(400).json({ error: 'cannot link a memory to itself' });
        const target = await memoryService.getMemory(targetId);
        if (!target) return res.status(404).json({ error: 'target memory not found' });
        // Both sides must be owned by the same account so we never weave a
        // cross-account link (mem is already ownership-checked above).
        if (target.userId !== mem.userId) {
            return res.status(403).json({ error: 'memories belong to different accounts' });
        }
        const unlink = req.body?.unlink === true;
        const result = await memoryService.setLink(mem.userId, mem.id, targetId, { unlink });
        if (!result) return res.status(404).json({ error: 'memory not found' });
        res.json({ success: true, changed: result.changed, source: result.a, target: result.b });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Clear ALL of the caller's own memories (the tab's "clear all" action).
app.delete('/api/memories', requireAuth, async (req, res) => {
    try {
        const removed = await memoryService.clearMemories(memAccountId(req));
        res.json({ success: true, removed });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Search/test box: score the caller's memories against a query the same way
// the chat injector does — semantic cosine (memory index) blended with
// keyword overlap, falling back to keyword-only when the engine is down.
app.post('/api/memories/search', requireAuth, async (req, res) => {
    try {
        const query = String(req.body?.query || '').trim();
        if (!query) return res.status(400).json({ error: 'query is required' });
        const k = Math.min(Math.max(parseInt(req.body?.k) || 10, 1), 50);
        const accountId = memAccountId(req);
        const all = await memoryService.listMemories(accountId, { all: callerIsAdmin(req) });
        // Semantic scores cover the caller's OWN index; an admin's view of
        // other users' memories scores keyword-only (their vectors live in
        // per-user indexes we don't cross-query).
        let sem = null;
        try { sem = await semanticMemoryScores(accountId, query, k * 2); } catch (_) { sem = null; }
        const qk = extractQueryKeywords(query);
        const scored = all.map((m) => {
            const kw = memoryService.jaccardSimilarity(m.keywords || [], qk);
            const s = sem?.scores?.get(m.id);
            return { ...m, score: s != null ? Math.max(s, kw) : kw, semantic: s ?? null };
        });
        scored.sort((a, b) => b.score - a.score);
        const results = scored.filter((m) => m.score > 0).slice(0, k);
        res.json({ query, count: results.length, results, mode: sem ? 'semantic+keyword' : 'keyword' });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// ============================================================================
// GLOBAL ERROR HANDLING MIDDLEWARE
// ============================================================================

// Catch-all error handler for Express routes (must be last middleware)
// This catches any errors thrown in async route handlers
app.use((err, req, res, next) => {
    console.error('Express error handler caught:', err);
    console.error('Stack:', err.stack);

    // Build detailed error message for the Logs tab
    const errorDetail = err.message || 'Internal server error';
    const route = `${req.method} ${req.originalUrl || req.url}`;
    const stack = err.stack
        ? err.stack.split('\n').slice(1, 3).join('\n').trim()
        : '';

    // Broadcast error to connected clients (visible in Logs tab)
    // Stack traces are logged server-side only — not broadcast to prevent info leakage
    try {
        broadcast({
            type: 'log',
            message: `[Error] ${route}: ${errorDetail}`,
            level: 'error'
        });
    } catch (broadcastError) {
        console.error('Failed to broadcast error:', broadcastError);
    }

    // Return error message to API caller (useful for debugging in browser devtools)
    // Include the error message but not the stack trace for security
    res.status(err.status || 500).json({
        error: errorDetail
    });
});

// 404 handler - must come after all other routes
// Don't reveal endpoint information to prevent API discovery attacks
app.use((req, res) => {
    res.status(404).json({ error: 'Invalid request' });
});

// ============================================================================
// NATIVE TOOL REGISTRATIONS
// ============================================================================
//
// Registered here at the bottom of server.js because the tool `execute`
// closures need in-scope access to helpers defined earlier in the file
// (fetchUrlContent, extractSearchQuery, isPrivateUrl, axios). chatTools
// is a singleton module, so this registration is visible to the chat
// stream handler without further wiring.
(() => {
    const tools = require('./services/chatTools');

    // ----- bot-protection heuristic ---------------------------------------
    // When fetch_url or playwright_fetch come back with a Cloudflare/DataDome
    // interstitial (or a suspiciously thin body) the model has no clean
    // signal that the fetch was challenged rather than genuinely empty —
    // so it gives up. This helper inspects the result and returns an
    // escalation hint the tool payload can carry alongside the content.
    // Callers attach the hint when present; models that read it will
    // retry via scrapling_fetch.
    const CHALLENGE_MARKERS = [
        /checking your browser/i,
        /enable javascript and cookies to continue/i,
        /cf-browser-verification/i,
        /cf-challenge/i,
        /challenge-platform/i,
        /__cf_chl_/i,
        /just a moment\.\.\./i,
        /attention required/i,
        /access denied/i,
        /please verify you are a human/i,
        /ddos protection by cloudflare/i,
        /perimeterx/i,
        /datadome/i,
        /px-captcha/i,
        /h-captcha/i,
        /hcaptcha/i,
        /recaptcha/i,
        // Cloudflare Turnstile + newer wording
        /turnstile/i,
        /cf-turnstile/i,
        /verifying you are human/i,
        /needs to review the security of your connection/i,
        /one more step/i,
        /ray id:/i,
        /error 10(15|20)/i,
        // DataDome
        /captcha-delivery\.com/i,
        /geo\.captcha-delivery/i,
        // Imperva / Incapsula / Distil
        /pardon our interruption/i,
        /imperva/i,
        /incapsula/i,
        /_incapsula_/i,
        /distil/i,
        // Akamai / Sucuri / generic
        /sucuri/i,
        /unusual traffic from your computer network/i,
        /are you a (?:robot|human)/i,
        /please verify you('| a)re human/i,
        /bot detection/i,
        /enable cookies/i,
    ];
    function detectBotChallenge({ title = '', content = '' } = {}) {
        const blob = `${title}\n${content}`.slice(0, 8000);
        const hit = CHALLENGE_MARKERS.find(rx => rx.test(blob));
        if (hit) return `bot protection detected (${hit.source}) — retry with scrapling_fetch for better evasion`;
        const trimmed = typeof content === 'string' ? content.trim() : '';
        if (trimmed.length < 400) {
            return 'response body is very thin — page may be JS-gated or bot-challenged; if unexpected, retry with scrapling_fetch';
        }
        return null;
    }

    // Shopping/product pages inject price & stock client-side, so a fetch can
    // "succeed" with a large page that omits or stales the figure, with no
    // bot-challenge marker (detectBotChallenge stays silent). The model then
    // re-scrapes the same URL with a second engine (which hits the same page)
    // before pivoting — the slow, 6-call path seen in practice. Recognize such a
    // page from its OWN visible text (vendor-agnostic — works for ANY store, no
    // hardcoded site list) and advise switching source via web_search. No site
    // name and no third-party service is hardcoded.
    const PRODUCT_SIGNALS = /\badd to (?:cart|basket|bag)\b|\badd to wishlist\b|\b(?:currently\s+)?(?:in|out of) stock\b/i;
    function productPageHint(content) {
        if (!content || !PRODUCT_SIGNALS.test(content)) return null;
        return 'this looks like a shopping/product page; price and availability are typically loaded dynamically and are often missing or out of date in scraped HTML. ' +
            'If the exact figure you need is not clearly present here, re-fetching this URL with another scraper will hit the same page — use web_search to get it from another source and cite that source.';
    }

    // ----- web_search ------------------------------------------------------
    tools.registerTool({
        name: 'web_search',
        build() {
            return null; // consolidated into the `web` tool — hidden from the chat catalog, still registered for automations + the web router
            return {
                type: 'function',
                function: {
                    name: 'web_search',
                    description:
                        'Search the web via DuckDuckGo; returns up to 5 results (title, url, snippet). Snippets are short — almost always follow up with fetch_url on top results. ' +
                        'For single-fact lookups, fetch 1 result; for lists / comparisons / "what\'s new" / multi-aspect questions, fetch 2–3 in parallel in the same round. ' +
                        'Trust the snippets over training when they conflict, and cite URLs in answers. Use search_string on long fetched pages instead of re-reading them. ' +
                        '**Don\'t lead with web_search when the artifact itself is available.** For a named npm / PyPI / crates.io / RubyGems / NuGet / GitHub package, the registry tarball is the source of truth — fetch it (npm: `https://registry.npmjs.org/<pkg>/-/<pkg>-<version>.tgz`; PyPI: `https://pypi.org/pypi/<pkg>/json` → `urls[*].url`; GitHub: clone or download the archive) via fetch_url / download_file, extract via extract_archive / tar_extract / unzip_file, and read the actual code. Reserve web_search for post-hoc cross-reference (CVE IDs, advisory write-ups) AFTER you\'ve looked at the artifact. If a search has already been rate-limited (DDG / Scrapling / Brave all failed), stop re-querying — pivot to the artifact instead.',
                    parameters: {
                        type: 'object',
                        properties: {
                            query: { type: 'string', description: 'Search query.' },
                            limit: { type: 'integer', minimum: 1, maximum: 10, description: 'Max results (default 5).' },
                        },
                        required: ['query'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const rawQuery = String(args?.query || '').trim();
            if (!rawQuery) return { error: 'query is required' };
            const q = extractSearchQuery(rawQuery);
            const limit = Math.min(10, Math.max(1, parseInt(args?.limit || 5, 10)));
            // Result cache — reuses the /api/search `searchCache` (1h TTL, 1000-entry
            // LRU). Repeated identical searches within a turn/session skip the full
            // DDG round-trip. ONLY successful, fully-parsed results are cached: error
            // / rate-limited returns are never pinned, so a transient block re-runs
            // the whole DDG→Brave→Scrapling evasion chain on the next call.
            const cacheKey = `wsearch:${q}:${limit}`;
            cleanExpiredCache();
            if (searchCache.has(cacheKey)) { const c = searchCache.get(cacheKey); return { ...c.data, cached: true }; }
            const cacheReturn = (out) => { searchCache.set(cacheKey, { data: out, timestamp: Date.now() }); return out; };
            try {
                const resp = await axios.get(
                    `https://html.duckduckgo.com/html/?q=${encodeURIComponent(q)}`,
                    {
                        headers: {
                            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
                            'Accept-Language': 'en-US,en;q=0.9',
                        },
                        // html.duckduckgo.com CAPTCHAs Node's axios on essentially every
                        // hit, so fail FAST to the Brave/Scrapling fallbacks instead of
                        // burning 8s on a layer that never succeeds.
                        timeout: 3500,
                    },
                );
                const html = resp.data || '';
                if (html.includes('anomaly-modal')) {
                    // DDG hit CAPTCHA — fall back through Brave FIRST, then Scrapling.
                    // Brave is a cheap axios HTML GET that actually produces results
                    // post-CAPTCHA (~10s). Scrapling here just re-fetches the SAME
                    // already-CAPTCHA'd DDG endpoint via a plain Fetcher (no evasion
                    // advantage in this block), so it's demoted below Brave and only
                    // runs when Brave parses nothing — avoiding a redundant subprocess.
                    try {
                        const braveResp = await axios.get(
                            `https://search.brave.com/search?q=${encodeURIComponent(q)}`,
                            {
                                headers: {
                                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
                                    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                                    'Accept-Language': 'en-US,en;q=0.9',
                                },
                                timeout: 10000,
                            },
                        );
                        const bhtml = braveResp.data || '';
                        // Reuse the same Brave parsing /api/search uses.
                        const linkPattern = /<a\s+href="(https?:\/\/(?!(?:search\.)?brave\.com|cdn\.search\.brave\.com|imgs\.search\.brave\.com|tiles\.search\.brave\.com)[^"]+)"[^>]*target="_self"[^>]*class="[^"]*svelte[^"]*"[^>]*>/gi;
                        const titlePattern = /<span[^>]*class="[^"]*title[^"]*"[^>]*>([^<]+)<\/span>/gi;
                        const descPattern = /<p[^>]*class="[^"]*snippet-description[^"]*"[^>]*>([\s\S]*?)<\/p>/gi;
                        const bUrls = [];
                        const bTitles = [];
                        const bDescs = [];
                        let lm;
                        while ((lm = linkPattern.exec(bhtml)) !== null) bUrls.push(lm[1]);
                        while ((lm = titlePattern.exec(bhtml)) !== null) bTitles.push(lm[1].trim());
                        while ((lm = descPattern.exec(bhtml)) !== null) bDescs.push(lm[1].replace(/<[^>]*>/g, '').trim());
                        const bSeen = new Set();
                        const bResults = [];
                        for (let i = 0; i < bUrls.length && bResults.length < limit; i++) {
                            const url = bUrls[i];
                            if (bSeen.has(url)) continue;
                            bSeen.add(url);
                            let title = bTitles[i] || '';
                            if (!title) {
                                try { title = new URL(url).hostname.replace(/^www\./, ''); } catch { title = 'Web Result'; }
                            }
                            bResults.push({ title, url, snippet: bDescs[i] || '' });
                        }
                        if (bResults.length) {
                            return cacheReturn({ query: q, source: 'brave', count: bResults.length, results: bResults });
                        }
                    } catch (_) { /* fall through to Scrapling */ }
                    if (scraplingService) {
                        try {
                            const sr = await scraplingService.search(q, limit);
                            if (sr?.success && Array.isArray(sr.results) && sr.results.length) {
                                return cacheReturn({
                                    query: q,
                                    source: 'scrapling',
                                    count: sr.results.length,
                                    results: sr.results.slice(0, limit).map(r => ({
                                        title: r.title || 'No title',
                                        url: r.url,
                                        snippet: r.snippet || '',
                                    })),
                                });
                            }
                        } catch (_) { /* fall through to error */ }
                    }
                    return { error: 'search rate-limited; all search backends (DuckDuckGo, Brave, Scrapling) are temporarily blocked. Read the target page directly with a url, or try again shortly.', retryable: true, source: 'rate-limited', query: q };
                }
                const resultRegex = /<div class="result[^"]*"[^>]*>([\s\S]*?)<\/div>\s*<\/div>/gi;
                const titleRegex = /<a[^>]*class="result__a"[^>]*href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/i;
                const snippetRegex = /<a[^>]*class="result__snippet"[^>]*>([\s\S]*?)<\/a>/i;
                const seen = new Set();
                const results = [];
                let m;
                while ((m = resultRegex.exec(html)) !== null && results.length < limit) {
                    const htmlFrag = m[1];
                    const tm = titleRegex.exec(htmlFrag);
                    if (!tm) continue;
                    const sm = snippetRegex.exec(htmlFrag);
                    const url = decodeURIComponent(tm[1].replace(/^\/\/duckduckgo\.com\/l\/\?uddg=/, '').split('&')[0]);
                    if (!url.startsWith('http') || seen.has(url)) continue;
                    seen.add(url);
                    results.push({
                        title: tm[2].replace(/<[^>]*>/g, '').trim() || 'No title',
                        url,
                        snippet: sm ? sm[1].replace(/<[^>]*>/g, '').trim() : '',
                    });
                }
                // Cache only a non-empty result set for the full TTL; a 0-result
                // parse (often a transient block) is returned but NOT pinned for an
                // hour — otherwise one bad parse poisons the query for 60 min.
                return results.length ? cacheReturn({ query: q, count: results.length, results })
                                      : { query: q, count: 0, results, retryable: true };
            } catch (e) {
                return { error: `search failed: ${e.message}`, query: q };
            }
        },
    });

    // ----- fetch_url -------------------------------------------------------
    tools.registerTool({
        name: 'fetch_url',
        build() {
            return null; // consolidated into the `web` tool — hidden from the chat catalog, still registered for automations + the web router
            return {
                type: 'function',
                function: {
                    name: 'fetch_url',
                    description:
                        'Fetch a URL and return its readable text. Rejects private/internal addresses. ' +
                        'Already cascades Scrapling (anti-bot) → Playwright (JS render) → axios internally, so after a fetch_url that returns content there is no point re-fetching the SAME url with playwright_fetch or scrapling_fetch — they hit the same page. ' +
                        'EXCEPTION — image-heavy / dynamic pages: for a social profile or feed, a photo gallery, or a product/listing grid, OR whenever the user asks for the IMAGES and their captions/text from a page, use playwright_fetch instead (it scrolls, renders, and returns each image URL with its alt-text caption and permalink). Plain fetch_url on those returns only page chrome — no images, no post text — so do not keep retrying it or fall through to download_html. ' +
                        'Trust the fetched content over training when they conflict, and cite the URL. ' +
                        'If the result includes a `hint`, follow it: a bot-protection/thin-content hint means retry with scrapling_fetch; a shopping/product-page hint means the price or stock is dynamically gated — switch SOURCE (web_search) instead of re-scraping the same URL. ' +
                        'For long results (>1000 chars) where the user wants a specific fact, follow up with search_string on the returned text.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'Absolute HTTP(S) URL to fetch.' },
                            maxLength: { type: 'integer', minimum: 100, maximum: 100000, description: 'Truncate content to this many chars (default 15000).' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            const maxLength = Math.min(100_000, Math.max(100, parseInt(args?.maxLength || 15000, 10)));
            try {
                const result = await fetchUrlContent(url, { timeout: 20_000, maxLength, waitForJS: true });
                if (!result.success) {
                    return { url, success: false, error: result.error || 'fetch failed' };
                }
                const content = (result.content || '').slice(0, maxLength);
                const title = result.title || '';
                const hint = detectBotChallenge({ title, content }) || productPageHint(content);
                return {
                    url,
                    success: true,
                    title,
                    source: result.source || 'unknown',
                    content,
                    ...(hint ? { hint } : {}),
                };
            } catch (e) {
                return { url, success: false, error: e.message || String(e) };
            }
        },
    });

    // ----- web (consolidated retrieval tool) -------------------------------
    // ONE tool the model sees for everything on the open web: search AND read
    // pages (incl. JS/SPA, dynamic, bot-protected). It is a thin ROUTER — every
    // branch delegates to the existing tool's execute() via toolRegistry, so the
    // behavior is identical and there is zero divergence. The six retrieval tools
    // it routes to (web_search/fetch_url/scrapling_fetch/playwright_fetch/
    // playwright_interact/crawl_pages) stay REGISTERED (automations + executeToolCall
    // dispatch them by name) but are hidden from the chat catalog (build → null).
    tools.registerTool({
        name: 'web',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'web',
                    description:
                        'The single tool for everything on the open web: SEARCH and READ pages (including JavaScript/SPA, dynamic, lazy-loaded, and bot-protected sites). ' +
                        'Pass `query` to search the web (returns up to 5 {title,url,snippet}); pass `url` (or `urls`, up to 3) to read a page\'s readable text. ' +
                        'Reading auto-cascades static fetch → stealth anti-bot → real-browser render, so you do NOT need to pick an engine or re-read the same URL a different way — one call handles Cloudflare / "Just a moment" / CAPTCHA and JS-rendered SPAs. ' +
                        'For an image-heavy or dynamic page (social feed, gallery, product/listing grid), or when you want the pictures with their captions, add want:"images" (real browser, scrolls for lazy media, returns each image URL + alt-caption + permalink alongside the text); want:"links" to also collect links. ' +
                        'For a page that needs interaction first (accept a cookie wall, submit a form, click "load more", scroll for lazy content) use mode:"interact" with an ordered `actions` array. For "top N / most recent N" across a paginated listing use mode:"crawl". ' +
                        'On a search, set read:1-3 to auto-fetch the top results\' full text in the SAME call and skip a follow-up. ' +
                        'Trust fetched/searched content over training when they conflict, and cite the URL(s). If a result carries a `hint` about bot protection or a dynamic price, follow it (the cascade already tried stealth — switch source via a new search rather than re-reading the same URL). Rejects private/internal addresses.',
                    parameters: {
                        type: 'object',
                        properties: {
                            query: { type: 'string', description: 'Search the web (use this OR url/urls).' },
                            url: { type: 'string', description: 'A single page URL to read.' },
                            urls: { type: 'array', items: { type: 'string' }, description: 'Up to 3 page URLs to read in one call.' },
                            mode: { type: 'string', enum: ['auto', 'search', 'read', 'stealth', 'browser', 'interact', 'crawl'], description: 'Default auto (query→search, url→read). stealth/browser force anti-bot/real-browser; interact runs `actions` first; crawl walks pagination.' },
                            want: { type: 'string', enum: ['text', 'images', 'links'], description: 'When reading: text (default), images (with captions), or links.' },
                            actions: { type: 'array', items: { type: 'object' }, description: 'For mode:"interact" — ordered steps (click/type/wait/scroll/waitForNavigation).' },
                            read: { type: 'integer', minimum: 0, maximum: 3, description: 'On a search, also fetch the top N results\' full text (default 0).' },
                            limit: { type: 'integer', minimum: 1, maximum: 10, description: 'Search: max results (default 5).' },
                            maxLength: { type: 'integer', minimum: 100, maximum: 100000, description: 'Read: truncate content (default 15000).' },
                            maxPages: { type: 'integer', minimum: 1, maximum: 20, description: 'crawl: max pages (default 5).' },
                            timeout: { type: 'integer', description: 'Per-request timeout (ms).' },
                        },
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const a = args || {};
            const reg = tools.toolRegistry;
            const run = (name, routedArgs) => {
                const def = reg.get(name);
                if (!def || typeof def.execute !== 'function') return Promise.resolve({ error: `web: inner tool "${name}" unavailable` });
                return def.execute(routedArgs, ctx);
            };
            const mode = a.mode || 'auto';
            const hasUrl = !!(a.url || (Array.isArray(a.urls) && a.urls.length));
            const wantSearch = mode === 'search' || (mode === 'auto' && a.query && !hasUrl);

            // ---- SEARCH ----
            if (wantSearch || (mode === 'auto' && !hasUrl && a.query)) {
                const sr = await run('web_search', { query: a.query, limit: a.limit });
                // Optionally read the top N result URLs in the same call.
                const readN = Math.min(3, Math.max(0, parseInt(a.read || 0, 10)));
                if (readN && sr && Array.isArray(sr.results) && sr.results.length) {
                    const top = sr.results.slice(0, readN);
                    const reads = await Promise.all(top.map(r =>
                        run('fetch_url', { url: r.url, maxLength: 2500 }).catch(() => null)));
                    top.forEach((r, i) => { const c = reads[i] && reads[i].content; if (c) r.content = String(c).slice(0, 2500); });
                }
                return { mode: 'search', ...(sr || {}) };
            }

            // ---- READ (single or batch) ----
            const want = a.want || 'text';
            const readOne = (url) => {
                if (mode === 'stealth') return run('scrapling_fetch', { url, maxLength: a.maxLength, timeout: a.timeout });
                if (mode === 'browser' || want === 'images') return run('playwright_fetch', { url, maxLength: a.maxLength, timeout: a.timeout, waitForJS: true });
                if (want === 'links') return run('playwright_fetch', { url, maxLength: a.maxLength, timeout: a.timeout, waitForJS: true, includeLinks: true });
                return run('fetch_url', { url, maxLength: a.maxLength });
            };
            if (mode === 'interact') {
                if (!a.url) return { error: 'web mode:"interact" requires a url and an actions[] array' };
                return { mode: 'interact', ...(await run('playwright_interact', { url: a.url, actions: a.actions || [], timeout: a.timeout, maxLength: a.maxLength })) };
            }
            if (mode === 'crawl') {
                if (!a.url) return { error: 'web mode:"crawl" requires a url' };
                return { mode: 'crawl', ...(await run('crawl_pages', { url: a.url, maxPages: a.maxPages, maxLength: a.maxLength, timeout: a.timeout })) };
            }
            if (Array.isArray(a.urls) && a.urls.length) {
                const list = a.urls.slice(0, 3);
                const results = await Promise.all(list.map(u => readOne(u).catch(e => ({ url: u, success: false, error: String(e && e.message || e) }))));
                return { mode: 'read', results };
            }
            if (a.url) return { mode: 'read', ...(await readOne(a.url)) };
            return { error: 'web: provide `query` to search or `url`/`urls` to read.' };
        },
    });

    // ----- render_chart ----------------------------------------------------
    // Lets the model emit a structured chart spec that the chat UI renders
    // inline as a real Recharts SVG. The tool itself does no I/O — it just
    // validates the spec and echoes it back inside `chartSpec`. The
    // ToolCallBlock chip in chat/ detects this field and mounts ChartBlock
    // instead of the text preview.
    tools.registerTool({
        name: 'render_chart',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'render_chart',
                    description:
                        'USE WHEN the user asks to visualize data, plot a chart, graph numbers, or display time-series. ' +
                        'Render an inline chart in the chat UI. Use whenever the user asks to graph, plot, chart, or visualize data — either data they provided in the conversation or data you fetched via fetch_timeseries or the `web` tool. ' +
                        'THIS IS THE PREFERRED WAY TO MAKE A CHART — do NOT write Python/matplotlib via run_python and do NOT create_file for a chart. Parse the numbers out of the conversation/log yourself and pass them straight here in `data[]`; this renders an interactive chart inline in one step, whereas run_python+matplotlib is slower, can truncate on large data, and only yields a static image. ' +
                        'Pick the chart type from the data shape: line/area for time series, bar for categorical comparisons, pie for parts-of-a-whole (≤8 slices), scatter for correlations. ' +
                        'For multi-series charts, pass each series as `{ name, color? }` in `series[]` and one `{ x, <seriesName>: y, ... }` object per x-value in `data[]`. For single-series charts, just use `{ x, y }`. ' +
                        'Always include a clear `title` and axis labels — the user reads the chart, not your prose summary.',
                    parameters: {
                        type: 'object',
                        properties: {
                            type: {
                                type: 'string',
                                enum: ['line', 'bar', 'area', 'pie', 'scatter'],
                                description: 'Chart type.',
                            },
                            title: { type: 'string', description: 'Chart title.' },
                            xLabel: { type: 'string', description: 'X-axis label (omit for pie).' },
                            yLabel: { type: 'string', description: 'Y-axis label (omit for pie).' },
                            data: {
                                type: 'array',
                                description:
                                    'Rows of data. Single-series: [{x, y}, ...]. Multi-series: [{x, seriesName1: y1, seriesName2: y2, ...}, ...]. ' +
                                    'Pie: [{label, value}, ...].',
                                items: { type: 'object' },
                            },
                            series: {
                                type: 'array',
                                description: 'Optional explicit series for multi-series charts.',
                                items: {
                                    type: 'object',
                                    properties: {
                                        name: { type: 'string', description: 'Series name — must match a key in each data row.' },
                                        color: { type: 'string', description: 'CSS color (hex / rgb / named). Optional; auto-assigned if omitted.' },
                                    },
                                    required: ['name'],
                                    additionalProperties: false,
                                },
                            },
                            summary: {
                                type: 'string',
                                description: 'One-sentence takeaway shown above the chart (e.g. "S&P 500 rose 18% over the period").',
                            },
                        },
                        required: ['type', 'data'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const type = String(args?.type || '').toLowerCase();
            if (!['line', 'bar', 'area', 'pie', 'scatter'].includes(type)) {
                return { error: `Unsupported chart type "${args?.type}". Use line, bar, area, pie, or scatter.` };
            }
            const data = Array.isArray(args?.data) ? args.data : null;
            if (!data || data.length === 0) {
                return { error: 'data must be a non-empty array of objects.' };
            }
            // Hard cap to keep the tool_result SSE event under the 32 KB
            // serialization cap that gates structured payload shipping.
            const MAX_POINTS = 1000;
            const trimmed = data.length > MAX_POINTS ? data.slice(0, MAX_POINTS) : data;
            const series = Array.isArray(args?.series)
                ? args.series.filter(s => s && typeof s.name === 'string').map(s => ({
                      name: s.name,
                      ...(typeof s.color === 'string' ? { color: s.color } : {}),
                  }))
                : null;
            const chartSpec = {
                type,
                title: typeof args?.title === 'string' ? args.title : '',
                xLabel: typeof args?.xLabel === 'string' ? args.xLabel : '',
                yLabel: typeof args?.yLabel === 'string' ? args.yLabel : '',
                data: trimmed,
                ...(series && series.length > 0 ? { series } : {}),
            };
            return {
                chartSpec,
                summary: typeof args?.summary === 'string' ? args.summary : '',
                pointCount: trimmed.length,
                truncated: data.length > MAX_POINTS,
            };
        },
    });

    // Tracks (conversationId|query) pairs already bounced by the web-search-
    // first gate, so a query is redirected at most once before falling through
    // to the built-in image search (loop-safe). Bounded/cleared in execute.
    const findImageWebFirstSeen = new Map();

    // ----- find_image ------------------------------------------------------
    // Answers "find/show me a picture of X". The model CANNOT reliably guess
    // working image URLs — it hallucinates links that 404 — so it has no good
    // way to satisfy this on its own. Two modes:
    //  • SEARCH: general web image search via DuckDuckGo Images (keyless, finds
    //    ANYTHING incl. games/characters/products/people), with Openverse +
    //    Wikimedia Commons as CC-licensed fallbacks if DDG is rate-limited.
    //  • DISPLAY: pass `urls` the model already found via any other tool
    //    (web_search/fetch_url/etc.) and they're rendered as-is — "search
    //    anywhere, just display it".
    // Either way it returns real, resolvable URLs inside `imageSpec`; the chat
    // UI detects imageSpec on the tool result and renders the photos inline as a
    // thumbnail grid (same lift-onto-the-chip pattern as render_chart), so the
    // user sees the picture without the model having to emit any markdown.
    tools.registerTool({
        name: 'find_image',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'find_image',
                    description:
                        'USE WHEN the user asks to find / show / display / get a picture, photo, image, or "what does X look like". This tool displays images inline in the chat as a thumbnail grid. ' +
                        'PREFERRED FLOW: FIRST use the `web` tool (search the web, or read a page with want:"images") to find real image URLs on relevant pages, THEN call this tool with those URLs in `urls` to display them. The `web` tool sees the live web and finds the most relevant, current images. ' +
                        'Do NOT invent image URLs or write your own markdown image links — they 404. Always route images through this tool; they display automatically from its result. ' +
                        'Pass EVERY image URL you find here even if you suspect the site blocks hotlinking — when a URL will not load directly the tool saves the picture server-side (like "save image as") and embeds the bytes so it still renders. NEVER fall back to printing the image URL as a text link. ' +
                        'You do NOT need direct image URLs: you can pass the PAGE URLs the web search returned (a wallpaper gallery, an Unsplash/Pexels/Pixabay listing, an article — e.g. "https://wallpaperaccess.com/abstract-space-art") and the tool opens each in a real browser and extracts the rendered images itself. So if scraping a page for <img> links fails because it is JavaScript-rendered, do NOT keep trying — just pass the page URL here. ' +
                        'FALLBACK: if you have no URLs yet (you skipped the web search, or it surfaced none), pass a concise VISUAL query — the subject only (e.g. "Bowser castle Super Mario 64", "margherita pizza"), not a full sentence — and this tool runs its own image search (DuckDuckGo Images, keyless, whole web). ' +
                        'Returns 4 images by default; pass count:1 when the user asks for "a"/"one" picture. After it succeeds, briefly say what you found — you do not need to repeat the URLs.',
                    parameters: {
                        type: 'object',
                        properties: {
                            query: { type: 'string', description: 'Fallback only: the visual subject to search for, when you have no `urls`. Optional if `urls` is given.' },
                            count: { type: 'integer', minimum: 1, maximum: 8, description: 'How many images to return (default 4).' },
                            urls: {
                                type: 'array',
                                items: { type: 'string' },
                                description: 'PREFERRED: URLs you found via a web-search tool — EITHER direct image URLs (displayed as-is) OR the web PAGE URLs that contain the images (gallery / listing / article pages), which the tool opens in a real browser and extracts the rendered images from. Mix both freely.',
                            },
                            retryDirect: {
                                type: 'boolean',
                                description: 'Set true ONLY after a web search surfaced no usable image URL, to run the built-in image search as a last resort.',
                            },
                        },
                        required: [],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const query = String(args?.query || '').trim();
            const count = Math.min(8, Math.max(1, parseInt(args?.count || 4, 10)));
            const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36';
            const { execFile } = require('child_process');
            // curl, not axios — see the DDG note below; also used to validate
            // candidate image URLs (axios is fingerprint-blocked by some hosts).
            const curlGet = (url, extra = []) => new Promise((resolve, reject) => {
                execFile('curl', ['-s', '-L', '--max-time', '10', '-A', UA, ...extra, url],
                    { maxBuffer: 8 * 1024 * 1024 },
                    (err, stdout) => (err ? reject(err) : resolve(stdout || '')));
            });
            // Liveness probe: a tiny ranged GET that confirms a URL actually
            // returns an image (2xx/206 + image/* content-type). Models guess
            // image URLs that 404 (a stale m.media-amazon.com poster returns a
            // text/plain CloudFront error, not a picture) and some origins
            // hotlink-block — both render as broken tiles. Dropping them here is
            // the only place we can guarantee the browser gets a live image.
            const probe = (url) => new Promise((resolve) => {
                if (!url || !/^https?:\/\//i.test(url)) return resolve(false);
                execFile('curl', ['-s', '-L', '-o', '/dev/null', '--max-time', '6', '-A', UA,
                    '-w', '%{http_code} %{content_type}', '-r', '0-0', url],
                    { timeout: 8000 },
                    (err, stdout) => {
                        if (err) return resolve(false);
                        const parts = String(stdout || '').trim().split(/\s+/);
                        resolve(/^2\d\d$/.test(parts[0] || '') && /image\//i.test(parts.slice(1).join(' ')));
                    });
            });
            // Like probe but returns the content-type string (''=unknown) so the
            // DISPLAY path can tell a direct image URL from a web PAGE the model
            // passed in (a gallery/article page → hand to Playwright to extract
            // the rendered images from).
            const probeContentType = (url) => new Promise((resolve) => {
                if (!url || !/^https?:\/\//i.test(url)) return resolve('');
                execFile('curl', ['-s', '-L', '-o', '/dev/null', '--max-time', '6', '-A', UA,
                    '-w', '%{content_type}', '-r', '0-0', url],
                    { timeout: 8000 },
                    (err, stdout) => resolve(err ? '' : String(stdout || '').trim().toLowerCase()));
            });
            // The chats are served over HTTPS, so an http:// <img src> is blocked
            // as mixed content (broken-tile icon) even when curl can fetch it —
            // the render URL MUST be https. Most hosts serve the same path over
            // https, so upgrade http→https for the rendered URL.
            const toHttps = (u) => (typeof u === 'string' && /^http:\/\//i.test(u))
                ? u.replace(/^http:\/\//i, 'https://') : u;
            // "Save image as": download the raw bytes server-side. The server has
            // no browser Referer / CSP / mixed-content constraints, so it can pull
            // images a hotlink-blocking origin refuses to serve to an <img> tag.
            // Sends the source PAGE as Referer (what a real "save image as" does)
            // to satisfy referer-gated CDNs.
            const curlBytes = (url, referer) => new Promise((resolve) => {
                if (!url || !/^https?:\/\//i.test(url)) return resolve(null);
                const args = ['-s', '-L', '--max-time', '14', '-A', UA];
                if (referer && /^https?:\/\//i.test(referer)) args.push('-e', referer);
                args.push(url);
                execFile('curl', args, { maxBuffer: 16 * 1024 * 1024, encoding: 'buffer' },
                    (err, stdout) => resolve(err ? null : (stdout && stdout.length ? stdout : null)));
            });
            // Sniff image magic bytes so an HTML error page / JSON saved with an
            // image URL isn't embedded as a fake picture.
            const sniffImageMime = (buf) => {
                if (!buf || buf.length < 12) return null;
                if (buf[0] === 0xFF && buf[1] === 0xD8 && buf[2] === 0xFF) return 'image/jpeg';
                if (buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47) return 'image/png';
                if (buf[0] === 0x47 && buf[1] === 0x49 && buf[2] === 0x46) return 'image/gif';
                if (buf[0] === 0x42 && buf[1] === 0x4D) return 'image/bmp';
                if ((buf[0] === 0x49 && buf[1] === 0x49 && buf[2] === 0x2A) || (buf[0] === 0x4D && buf[1] === 0x4D && buf[2] === 0x00)) return 'image/tiff';
                if (buf.toString('ascii', 0, 4) === 'RIFF' && buf.toString('ascii', 8, 12) === 'WEBP') return 'image/webp';
                if (buf.toString('utf8', 0, 256).trimStart().startsWith('<svg') || buf.toString('utf8', 0, 256).includes('<svg')) return 'image/svg+xml';
                return null;
            };
            const MAX_CAPTURE_BYTES = 8 * 1024 * 1024;   // don't pull huge originals
            const MAX_RAW_EMBED_BYTES = 1.5 * 1024 * 1024; // cap for the no-reencode path
            // Pull the bytes (prefer the full original, fall back to the thumbnail),
            // confirm they're really an image, then downscale/re-encode via Jimp to
            // keep the embedded data URL small. Formats Jimp can't decode (webp/svg)
            // embed raw if under the cap. Returns a data: URL or null.
            const captureAsDataUrl = async (im) => {
                for (const src of [im.url, im.thumbnail]) {
                    if (!src || !/^https?:\/\//i.test(src)) continue;
                    const buf = await curlBytes(src, im.sourceUrl || src);
                    if (!buf || buf.length > MAX_CAPTURE_BYTES) continue;
                    const mime = sniffImageMime(buf);
                    if (!mime) continue; // not an image (HTML 404 / error page)
                    try {
                        const { Jimp } = require('jimp');
                        const image = await Jimp.read(buf);
                        if (image.bitmap.width > 1024) image.resize({ w: 1024 });
                        const out = await image.getBuffer('image/jpeg', { quality: 78 });
                        return `data:image/jpeg;base64,${out.toString('base64')}`;
                    } catch (_) {
                        // Jimp can't decode this format (webp/svg/animated) — embed
                        // the raw bytes if they're small enough; the browser renders
                        // webp/svg data URLs natively.
                        if (buf.length <= MAX_RAW_EMBED_BYTES) {
                            return `data:${mime};base64,${buf.toString('base64')}`;
                        }
                    }
                }
                return null;
            };
            // Keep absolute http(s) entries, then validate each so dead/blocked
            // URLs never reach the UI. Build https render-candidates (thumbnail
            // first — hotlink-safe — then the original), probe each, use the first
            // live one; drop the image if none render. Probe a buffer beyond
            // `count` so a few dead results can be skipped without re-querying.
            // Normalize a URL for duplicate detection: drop protocol, a leading
            // www., the trailing slash, and case. Query strings are KEPT — image
            // CDNs (Bing thumbs, resize endpoints) encode the distinct original
            // in the query, so two different pictures don't collapse to one key.
            const normKey = (u) => (typeof u === 'string'
                ? u.replace(/^https?:\/\//i, '').replace(/^www\./i, '').replace(/\/+$/, '').toLowerCase()
                : '');
            const finalize = async (imgs, source) => {
                // Pass 1: drop exact-duplicate SOURCE urls before probing — the
                // model often lists the same image twice and providers return
                // repeats, so we'd otherwise probe + render the same picture in
                // multiple tiles.
                const seenSrc = new Set();
                const candidates = (imgs || [])
                    .filter(im => im && typeof im.url === 'string' && /^https?:\/\//i.test(im.url))
                    .filter(im => { const k = normKey(im.url); if (!k || seenSrc.has(k)) return false; seenSrc.add(k); return true; })
                    // Probe ~1.5x the needed count (+4 floor for dead-result
                    // tolerance) instead of 3x — every extra candidate pays a
                    // liveness probe + capture; 1.5x amply covers the dead-URL drop
                    // rate while cutting wasted probes/bandwidth and tail latency.
                    .slice(0, Math.max(Math.ceil(count * 1.5), count + 4));
                const vetted = await Promise.all(candidates.map(async (im) => {
                    const renderTries = [];
                    for (const cand of [im.thumbnail, im.url]) {
                        if (cand && /^https?:\/\//i.test(cand)) {
                            const https = toHttps(cand);
                            if (!renderTries.includes(https)) renderTries.push(https);
                        }
                    }
                    for (const t of renderTries) {
                        if (await probe(t)) return { ...im, thumbnail: t, url: toHttps(im.url) };
                    }
                    // No URL hotlinks (404 / 403 / referer-gated / mixed-content).
                    // Rather than drop the picture and leave the model with only a
                    // dead link, "save image as": fetch the bytes server-side and
                    // embed them as a data URL so it still renders inline.
                    const dataUrl = await captureAsDataUrl(im);
                    if (dataUrl) return { ...im, thumbnail: dataUrl, url: toHttps(im.url), captured: true };
                    return null;
                }));
                // Pass 2: dedup on the FINAL render url (the actual <img src>) —
                // two distinct source urls can resolve to the same https
                // thumbnail after the upgrade/fallback, which the user sees as a
                // duplicate tile. For a captured image the thumbnail is a (large)
                // data URL — key it on its source url instead of hashing the bytes.
                const seenRender = new Set();
                const clean = [];
                for (const im of vetted.filter(Boolean)) {
                    const k = (im.thumbnail && !/^data:/i.test(im.thumbnail) ? normKey(im.thumbnail) : '') || normKey(im.url);
                    if (k && seenRender.has(k)) continue;
                    if (k) seenRender.add(k);
                    clean.push(im);
                    if (clean.length >= count) break;
                }
                return clean.length
                    ? { imageSpec: { query, images: clean }, count: clean.length, source }
                    : null;
            };

            // --- Mode DISPLAY: the model already found URLs elsewhere ---------
            // Each provided URL is either a DIRECT image (use as-is) or a web
            // PAGE the model found (a wallpaper gallery / article / Unsplash etc.).
            // For a page we load it in a real browser and read the rendered
            // images out of it — "right click → save image as" — because those
            // sites are JS-rendered and their <img> URLs aren't in the static
            // HTML the model can scrape. Both then flow through finalize (probe →
            // server-side capture) so the picture always renders.
            if (Array.isArray(args?.urls) && args.urls.length) {
                const mk = (u, url, extra = {}) => ({
                    url: String(url),
                    thumbnail: String((u && u.thumbnail) || url),
                    title: String((u && u.title) || query || ''),
                    source: (u && u.source) || extra.source || 'provided',
                    sourceUrl: String((u && (u.sourceUrl || u.page)) || extra.sourceUrl || url),
                    license: (u && u.license) || null,
                    attribution: (u && u.attribution) || null,
                });
                const directImages = [];
                const pageUrls = [];
                const IMG_EXT = /\.(jpe?g|png|gif|webp|bmp|avif|svg|tiff?)(?:[?#]|$)/i;
                for (const u of args.urls) {
                    const url = typeof u === 'string' ? u : (u && u.url);
                    if (!url || !/^https?:\/\//i.test(url)) continue;
                    if (IMG_EXT.test(url)) { directImages.push(mk(u, url)); continue; }
                    // No image extension — could be an extensionless image CDN or a
                    // web page. Ask the server what it actually serves.
                    const ct = await probeContentType(url);
                    if (/^image\//.test(ct)) directImages.push(mk(u, url));
                    else if (!ct || /text\/html|application\/xhtml/.test(ct)) pageUrls.push({ url, meta: u });
                    else directImages.push(mk(u, url)); // unknown non-html → let finalize probe/capture decide
                }

                let images = [...directImages];
                // Extract rendered images from any page URLs via Playwright
                // (bounded — the pool is small). Largest images first.
                if (pageUrls.length && playwrightEnabled && playwrightService && typeof playwrightService.extractPageImages === 'function') {
                    const perPage = Math.max(4, count * 2);
                    const targets = pageUrls.slice(0, 4);
                    // Render the gallery pages in PARALLEL (matches find_video's
                    // page extraction). Concurrency is hard-capped by the Playwright
                    // pool (getBrowser queues, never over-subscribes), and
                    // extractPageImages self-bounds with an internal timeout. Results
                    // are consumed IN ARRAY ORDER so which images survive finalize's
                    // count-slice is identical to the old serial loop.
                    const perPageResults = await Promise.all(targets.map(pg =>
                        playwrightService.extractPageImages(pg.url, { maxResults: perPage })
                            .then(res => ({ pg, res }))
                            .catch(() => ({ pg, res: null }))));   // one bad page can't sink the batch
                    for (const { pg, res } of perPageResults) {
                        if (res && res.success && Array.isArray(res.images)) {
                            for (const im of res.images.slice(0, perPage)) {
                                images.push(mk(pg.meta, im.url, { source: 'page', sourceUrl: pg.url }));
                            }
                        }
                    }
                }

                const out = await finalize(images, pageUrls.length ? 'page-extract' : 'provided');
                if (out) return out;
                // nothing valid provided → fall through to search
            }

            if (!query) return { error: 'Provide a `query` to search for, or `urls` to display.' };

            // --- Web-search-first gate ---------------------------------------
            // User preference: the model should source images via the web-search
            // tools FIRST, then feed the URLs here for display. A tool
            // description alone did not reliably move a local model off calling
            // find_image directly, so this is a RUNTIME gate: a plain query-only
            // call (no urls, no explicit retryDirect) is bounced back ONCE with
            // instructions to web_search first. Loop-safe and never dead-ends —
            // the SAME (conversation, query) seen again, or an explicit
            // retryDirect, falls through to the built-in image search, so if the
            // web search surfaces nothing the user still gets pictures.
            const noUrlsProvided = !(Array.isArray(args?.urls) && args.urls.length);
            if (noUrlsProvided && !args?.retryDirect) {
                const gateKey = `${(ctx && ctx.conversationId) || 'global'}|${query.toLowerCase()}`;
                if (!findImageWebFirstSeen.has(gateKey)) {
                    if (findImageWebFirstSeen.size > 1000) findImageWebFirstSeen.clear();
                    findImageWebFirstSeen.set(gateKey, 1);
                    return {
                        needsWebSearch: true,
                        query,
                        instruction: `Do NOT display images from the built-in search yet. FIRST use the \`web\` tool (search the web, or read a page with want:"images") to find real image URLs for "${query}" on relevant pages, then call find_image again with those URLs in \`urls\` to display them. ONLY if the web search surfaces no usable image URL, call find_image again with query:"${query}" and retryDirect:true.`,
                    };
                }
                // already redirected once for this query → proceed to built-in search
            }

            // --- Mode SEARCH, primary: DuckDuckGo Images (whole web, keyless) ---
            // Two-step: scrape a vqd token from the search page, then hit i.js.
            // NB: this MUST go through curl, not axios — DDG fingerprints Node's
            // TLS/HTTP stack and 403s axios on i.js (every header combo, incl.
            // UA-only) while curl (browser-like fingerprint) gets 200. curl ships
            // in the webapp image. URL is passed as a single execFile arg (no
            // shell), query URL-encoded, so there's no injection surface.
            // Thumbnails come from Bing's CDN (hotlink-safe) — prefer them for
            // display so a hotlink-blocking origin can't break the inline render.
            try {
                const enc = encodeURIComponent(query);
                // SafeSearch is disabled on both the page request (kp=-1) and the
                // i.js call (p=-1) so the search is unfiltered — no content
                // restrictions. (DDG: kp/p = 1 strict, -2 moderate, -1 off.)
                const page = await curlGet(`https://duckduckgo.com/?q=${enc}&iar=images&iax=images&ia=images&kp=-1`);
                const m = String(page).match(/vqd="?([\d-]+)"?/);
                if (m && m[1]) {
                    const body = await curlGet(
                        `https://duckduckgo.com/i.js?l=us-en&o=json&q=${enc}&vqd=${encodeURIComponent(m[1])}&f=,,,,,&p=-1`,
                        ['-H', 'Referer: https://duckduckgo.com/', '-H', 'Cookie: p=-1'],
                    );
                    let parsed = null;
                    try { parsed = JSON.parse(body); } catch (_) { /* not JSON → fall through */ }
                    const rows = Array.isArray(parsed?.results) ? parsed.results : [];
                    const images = rows.map(r => ({
                        url: r.image,
                        thumbnail: r.thumbnail || r.image,
                        title: r.title || query,
                        source: r.source ? String(r.source).toLowerCase() : 'web',
                        sourceUrl: r.url || r.image,
                        license: null,
                        attribution: null,
                        width: r.width || null,
                        height: r.height || null,
                    }));
                    const out = await finalize(images, 'duckduckgo');
                    if (out) return out;
                }
            } catch (_) { /* fall through to Openverse */ }

            // --- Fallback 1: Openverse (CC-licensed aggregator; mature included, no filtering) ---
            try {
                const resp = await axios.get('https://api.openverse.org/v1/images/', {
                    params: { q: query, page_size: count, mature: true },
                    headers: { 'User-Agent': UA, Accept: 'application/json' },
                    timeout: 10000,
                });
                const rows = Array.isArray(resp.data?.results) ? resp.data.results : [];
                const out = await finalize(rows.map(r => ({
                    url: r.url,
                    thumbnail: r.thumbnail || r.url,
                    title: r.title || query,
                    source: r.source || r.provider || 'openverse',
                    sourceUrl: r.foreign_landing_url || r.url,
                    license: [r.license, r.license_version].filter(Boolean).join(' ').toUpperCase() || null,
                    attribution: r.attribution || (r.creator ? `by ${r.creator}` : null),
                    width: r.width || null,
                    height: r.height || null,
                })), 'openverse');
                if (out) return out;
            } catch (_) { /* fall through to Wikimedia */ }

            // --- Fallback 2: Wikimedia Commons ---
            try {
                const resp = await axios.get('https://commons.wikimedia.org/w/api.php', {
                    params: {
                        action: 'query', format: 'json', generator: 'search',
                        gsrsearch: `filetype:bitmap ${query}`, gsrnamespace: 6, gsrlimit: count,
                        prop: 'imageinfo', iiprop: 'url|size|extmetadata', iiurlwidth: 640,
                    },
                    headers: { 'User-Agent': UA, Accept: 'application/json' },
                    timeout: 10000,
                });
                const pages = resp.data?.query?.pages ? Object.values(resp.data.query.pages) : [];
                const out = await finalize(pages.map(p => {
                    const ii = Array.isArray(p.imageinfo) ? p.imageinfo[0] : null;
                    if (!ii) return null;
                    const meta = ii.extmetadata || {};
                    const artist = meta.Artist?.value ? String(meta.Artist.value).replace(/<[^>]*>/g, '').trim() : null;
                    return {
                        url: ii.url,
                        thumbnail: ii.thumburl || ii.url,
                        title: String(p.title || query).replace(/^File:/, '').replace(/\.[a-z0-9]+$/i, ''),
                        source: 'wikimedia commons',
                        sourceUrl: ii.descriptionurl || ii.url,
                        license: meta.LicenseShortName?.value || null,
                        attribution: artist || null,
                        width: ii.width || null,
                        height: ii.height || null,
                    };
                }).filter(Boolean), 'wikimedia');
                if (out) return out;
            } catch (_) { /* fall through to error */ }

            return {
                error: `No images found for "${query}" via the built-in image search.`,
                query,
                hint: 'Try a simpler, more visual query (the subject only). If it still finds nothing, use the `web` tool (search the web, or read a page with want:"images") to locate a real image URL on a relevant page, then call find_image again with that URL in `urls` to display it.',
            };
        },
    });

    // Tracks (conversationId|query) pairs already bounced once by find_video's
    // web-search-first gate, so a query-only call is nudged to web_search just
    // once instead of looping (mirrors findImageWebFirstSeen).
    const findVideoWebFirstSeen = new Map();

    // ----- find_video ------------------------------------------------------
    // Answers "find/show/play me a video of X". The MODEL drives discovery:
    // it web_searches (and, if needed, fetch_url/scrapling/playwright) to find
    // the video, then passes the URLs it found to this tool. find_video does
    // NOT run its own search — it is a URL→player EXTRACTOR + renderer:
    //  • A clean watch/file URL (YouTube/Vimeo/Dailymotion watch page, or a
    //    direct .mp4/.webm) is turned into an inline player as-is.
    //  • ANY other page (a news article, blog, etc. that embeds a video) is
    //    fetched server-side (SSRF-guarded) and the real video is scraped out
    //    of it — og:video / twitter:player meta, provider <iframe> embeds,
    //    <video>/<source> tags, or a direct .mp4/.webm in the markup.
    // It returns a `videoSpec` the chat UI renders inline (same lift-onto-the-
    // chip pattern as render_chart/find_image). A query-only call (no URLs) is
    // bounced once to web_search, since the model owns discovery.
    tools.registerTool({
        name: 'find_video',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'find_video',
                    description:
                        'USE WHEN the user asks to find / show / display / get / play a video, clip, trailer, or "show me footage of X". It displays videos inline in the chat as click-to-play players. ' +
                        'HOW IT WORKS: YOU find the video, this tool displays it. The normal flow is: (1) use the `web` tool (search) for the topic to find pages/URLs that have the video; (2) call find_video with those URLs in `urls`. find_video then EXTRACTS the playable video from each URL and renders it inline — pass a YouTube/Vimeo/Dailymotion watch link OR a direct .mp4/.webm OR even an ordinary article/page that contains a video (the tool pulls the embedded video out of the page for you). ' +
                        'If a page loads its video via JavaScript, find_video automatically inspects the page network traffic in a real browser to recover the stream (HLS .m3u8 / DASH .mpd / a dynamically-loaded .mp4) — so passing the page URL usually just works, and a .m3u8 plays via the built-in HLS player. If it still reports it could not extract one, call sniff_media_streams on that page to list every streaming URL, then pass the best one back here. ' +
                        'Do NOT invent video URLs — only pass URLs you actually found via a tool. If you call this with just a `query` and no `urls`, it will tell you to web_search first. Do not write your own markdown/HTML video links; route everything through this tool so it displays automatically. ' +
                        'Shows up to ~6 videos (whatever you pass, capped); pass count:1 when the user asks for "a"/"one" video. After it succeeds, briefly say what you found — you do not need to repeat the URLs.',
                    parameters: {
                        type: 'object',
                        properties: {
                            urls: {
                                type: 'array',
                                items: { type: 'string' },
                                description: 'The video/page URLs you found via web_search (or fetch_url/scrapling/playwright): watch pages (YouTube/Vimeo/Dailymotion/…), direct .mp4/.webm files, OR ordinary pages that embed a video. The tool extracts the playable video from each and displays it. This is the main input.',
                            },
                            query: { type: 'string', description: 'What the user wants a video of (the subject only). Used to label results; if given WITHOUT `urls`, the tool tells you to web_search first.' },
                            count: { type: 'integer', minimum: 1, maximum: 6, description: 'Max videos to show (default: as many as you pass, capped at 6). Pass 1 for "a"/"one" video.' },
                        },
                        required: [],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const query = String(args?.query || '').trim();
            const count = Math.min(6, Math.max(1, parseInt(args?.count || 3, 10)));
            const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36';
            const { execFile } = require('child_process');
            // Liveness probe: a tiny ranged GET confirming a URL serves the
            // expected content-type (2xx/206 + image/* for poster thumbnails,
            // video/* for direct media files). Embeds are trusted (the iframe
            // provider serves its own poster), so they're not probed.
            const probeType = (url, typeRe) => new Promise((resolve) => {
                if (!url || !/^https?:\/\//i.test(url)) return resolve(false);
                execFile('curl', ['-s', '-L', '-o', '/dev/null', '--max-time', '6', '-A', UA,
                    '-w', '%{http_code} %{content_type}', '-r', '0-0', url],
                    { timeout: 8000 },
                    (err, stdout) => {
                        if (err) return resolve(false);
                        const parts = String(stdout || '').trim().split(/\s+/);
                        resolve(/^2\d\d$/.test(parts[0] || '') && typeRe.test(parts.slice(1).join(' ')));
                    });
            });
            const probeImage = (u) => probeType(u, /image\//i);
            const probeVideo = (u) => probeType(u, /video\//i);
            // The chats are HTTPS — an http:// embed/poster/media src is blocked
            // as mixed content even when reachable. Upgrade http→https.
            const toHttps = (u) => (typeof u === 'string' && /^http:\/\//i.test(u))
                ? u.replace(/^http:\/\//i, 'https://') : u;
            // Derive an embeddable player URL + poster from a watch/page URL so a
            // bare YouTube/Vimeo link the model passes still plays inline.
            const ytId = (u) => {
                const m = String(u || '').match(/(?:youtube\.com\/(?:watch\?(?:.*&)?v=|embed\/|shorts\/|v\/|live\/)|youtu\.be\/)([A-Za-z0-9_-]{11})/i);
                return m ? m[1] : null;
            };
            const vimeoId = (u) => { const m = String(u || '').match(/vimeo\.com\/(?:video\/)?(\d+)/i); return m ? m[1] : null; };
            const dmId = (u) => { const m = String(u || '').match(/(?:dailymotion\.com\/(?:video|embed\/video)\/|dai\.ly\/)([A-Za-z0-9]+)/i); return m ? m[1] : null; };
            const isDirectVideo = (u) => /\.(mp4|webm|ogg|ogv|mov|m4v|mkv|avi|3gp|3g2|mpeg|mpg|m2ts|ts|flv|wmv)(?:[?#]|$)/i.test(String(u || ''));
            // HLS (.m3u8) / DASH (.mpd) adaptive-stream manifests — the format JS
            // players actually load. The client plays HLS via the bundled hls.js
            // (native on Safari); the videoSpec carries streamType so the frontend
            // knows to wire it up rather than drop it into a bare <video src>.
            const isStreamManifest = (u) => /\.(m3u8|mpd)(?:[?#]|$)/i.test(String(u || ''));
            const streamKindOf = (u) => /\.m3u8(?:[?#]|$)/i.test(String(u || '')) ? 'hls'
                : (/\.mpd(?:[?#]|$)/i.test(String(u || '')) ? 'dash' : null);
            // Generic reachability probe (any 2xx/3xx). A manifest is a tiny text
            // file served as application/vnd.apple.mpegurl / dash+xml / text /
            // octet-stream — NOT video/* — so probeVideo would wrongly reject it.
            const probeReachable = (url) => new Promise((resolve) => {
                if (!url || !/^https?:\/\//i.test(url)) return resolve(false);
                execFile('curl', ['-s', '-L', '-o', '/dev/null', '--max-time', '6', '-A', UA,
                    '-w', '%{http_code}', '-r', '0-0', url], { timeout: 8000 },
                    (err, stdout) => { if (err) return resolve(false); resolve(/^[23]\d\d$/.test(String(stdout || '').trim())); });
            });
            // Provider tag for a result URL — used to diversify the result mix.
            const providerOf = (u) => {
                const s = String(u || '').toLowerCase();
                if (/youtube\.com|youtu\.be/.test(s)) return 'youtube';
                if (/vimeo\.com/.test(s)) return 'vimeo';
                if (/dailymotion\.com|dai\.ly/.test(s)) return 'dailymotion';
                try { return new URL(s).hostname.replace(/^www\./, ''); } catch (_) { return 'web'; }
            };
            const deriveEmbed = (u) => {
                const y = ytId(u);
                if (y) return { embedUrl: `https://www.youtube-nocookie.com/embed/${y}`, thumbnail: `https://i.ytimg.com/vi/${y}/hqdefault.jpg`, source: 'youtube' };
                const v = vimeoId(u);
                if (v) return { embedUrl: `https://player.vimeo.com/video/${v}`, thumbnail: null, source: 'vimeo' };
                const d = dmId(u);
                // Dailymotion's real embeddable player is the geo host; the older
                // www.dailymotion.com/embed/video/<id> form 301-redirects there
                // (an extra round-trip and host-pinned-CSP footgun), so emit geo
                // directly. frame-src is https: so the geo host is allowed.
                if (d) return { embedUrl: `https://geo.dailymotion.com/player.html?video=${d}`, thumbnail: null, source: 'dailymotion' };
                return null;
            };
            // Cap any single async extraction so one slow/hung page can't stall
            // the whole parallel batch; on timeout it contributes nothing. The
            // pending timer is cleared once the race settles so a fast extraction
            // doesn't leave an unreferenced timer hanging.
            const withTimeout = (p, ms, fallback) => {
                let t;
                const timer = new Promise((res) => { t = setTimeout(() => res(fallback), ms); });
                return Promise.race([Promise.resolve(p).catch(() => fallback), timer])
                    .finally(() => clearTimeout(t));
            };
            // Stable per-video identity, used to drop exact duplicates while
            // PRESERVING the order the model passed its URLs in.
            const dedupKey = (v) => {
                const e = String((v && v.embedUrl) || ''), u = String((v && (v.url || v.sourceUrl)) || '');
                const y = ytId(e) || ytId(u); if (y) return 'yt:' + y;
                const vi = vimeoId(e) || vimeoId(u); if (vi) return 'vi:' + vi;
                const dm = (e.match(/[?&]video=([A-Za-z0-9]+)/) || [])[1] || dmId(u); if (dm) return 'dm:' + dm;
                return (e || String((v && v.videoUrl) || '') || u).toLowerCase();
            };
            // Validate candidates: a video must be playable (an embed, or a direct
            // file that probes as video/* — but trust a known video extension even
            // when the host sends a generic content-type so less-common formats
            // still reach <video>). Poster thumbnails are probed unless trustThumb
            // (the client also falls back to a gradient via <img onError>).
            const finalize = async (vids, source, lim = count) => {
                const candidates = (vids || [])
                    .filter(v => v && (v.embedUrl || v.videoUrl))
                    // ~1.5x margin (+4 floor) instead of 3x — same dead-result
                    // tolerance, fewer wasted ranged probes (see find_image).
                    .slice(0, Math.max(Math.ceil(lim * 1.5), lim + 4));
                const vetted = await Promise.all(candidates.map(async (v) => {
                    const embedUrl = v.embedUrl ? toHttps(v.embedUrl) : null;
                    let videoUrl = v.videoUrl ? toHttps(v.videoUrl) : null;
                    // A direct file must serve video bytes. For files SCRAPED
                    // heuristically (mustProbe — a <video>/<source> src or a bare
                    // .mp4/.webm in the markup, which can be a decorative asset)
                    // the probe is authoritative. For a file the model or an
                    // og:video tag explicitly declared, a known video extension is
                    // trusted even when the ranged probe is flaky.
                    // Run the video + thumbnail probes CONCURRENTLY (the direct-file
                    // branch otherwise did them serially). Trust logic is byte-for-
                    // byte the original, applied to the resolved booleans.
                    const streamy = videoUrl && (v.streamType || isStreamManifest(videoUrl));
                    const vidP = (!embedUrl && videoUrl)
                        ? (streamy ? probeReachable(videoUrl) : probeVideo(videoUrl))
                        : null;
                    const httpsThumb = (v.thumbnail && !v.trustThumb) ? toHttps(v.thumbnail) : null;
                    const thumbP = httpsThumb ? probeImage(httpsThumb) : null;
                    const [vidOk, thumbOk] = await Promise.all([vidP, thumbP]);
                    if (!embedUrl && videoUrl) {
                        if (streamy) {
                            // HLS/DASH manifest — liveness is "does it load", not
                            // "is it video/*". The client plays it via hls.js.
                            if (!vidOk) videoUrl = null;
                        } else {
                            if (!vidOk && (v.mustProbe || !isDirectVideo(videoUrl))) videoUrl = null;
                        }
                    }
                    if (!embedUrl && !videoUrl) return null;
                    let thumbnail = v.thumbnail ? toHttps(v.thumbnail) : null;
                    if (thumbnail && !v.trustThumb && thumbOk === false) thumbnail = null;   // === false: a non-probed (null) thumb never gets nulled
                    return { ...v, embedUrl, videoUrl, thumbnail, url: toHttps(v.url || v.sourceUrl || '') };
                }));
                const clean = vetted.filter(Boolean).slice(0, lim);
                return clean.length
                    ? { videoSpec: { query, videos: clean }, count: clean.length, source }
                    : null;
            };

            // Decode the handful of HTML entities that show up in meta/title text.
            const decodeEntities = (s) => String(s || '')
                .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
                .replace(/&quot;/g, '"').replace(/&#0?39;|&apos;/gi, "'").replace(/&#x2f;/gi, '/');
            const absolutize = (u, base) => {
                if (!u) return null;
                if (u.startsWith('//')) return 'https:' + u;
                try { return new URL(u, base).href; } catch (_) { return /^https?:\/\//i.test(u) ? u : null; }
            };
            // Pull a playable video out of ANY URL the model found via web_search.
            // A clean watch/file URL is used directly; otherwise the page HTML is
            // fetched (SSRF-guarded) and scraped, in priority order, for:
            //   og:video / twitter:player → provider <iframe> embeds →
            //   <video>/<source> tags → any direct .mp4/.webm in the markup.
            const extractVideoFromPage = async (rawUrl) => {
                const pageUrl = toHttps(String(rawUrl || '').trim());
                if (!/^https?:\/\//i.test(pageUrl)) return null;
                // Fast path: it's already a watch/file URL — no fetch needed.
                const direct = deriveEmbed(pageUrl);
                if (direct) return { ...direct, url: pageUrl, sourceUrl: pageUrl };
                if (isDirectVideo(pageUrl)) return { videoUrl: pageUrl, url: pageUrl, sourceUrl: pageUrl, source: providerOf(pageUrl) };
                if (isStreamManifest(pageUrl)) return { videoUrl: pageUrl, streamType: streamKindOf(pageUrl), url: pageUrl, sourceUrl: pageUrl, source: providerOf(pageUrl) };
                // SSRF guard before fetching a model-supplied URL.
                if (isPrivateUrl(pageUrl)) return null;
                let html = '';
                try {
                    const resp = await axios.get(pageUrl, {
                        headers: { 'User-Agent': UA, Accept: 'text/html,application/xhtml+xml' },
                        timeout: 12000, maxRedirects: 5, responseType: 'text',
                        maxContentLength: 6 * 1024 * 1024,
                        validateStatus: (s) => s >= 200 && s < 400,
                    });
                    html = typeof resp.data === 'string' ? resp.data : '';
                } catch (_) { return null; }
                if (!html) return null;
                const metaContent = (key) => {
                    const re1 = new RegExp(`<meta[^>]+(?:property|name)=["']${key}["'][^>]*\\scontent=["']([^"']*)["']`, 'i');
                    const re2 = new RegExp(`<meta[^>]+content=["']([^"']*)["'][^>]*(?:property|name)=["']${key}["']`, 'i');
                    const m = html.match(re1) || html.match(re2);
                    return m ? decodeEntities(m[1]) : null;
                };
                const host = providerOf(pageUrl);
                const title = metaContent('og:title') || metaContent('twitter:title') ||
                    decodeEntities((html.match(/<title[^>]*>([^<]*)<\/title>/i) || [])[1] || '') || query || '';
                const thumb = absolutize(metaContent('og:image') || metaContent('og:image:url') ||
                    metaContent('twitter:image') || metaContent('twitter:image:src'), pageUrl);
                const fromUrl = (u) => {
                    const abs = absolutize(u, pageUrl);
                    if (!abs) return null;
                    const e = deriveEmbed(abs); if (e) return { ...e };
                    if (isDirectVideo(abs)) return { videoUrl: abs, source: host };
                    if (isStreamManifest(abs)) return { videoUrl: abs, streamType: streamKindOf(abs), source: host };
                    return null;
                };
                // 1) Open Graph / Twitter player video.
                let d = fromUrl(metaContent('og:video:secure_url')) || fromUrl(metaContent('og:video:url')) ||
                    fromUrl(metaContent('og:video')) || fromUrl(metaContent('twitter:player:stream')) ||
                    fromUrl(metaContent('twitter:player'));
                // 2) Provider <iframe> embeds in the body.
                if (!d) {
                    for (const m of html.matchAll(/<iframe[^>]+src=["']([^"']+)["']/ig)) {
                        const e = deriveEmbed(absolutize(m[1], pageUrl) || '');
                        if (e) { d = e; break; }
                    }
                }
                // 3) <video src> / <source src=…mp4|webm>. Heuristic → mustProbe.
                if (!d) {
                    const vs = html.match(/<video[^>]*\ssrc=["']([^"']+)["']/i) ||
                        html.match(/<source[^>]+src=["']([^"']+\.(?:mp4|webm|ogg|ogv|m4v|mov)[^"']*)["']/i);
                    if (vs) { const u = absolutize(vs[1], pageUrl); if (u) d = { videoUrl: u, source: host, mustProbe: true }; }
                }
                // 4) Last resort: a direct .mp4/.webm in the markup — but skip
                // decorative/asset files (favicons, sprites, logos, loaders) that
                // aren't real content, and force a content-type probe (mustProbe).
                if (!d) {
                    const ASSET = /favicon|sprite|\/icons?\/|logo|placeholder|loading|spinner|site\.webm/i;
                    for (const m of html.matchAll(/https?:\/\/[^"'\s<>\\]+\.(?:mp4|webm)(?:\?[^"'\s<>\\]*)?/ig)) {
                        if (ASSET.test(m[0])) continue;
                        d = { videoUrl: m[0], source: host, mustProbe: true };
                        break;
                    }
                }
                // 5) An HLS/DASH manifest embedded in inline player config / JSON.
                // Many sites never put the stream in a <video> tag — it's a string
                // in a <script>. JSON escapes slashes (https:\/\/…), so unescape a
                // working copy first (guarded so the 6MB replace only runs when a
                // manifest token is actually present).
                if (!d && (html.indexOf('.m3u8') >= 0 || html.indexOf('.mpd') >= 0)) {
                    const hay = html.replace(/\\\//g, '/');
                    const mm = hay.match(/https?:\/\/[^"'\s<>\\]+?\.m3u8(?:\?[^"'\s<>\\]*)?/i) ||
                        hay.match(/https?:\/\/[^"'\s<>\\]+?\.mpd(?:\?[^"'\s<>\\]*)?/i);
                    if (mm && !/favicon|sprite|logo|placeholder|loading|spinner|advert|\/ads?\//i.test(mm[0])) {
                        d = { videoUrl: mm[0], streamType: streamKindOf(mm[0]), source: host };
                    }
                }
                if (!d) return null;
                return {
                    url: pageUrl,
                    embedUrl: d.embedUrl || null,
                    videoUrl: d.videoUrl || null,
                    streamType: d.streamType || null,
                    thumbnail: d.thumbnail || thumb || null,
                    title: title || '',
                    duration: null,
                    source: d.source || host,
                    sourceUrl: pageUrl,
                    mustProbe: d.mustProbe || false,
                };
            };

            // Network-inspection fallback: when the static scrape above finds
            // nothing, load the page in a REAL browser and watch its network
            // traffic for the stream URL (HLS .m3u8 / DASH .mpd / a JS-fetched
            // .mp4) that the player requests but never writes into the page HTML.
            // Same candidate shape as extractVideoFromPage (or null). Heavy
            // (Playwright pool of 3), so the caller bounds how many it runs.
            const sniffVideoFromPage = async (rawUrl) => {
                if (!playwrightEnabled || !playwrightService || typeof playwrightService.sniffMediaStreams !== 'function') return null;
                const pageUrl = toHttps(String(rawUrl || '').trim());
                if (!/^https?:\/\//i.test(pageUrl) || isPrivateUrl(pageUrl)) return null;
                let res;
                try {
                    res = await playwrightService.sniffMediaStreams(pageUrl, { interact: true, timeout: 18000, settleMs: 2500, captureMs: 4500, maxResults: 12, earlyExit: true });
                } catch (_) { return null; }
                if (!res || !res.success) return null;
                const media = Array.isArray(res.media) ? res.media : [];
                // Best playable stream: HLS manifest → direct file → DASH manifest.
                const pick = media.find((m) => m.kind === 'hls') ||
                    media.find((m) => m.kind === 'file') ||
                    media.find((m) => m.kind === 'dash');
                if (pick) {
                    return {
                        url: pageUrl,
                        embedUrl: null,
                        videoUrl: pick.url,
                        streamType: pick.kind === 'file' ? null : pick.kind,
                        thumbnail: null,
                        title: res.title || query || '',
                        duration: null,
                        source: providerOf(res.finalUrl || pageUrl),
                        sourceUrl: pageUrl,
                        mustProbe: false,
                    };
                }
                // No raw stream — recover a JS-injected provider <iframe> embed
                // (YouTube/Vimeo/etc.) the sniffer pulled from the rendered DOM.
                for (const e of (Array.isArray(res.embeds) ? res.embeds : [])) {
                    const d = deriveEmbed(toHttps(String(e || '')));
                    if (d) {
                        return {
                            url: pageUrl,
                            embedUrl: d.embedUrl || null,
                            videoUrl: d.videoUrl || null,
                            streamType: d.streamType || null,
                            thumbnail: d.thumbnail || null,
                            title: res.title || query || '',
                            duration: null,
                            source: d.source || providerOf(res.finalUrl || pageUrl),
                            sourceUrl: pageUrl,
                            mustProbe: false,
                        };
                    }
                }
                return null;
            };

            // --- Primary: display the videos the model found via web search ---
            // find_video runs NO search of its own — the model discovers videos
            // (web_search, then optionally fetch_url/scrapling/playwright) and
            // hands the URLs here. Each URL becomes a playable video: a clean
            // watch/file URL plays directly; any other page is fetched and the
            // embedded video scraped out of it (og:video/<video>/provider iframe/
            // direct file). If the static scrape comes up empty for a page, the
            // page's network traffic is inspected to recover JS-loaded streams.
            // The model's order is preserved (exact dupes dropped).
            if (Array.isArray(args?.urls) && args.urls.length) {
                const inputUrls = args.urls
                    .map((u) => (typeof u === 'string' ? u : (u && (u.url || u.content || u.href))))
                    .filter((u) => typeof u === 'string' && u.trim())
                    .slice(0, 12);
                const extracted = await Promise.all(
                    inputUrls.map((u) => withTimeout(extractVideoFromPage(u), 14000, null)),
                );
                // For pages the static pass missed, inspect the network (bounded:
                // Playwright is heavy and serialises behind a pool of 3).
                const results = inputUrls.map((u, i) => extracted[i]);
                if (playwrightEnabled && playwrightService) {
                    const missIdx = results.map((v, i) => (v ? -1 : i)).filter((i) => i >= 0);
                    const targets = missIdx.slice(0, 4);
                    if (targets.length) {
                        const sniffed = await Promise.all(
                            targets.map((i) => withTimeout(sniffVideoFromPage(inputUrls[i]), 30000, null)),
                        );
                        targets.forEach((idx, k) => { if (sniffed[k]) results[idx] = sniffed[k]; });
                    }
                }
                const videos = results.filter(Boolean).map((v) => ({ ...v, title: v.title || query || '' }));
                const seen = new Set();
                const ordered = videos.filter((v) => { const k = dedupKey(v); if (seen.has(k)) return false; seen.add(k); return true; });
                const lim = Math.min(6, Math.max(count, ordered.length));
                const out = await finalize(ordered, 'extracted', lim);
                if (out) return out;
                return {
                    error: 'Could not extract a playable video from the provided URL(s).',
                    query: query || null,
                    hint: 'Pass the actual video page or file — a YouTube/Vimeo/Dailymotion watch link, or a direct .mp4/.webm. If a page loads its video via JavaScript, fetch it first with playwright_fetch (it renders the page and lists the playable video URLs under a "Videos:" heading — embeds, <video> files, og:video) or sniff_media_streams (for HLS/DASH stream URLs), then pass those URLs in `urls`.',
                };
            }

            // --- No URLs yet: the model owns discovery → send it to web_search --
            if (!query) return { error: 'Provide `urls` (video/page URLs you found) to display, or a `query` describing what to look for.' };
            const gateKey = `${(ctx && ctx.conversationId) || 'global'}|${query.toLowerCase()}`;
            if (!findVideoWebFirstSeen.has(gateKey)) {
                if (findVideoWebFirstSeen.size > 1000) findVideoWebFirstSeen.clear();
                findVideoWebFirstSeen.set(gateKey, 1);
                return {
                    needsWebSearch: true,
                    query,
                    instruction: `find_video does not search on its own — YOU find the video. FIRST use the \`web\` tool to search for "${query}" (add a word like "video", "trailer", or "clip", or the platform, if it helps). Collect the resulting URLs: watch pages (YouTube/Vimeo/Dailymotion/etc.) AND ordinary pages/articles that contain a video both work — find_video will pull the embedded video out of a page for you. If a page's video is JavaScript-loaded and find_video cannot extract it, read the page with the \`web\` tool using want:"links" — it renders the page and lists the playable video URLs under a "Videos:" heading (provider embeds, <video> files, og:video) — or use sniff_media_streams for HLS/DASH stream URLs, then pass those. Then call find_video again with the URLs in \`urls\` to display them inline.`,
                };
            }
            return {
                error: `No videos to display for "${query}".`,
                query,
                hint: 'web_search for the topic, then call find_video again with the video/page URLs in `urls`.',
            };
        },
    });

    // ----- sniff_media_streams ---------------------------------------------
    // Network inspector — the "see the networking of a website" capability.
    // Opens a page in a real browser, presses play, and watches its network
    // traffic to surface the actual streaming URLs that JS video players fetch
    // (HLS .m3u8 / DASH .mpd / a dynamically-loaded .mp4) but never write into
    // the page HTML — i.e. what a human opening DevTools → Network would read
    // off. Pairs with find_video to display one inline (find_video also runs
    // this automatically as a fallback; this explicit tool is for when the
    // model wants the full list or to pick a specific stream). Hidden when
    // Playwright is unavailable (build() returns null).
    tools.registerTool({
        name: 'sniff_media_streams',
        build() {
            if (!playwrightEnabled || !playwrightService || typeof playwrightService.sniffMediaStreams !== 'function') return null;
            return {
                type: 'function',
                function: {
                    name: 'sniff_media_streams',
                    description:
                        'USE WHEN a web page plays a video/audio stream but the link is NOT in the page HTML — modern players (live TV, sports, embedded players, many news/streaming sites) load the real media over the network as an HLS playlist (.m3u8), a DASH manifest (.mpd), or a dynamically-fetched .mp4. ' +
                        'This opens the page in a REAL browser, presses play, and watches the NETWORK TRAFFIC to capture those streaming URLs for you (it does what a human opening DevTools → Network would do). ' +
                        'It returns the media URLs it observed (manifests first, then direct files). To DISPLAY one inline in the chat, pass it to find_video in `urls` — a .m3u8 plays via the built-in HLS player. ' +
                        'Reach for this when find_video could not extract a video from a page, or when the user explicitly wants the underlying stream link. Give it the actual watch/player page (not a search-results page). One page per call; rejects private addresses.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'The page URL to inspect (the watch/player page). The tool loads it, plays it, and reports the streaming URLs requested over the network.' },
                            interact: { type: 'boolean', description: 'Press play / click the player to trigger lazy-loaded streams (default true). Set false to only capture what loads automatically.' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            if (!playwrightEnabled || !playwrightService || typeof playwrightService.sniffMediaStreams !== 'function') {
                return { success: false, error: 'Network inspection (Playwright) is not available on this host. Fall back to scrapling_fetch/playwright_fetch and look for an og:video or .m3u8 in the page.' };
            }
            const interact = args?.interact !== false;
            try {
                const res = await playwrightService.sniffMediaStreams(url, { interact, timeout: 22000, settleMs: 3500, captureMs: 6500, maxResults: 25 });
                const media = Array.isArray(res?.media) ? res.media : [];
                const streams = media.map((m) => ({ url: m.url, type: m.kind, ...(m.contentType ? { contentType: m.contentType } : {}) }));
                if (!res?.success && !streams.length) {
                    return { url, success: false, error: res?.error || 'Could not load the page.', hint: 'Confirm the page loads with playwright_fetch/scrapling_fetch, or pass a different (watch/player) URL.' };
                }
                const playable = streams.filter((s) => s.type === 'hls' || s.type === 'file' || s.type === 'dash');
                return {
                    url,
                    success: true,
                    finalUrl: res.finalUrl || url,
                    title: res.title || '',
                    streams,
                    ...(res.counts ? { counts: res.counts } : {}),
                    ...(playable.length
                        ? { hint: `Found ${playable.length} playable stream(s). To show one in the chat, call find_video with that URL in \`urls\` (a .m3u8 plays via the built-in HLS player).` }
                        : { hint: 'No streaming URLs were observed. The media may be DRM-protected, inside a cross-origin iframe (sniff that iframe’s src directly), or only loads after sign-in. Try again with interact:true, or use playwright_interact to navigate/dismiss overlays first.' }),
                };
            } catch (e) {
                return { url, success: false, error: e.message || String(e) };
            }
        },
    });

    // ----- fetch_timeseries ------------------------------------------------
    // Pulls historical OHLC data from Yahoo Finance's v8 chart endpoint —
    // free, no API key, JSON, broad coverage (stocks, indexes, FX, crypto).
    // Stooq used to be the obvious choice but they moved their CSV endpoint
    // behind an apikey gate in 2026, so any unauthenticated request now
    // returns the apikey-instructions blurb instead of data.
    //
    // Symbol normalisation lets the model use its training-era instincts:
    // `^spx`/`^ndq`/`^dji` get rewritten to Yahoo's `^GSPC`/`^IXIC`/`^DJI`,
    // `aapl.us` strips to `AAPL`, `eurusd` becomes `EURUSD=X`. Anything
    // else passes through verbatim.
    const YF_INDEX_ALIASES = {
        '^spx': '^GSPC', '^sp500': '^GSPC', '^sp': '^GSPC',
        '^dji': '^DJI', '^dow': '^DJI',
        '^ndq': '^IXIC', '^nasdaq': '^IXIC', '^ixic': '^IXIC',
        '^rut': '^RUT', '^russell': '^RUT', '^russell2000': '^RUT',
        '^vix': '^VIX', '^ftse': '^FTSE', '^dax': '^GDAXI',
        '^nikkei': '^N225', '^n225': '^N225',
    };
    function normaliseYahooSymbol(raw) {
        const s = String(raw || '').trim();
        if (!s) return '';
        const lower = s.toLowerCase();
        if (YF_INDEX_ALIASES[lower]) return YF_INDEX_ALIASES[lower];
        // US stock with .us suffix → strip
        if (/^[a-z0-9.-]+\.us$/i.test(s)) return s.replace(/\.us$/i, '').toUpperCase();
        // Six-letter forex pair with no =X → add =X
        if (/^[a-z]{6}$/i.test(s)) return s.toUpperCase() + '=X';
        // Index-style with caret → uppercase preserves Yahoo's convention
        if (s.startsWith('^')) return '^' + s.slice(1).toUpperCase();
        // Plain ticker → uppercase
        if (/^[a-z]+$/i.test(s)) return s.toUpperCase();
        return s;
    }
    tools.registerTool({
        name: 'fetch_timeseries',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'fetch_timeseries',
                    description:
                        'USE WHEN the user asks for stock/index/forex/crypto charts, price history, or to graph a ticker. ' +
                        'Fetch historical OHLC time series from Yahoo Finance (free, no API key). Use for stock tickers (AAPL, MSFT), market indexes (^GSPC for S&P 500, ^DJI for Dow, ^IXIC for Nasdaq — also accepts ^spx/^dji/^ndq aliases), forex (EURUSD=X or just "eurusd"), crypto (BTC-USD), and commodities (GC=F gold, CL=F oil). ' +
                        'After fetching, pass the rows into render_chart with type=line and a `close` series for a price chart. If a symbol returns no data, the model should suggest the user check the ticker — Yahoo uses different symbols than some other sources (e.g. ^GSPC not ^SPX).',
                    parameters: {
                        type: 'object',
                        properties: {
                            symbol: {
                                type: 'string',
                                description: 'Yahoo Finance symbol. Stocks: bare ticker (AAPL, MSFT). Indexes: ^GSPC (S&P 500), ^DJI (Dow), ^IXIC (Nasdaq), ^RUT, ^VIX, ^FTSE, ^GDAXI, ^N225. FX: EURUSD=X, GBPUSD=X (or just "eurusd" — auto-suffixed). Crypto: BTC-USD, ETH-USD.',
                            },
                            period: {
                                type: 'string',
                                enum: ['1mo', '3mo', '6mo', '1y', '2y', '5y', 'ytd', 'max'],
                                description: 'Lookback window (default 1y).',
                            },
                            interval: {
                                type: 'string',
                                enum: ['d', 'w', 'm'],
                                description: 'Bar interval: d=daily, w=weekly, m=monthly (default d).',
                            },
                        },
                        required: ['symbol'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const rawSymbol = String(args?.symbol || '').trim();
            if (!rawSymbol) return { error: 'symbol is required' };
            if (!/^[\^a-zA-Z0-9.=_-]{1,32}$/.test(rawSymbol)) {
                return { error: 'symbol contains invalid characters' };
            }
            const symbol = normaliseYahooSymbol(rawSymbol);
            const period = ['1mo', '3mo', '6mo', '1y', '2y', '5y', 'ytd', 'max'].includes(args?.period) ? args.period : '1y';
            const interval = ['d', 'w', 'm'].includes(args?.interval) ? args.interval : 'd';
            const yfInterval = interval === 'd' ? '1d' : interval === 'w' ? '1wk' : '1mo';
            // Yahoo's chart endpoint accepts the period as `range` directly.
            const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=${yfInterval}&range=${period}`;
            try {
                const resp = await axios.get(url, {
                    headers: {
                        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
                        'Accept': 'application/json,text/plain,*/*',
                        'Accept-Language': 'en-US,en;q=0.9',
                    },
                    timeout: 12000,
                    // Surface non-2xx responses (e.g. 404 for unknown tickers)
                    // without throwing so we can return a structured error.
                    validateStatus: () => true,
                });
                const body = resp.data;
                // Yahoo packages errors inside the chart envelope, e.g.
                //   { chart: { result: null, error: { code: "Not Found", description: "..." } } }
                if (body?.chart?.error) {
                    return {
                        symbol, normalisedSymbol: symbol, period, interval,
                        error: `Yahoo error: ${body.chart.error.description || body.chart.error.code || 'unknown'} — check ticker (Yahoo uses ^GSPC for S&P 500, ^DJI for Dow, ^IXIC for Nasdaq)`,
                    };
                }
                const result = body?.chart?.result?.[0];
                if (!result || !Array.isArray(result.timestamp) || result.timestamp.length === 0) {
                    return {
                        symbol, normalisedSymbol: symbol, period, interval,
                        error: 'no data returned — symbol may be wrong, delisted, or this period/interval combo is unsupported',
                    };
                }
                const ts = result.timestamp;
                const quote = result.indicators?.quote?.[0] || {};
                const adjclose = result.indicators?.adjclose?.[0]?.adjclose;
                const opens = quote.open || [];
                const highs = quote.high || [];
                const lows = quote.low || [];
                const closes = quote.close || [];
                const volumes = quote.volume || [];
                const rows = [];
                for (let i = 0; i < ts.length; i++) {
                    const close = closes[i];
                    if (close == null || !Number.isFinite(close)) continue;
                    const d = new Date(ts[i] * 1000);
                    const date = `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, '0')}-${String(d.getUTCDate()).padStart(2, '0')}`;
                    const row = { date, close };
                    if (Number.isFinite(opens[i])) row.open = opens[i];
                    if (Number.isFinite(highs[i])) row.high = highs[i];
                    if (Number.isFinite(lows[i])) row.low = lows[i];
                    if (Number.isFinite(volumes[i])) row.volume = volumes[i];
                    if (adjclose && Number.isFinite(adjclose[i])) row.adjclose = adjclose[i];
                    rows.push(row);
                }
                if (rows.length === 0) {
                    return {
                        symbol, normalisedSymbol: symbol, period, interval,
                        error: 'data returned but every close is null (likely an off-market period or a non-trading symbol)',
                    };
                }
                // Cap rows so a `period: max` request doesn't blow past the
                // tool_result SSE size cap. 800 daily bars ≈ 3.2 years.
                const MAX_ROWS = 800;
                const truncated = rows.length > MAX_ROWS;
                const data = truncated ? rows.slice(-MAX_ROWS) : rows;
                return {
                    symbol: rawSymbol,
                    normalisedSymbol: symbol,
                    period,
                    interval,
                    count: data.length,
                    truncated,
                    source: 'finance.yahoo.com',
                    currency: result.meta?.currency,
                    longName: result.meta?.longName || result.meta?.shortName,
                    data,
                };
            } catch (e) {
                return { symbol: rawSymbol, normalisedSymbol: symbol, period, interval, error: `fetch failed: ${e.message || e}` };
            }
        },
    });

    // ----- scrapling_fetch -------------------------------------------------
    // Exposes Scrapling (StealthyFetcher + curl_cffi) as a first-class tool.
    // Today Scrapling only runs as a fallback inside fetch_url / web_search;
    // this lets the model deliberately pick it when a site is known to block
    // bots (Cloudflare, PerimeterX, etc.) instead of burning a failed
    // playwright_fetch first.
    tools.registerTool({
        name: 'scrapling_fetch',
        build() {
            return null; // consolidated into the `web` tool (mode:"stealth") — hidden from chat catalog, still registered
            return {
                type: 'function',
                function: {
                    name: 'scrapling_fetch',
                    description:
                        'USE WHEN fetch_url or playwright_fetch returned thin/bot-blocked content (Cloudflare, DataDome, "Just a moment", CAPTCHA). ' +
                        'Fetch a webpage with Scrapling stealth (StealthyFetcher + curl_cffi). Strongest anti-bot tool — use when fetch_url/playwright_fetch returned a `hint` about bot protection or thin content, ' +
                        'on Cloudflare/PerimeterX/DataDome/Akamai-gated sites, threat-intel portals (abuse.ch, threatfox, urlhaus), or pages showing "Checking your browser" / "Just a moment" / "Access denied" / CAPTCHA. ' +
                        'Slower than fetch_url; reach for it only when evasion is needed, but try it before asking the user to paste. Rejects private addresses.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'Absolute HTTP(S) URL to fetch.' },
                            timeout: { type: 'integer', minimum: 1000, maximum: 120000, description: 'Timeout in ms (default 30000).' },
                            extractLinks: { type: 'boolean', description: 'Include extracted links in the result (default false).' },
                            maxLength: { type: 'integer', minimum: 100, maximum: 100000, description: 'Truncate content to this many chars (default 15000).' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            if (!scraplingService) {
                return { success: false, error: 'Scrapling service not available on this host' };
            }
            if (scraplingEnabled === false) {
                return { success: false, error: 'Scrapling Python module not installed — fall back to fetch_url or playwright_fetch' };
            }
            const timeout = Math.min(120_000, Math.max(1000, parseInt(args?.timeout || 30000, 10)));
            const maxLength = Math.min(100_000, Math.max(100, parseInt(args?.maxLength || 15000, 10)));
            const extractLinks = args?.extractLinks === true;
            try {
                const result = await scraplingService.fetchUrl(url, { timeout, extractLinks });
                if (!result?.success) {
                    return { url, success: false, error: result?.error || 'scrapling fetch failed', engine: 'scrapling' };
                }
                const content = typeof result.content === 'string' ? result.content.slice(0, maxLength) : '';
                const hint = productPageHint(content);
                return {
                    url,
                    success: true,
                    title: result.title || '',
                    content,
                    ...(extractLinks && Array.isArray(result.links) ? { links: result.links.slice(0, 100) } : {}),
                    engine: 'scrapling',
                    ...(hint ? { hint } : {}),
                };
            } catch (e) {
                return { url, success: false, error: e.message || String(e), engine: 'scrapling' };
            }
        },
    });

    // ----- playwright_fetch -----------------------------------------------
    // The default skill's `code` field is comment-only documentation — the
    // real work lives at /api/playwright/fetch. Register as a static native
    // tool so the chat tool-call dispatcher routes straight to
    // playwrightService instead of trying to exec the comments as Python
    // (which fails with `name 'execute' is not defined`). The dynamic skill
    // provider dedupes against toolRegistry, so the comment-only skill is
    // skipped there.
    tools.registerTool({
        name: 'playwright_fetch',
        build() {
            return null; // consolidated into the `web` tool (mode:"browser" / want:"images") — hidden from chat catalog, still registered
            return {
                type: 'function',
                function: {
                    name: 'playwright_fetch',
                    description:
                        'USE WHEN fetch_url returned empty/wrong content for a JS-rendered page (SPA, lazy-loaded, dynamic), OR WHENEVER the user wants the IMAGES and/or the TEXT off an image-heavy page — a social profile or feed (Instagram, etc.), a photo gallery, a product/listing grid, any infinite-scroll page. ' +
                        'It renders the page in a real browser (Playwright + stealth), SCROLLS to trigger lazy-loaded media, and returns an "Images:" section listing each rendered image\'s URL, its caption (the alt text — this is where image-only feeds keep their per-image description), and its post/permalink, alongside the page\'s headings/paragraphs/tables. So a SINGLE call gets both the pictures and the text describing them. ' +
                        'For those requests call this DIRECTLY and do NOT loop through fetch_url / scrapling_fetch / download_html / crawl_pages first — on JS-rendered sites those see only the static HTML shell, which contains none of the images or post text (that is the loop that fails). Pass includeLinks:true to also collect every link. ' +
                        'Falls back to axios if Playwright is unavailable. Rejects private/internal addresses. ' +
                        'If the result includes a `hint` mentioning bot protection or thin content (Cloudflare, "Just a moment...", CAPTCHA), retry the same URL with scrapling_fetch — do NOT ask the user to paste before trying it. ' +
                        'This loads ONE view (it does auto-scroll for lazy content) — to click, accept a cookie wall, paginate, search, or otherwise move around the page to find items, use playwright_interact instead.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'Absolute HTTP(S) URL to fetch.' },
                            timeout: { type: 'integer', minimum: 1000, maximum: 120000, description: 'Timeout in ms (default 15000).' },
                            waitForJS: { type: 'boolean', description: 'Wait for JS to render (default true).' },
                            includeLinks: { type: 'boolean', description: 'Include extracted links (default false).' },
                            maxLength: { type: 'integer', minimum: 100, maximum: 100000, description: 'Truncate content to this many chars (default 8000).' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            const timeout = Math.min(120_000, Math.max(1000, parseInt(args?.timeout || 15000, 10)));
            const maxLength = Math.min(100_000, Math.max(100, parseInt(args?.maxLength || 8000, 10)));
            const waitForJS = args?.waitForJS !== false;
            const includeLinks = args?.includeLinks === true;
            if (!playwrightEnabled || !playwrightService) {
                try {
                    const fallback = await fetchUrlContentAxios(url, timeout);
                    return { ...fallback, engine: 'axios' };
                } catch (e) {
                    return { url, success: false, error: e.message || String(e), engine: 'axios' };
                }
            }
            try {
                const result = await playwrightService.fetchUrlContent(url, {
                    timeout, waitForJS, includeLinks, maxLength,
                });
                const hint = result?.success
                    ? (detectBotChallenge({ title: result.title, content: result.content }) || productPageHint(result.content))
                    : null;
                return { ...result, engine: 'playwright', ...(hint ? { hint } : {}) };
            } catch (e) {
                return { url, success: false, error: e.message || String(e), engine: 'playwright' };
            }
        },
    });

    // ----- playwright_interact --------------------------------------------
    // Same shape as playwright_fetch — the default skill's code is
    // comment-only, so we register a static handler that calls
    // playwrightService.interactAndFetch directly.
    tools.registerTool({
        name: 'playwright_interact',
        build() {
            return null; // consolidated into the `web` tool (mode:"interact") — hidden from chat catalog, still registered
            return {
                type: 'function',
                function: {
                    name: 'playwright_interact',
                    description:
                        'Navigate a page and perform an action sequence (click, type, wait, scroll, waitForNavigation) before extracting content. Use when a page needs interaction (accept cookies, submit a form, scroll for lazy content) before it renders useful text, or to MOVE AROUND a page to find items. Requires Playwright; errors if unavailable.\n' +
                        'FINDING ITEMS / MOVING AROUND:\n' +
                        '• Dismiss blockers first: click the cookie/consent/"close" button if a banner or modal is covering the content (e.g. {"type":"click","selector":"#accept-cookies"}).\n' +
                        '• Lazy-load / infinite scroll: add several {"type":"scroll"} actions (each scrolls one viewport down) with a {"type":"wait","timeout":1200} between them so new items load; content is read from the fully-scrolled page.\n' +
                        '• "Load more" / "Show all": click that button — repeat the click for several batches, with a wait after each, to pull in more items.\n' +
                        '• Search to locate an item: {"type":"type","selector":"#search","text":"<query>"} then click/submit, then {"type":"wait","selector":".results"}.\n' +
                        '• Open a tab/category/filter: click it, then wait for its result selector before extraction.\n' +
                        'PAGINATION (next pages): content is extracted only from the FINAL page state, so this returns ONE page per call. Two patterns: (a) click the Next/page link then {"type":"waitForNavigation"} (or wait for the results selector) to land on — and read — that page; (b) to collect items across MANY pages, call playwright_interact once per page, advancing the URL\'s page param (…?page=2, &offset=20) each call, and merge the results yourself. For broad link-following across a site, prefer crawl_pages.\n' +
                        'If a selector times out, the page likely uses a different selector — inspect it first with playwright_fetch (includeLinks:true) or scrapling_fetch to find the real one rather than retrying blindly.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'Absolute HTTP(S) URL to navigate to.' },
                            actions: {
                                type: 'array',
                                description: 'Ordered actions run before content is extracted. Each: { "type": "click|type|wait|scroll|waitForNavigation", ... }. ' +
                                    'click → needs "selector"; type → needs "selector" + "text"; wait → "selector" (wait until it appears) OR "timeout" (ms pause); scroll → scrolls one viewport down (repeat to trigger lazy/infinite loading); waitForNavigation → wait for a full page load after a click. ' +
                                    'Optional per-action "timeout" (ms, default 8000) widens slow elements. ' +
                                    'Examples — reveal more: [{"type":"click","selector":".load-more"},{"type":"wait","timeout":1500}]; next page: [{"type":"click","selector":"a.next"},{"type":"waitForNavigation"}]; search: [{"type":"type","selector":"#q","text":"laptop"},{"type":"click","selector":"button[type=submit]"},{"type":"wait","selector":".results"}].',
                                items: { type: 'object' },
                            },
                            timeout: { type: 'integer', minimum: 1000, maximum: 120000, description: 'Overall timeout in ms (default 30000).' },
                            maxLength: { type: 'integer', minimum: 100, maximum: 100000, description: 'Truncate content to this many chars (default 8000).' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            if (!playwrightEnabled || !playwrightService) {
                return { success: false, error: 'Playwright not available — interaction requires browser automation' };
            }
            const timeout = Math.min(120_000, Math.max(1000, parseInt(args?.timeout || 30000, 10)));
            const maxLength = Math.min(100_000, Math.max(100, parseInt(args?.maxLength || 8000, 10)));
            const actions = Array.isArray(args?.actions) ? args.actions : [];
            try {
                const result = await playwrightService.interactAndFetch(url, actions, { timeout, maxLength });
                const hint = result?.success
                    ? (detectBotChallenge({ title: result.title, content: result.content }) || productPageHint(result.content))
                    : null;
                return { ...result, engine: 'playwright', ...(hint ? { hint } : {}) };
            } catch (e) {
                return { url, success: false, error: e.message || String(e), engine: 'playwright' };
            }
        },
    });

    // ----- virustotal_lookup -----------------------------------------------
    // Queries VirusTotal for an IP, domain, URL, or file hash. Primary
    // path hits VT API v3 with process.env.VIRUSTOTAL_API_KEY; when the
    // key is absent, falls back to a Scrapling scrape of the GUI page so
    // the model still gets *something* (unstructured, best-effort) to
    // work with. Resource type is auto-detected from the input.
    const virustotalService = require('./services/virustotalService');
    tools.registerTool({
        name: 'virustotal_lookup',
        build() {
            const keySet = !!(process.env.VIRUSTOTAL_API_KEY && process.env.VIRUSTOTAL_API_KEY.trim());
            const keyNote = keySet
                ? 'API key configured — returns structured detection stats, flagging engines, and metadata.'
                : 'No VIRUSTOTAL_API_KEY set — falls back to scraping the GUI page (unstructured text). Set the env var for full detection data.';
            return {
                type: 'function',
                function: {
                    name: 'virustotal_lookup',
                    description:
                        `Query VirusTotal for an IP, domain, URL, or file hash (md5/sha1/sha256). ${keyNote} ` +
                        'view=detection (default): stats + flagging engines + metadata; view=community: votes + comments; view=full: both. ' +
                        'Resource type auto-detected; pass resource_type to override. Use before asking the user to paste VT screenshots.',
                    parameters: {
                        type: 'object',
                        properties: {
                            resource: { type: 'string', description: 'IP address, domain, absolute URL, or file hash (md5/sha1/sha256).' },
                            resource_type: { type: 'string', enum: ['ip_address', 'domain', 'url', 'file'], description: 'Optional override when auto-detection is wrong.' },
                            view: { type: 'string', enum: ['detection', 'community', 'full'], description: 'Which slice to fetch (default detection).' },
                            timeout: { type: 'integer', minimum: 1000, maximum: 60000, description: 'Per-request timeout in ms (default 15000).' },
                        },
                        required: ['resource'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const resource = String(args?.resource || '').trim();
            if (!resource) return { error: 'resource is required' };
            const timeout = Math.min(60_000, Math.max(1000, parseInt(args?.timeout || 15000, 10)));
            try {
                const result = await virustotalService.lookup(resource, {
                    resource_type: args?.resource_type,
                    view: args?.view || 'detection',
                    timeout,
                });
                return result;
            } catch (e) {
                return { success: false, resource, error: e.message || String(e) };
            }
        },
    });

    // ----- crawl_pages ----------------------------------------------------
    // Walks paginated listings. Four modes — url-pattern (fast, stateless;
    // increments a ?page=N / /page/N/ / ?offset=N marker), link-follow
    // (clicks Next), load-more (clicks a Load-more button), and
    // infinite-scroll (scrolls the viewport). `auto` picks one by
    // inspecting the URL and, if needed, the rendered DOM.
    const crawlerService = require('./services/crawlerService');
    tools.registerTool({
        name: 'crawl_pages',
        build() {
            return null; // consolidated into the `web` tool (mode:"crawl") — hidden from chat catalog, still registered
            return {
                type: 'function',
                function: {
                    name: 'crawl_pages',
                    description:
                        'USE WHEN the user asks for "top N / most recent N" items spanning a paginated listing or when a fetch returned only page 1. ' +
                        'Walk a paginated listing across multiple pages in one call. Use for "top N / most recent N" requests or when a fetch returned only page 1. ' +
                        'Modes: auto (default; URL pattern then DOM Next/Load-more), url-pattern (increments ?page=/?p=/?offset=//page/N/), link-follow (clicks Next; pass nextSelector to override), ' +
                        'load-more (clicks button; pass loadMoreSelector), infinite-scroll. Rejects private addresses. Stops on duplicate content.',
                    parameters: {
                        type: 'object',
                        properties: {
                            url: { type: 'string', description: 'Absolute HTTP(S) starting URL.' },
                            maxPages: { type: 'integer', minimum: 1, maximum: 20, description: 'Hard cap on pages to walk (default 5).' },
                            mode: { type: 'string', enum: ['auto', 'url-pattern', 'link-follow', 'load-more', 'infinite-scroll'], description: 'Pagination strategy (default auto).' },
                            nextSelector: { type: 'string', description: 'CSS selector for the Next link (link-follow mode). Optional override when auto-detection picks the wrong element.' },
                            loadMoreSelector: { type: 'string', description: 'CSS selector for the Load-more button (load-more mode).' },
                            waitForSelector: { type: 'string', description: 'CSS selector to wait for on each page before extracting.' },
                            timeout: { type: 'integer', minimum: 1000, maximum: 120000, description: 'Per-page timeout in ms (default 20000).' },
                            maxLength: { type: 'integer', minimum: 1000, maximum: 200000, description: 'Total combined content cap across all pages (default 30000).' },
                            includeLinks: { type: 'boolean', description: 'Include extracted links per page (default false).' },
                            stealth: { type: 'boolean', description: 'Prefer Scrapling for url-pattern fetches (use when a site is known to be bot-gated).' },
                        },
                        required: ['url'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const url = String(args?.url || '').trim();
            if (!url) return { error: 'url is required' };
            { const _block = urlBlockReason(url); if (_block) return { error: _block }; }
            const mode = args?.mode || 'auto';
            const maxPages = Math.min(20, Math.max(1, parseInt(args?.maxPages || 5, 10)));
            const timeout = Math.min(120_000, Math.max(1000, parseInt(args?.timeout || 20000, 10)));
            const maxLength = Math.min(200_000, Math.max(1000, parseInt(args?.maxLength || 30000, 10)));
            const includeLinks = args?.includeLinks === true;
            const stealth = args?.stealth === true;
            try {
                const result = await crawlerService.crawl(url, {
                    mode, maxPages, timeout, maxLength, includeLinks, stealth,
                    nextSelector: args?.nextSelector,
                    loadMoreSelector: args?.loadMoreSelector,
                    waitForSelector: args?.waitForSelector,
                });
                if (!result?.success) {
                    return { url, success: false, error: result?.error || 'crawl failed', mode: result?.mode };
                }
                // Build the combined content here (rather than inside the
                // service) so we can attach a challenge hint at the outer
                // tool layer, same as fetch_url / playwright_fetch.
                const combinedContent = (result.pages || [])
                    .map(p => `=== Page ${p.index + 1}: ${p.title || '(no title)'} — ${p.url} ===\n${p.content}`)
                    .join('\n\n');
                const hint = detectBotChallenge({ content: combinedContent });
                return {
                    url,
                    success: true,
                    mode: result.mode,
                    pagesVisited: result.pagesVisited,
                    pages: result.pages,
                    combinedContent,
                    ...(hint ? { hint } : {}),
                };
            } catch (e) {
                return { url, success: false, error: e.message || String(e) };
            }
        },
    });

    // ----- search_string --------------------------------------------------
    // Line-oriented search inside provided text or a file on disk. Use this
    // instead of dumping a whole fetched page or large file back to yourself
    // when you only need lines that mention a specific keyword/pattern —
    // saves a lot of tokens and lets the model pinpoint data quickly.
    tools.registerTool({
        name: 'search_string',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'search_string',
                    description:
                        'Search for a string or regex in text content or a file; return only matching lines with surrounding context. ' +
                        'Provide exactly one of `text` (raw content) or `file` (path under /tmp, /models, or /app). ' +
                        'Use after fetch_url / web_search / playwright_fetch / crawl_pages whenever the user asked for specific data (price, date, name, number, error code, IP, hash, version) — searching the returned body is far cheaper than re-reading it. ' +
                        'mode="regex" for patterns; default mode is literal.',
                    parameters: {
                        type: 'object',
                        properties: {
                            query: { type: 'string', description: 'The string or regex pattern to search for.' },
                            text: { type: 'string', description: 'Raw text content to search within. Pass the body returned by a previous fetch_url / web_search call.' },
                            file: { type: 'string', description: 'Absolute path to a text file to search within. Use only for paths under /tmp or /models.' },
                            mode: { type: 'string', enum: ['literal', 'regex'], description: 'How to interpret query (default literal).' },
                            case_sensitive: { type: 'boolean', description: 'Match case (default false).' },
                            context_lines: { type: 'integer', minimum: 0, maximum: 10, description: 'Lines of surrounding context to include around each match (default 2).' },
                            max_matches: { type: 'integer', minimum: 1, maximum: 500, description: 'Cap on returned matches (default 50).' },
                        },
                        required: ['query'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args) {
            const query = String(args?.query || '');
            if (!query) return { error: 'query is required' };
            const hasText = typeof args?.text === 'string' && args.text.length > 0;
            const hasFile = typeof args?.file === 'string' && args.file.length > 0;
            if (hasText === hasFile) {
                return { error: 'Provide exactly one of `text` or `file`.' };
            }
            const mode = args?.mode === 'regex' ? 'regex' : 'literal';
            const caseSensitive = args?.case_sensitive === true;
            const contextLines = Math.min(10, Math.max(0, parseInt(args?.context_lines ?? 2, 10)));
            const maxMatches = Math.min(500, Math.max(1, parseInt(args?.max_matches ?? 50, 10)));

            let content;
            let sourceLabel;
            if (hasFile) {
                const filePath = path.resolve(String(args.file));
                // Confine file access to the same areas existing tools touch:
                // /tmp (chat uploads, archive extracts) and /models (mounted
                // models tree which holds .modelserver/conversations etc.).
                const allowedRoots = ['/tmp/', '/models/', '/app/'];
                if (!allowedRoots.some(r => filePath === r.slice(0, -1) || filePath.startsWith(r))) {
                    return { error: `file path must be under one of: ${allowedRoots.join(', ')}` };
                }
                try {
                    const stat = await fs.stat(filePath);
                    if (!stat.isFile()) return { error: 'file is not a regular file' };
                    if (stat.size > 20 * 1024 * 1024) {
                        return { error: `file too large (${stat.size} bytes); cap is 20MB` };
                    }
                    content = await fs.readFile(filePath, 'utf8');
                    sourceLabel = filePath;
                } catch (e) {
                    return { error: `failed to read file: ${e.message}` };
                }
            } else {
                content = String(args.text);
                sourceLabel = 'text';
            }

            let regex;
            try {
                const escaped = mode === 'regex'
                    ? query
                    : query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
                regex = new RegExp(escaped, caseSensitive ? 'g' : 'gi');
            } catch (e) {
                return { error: `invalid regex: ${e.message}` };
            }

            const lines = content.split(/\r?\n/);
            const matches = [];
            let totalMatches = 0;
            for (let i = 0; i < lines.length; i++) {
                regex.lastIndex = 0;
                if (!regex.test(lines[i])) continue;
                totalMatches++;
                if (matches.length >= maxMatches) continue;
                const start = Math.max(0, i - contextLines);
                const end = Math.min(lines.length - 1, i + contextLines);
                const before = lines.slice(start, i);
                const after = lines.slice(i + 1, end + 1);
                matches.push({
                    line_number: i + 1,
                    line: lines[i].length > 500 ? lines[i].slice(0, 500) + '…' : lines[i],
                    ...(contextLines > 0 ? { context_before: before, context_after: after } : {}),
                });
            }

            return {
                success: true,
                source: sourceLabel,
                query,
                mode,
                case_sensitive: caseSensitive,
                total_lines: lines.length,
                total_matches: totalMatches,
                returned_matches: matches.length,
                truncated: totalMatches > matches.length,
                matches,
            };
        },
    });

    // ----- extract_archive ------------------------------------------------
    // Unpack an archive (zip, 7z, rar, tar, tar.gz/bz2/xz, gz, bz2, xz).
    // Two input modes:
    //   1. archiveId — refers to a file persisted by /api/chat/upload
    //      (the normal chat-UI path). The upload endpoint writes the
    //      bytes to disk and puts a [Archive uploaded: ...archiveId=X...]
    //      marker in the user's message. This is the ONLY reliable path
    //      for archives >~100KB — passing raw base64 through tool-call
    //      arguments truncates silently.
    //   2. base64Data + filename — direct bytes. Fine for tiny archives,
    //      fails in practice for anything bigger due to tokenizer limits.
    //
    // Returns entry listing + inline text for small UTF-8 entries so the
    // model can read them without a follow-up tool call. Cleans up its
    // temp extraction directory on return.
    const archiveExtractor = require('./services/archiveExtractor');
    const ARCHIVE_STORE_ROOT = '/tmp/modelserver-archives';

    // List archive ids currently on disk for this user (ARCHIVE_TTL_MS, see
    // /api/chat/upload's sweep). Used both for auto-select when the model
    // calls extract_archive without an id and to produce a helpful error
    // listing valid ids when it passes a wrong/missing one.
    async function listUserArchives(userId) {
        const safeUser = String(userId || 'anon').replace(/[^a-zA-Z0-9_-]/g, '_');
        const root = `${ARCHIVE_STORE_ROOT}/${safeUser}`;
        const fsp = require('fs').promises;
        const ids = await fsp.readdir(root).catch(() => []);
        const out = [];
        for (const id of ids) {
            if (!/^[a-f0-9]{32}$/.test(id)) continue;
            const entries = await fsp.readdir(`${root}/${id}`).catch(() => []);
            if (entries.length) out.push({ archiveId: id, filename: entries[0] });
        }
        return out;
    }

    // Archive-looking files in the conversation workspace (downloaded via
    // download_file / fetch_url, or created by earlier tools). Lets the model
    // extract what it just downloaded — previously only UPLOADED archives
    // (archiveId) worked, so the documented "fetch the .tgz → extract_archive"
    // flow dead-ended on "No uploaded archives are available". Skips the
    // archives/ output dir (already-extracted content) and node_modules.
    const ARCHIVE_EXT_RE = /\.(zip|7z|rar|tar|tar\.gz|tgz|tar\.bz2|tbz2?|tar\.xz|txz|gz|bz2|xz)$/i;
    async function listWorkspaceArchives(ctx, cap = 10) {
        const sandboxRunner = require('./services/sandboxRunner');
        let workspace;
        try {
            workspace = await sandboxRunner.ensureWorkspace(ctx?.userId ?? null, ctx?.conversationId ?? null);
        } catch (_) { return { workspace: null, files: [] }; }
        const fsp = require('fs').promises;
        const pathMod = require('path');
        const root = workspace.localInContainer;
        const files = [];
        async function walk(dir, rel, depth) {
            if (files.length >= cap || depth > 4) return;
            const entries = await fsp.readdir(dir, { withFileTypes: true }).catch(() => []);
            for (const ent of entries) {
                if (files.length >= cap) return;
                if (ent.name === 'node_modules' || (depth === 0 && ent.name === 'archives')) continue;
                const full = pathMod.join(dir, ent.name);
                const relPath = rel ? `${rel}/${ent.name}` : ent.name;
                if (ent.isDirectory()) await walk(full, relPath, depth + 1);
                else if (ent.isFile() && ARCHIVE_EXT_RE.test(ent.name)) files.push(relPath);
            }
        }
        await walk(root, '', 0);
        return { workspace, files };
    }

    // Resolve a workspace-relative path to archive bytes. Traversal-guarded
    // against the workspace root; accepts the /workspace/-prefixed form the
    // sandbox tools report so the model can pass paths verbatim.
    async function resolveArchiveByPath(rawPath, ctx) {
        const sandboxRunner = require('./services/sandboxRunner');
        const workspace = await sandboxRunner.ensureWorkspace(ctx?.userId ?? null, ctx?.conversationId ?? null);
        const pathMod = require('path');
        const fsp = require('fs').promises;
        const rel = String(rawPath).trim().replace(/^\/workspace\/?/, '').replace(/^\/+/, '');
        if (!rel) throw new Error('path is empty.');
        const resolved = pathMod.resolve(workspace.localInContainer, rel);
        if (resolved !== workspace.localInContainer &&
            !resolved.startsWith(workspace.localInContainer + pathMod.sep)) {
            throw new Error('Resolved path escapes the workspace.');
        }
        const stat = await fsp.stat(resolved).catch(() => null);
        if (!stat || !stat.isFile()) {
            const { files } = await listWorkspaceArchives(ctx).catch(() => ({ files: [] }));
            const hint = files.length ? ` Archives in the workspace: ${files.join(', ')}` : '';
            throw new Error(`No file at workspace path "${rel}".${hint}`);
        }
        if (stat.size > 50 * 1024 * 1024) throw new Error(`File is ${stat.size} bytes; 50MB max.`);
        return { buffer: await fsp.readFile(resolved), filename: pathMod.basename(resolved) };
    }

    async function resolveArchiveById(archiveId, userId) {
        if (!/^[a-f0-9]{32}$/.test(String(archiveId || ''))) {
            throw new Error('archiveId must be a 32-char hex string.');
        }
        const safeUser = String(userId || 'anon').replace(/[^a-zA-Z0-9_-]/g, '_');
        const dir = `${ARCHIVE_STORE_ROOT}/${safeUser}/${archiveId}`;
        const fsp = require('fs').promises;
        const pathMod = require('path');
        const resolved = pathMod.resolve(dir);
        if (!resolved.startsWith(pathMod.resolve(`${ARCHIVE_STORE_ROOT}/${safeUser}`) + pathMod.sep)) {
            throw new Error('Resolved archive path escapes the store.');
        }
        const entries = await fsp.readdir(dir).catch(() => null);
        if (!entries || !entries.length) {
            throw new Error(`No archive found for id ${archiveId}. It may have expired (${Math.round(ARCHIVE_TTL_MS / 3600000)}h TTL) or the id is wrong.`);
        }
        const filename = entries[0];
        const diskPath = `${dir}/${filename}`;
        const buf = await fsp.readFile(diskPath);
        return { buffer: buf, filename };
    }

    tools.registerTool({
        name: 'extract_archive',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'extract_archive',
                    description:
                        'Extract an archive (.zip, .7z, .rar, .tar, .tar.gz/.tgz, .tar.bz2, .tar.xz, .gz, .bz2, .xz). Type is detected from the file bytes, so a mislabeled extension still extracts. ' +
                        'Three inputs (pass exactly one): (1) `archiveId` from the `[Archive uploaded: ... archiveId=... ]` marker when the user uploaded the archive; ' +
                        '(2) `path` — the workspace path of an archive a previous tool downloaded or created (use the exact savePath/path that tool returned, e.g. after download_file or fetch_url); ' +
                        '(3) `base64Data` + `filename` for tiny inline archives ONLY — base64 in tool args gets truncated, never paste real archive bytes. ' +
                        'Extracts into the conversation workspace and returns the entry list — pass an entry `path` to read_file/grep_code to inspect contents.',
                    parameters: {
                        type: 'object',
                        properties: {
                            archiveId: {
                                type: 'string',
                                description: '32-char hex id from the [Archive uploaded: ...] marker in the user message.',
                            },
                            path: {
                                type: 'string',
                                description: 'Workspace-relative path of an archive already in this conversation workspace (e.g. "color-util.tgz" downloaded earlier). "/workspace/..." prefix accepted.',
                            },
                            base64Data: {
                                type: 'string',
                                description: 'Fallback for small inline archives only. Raw archive bytes encoded as standard base64 (no data: URL prefix).',
                            },
                            filename: {
                                type: 'string',
                                description: 'Required when using base64Data. The extension hints the extractor (e.g. "report.tar.gz"); magic bytes override a wrong extension.',
                            },
                        },
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            let buffer, filename;
            let archiveId = String(args?.archiveId || '').trim();
            let wsPath = String(args?.path || '').trim();
            // Model frequently calls extract_archive with no args or with a
            // FILENAME in the archiveId slot. Resolution order when archiveId
            // isn't a valid id: (1) explicit workspace path; (2) a filename
            // passed as archiveId matched against uploads then workspace
            // files; (3) auto-select when exactly one candidate exists
            // anywhere; (4) an error that lists everything extractable.
            const valid = /^[a-f0-9]{32}$/.test(archiveId);
            const b64Given = !!String(args?.base64Data || '').trim();
            if (!valid && !wsPath && !b64Given) {
                const available = await listUserArchives(ctx?.userId).catch(() => []);
                const ws = await listWorkspaceArchives(ctx).catch(() => ({ files: [] }));
                if (archiveId) {
                    // A non-hex archiveId is usually a filename — match it.
                    const base = archiveId.split('/').pop().toLowerCase();
                    const up = available.find(a => a.filename.toLowerCase() === base);
                    const wf = ws.files.find(f => f.split('/').pop().toLowerCase() === base)
                        || ws.files.find(f => f.toLowerCase() === archiveId.toLowerCase());
                    if (up) archiveId = up.archiveId;
                    else if (wf) wsPath = wf;
                }
                if (!/^[a-f0-9]{32}$/.test(archiveId) && !wsPath) {
                    const candidates = available.length + ws.files.length;
                    if (available.length === 1 && !ws.files.length) {
                        archiveId = available[0].archiveId;
                    } else if (ws.files.length === 1 && !available.length) {
                        wsPath = ws.files[0];
                    } else if (candidates === 0) {
                        return { error: `No archives found — none uploaded by the user (${Math.round(ARCHIVE_TTL_MS / 3600000)}h TTL) and none in the conversation workspace. Download one first (download_file/fetch_url) and pass its path, or ask the user to upload it.` };
                    } else {
                        const list = [
                            ...available.map(a => `archiveId=${a.archiveId} (${a.filename})`),
                            ...ws.files.map(f => `path=${f}`),
                        ].join('; ');
                        return { error: `Ambiguous or malformed archive reference. Pass one of: ${list}` };
                    }
                }
            }
            if (wsPath && !/^[a-f0-9]{32}$/.test(archiveId)) {
                try {
                    const resolved = await resolveArchiveByPath(wsPath, ctx);
                    buffer = resolved.buffer;
                    filename = resolved.filename;
                } catch (e) {
                    return { error: e.message };
                }
                archiveId = ''; // extraction dir gets a random suffix below
            } else if (archiveId) {
                try {
                    const resolved = await resolveArchiveById(archiveId, ctx?.userId);
                    buffer = resolved.buffer;
                    filename = resolved.filename;
                } catch (e) {
                    const available = await listUserArchives(ctx?.userId).catch(() => []);
                    const hint = available.length
                        ? ` Available archiveIds: ${available.map(a => `${a.archiveId} (${a.filename})`).join('; ')}`
                        : ' No uploaded archives are currently on disk for this user.';
                    return { error: e.message + hint };
                }
            } else {
                const b64 = String(args?.base64Data || '').trim();
                filename = String(args?.filename || '').trim();
                if (!b64) return { error: 'Provide archiveId (preferred) or base64Data + filename.' };
                if (!filename) return { error: 'filename is required when using base64Data.' };
                try {
                    buffer = Buffer.from(b64.replace(/^data:[^;]+;base64,/, ''), 'base64');
                } catch (e) {
                    return { error: `Invalid base64Data: ${e.message}` };
                }
            }
            if (!buffer?.length) return { error: 'Decoded buffer is empty' };
            if (buffer.length > 50 * 1024 * 1024) {
                return { error: `Archive is ${buffer.length} bytes; 50MB max.` };
            }
            try {
                // Persist extracted contents into the conversation's workspace
                // bucket so subsequent read_file calls (sandboxed, rooted at
                // /workspace) can read individual entries on demand. Without
                // this the extractor would either inline ~2 MB of text into the
                // tool result (overflowing the model's context — observed:
                // 243k-token request against a 131k-token model after a tar.gz
                // upload) or extract to a temp dir the sandboxed read_file
                // can't see.
                const sandboxRunner = require('./services/sandboxRunner');
                let workspace;
                try {
                    workspace = await sandboxRunner.ensureWorkspace(
                        ctx?.userId ?? null,
                        ctx?.conversationId ?? null,
                    );
                } catch (wsErr) {
                    // Fall back to legacy inline-extraction mode if no workspace
                    // (e.g. /v1 passthrough callers without conv plumbing).
                    return await archiveExtractor.extractArchive(buffer, filename);
                }
                const fsp = require('fs').promises;
                const pathMod = require('path');
                const extractRoot = pathMod.join(workspace.localInContainer, 'archives', archiveId || crypto.randomBytes(8).toString('hex'));
                await fsp.mkdir(extractRoot, { recursive: true });
                await fsp.chmod(extractRoot, 0o777);
                const result = await archiveExtractor.extractArchive(buffer, filename, {
                    extractTo: extractRoot,
                    pathBase: workspace.localInContainer,
                });
                return {
                    ...result,
                    workspaceRoot: workspace.containerMount,
                    note: (result.note ? result.note + ' ' : '') +
                        `Files extracted into the conversation workspace. Each entry's \`path\` is workspace-relative — pass it to read_file to inspect contents (e.g. read_file(filePath="${result.entries?.[0]?.path || 'archives/.../foo'}")).`,
                };
            } catch (e) {
                return { error: e.message || String(e) };
            }
        },
    });

    // --------------------------------------------------------------
    // Expose every enabled skill as a native tool call.
    // --------------------------------------------------------------
    //
    // The model sees these as first-class OpenAI tools alongside
    // load_skill / web_search / fetch_url, so prompts like "decode this
    // base64" / "list the directory" / "do a dns lookup on X" resolve
    // to a direct tool call instead of a text answer.
    //
    // Built per-request via setDynamicToolProvider so we always pull
    // the current (user-scoped) skill set, including anything the user
    // just added. Dispatch goes through executePythonSkill which already
    // applies the sandbox / workspace / network-allowlist policy on the
    // skill record.

    // OpenAI tool names accept only [a-zA-Z0-9_-]{1,64}. `safeToolName` is
    // module-scope (defined near the top of this file) so the REST route
    // `/api/skills/:name/execute` can use the same sanitizer when checking
    // whitelist entries.

    // Skills store their parameter list as a flat map
    //   { paramName: 'string' | 'number' | 'boolean' | 'array' | 'object' }
    // Convert to a JSON Schema object that OpenAI tool-calling understands.
    // Every listed param is treated as required — skill implementations
    // generally throw on missing arguments, so this matches their
    // runtime contract. Unknown type hints fall back to "string".
    function paramsToJsonSchema(params) {
        const properties = {};
        const required = [];
        if (params && typeof params === 'object') {
            for (const [k, v] of Object.entries(params)) {
                const hint = String(v || '').toLowerCase();
                let type = 'string';
                if (hint === 'number' || hint === 'integer' || hint === 'float') type = 'number';
                else if (hint === 'boolean' || hint === 'bool') type = 'boolean';
                else if (hint === 'array' || hint === 'list') type = 'array';
                else if (hint === 'object' || hint === 'dict' || hint === 'map') type = 'object';
                properties[k] = type === 'array'
                    ? { type: 'array', items: { type: 'string' } }
                    : { type };
                required.push(k);
            }
        }
        return {
            type: 'object',
            properties,
            ...(required.length ? { required } : {}),
            additionalProperties: false,
        };
    }

    // `resolveSkillPolicy` and `isSkillBlocked` are module-scope — see the
    // helper near the auth destructure at the top of this file.

    // ----- search_knowledge_base -------------------------------------------
    // Semantic retrieval over the user's uploaded knowledge base(s). Surfaced
    // only when the user actually has a KB. Returns short, source-cited
    // snippets (top-k) — never whole documents — so it stays context-cheap and
    // can be called repeatedly with refined queries.
    tools.registerTool({
        name: 'search_knowledge_base',
        async build(ctx) {
            let kbs = [];
            try { kbs = await knowledgeBaseService.listKBs(ctx?.userId || null); } catch (_) { return null; }
            if (!kbs.length) return null;
            // Surface document counts AND the actual filenames so the model
            // (a) can answer "how many files do I have" without guessing from
            // snippets, and (b) recognizes that a file the user names by hand
            // lives in the KB — not on the sandbox disk — so it reaches for
            // this tool instead of wasting a read_pdf/read_file on a guessed
            // /workspace path. Filenames are capped per-KB to keep the catalog
            // small on large collections.
            const FN_CAP = 15;
            const names = kbs.map((k) => {
                const docs = k.documents || [];
                const shown = docs.slice(0, FN_CAP).map((d) => d.filename).join(', ');
                const more = docs.length > FN_CAP ? `, …+${docs.length - FN_CAP} more` : '';
                const fileList = docs.length ? `: ${shown}${more}` : '';
                return `"${k.name}" (${docs.length} file${docs.length === 1 ? '' : 's'}${fileList})`;
            }).join('; ');
            return {
                type: 'function',
                function: {
                    name: 'search_knowledge_base',
                    description:
                        "Semantically search the user's uploaded knowledge base(s) and return the most relevant passages. " +
                        "Call this whenever the answer may live in the user's own documents, notes, or files. " +
                        'Returns short, source-cited snippets only (not whole documents), so it is cheap and safe to call repeatedly with refined queries. ' +
                        'To list or count the files in a knowledge base (e.g. "how many files / which documents do I have"), call with list_documents=true instead of guessing from search results. ' +
                        'IMPORTANT: the files listed below live ONLY in the knowledge base, NOT on the sandbox filesystem — if the user names one of them, use THIS tool to read it; do NOT call read_pdf/read_file/list_directory on a /workspace path (those will fail). ' +
                        `Available knowledge bases: ${names}.`,
                    parameters: {
                        type: 'object',
                        properties: {
                            query: { type: 'string', description: 'Natural-language search query. Required unless list_documents is true.' },
                            knowledge_base: { type: 'string', description: "Optional KB name to restrict the search; omit to search all of the user's knowledge bases." },
                            list_documents: { type: 'boolean', description: 'Set true to return the inventory of files (filenames, types, counts) in the knowledge base(s) instead of doing a semantic search.' },
                            k: { type: 'number', description: 'Max passages to return (default 6, max 20).' },
                        },
                        required: [],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const query = String(args?.query || '').trim();
            const wantList = args?.list_documents === true || args?.list_documents === 'true';
            if (!query && !wantList) return { error: 'query is required (or set list_documents=true to list files)' };
            const k = Math.min(Math.max(parseInt(args?.k) || 6, 1), 20);
            let kbs = [];
            try { kbs = await knowledgeBaseService.listKBs(ctx?.userId || null); }
            catch (e) { return { error: 'knowledge base unavailable: ' + e.message }; }
            if (!kbs.length) return { results: [], note: 'No knowledge bases available for this user.' };

            let target = kbs;
            if (args?.knowledge_base) {
                const want = String(args.knowledge_base).toLowerCase();
                const match = kbs.filter((k) => k.name.toLowerCase() === want || k.id === args.knowledge_base);
                if (match.length) target = match;
            }

            // Inventory mode: return the file manifest so the model can count /
            // enumerate documents precisely instead of inferring from snippets.
            if (wantList) {
                const knowledgeBases = target.map((kb) => {
                    const docs = kb.documents || [];
                    return {
                        knowledgeBase: kb.name,
                        documentCount: docs.length,
                        files: docs.map((d) => ({
                            filename: d.filename,
                            type: d.mimeType || (d.filename.includes('.') ? d.filename.split('.').pop() : 'unknown'),
                            chunks: d.chunkCount,
                            addedAt: d.addedAt,
                        })),
                    };
                });
                const totalFiles = knowledgeBases.reduce((n, kb) => n + kb.documentCount, 0);
                logUserActivity(ctx?.userId,
                    `KB: listed inventory — ${totalFiles} file${totalFiles === 1 ? '' : 's'} across ${knowledgeBases.length} knowledge base${knowledgeBases.length === 1 ? '' : 's'} (${target.map(kb => kb.name).join(', ')})`);
                return {
                    totalFiles,
                    knowledgeBases,
                    note: `The user has ${totalFiles} file${totalFiles === 1 ? '' : 's'} across ${knowledgeBases.length} knowledge base${knowledgeBases.length === 1 ? '' : 's'}. Cite filenames exactly as shown.`,
                };
            }

            const all = [];
            for (const kb of target) {
                try {
                    const r = await knowledgeBaseService.search(kb, query, k);
                    for (const item of r) all.push({ ...item, knowledgeBase: kb.name });
                } catch (_) { /* skip a KB whose engine call failed */ }
            }
            all.sort((a, b) => b.score - a.score);
            const top = all.slice(0, k);
            // Process-log which KB documents this search referenced so the user
            // can see the knowledge base being used to answer.
            const refDocs = [...new Set(top.map(r => r.filename).filter(Boolean))];
            const refKbs = [...new Set(top.map(r => r.knowledgeBase).filter(Boolean))];
            logUserActivity(ctx?.userId,
                `KB: searched “${String(query).slice(0, 50)}” — ${top.length === 0 ? 'no matches' : `${top.length} passage${top.length === 1 ? '' : 's'}`}` +
                (refDocs.length ? ` from ${refDocs.length} file${refDocs.length === 1 ? '' : 's'} (${refDocs.slice(0, 3).join(', ')}${refDocs.length > 3 ? ', …' : ''})` : '') +
                (refKbs.length ? ` in ${refKbs.join(', ')}` : ''));
            return {
                query,
                count: top.length,
                results: top.map((r) => ({
                    source: r.filename || r.knowledgeBase,
                    knowledgeBase: r.knowledgeBase,
                    score: r.score,
                    text: r.text,
                })),
                note: top.length
                    ? 'Cite the source filename when you use these passages.'
                    : 'No relevant passages found in the knowledge base.',
            };
        },
    });

    // ----- record_learning -------------------------------------------------
    // Lets the model proactively persist a durable LEARNING into the user's
    // account memory — a correction, a stated preference, a mistake to avoid,
    // a workaround, or an environment limitation it discovered. These are
    // account-scoped and injected into future turns, so the assistant keeps
    // getting better and avoids repeating the same misstep ("continuous
    // improvement"). Recording is autonomous and silent (no confirmation).
    // Hidden when the user has disabled memory.
    tools.registerTool({
        name: 'record_learning',
        async build(ctx) {
            const uid = ctx?.memoryUserId || ctx?.userId;
            if (!uid || uid === 'default') return null;
            if (ctx?.memoryDisabled) return null;
            return {
                type: 'function',
                function: {
                    name: 'record_learning',
                    description:
                        'Save OR refine a durable, experience-based lesson in your long-term memory of THIS user, so your answers get better over time (continual learning). ' +
                        'Use it when an approach worked well (or poorly) and you found a better one, when the user corrects you or states a preference, or when you hit and worked around a limitation. ' +
                        'Capture the OUTCOME and the better next move — e.g. "Searched site A first, results were thin; broadening to A+B+C worked better — start broad next time, keep searching if weak." ' +
                        'Phrase lessons as ADAPTIVE HEURISTICS, never rigid absolutes: prefer "start with X, then try a few alternatives and keep going if results are weak" over "only ever use X". ' +
                        'CONSOLIDATE rather than pile up near-duplicates: if a related lesson already exists (you may see it tagged like [#a1b2c3] in your context), pass that handle as `replaces` to UPDATE/improve it in place. If you omit `replaces`, a close existing lesson is refined automatically. ' +
                        'CONNECT related memories: if this lesson is RELATED to other memories you can see (tagged [#handle]) but does NOT replace them — e.g. a preference that pairs with a fact, or two lessons about the same project — pass their handles in `relatesTo` to link them, so they surface together next time. ' +
                        'Record generalizable lessons, not one-off task facts (those are captured automatically). ' +
                        'If the lesson is about HOW you performed a kind of task (reading emails, web research, analyzing a file), set `activity` to that high-level label — it consolidates into your EXPERIENCE for that activity (your persona) and is reused to do it faster next time. ' +
                        'Runs silently — do not announce it, ask permission, or mention the [#handles] to the user.',
                    parameters: {
                        type: 'object',
                        properties: {
                            lesson: { type: 'string', description: 'The concrete, generalizable, outcome-aware lesson (one or two sentences). State what worked best and what to try next time.' },
                            type: {
                                type: 'string',
                                enum: ['feedback', 'preference', 'correction', 'workaround', 'issue', 'limitation'],
                                description: 'What kind of learning this is.',
                            },
                            impact: {
                                type: 'string',
                                enum: ['important', 'medium', 'low'],
                                description: 'How strongly this should shape future behavior. Set it deliberately: "important" = almost always surface (core preference/correction); "low" = minor/situational. Required.',
                            },
                            context: { type: 'string', description: 'Optional: when/why it matters, so future-you applies it correctly.' },
                            replaces: { type: 'string', description: 'Optional: the [#handle] of an existing learning shown in your context to UPDATE/replace instead of creating a new one. Use this to keep memory consolidated.' },
                            activity: { type: 'string', description: 'Optional: a high-level ACTIVITY label (e.g. "reading emails", "web research", "binary analysis") if this lesson is about HOW you performed that kind of task. Consolidates into your experience for that activity (your persona) and is reused to go faster next time.' },
                            relatesTo: { type: 'array', items: { type: 'string' }, description: 'Optional: [#handles] of existing memories this lesson is RELATED to (but does not replace). They will be linked so they surface together next time. Internal — never shown to the user.' },
                        },
                        required: ['lesson', 'impact'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const userId = ctx?.memoryUserId || ctx?.userId;
            if (!userId || userId === 'default') return { success: false, error: 'no account context for memory' };
            if (ctx?.memoryDisabled) return { success: false, note: 'memory is disabled for this user' };
            const lesson = String(args?.lesson || '').trim();
            if (!lesson) return { success: false, error: 'lesson is required' };
            // Soft per-turn cap so a misbehaving loop can't flood the store.
            ctx._learningCalls = (ctx._learningCalls || 0) + 1;
            if (ctx._learningCalls > 6) return { success: false, note: 'learning limit reached for this turn' };
            const type = memoryService.VALID_TYPES.has(args?.type) ? args.type : 'learning';
            const impact = memoryService.VALID_IMPACTS.has(args?.impact) ? args.impact : 'medium';
            const context = String(args?.context || '').trim();
            const text = context ? `${lesson} — context: ${context}` : lesson;
            const keywords = extractQueryKeywords(text);
            // Explicit model-driven LINKING: connect this lesson to the related
            // memories the model named by [#handle] (resolved to ids), symmetric
            // and best-effort. Returns how many new links were made. 1-hop
            // retrieval expansion then surfaces them together next time.
            const relatesTo = Array.isArray(args?.relatesTo) ? args.relatesTo.slice(0, 5) : [];
            const linkRelated = async (newId) => {
                if (!newId || !relatesTo.length) return 0;
                let linked = 0;
                for (const h of relatesTo) {
                    try {
                        const tgt = await memoryService.resolveHandle(userId, h);
                        if (tgt && tgt.id !== newId) {
                            const r = await memoryService.setLink(userId, newId, tgt.id);
                            if (r && r.changed) linked++;
                        }
                    } catch (_) { /* best-effort */ }
                }
                return linked;
            };
            try {
                // Experience path: when the model labels an ACTIVITY, this lesson
                // is about HOW it did that kind of task — store it as a procedure
                // (persona), consolidated by activity key and reused to go faster.
                // BUT a behavioral preference/correction is NOT a tool-path: the
                // model sometimes tags one with an activity ("activity:coding,
                // always use type hints"), which would OVERWRITE the activity's
                // lean tool-recipe with a style rule. Route those to the learning
                // store instead, where they become a curated directive that
                // applies across every activity (and always injects).
                // Note: type 'learning'/'workaround'/'issue' WITH an activity is
                // genuinely procedural (how a task was done) and correctly takes
                // the experience path; only preference/correction/feedback bypass
                // it to become cross-topic directives.
                const activityLabel = String(args?.activity || '').trim();
                const isBehavioralLesson = type === 'preference' || type === 'correction' || type === 'feedback';
                if (activityLabel && !isBehavioralLesson) {
                    const ar = await memoryService.upsertActivityMemory(userId, {
                        activity: activityLabel, text, keywords, impact,
                        tokens: Math.ceil(text.length / 3), source: 'model',
                        sourceConvId: ctx.conversationId || null,
                    });
                    const arLinked = await linkRelated(ar.id);
                    logUserActivity(userId,
                        `Memory: ${ar.updated ? 'updated existing experience (refined)' : 'created new experience'} [${memoryService.normalizeActivity(activityLabel)}] (×${ar.count}, ${ar.impact})${arLinked ? ` +${arLinked} link${arLinked === 1 ? '' : 's'}` : ''} — “${lesson.slice(0, 70)}”`);
                    return {
                        success: true, id: ar.id, updated: ar.updated, linked: arLinked,
                        recorded: { activity: memoryService.normalizeActivity(activityLabel), impact: ar.impact, count: ar.count },
                        note: ar.updated ? 'Refined your experience for this activity.' : 'Recorded experience for this activity; it will guide similar tasks.',
                    };
                }
                // CONSOLIDATION lives in the service (race-safe, atomic): refine an
                // existing learning instead of appending a near-duplicate, so the
                // store self-improves rather than sprawls. An explicit [#handle]
                // (replaces) can refine ANY of the user's memories; otherwise the
                // closest prior MODEL learning is merged automatically.
                const res = await memoryService.upsertModelLearning(userId, {
                    text, keywords, type, impact,
                    tokens: Math.ceil(text.length / 3),
                    sourceConvId: ctx.conversationId || null,
                }, { replaces: args?.replaces || null });
                const resLinked = await linkRelated(res.id);
                // Process-log the model-recorded learning so the user sees the
                // assistant's self-improvement happening, not just a silent tool call.
                logUserActivity(userId,
                    `Memory: ${res.updated ? 'updated existing learning (refined)' : 'created new learning'} [${type}/${res.impact}]${resLinked ? ` +${resLinked} link${resLinked === 1 ? '' : 's'}` : ''} — “${lesson.slice(0, 80)}”`);
                return {
                    success: true,
                    id: res.id,
                    updated: res.updated,
                    linked: resLinked,
                    recorded: { type, impact: res.impact },
                    note: res.updated
                        ? 'Refined an existing learning (consolidated, not duplicated).'
                        : 'Learning recorded; it will inform future responses.',
                };
            } catch (e) {
                return { success: false, error: e.message };
            }
        },
    });

    // find_tools — the router's discovery meta-tool. build()->null so it's HIDDEN
    // from the normal catalog (routing-OFF stays byte-identical), but registered
    // so executeToolCall dispatches it by name; selectForTurn injects its def
    // directly when routing is active.
    tools.registerTool(toolRouter.findToolsTool);

    tools.setDynamicToolProvider(async (ctx) => {
        try {
            const all = await loadSkills();
            const scoped = filterByUserId(all, ctx?.userId);
            const policy = await resolveSkillPolicy(ctx);
            const out = [];
            // Tool names must be unique — load_skill / web_search /
            // fetch_url are already in the static registry. Dedupe.
            const taken = new Set(tools.toolRegistry.keys());
            for (const s of scoped) {
                if (!s || s.enabled === false || !s.name) continue;
                const name = safeToolName(s.name);
                if (isSkillBlocked(policy, s.name)) continue;
                if (!name || taken.has(name)) continue;
                taken.add(name);
                // Description is the primary selection signal — most skills
                // have a clear, terse description (avg ~97 chars). When
                // description is short and systemPrompt has a useful trigger
                // sentence, append the first sentence of systemPrompt as
                // hinting. Final cap at 150 chars (was 400): with 100
                // tools the catalog can otherwise approach 30 KB, dominating
                // the per-turn prompt eval. Beyond ~150 chars, additional
                // verbosity actively hurts selection accuracy on small
                // models because each schema sprawls.
                let desc = (typeof s.description === 'string' ? s.description.trim() : '') || s.name;
                if (desc.length < 80 && typeof s.systemPrompt === 'string' && s.systemPrompt.trim()) {
                    // Pull the first sentence of systemPrompt — usually the
                    // load-bearing trigger phrase ("Use this skill to ...").
                    // Strip the boilerplate "Use this skill to" lead-in and any
                    // chat-sandbox workspace clauses so the description stays
                    // task-focused (avoids "in your workspace at /workspace/..."
                    // leaking into external tool catalogs).
                    const cleaned = s.systemPrompt
                        .replace(/^\s*Use this skill to\s+/i, '')
                        .replace(/\bin (?:your |the )?workspace[^.]*\./gi, '')
                        .trim();
                    const firstSentence = cleaned.split(/(?<=[.!?])\s+/)[0] || '';
                    if (firstSentence && firstSentence.length <= 150 - desc.length - 3) {
                        desc = `${desc} — ${firstSentence}`;
                    }
                }
                let truncatedDesc;
                if (desc.length > 150) {
                    const sp = desc.lastIndexOf(' ', 147);
                    truncatedDesc = (sp > 0 ? desc.slice(0, sp) : desc.slice(0, 147)) + '…';
                } else {
                    truncatedDesc = desc;
                }
                out.push({
                    type: 'function',
                    function: {
                        name,
                        description: truncatedDesc,
                        parameters: paramsToJsonSchema(s.parameters),
                    },
                });
            }
            return out;
        } catch (e) {
            console.warn('[chatTools] dynamic skill provider failed:', e.message);
            return [];
        }
    });

    tools.setFallbackDispatch(async (toolName, args, ctx) => {
        // Called when the model invokes a tool name that isn't in the
        // static registry — expected to be a skill from the dynamic
        // catalog. Dispatch via executePythonSkill so the sandbox /
        // workspace / network-allowlist policy on the skill record is
        // respected, same as if it were called through /api/skills/:name/execute.
        const all = await loadSkills();
        const scoped = filterByUserId(all, ctx?.userId);
        const safe = toolName;
        const skill = scoped.find(s => safeToolName(s.name) === safe);
        if (!skill) {
            return { success: false, error: `Unknown skill: ${toolName}` };
        }
        const policy = await resolveSkillPolicy(ctx);
        if (isSkillBlocked(policy, skill.name)) {
            const inDeny = policy.deny && policy.deny.has(safeToolName(skill.name));
            return {
                success: false,
                error: inDeny
                    ? `Skill "${toolName}" is disabled for this API key.`
                    : `Skill "${toolName}" is not in the allowed-skills list for this scope.`
            };
        }
        if (skill.enabled === false) {
            return { success: false, error: `Skill "${toolName}" is disabled` };
        }
        try {
            let result;
            if (skill.code && skill.code.trim() && !skill.code.startsWith('Uses ') && !skill.code.startsWith('Runs ')) {
                result = await executePythonSkill(skill, args, ctx);
            } else {
                result = await executeLegacySkill(skill.name, args);
            }
            return result;
        } catch (e) {
            return { success: false, error: e.message || String(e) };
        }
    });

    // ----- query_document / read_document_chunk ---------------------------
    // Agentic alternative to map-reduce: when input exceeds the model's
    // context, the chat-stream handler stashes the content via
    // documentIndex.saveAndIndex and rewrites the user message with a
    // small handle. These two tools let the model walk the indexed
    // document inside its normal tool loop instead of receiving a
    // single condensed synthesis of pre-summarised chunks. See
    // services/documentIndex.js for the index format.
    const documentIndex = require('./services/documentIndex');

    tools.registerTool({
        name: 'query_document',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'query_document',
                    description:
                        'Search a large indexed document (one whose `documentId` was provided in your most recent user message) for the chunks most relevant to a query. ' +
                        'Use this FIRST on any large content — it returns the top-matching chunks ranked by TF-IDF cosine similarity, with line ranges so you can cite. ' +
                        'Each match includes ~1500 chars of chunk text; if you need the full chunk, follow up with read_document_chunk(documentId, chunkIndex). ' +
                        'For multi-aspect questions ("compare X and Y"), call this multiple times in parallel with different queries — once per aspect.',
                    parameters: {
                        type: 'object',
                        properties: {
                            documentId: {
                                type: 'string',
                                description: '32-hex documentId from the user message handle.',
                            },
                            query: {
                                type: 'string',
                                description: 'Search terms — entities, phrases, or keywords. Stopwords are stripped automatically.',
                            },
                            topK: {
                                type: 'integer',
                                minimum: 1,
                                maximum: 10,
                                description: 'Number of top-ranked chunks to return (default 3).',
                            },
                        },
                        required: ['documentId', 'query'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const documentId = String(args?.documentId || '').trim();
            const query = String(args?.query || '').trim();
            if (!documentId) return { error: 'documentId is required' };
            if (!query) return { error: 'query is required' };
            const topK = args?.topK ? parseInt(args.topK, 10) : 3;
            try {
                return await documentIndex.queryDocument(ctx?.userId, documentId, query, {
                    topK,
                    activeDocumentId: ctx?.activeDocumentId || null,
                });
            } catch (e) {
                return { error: `query_document failed: ${e.message || String(e)}` };
            }
        },
    });

    tools.registerTool({
        name: 'read_document_chunk',
        build() {
            return {
                type: 'function',
                function: {
                    name: 'read_document_chunk',
                    description:
                        'Read one or more sequential chunks of an indexed document by chunkIndex. Use after query_document when you need a chunk in full, or to walk the document linearly (e.g. chunkIndex 0, 1, 2…). ' +
                        'Each chunk is ~3500 chars; the response includes line ranges and a `nextChunkIndex` you can pass back on the next call to continue reading. Cap a single call to `count` ≤ 5.',
                    parameters: {
                        type: 'object',
                        properties: {
                            documentId: {
                                type: 'string',
                                description: '32-hex documentId from the user message handle.',
                            },
                            chunkIndex: {
                                type: 'integer',
                                minimum: 0,
                                description: 'Zero-based chunk index to start at.',
                            },
                            count: {
                                type: 'integer',
                                minimum: 1,
                                maximum: 5,
                                description: 'How many sequential chunks to return (default 1, max 5). Bounded by a 12000-char total.',
                            },
                        },
                        required: ['documentId', 'chunkIndex'],
                        additionalProperties: false,
                    },
                },
            };
        },
        async execute(args, ctx) {
            const documentId = String(args?.documentId || '').trim();
            if (!documentId) return { error: 'documentId is required' };
            const chunkIndex = parseInt(args?.chunkIndex, 10);
            if (!Number.isFinite(chunkIndex) || chunkIndex < 0) {
                return { error: 'chunkIndex must be a non-negative integer' };
            }
            const count = args?.count ? parseInt(args.count, 10) : 1;
            try {
                return await documentIndex.readChunk(ctx?.userId, documentId, chunkIndex, {
                    count,
                    activeDocumentId: ctx?.activeDocumentId || null,
                });
            } catch (e) {
                return { error: `read_document_chunk failed: ${e.message || String(e)}` };
            }
        },
    });

    console.log(`[chatTools] registered ${tools.toolRegistry.size} static native tools:`,
        [...tools.toolRegistry.keys()].join(', '),
        '+ dynamic skill catalog');
})();

// ============================================================================
// SERVER
// ============================================================================

const PORT = process.env.PORT || 3001;
const HTTP_REDIRECT_PORT = process.env.HTTP_REDIRECT_PORT || 3080;

server.listen(PORT, async () => {
    const protocol = useHttps ? 'https' : 'http';
    console.log(`Server is listening on ${protocol}://localhost:${PORT}`);

    // Parallel initialization for faster startup
    console.log('Starting parallel initialization...');

    // Phase 1: Independent async operations that don't depend on each other
    const [detectedPath, loadedStats] = await Promise.all([
        // Detect the host models path for creating dynamic containers
        // This is critical for cross-platform compatibility (Windows+WSL, macOS, Linux)
        detectHostModelsPath(),
        // Load API key usage stats from disk
        loadApiKeyUsageStats(),
        // Migrate unencrypted API keys to encrypted format (one-time operation)
        migrateApiKeysEncryption()
    ]);

    hostModelsPath = detectedPath;
    console.log(`Host models path configured: ${hostModelsPath}`);

    // Sandbox runner needs the host path to stage scratch dirs that sibling
    // tool-exec containers can mount. Tell it now that hostModelsPath is known.
    try {
        require('./services/sandboxRunner').setHostBase(hostModelsPath);
    } catch (_) { /* sandbox runner absent — runs will throw on use */ }

    for (const [key, value] of loadedStats.entries()) {
        apiKeyUsageStats.set(key, value);
    }
    console.log(`Loaded usage stats for ${apiKeyUsageStats.size} API keys`);

    // Phase 2: Independent initialization tasks that can run in parallel
    await Promise.all([
        initializeDefaultSkills(),
        initializeDefaultApiKeys(),
        syncModelInstances()
    ]);

    // Start the egress proxy used by sandboxed tool-execution containers.
    // Safe to start even when no tools use 'allowlist' — it just sits idle.
    try {
        require('./services/egressProxy').start();
    } catch (e) {
        console.warn('[Startup] egressProxy failed to start:', e.message);
    }

    // Hydrate admin system settings (e.g. allowInternalNetwork) and push the
    // internal-network choice into BOTH enforcement points (done inside).
    try {
        const s = await loadSystemSettings();
        if (s.allowInternalNetwork) console.warn('[Startup] allowInternalNetwork is ON — internal/private network access is permitted (metadata IP still blocked).');
    } catch (e) {
        console.warn('[Startup] loadSystemSettings failed:', e.message);
    }

    // Warm up the Knowledge Base embedding engine in the background so the
    // model is resident before the first query. Fire-and-forget — boot must
    // not block on the model load, and KB calls lazily spawn it anyway.
    knowledgeBaseService.ensureEngine()
        .then(() => knowledgeBaseService.health())
        .then((h) => console.log(`[kb] embedding engine ready (${h.model}, dim=${h.dim})`))
        .catch((e) => console.warn('[kb] engine warm-up deferred:', e.message));

    // One-shot legacy-workspace migration: older installs kept per-user
    // files directly under /models/.modelserver/workspaces/<userId>/; the
    // new per-conversation scheme buckets into <userId>/{conv-<id>|global}/.
    // Shuffle loose legacy entries into the `global` bucket so existing
    // content stays accessible to non-chat callers. Idempotent.
    try {
        const sbRunner = require('./services/sandboxRunner');
        if (typeof sbRunner.migrateLegacyWorkspaces === 'function') {
            await sbRunner.migrateLegacyWorkspaces();
        }
    } catch (e) {
        console.warn('[workspace-migration] failed (non-fatal):', e.message);
    }

    // Attachment-store orphan sweep. Walks every user's conversations,
    // collects every attachmentId still referenced, and deletes any
    // attachment dir older than 14 days that no live message references.
    // Catches:
    //   - uploads that never made it into a sent message (browser closed
    //     before send, conversation never persisted)
    //   - persistence races where the message file was overwritten without
    //     the attachment getting a chance to be referenced
    // Runs once at boot and again every 12 hours so a long-running webapp
    // doesn't grow attachments without bound.
    async function sweepAttachmentOrphans() {
        try {
            const refsByUser = new Map();
            let userEntries;
            try {
                userEntries = await fs.readdir(CONVERSATIONS_DIR, { withFileTypes: true });
            } catch (e) {
                if (e.code !== 'ENOENT') throw e;
                userEntries = [];
            }
            for (const userEnt of userEntries) {
                if (!userEnt.isDirectory()) continue;
                const userId = userEnt.name;
                const userBucket = attachmentStore.userIdSafe(userId);
                let refs = refsByUser.get(userBucket);
                if (!refs) { refs = new Set(); refsByUser.set(userBucket, refs); }
                let convFiles;
                try {
                    convFiles = await fs.readdir(path.join(CONVERSATIONS_DIR, userId));
                } catch (_) { continue; }
                for (const f of convFiles) {
                    if (!f.endsWith('.json') || f === 'index.json') continue;
                    const convId = f.replace(/\.json$/, '');
                    if (!/^[a-zA-Z0-9_-]+$/.test(convId)) continue;
                    let messages;
                    try {
                        messages = await loadConversationMessages(userId, convId);
                    } catch (_) { continue; }
                    for (const msg of messages) {
                        const atts = Array.isArray(msg?.attachments) ? msg.attachments : [];
                        for (const att of atts) {
                            if (att && typeof att.attachmentId === 'string') {
                                refs.add(att.attachmentId);
                            }
                        }
                    }
                }
            }
            const result = await attachmentStore.sweepOrphans(refsByUser);
            if (result.swept > 0) {
                const kb = Math.round((result.byteSize || 0) / 1024);
                console.log(`[AttachmentSweeper] removed ${result.swept} orphan attachment(s), reclaimed ${kb} KB`);
            }
        } catch (e) {
            console.warn('[AttachmentSweeper] failed:', e.message);
        }
    }
    // Boot pass — fires after server is listening so it doesn't block.
    sweepAttachmentOrphans();
    const ATTACHMENT_SWEEP_INTERVAL_MS = 12 * 60 * 60 * 1000;
    setInterval(sweepAttachmentOrphans, ATTACHMENT_SWEEP_INTERVAL_MS).unref();

    // Sandbox scratch dir TTL sweeper — deletes run directories older than
    // ARTIFACT_TTL_MS so artifact files from sandboxed tool runs don't
    // accumulate on disk. Runs every 10 minutes; default TTL 1 hour.
    const ARTIFACT_TTL_MS = parseInt(process.env.SANDBOX_ARTIFACT_TTL_MS || '3600000', 10);
    const SANDBOX_SWEEP_INTERVAL_MS = 10 * 60 * 1000;
    setInterval(async () => {
        const sandboxDir = '/models/.modelserver/sandbox';
        try {
            const entries = await fs.readdir(sandboxDir, { withFileTypes: true }).catch(() => []);
            const now = Date.now();
            let swept = 0;
            for (const e of entries) {
                if (!e.isDirectory()) continue;
                const p = `${sandboxDir}/${e.name}`;
                try {
                    const st = await fs.stat(p);
                    if (now - st.mtimeMs > ARTIFACT_TTL_MS) {
                        await fs.rm(p, { recursive: true, force: true });
                        swept++;
                    }
                } catch (_) { /* ignore */ }
            }
            if (swept) console.log(`[SandboxSweeper] removed ${swept} expired tool-run dir(s)`);
        } catch (e) {
            console.warn('[SandboxSweeper] failed:', e.message);
        }
    }, SANDBOX_SWEEP_INTERVAL_MS).unref();

    // Automation scheduler — a 5s tick fires due trigger.schedule nodes (cron
    // fires once per matching minute; intervals are epoch-aligned and honored to
    // ~5s). Single timer for all workflows; .unref()'d so it never holds the process.
    const AUTOMATION_TICK_MS = 5 * 1000;
    setInterval(automationSchedulerTick, AUTOMATION_TICK_MS).unref();

    // Telegram trigger poller — getUpdates per bot every ~15s (no public webhook
    // on a localhost/self-signed host). .unref()'d so it never holds the process.
    const AUTOMATION_TELEGRAM_TICK_MS = 15 * 1000;
    setInterval(automationTelegramTick, AUTOMATION_TELEGRAM_TICK_MS).unref();

    // Slack trigger poller — conversations.history per (bot token, channel) every
    // ~15s (no public webhook on a localhost/self-signed host). .unref()'d so it
    // never holds the process.
    const AUTOMATION_SLACK_TICK_MS = 15 * 1000;
    setInterval(automationSlackTick, AUTOMATION_SLACK_TICK_MS).unref();

    console.log('Initialization complete');
});

// Start HTTP redirect server if HTTPS is enabled
if (useHttps && httpRedirectServer) {
    httpRedirectServer.listen(HTTP_REDIRECT_PORT, () => {
        console.log(`HTTP redirect server listening on port ${HTTP_REDIRECT_PORT} -> redirects to HTTPS`);
    });
}
